UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "«التبشير» شعار أعلنه المنصِّرون، وتسموا به، وسلكوا طرقه وأساليبه، وكثيرًا ما كنا نرى أساليبهم المحببة للنفوس والتي يستبشر بها المتعاملون معهم.. بينما نجد طريقة تعامل بعض الدعاة ينفر منها المدعوُّون، أوليس الداعية أحقَّ باسم التبشير خُلقًا ووسيلة وغاية؟! هذا ما سنتعرف عليه في هذا الخُلُق.", "page": 263, "id": "unit-24__lesson-05__b01", "inline": [{"t": "quote", "s": "التبشير"}, {"t": "text", "s": " شعار أعلنه المنصِّرون، وتسموا به، وسلكوا طرقه وأساليبه، وكثيرًا ما كنا نرى أساليبهم المحببة للنفوس والتي يستبشر بها المتعاملون معهم.. بينما نجد طريقة تعامل بعض الدعاة ينفر منها المدعوُّون، أوليس الداعية أحقَّ باسم التبشير خُلقًا ووسيلة وغاية؟! هذا ما سنتعرف عليه في هذا الخُلُق."}]}, {"type": "paragraph", "md": "معنى «التبشير»: التخلق بالصفات التي تستدعي الاستئناس والارتياح والتحبب وبث الأمل في القلوب، والبعد عن أساليب «التنفير» ودواعي الانقباض، حتى في التخويف من الله والترهيب من النار.", "page": 263, "id": "unit-24__lesson-05__b02", "inline": [{"t": "text", "s": "معنى "}, {"t": "quote", "s": "التبشير"}, {"t": "text", "s": ": التخلق بالصفات التي تستدعي الاستئناس والارتياح والتحبب وبث الأمل في القلوب، والبعد عن أساليب "}, {"t": "quote", "s": "التنفير"}, {"t": "text", "s": " ودواعي الانقباض، حتى في التخويف من الله والترهيب من النار."}]}, {"type": "paragraph", "md": "فقد بُعث رسول الله صلى الله عليه وسلم بشيرًا لأتباعه، نذيرًا لأعدائه، بل كانت مهمة الرسل لا تعدو هذينِ الوصفين: ﴿وَمَا نُرۡسِلُ ٱلۡمُرۡسَلِينَ إِلَّا مُبَشِّرِينَ وَمُنذِرِينَۚ﴾، وأمر الله في كتابه بتبشير المؤمنين والصابرين والمحسنين والمخبتين؛ في آيات كثيرة، وكان من أساليب تبشير رسول الله صلى الله عليه وسلم أنه يختار الوقت والقدر المناسبين لأداء الموعظة والعلم كيلا ينفر الصحابة، وفي ذلك يقول صلى الله عليه وسلم : (يَسِّروا ولا تُعسِّروا، وبَشِّروا ولا تُنفِّروا).", "page": 263, "id": "unit-24__lesson-05__b03", "inline": [{"t": "text", "s": "فقد بُعث رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بشيرًا لأتباعه، نذيرًا لأعدائه، بل كانت مهمة الرسل لا تعدو هذينِ الوصفين: "}, {"t": "ayah", "s": "وَمَا نُرۡسِلُ ٱلۡمُرۡسَلِينَ إِلَّا مُبَشِّرِينَ وَمُنذِرِينَۚ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "، وأمر الله في كتابه بتبشير المؤمنين والصابرين والمحسنين والمخبتين؛ في آيات كثيرة، وكان من أساليب تبشير رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أنه يختار الوقت والقدر المناسبين لأداء الموعظة والعلم كيلا ينفر الصحابة، وفي ذلك يقول "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(يَسِّروا ولا تُعسِّروا، وبَشِّروا ولا تُنفِّروا)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "قال ابن حجر شارحًا للحديث: «المراد: تأليف من قرب إسلامه، وتركُ التشديد عليه في الابتداء، وكذلك الزجر عن المعاصي ينبغي أن يكون بتلطف ليقبل، وكذا تعليم العلم ينبغي أن يكون بالتدريج؛ لأن الشيء إذا كان في ابتدائه سهلًا حبب إلى مَن يدخل فيه، وتلقَّاه بانبساط، وكانت عاقبته غالبًا الازدياد..».", "page": 263, "id": "unit-24__lesson-05__b04", "inline": [{"t": "text", "s": "قال ابن حجر شارحًا للحديث: "}, {"t": "quote", "s": "المراد: تأليف من قرب إسلامه، وتركُ التشديد عليه في الابتداء، وكذلك الزجر عن المعاصي ينبغي أن يكون بتلطف ليقبل، وكذا تعليم العلم ينبغي أن يكون بالتدريج؛ لأن الشيء إذا كان في ابتدائه سهلًا حبب إلى مَن يدخل فيه، وتلقَّاه بانبساط، وكانت عاقبته غالبًا الازدياد..", "speaker": "ابن حجر شارحا للحديث"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ومن حكمته صلى الله عليه وسلم : أنه استعمل أساليب التبشير في إيقاظ الهمم والتنشيط للطاعة، ومن ذلك قوله: (بشِّر المشائين في الظُّلَم إلى المساجد بالنور التامِّ يوم القيامة)، وصلى العشاء مرة بأصحابه، وقبل أن ينصرفوا قال لهم: (على رسلكم، أبشروا، إن من نعمة الله عليكم أنه ليس أحد من الناس يصلي هذه الساعة غيركم)، قال أبو موسى الأشعري: فرجعنا ففرحنا بما سمعنا من رسول الله صلى الله عليه وسلم .", "page": 263, "id": "unit-24__lesson-05__b05", "inline": [{"t": "emphasis", "s": "ومن حكمته", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : أنه استعمل أساليب التبشير في إيقاظ الهمم والتنشيط للطاعة، ومن ذلك قوله: "}, {"t": "emphasis", "s": "(بشِّر المشائين في الظُّلَم إلى المساجد بالنور التامِّ يوم القيامة)", "role": "emphasis"}, {"t": "text", "s": "، وصلى العشاء مرة بأصحابه، وقبل أن ينصرفوا قال لهم: "}, {"t": "emphasis", "s": "(على رسلكم، أبشروا، إن من نعمة الله عليكم أنه ليس أحد من الناس يصلي هذه الساعة غيركم)", "role": "emphasis"}, {"t": "text", "s": "، قال أبو موسى الأشعري: فرجعنا ففرحنا بما سمعنا من رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "ويحتاج الإنسان في حالات الاضطراب إلى التبشير بما يزيل عنه دواعي الاضطراب؛ فبعد نزول الوحي على رسول الله صلى الله عليه وسلم ذكر لخديجة رضي الله عنها ما جرى له، وأخبرها بخوفه على نفسه من هذه الظاهرة الجديدة، فبشَّرته بأن له من سابقة الخير ما يستبعد معها مكافأة الله له بمكروه، فقالت: «كلا، أبشر، فوالله لا يخزيك الله أبدًا، فوالله إنك لتَصِل الرحم، وتصدق الحديث، وتحمل الكلَّ، وتَكسِب المعدوم، وتعين على نوائب الحق»، وكان هذا شأن رسول الله صلى الله عليه وسلم مع أمته ليزيل عنها دواعي القلق على مستقبل هذا الدين؛ فيقول مبشرًا: (بشر هذه الأمة بالسناء والرفعة والدين والنصر والتمكين في الأرض).", "page": 263, "id": "unit-24__lesson-05__b06", "inline": [{"t": "text", "s": "ويحتاج الإنسان في حالات الاضطراب إلى التبشير بما يزيل عنه دواعي الاضطراب؛ فبعد نزول الوحي على رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ذكر لخديجة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " ما جرى له، وأخبرها بخوفه على نفسه من هذه الظاهرة الجديدة، فبشَّرته بأن له من سابقة الخير ما يستبعد معها مكافأة الله له بمكروه، فقالت: "}, {"t": "quote", "s": "كلا، أبشر، فوالله لا يخزيك الله أبدًا، فوالله إنك لتَصِل الرحم، وتصدق الحديث، وتحمل الكلَّ، وتَكسِب المعدوم، وتعين على نوائب الحق"}, {"t": "text", "s": "، وكان هذا شأن رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " مع أمته ليزيل عنها دواعي القلق على مستقبل هذا الدين؛ فيقول مبشرًا: "}, {"t": "emphasis", "s": "(بشر هذه الأمة بالسناء والرفعة والدين والنصر والتمكين في الأرض)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وحتى في حالات الضعف البشري؛ لم يكن رسول الله صلى الله عليه وسلم ليعنِّف أصحابه بفظاظة، وهم الذين سمعوا بقدوم أبي عبيدة بجزية البحرين، فاجتمعوا فجرًا، وتبعوا رسول الله صلى الله عليه وسلم بعد الصلاة، ففهم ماذا يريدون، فقال: (أبشروا وأملوا ما يسركم، فوالله لا الفقر أخشى عليكم، ولكن أخشى أن تبسط عليكم الدنيا).", "page": 264, "id": "unit-24__lesson-05__b07", "inline": [{"t": "text", "s": "وحتى في حالات الضعف البشري؛ لم يكن رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ليعنِّف أصحابه بفظاظة، وهم الذين سمعوا بقدوم أبي عبيدة بجزية البحرين، فاجتمعوا فجرًا، وتبعوا رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بعد الصلاة، ففهم ماذا يريدون، فقال: "}, {"t": "emphasis", "s": "(أبشروا وأملوا ما يسركم، فوالله لا الفقر أخشى عليكم، ولكن أخشى أن تبسط عليكم الدنيا)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "والمؤمن محتاجٌ في حال البلاء إلى من يكشف همه، ويبشره بما يسره، إما بفرج عاجل، أو بأجر آجل، ولقد وجد رسول الله صلى الله عليه وسلم أم العلاء مريضة فقال لها: (أبشري يا أم العلاء، فإن مرض المسلم يُذهب خطاياه، كما تُذهب النار خبث الحديد)، فالمؤمن بشير في مواقف الأسى؛ يُسَرِّي عن الناس أحزانهم؛ بما يدخل البهجة إلى قلوبهم، ويُبعد الكآبة عنهم، وقد كتب زيد بن أرقم إلى أنس بن مالك زمن وقعة الحرة (63هـ) يعزِّيه فيمن قُتل من ولده وقومه، فقال: أبشرك ببشرى من الله عز وجل ، سمعت رسول الله صلى الله عليه وسلم يقول: (اللهم اغفر للأنصار، ولأبناء الأنصار، ولأبناء أبناء الأنصار).. فسكنت بذلك نفوسهم ورضيت.", "page": 264, "id": "unit-24__lesson-05__b08", "inline": [{"t": "text", "s": "والمؤمن محتاجٌ في حال البلاء إلى من يكشف همه، ويبشره بما يسره، إما بفرج عاجل، أو بأجر آجل، ولقد وجد رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أم العلاء مريضة فقال لها: "}, {"t": "emphasis", "s": "(أبشري يا أم العلاء، فإن مرض المسلم يُذهب خطاياه، كما تُذهب النار خبث الحديد)", "role": "emphasis"}, {"t": "text", "s": "، فالمؤمن بشير في مواقف الأسى؛ يُسَرِّي عن الناس أحزانهم؛ بما يدخل البهجة إلى قلوبهم، ويُبعد الكآبة عنهم، وقد كتب زيد بن أرقم إلى أنس بن مالك زمن وقعة الحرة "}, {"t": "emphasis", "s": "(63هـ)", "role": "emphasis"}, {"t": "text", "s": " يعزِّيه فيمن قُتل من ولده وقومه، فقال: أبشرك ببشرى من الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ، سمعت رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يقول: "}, {"t": "emphasis", "s": "(اللهم اغفر للأنصار، ولأبناء الأنصار، ولأبناء أبناء الأنصار)", "role": "emphasis"}, {"t": "text", "s": ".. فسكنت بذلك نفوسهم ورضيت."}]}, {"type": "paragraph", "md": "ولقد بشر الله المبايعين على الجهاد بما ادخر الله لهم من الأجر إن وفُّوا بالبيعة: ﴿فَٱسۡتَبۡشِرُواْ بِبَيۡعِكُمُ ٱلَّذِي بَايَعۡتُم بِهِۦۚ﴾، وبشر رسول الله صلى الله عليه وسلم الموحِّدين بالجنة جزاءَ التزامهم بكلمة التوحيد قولًا واعتقادًا وعملًا: (أبشروا. وبشروا من وراءكم؛ أنه من شهد أن لا إله إلا الله صادقًا من قلبه، دخل الجنة) وقال جبريل عليه السلام للنبي صلى الله عليه وسلم مبشرًا المؤمنين: (بشر أمتك أنه من مات لا يشرك بالله شيئًا، دخل الجنة).", "page": 264, "id": "unit-24__lesson-05__b09", "inline": [{"t": "text", "s": "ولقد بشر الله المبايعين على الجهاد بما ادخر الله لهم من الأجر إن وفُّوا بالبيعة: "}, {"t": "ayah", "s": "فَٱسۡتَبۡشِرُواْ بِبَيۡعِكُمُ ٱلَّذِي بَايَعۡتُم بِهِۦۚ", "ayah": [], "verses": [{"n": 111, "text": "فَٱسۡتَبۡشِرُواْ بِبَيۡعِكُمُ ٱلَّذِي بَايَعۡتُم بِهِۦۚ", "surah": 9, "surah_name": "التوبة", "ref": "9:111", "ref_api": "https://api.quran.com/api/v4/verses/by_key/9:111"}], "surah": 9, "ref_api": "https://api.quran.com/api/v4/verses/by_key/9:111", "surah_name": "التوبة", "ayah_canonical": 111, "match": "contained", "ref": "9:111"}, {"t": "text", "s": "، وبشر رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " الموحِّدين بالجنة جزاءَ التزامهم بكلمة التوحيد قولًا واعتقادًا وعملًا: "}, {"t": "emphasis", "s": "(أبشروا. وبشروا من وراءكم؛ أنه من شهد أن لا إله إلا الله صادقًا من قلبه، دخل الجنة)", "role": "emphasis"}, {"t": "text", "s": " وقال جبريل "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " للنبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " مبشرًا المؤمنين: "}, {"t": "emphasis", "s": "(بشر أمتك أنه من مات لا يشرك بالله شيئًا، دخل الجنة)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وفي توبة كعب بن مالك صورة عملية من صور التعاطف الاجتماعي والتهنئة بقبول التوبة؛ حيث ذهب إليه عدد من المبشِّرين يزفون له الخبر، فناداه أحدهم قبل أن يصل إليه: «يا كعبُ بنَ مالكٍ، أبشر»، يقول كعب: «فخررت ساجدًا، وعرفت أن قد جاء فرج»، وتلقاه الناس فوجًا فوجًا يهنئونه بالتوبة ويقولون له: «لتهنك توبة الله عليك»، ولما سلم على رسول الله صلى الله عليه وسلم قال له وهو يبرق وجهه من السرور: (أبشر بخير يوم مر عليك منذ ولدتك أمك..)، ومن لطيف ما ورد في هذه القصة رواية نقلها صاحب الفتح، تبين مدى حرص المجتمع الإسلامي على تبادل البشريات، يقول كعب: فأنزل الله توبتنا على نبيه حين بقي الثلث الأخير من الليل، ورسول الله صلى الله عليه وسلم عند أم سلمة، وكانت أم سلمة محسنة في شأني معتنية بأمري، فقال: (يا أم سلمة! تِيب على كعب)، قالت: أفلا أُرسِل إليه فأبشره؟ قال: (إذًا يحطمكم الناس فيمنعوكم النوم سائر الليلة)؛ فقد كانت أم سلمة حريصة على ألا تنتظر الصباح وألا تدخر البُشرى لرجل مسلم.", "page": 264, "id": "unit-24__lesson-05__b10", "inline": [{"t": "text", "s": "وفي توبة كعب بن مالك صورة عملية من صور التعاطف الاجتماعي والتهنئة بقبول التوبة؛ حيث ذهب إليه عدد من المبشِّرين يزفون له الخبر، فناداه أحدهم قبل أن يصل إليه: "}, {"t": "quote", "s": "يا كعبُ بنَ مالكٍ، أبشر"}, {"t": "text", "s": "، يقول كعب: "}, {"t": "quote", "s": "فخررت ساجدًا، وعرفت أن قد جاء فرج", "speaker": "كعب"}, {"t": "text", "s": "، وتلقاه الناس فوجًا فوجًا يهنئونه بالتوبة ويقولون له: "}, {"t": "quote", "s": "لتهنك توبة الله عليك"}, {"t": "text", "s": "، ولما سلم على رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قال له وهو يبرق وجهه من السرور: "}, {"t": "emphasis", "s": "(أبشر بخير يوم مر عليك منذ ولدتك أمك..)", "role": "emphasis"}, {"t": "text", "s": "، ومن لطيف ما ورد في هذه القصة رواية نقلها صاحب الفتح، تبين مدى حرص المجتمع الإسلامي على تبادل البشريات، يقول كعب: فأنزل الله توبتنا على نبيه حين بقي الثلث الأخير من الليل، ورسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " عند أم سلمة، وكانت أم سلمة محسنة في شأني معتنية بأمري، فقال: "}, {"t": "emphasis", "s": "(يا أم سلمة! تِيب على كعب)", "role": "emphasis"}, {"t": "text", "s": "، قالت: أفلا أُرسِل إليه فأبشره؟ قال: "}, {"t": "emphasis", "s": "(إذًا يحطمكم الناس فيمنعوكم النوم سائر الليلة)", "role": "emphasis"}, {"t": "text", "s": "؛ فقد كانت أم سلمة حريصة على ألا تنتظر الصباح وألا تدخر البُشرى لرجل مسلم."}]}, {"type": "paragraph", "md": "وقد وعد الله الذين آمنوا وكانوا يتقون بأن ﴿لَهُمُ ٱلۡبُشۡرَىٰ فِي ٱلۡحَيَوٰةِ ٱلدُّنۡيَا وَفِي ٱلۡأٓخِرَةِۚ﴾، ومن البشرى العاجلة في الحياة الدنيا: أن يلقى المسلم قبولًا حسنًا من إخوانه، وأن تشكره على إحسانه، فذلك من التبشير، وقد روى مسلم في باب: «إذا أُثنِي على الصالح فهي بشرى ولا تضره» حديث: قيل لرسول الله صلى الله عليه وسلم أرأيت الرجل يعمل العمل من الخير ويحمده الناس عليه؟، قال: (تلك عاجل بُشرى المؤمن).", "page": 265, "id": "unit-24__lesson-05__b11", "inline": [{"t": "text", "s": "وقد وعد الله الذين آمنوا وكانوا يتقون بأن "}, {"t": "ayah", "s": "لَهُمُ ٱلۡبُشۡرَىٰ فِي ٱلۡحَيَوٰةِ ٱلدُّنۡيَا وَفِي ٱلۡأٓخِرَةِۚ", "ayah": [], "verses": [{"n": 64, "text": "لَهُمُ ٱلۡبُشۡرَىٰ فِي ٱلۡحَيَوٰةِ ٱلدُّنۡيَا وَفِي ٱلۡأٓخِرَةِۚ", "surah": 10, "surah_name": "يونس", "ref": "10:64", "ref_api": "https://api.quran.com/api/v4/verses/by_key/10:64"}], "surah": 10, "ref_api": "https://api.quran.com/api/v4/verses/by_key/10:64", "surah_name": "يونس", "ayah_canonical": 64, "match": "contained", "ref": "10:64"}, {"t": "text", "s": "، ومن البشرى العاجلة في الحياة الدنيا: أن يلقى المسلم قبولًا حسنًا من إخوانه، وأن تشكره على إحسانه، فذلك من التبشير، وقد روى مسلم في باب: "}, {"t": "quote", "s": "إذا أُثنِي على الصالح فهي بشرى ولا تضره"}, {"t": "text", "s": " حديث: قيل لرسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أرأيت الرجل يعمل العمل من الخير ويحمده الناس عليه؟، قال: "}, {"t": "emphasis", "s": "(تلك عاجل بُشرى المؤمن)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وحالُه صلى الله عليه وسلم مع أصحابه ملازمة التبشير لهم؛ كما في قوله: (إن الدين يسر، ولن يشادَّ الدين أحد إلا غلبه، فسددوا وقاربوا وأبشروا..)، قال ابن حجر في الفتح: «وأبشروا: أي بالثواب على العمل الدائم -وإن قل- والمراد: تبشير من عجز عن العمل بالأكمل، بأن العجز إذا لم يكن من صنيعه لا يستلزم نقص أجره، وأبهم المبشَّر به تعظيمًا له وتفخيمًا»، ومبنى هذا الخلق وأساسه: أن يكون المسلم مصدرًا للفأل الحسن، والأمل الواسع، والعاقبة الخيرة، وألا يرى أخوه منه ما يكره.", "page": 265, "id": "unit-24__lesson-05__b12", "inline": [{"t": "text", "s": "وحالُه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " مع أصحابه ملازمة التبشير لهم؛ كما في قوله: "}, {"t": "emphasis", "s": "(إن الدين يسر، ولن يشادَّ الدين أحد إلا غلبه، فسددوا وقاربوا وأبشروا..)", "role": "emphasis"}, {"t": "text", "s": "، قال ابن حجر في الفتح: "}, {"t": "quote", "s": "وأبشروا: أي بالثواب على العمل الدائم -وإن قل- والمراد: تبشير من عجز عن العمل بالأكمل، بأن العجز إذا لم يكن من صنيعه لا يستلزم نقص أجره، وأبهم المبشَّر به تعظيمًا له وتفخيمًا", "speaker": "ابن حجر في الفتح"}, {"t": "text", "s": "، "}, {"t": "emphasis", "s": "ومبنى هذا الخلق وأساسه:", "role": "emphasis"}, {"t": "text", "s": " أن يكون المسلم مصدرًا للفأل الحسن، والأمل الواسع، والعاقبة الخيرة، وألا يرى أخوه منه ما يكره."}]}, {"type": "paragraph", "md": "أفبعد كل هذه الإشارات يقبل أحدنا لنفسه أن يكون مصدر شؤم، ومظنة تخذيل، أو إحباط، أو تنفير، أو قتل للقدرات؟ أم نشيع البشرى، وننشر التفاؤل، ونحيي النفوس، ونحرض على الخير، ونُعِين على المعروف، ونستنهض الهمم؟", "page": 265, "id": "unit-24__lesson-05__b13"}, {"type": "paragraph", "md": "أفلا يكون كل منا بشيرًا لإخوانه يحيي فيهم الأمل ويدفعهم إلى مزيد من العمل؟ هذا ما يجب أن نحرصَ عليه ونسعى لتحقيقه في واقعنا؛ فالبِشارة حياة وسعادة..", "page": 265, "id": "unit-24__lesson-05__b14"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 265, "id": "unit-24__lesson-05__b15", "role": "assessment"}, {"type": "paragraph", "md": "- ما معنى خلق التبشير؟ وما أدلته في القرآن والسنة؟", "page": 265, "id": "unit-24__lesson-05__b16", "item_role": "question", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- ورد في الدرس قصة تبشير كعب بن مالك رضي الله عنه بالتوبة.. اسردها وبين أثرها عليه.", "page": 265, "id": "unit-24__lesson-05__b17", "inline": [{"t": "text", "s": "- ورد في الدرس قصة تبشير كعب بن مالك "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " بالتوبة.. اسردها وبين أثرها عليه."}], "item_role": "question", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "نشاط إثرائي بحثي", "page": 265, "id": "unit-24__lesson-05__b18", "role": "activity"}, {"type": "paragraph", "md": "1- ارجع إلى قصة الثلاثة المخلفين عن غزوة تبوك واقرأها في آيات التوبة وكتب السنة.", "page": 265, "id": "unit-24__lesson-05__b19", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- نتدرب على خلق التبشير عمليا، ونجرب أن نبشر خمسة من المسلمين بفضل أعمال يقومون بها؛ حيثُ نكتبها بالتعاون مع معلمنا وزملائنا ثم نبشر الناس بها..", "page": 265, "id": "unit-24__lesson-05__b20", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-24__lesson-05';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-25__lesson-01','unit-25',1,'سورة الشمس','القرآن والتفسير',NULL,0,11,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 266, "id": "unit-25__lesson-01__b01", "role": "objectives"}, {"type": "paragraph", "md": "1- معرفة مقاصد سورة الشمس، وأهم موضوعاتها، وإتقان تلاوتها غيبًا.", "page": 266, "id": "unit-25__lesson-01__b02", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- معرفة الألفاظ الغريبة في سورة الشمس، والمعنى الإجمالي لها.", "page": 266, "id": "unit-25__lesson-01__b03", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- معرفة أهم الفوائد التربوية والعلمية من سورة الشمس.", "page": 266, "id": "unit-25__lesson-01__b04", "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "أهم مقاصد السورة:", "page": 266, "id": "unit-25__lesson-01__b05", "role": "section"}, {"type": "paragraph", "md": "1- الترغيب في الطاعات، والتحذير من المعاصي.", "page": 266, "id": "unit-25__lesson-01__b06", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- تهديد المشركين بأنهم يوشك أن يصيبهم عذاب بسبب كفرهم، كما أصاب مَن قبلهم مِن الأمم.", "page": 266, "id": "unit-25__lesson-01__b07", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "أهم موضوعات السورة", "page": 266, "id": "unit-25__lesson-01__b08", "role": "section"}, {"type": "paragraph", "md": "1- البدء بالقَسَم بالمخلوقات العظيمة؛ التي تمثل دليلًا على بديع صنع الله تعالى.", "page": 266, "id": "unit-25__lesson-01__b09", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ذكر أحوال النفوس ومراتبها في مسالك الهدى والضلال، والدعوة إلى سلوك طرق الخير وترك الشر.", "page": 266, "id": "unit-25__lesson-01__b10", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- بيان حسن عاقبة من يزكي نفسه، وسوء عاقبة من يُتبع نفسَه هواها.", "page": 266, "id": "unit-25__lesson-01__b11", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- الإخبار بإهلاك ثمود، وتهديد المشركين بأنهم سيصيبهم العذاب كقوم ثمود؛ إذا استمروا في كفرهم.", "page": 266, "id": "unit-25__lesson-01__b12", "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "غريب الكلمات:", "page": 266, "id": "unit-25__lesson-01__b13", "role": "vocabulary"}, {"type": "table", "rows": [["وضحاها: الضحى: ارتفاع الضوء وكماله", "زكاها: أي: طهرها من الكفر والمعاصي."], ["تلاها: تبعها.", "خاب: أي: خسر وفاته الفوز الظفر"], ["جلاها: بينها وكشفها.", "دساها: أخفى فضائلها وحملها على الفجور أو أخفى نفسه في المعاصي."], ["يغشاها: أي: يغطيها.", "بطغواها: أي: بطغيانها."], ["طحاها: أي: بسطها ووسعها.", "انبعث: نهض، وخرج بسرعة ونشاط لعقر الناقة."], ["سواها: أي: عدل خلقها، وسوى أعضاءها.", "فعقروها: أي: نحروها وقتلوها."], ["فجورها: الفجور هو: المعاصي والكفر، والمراد: طريق الشر والضلال والغواية؛ عافانا الله.", "فدمدم: أي: دمر عليهم وأهلكهم عن بكرة أبيهم، والدمدمة: إهلاك باستئصال."], ["أفلح: فاز بالمطلوب ونجا من المرهوب.", "عقباها: أي: عاقبتها وتبعتها."]], "html": "<table dir=\"rtl\"><tr><td>وضحاها: الضحى: ارتفاع الضوء وكماله</td><td>زكاها: أي: طهرها من الكفر والمعاصي.</td></tr><tr><td>تلاها: تبعها.</td><td>خاب: أي: خسر وفاته الفوز الظفر</td></tr><tr><td>جلاها: بينها وكشفها.</td><td>دساها: أخفى فضائلها وحملها على الفجور أو أخفى نفسه في المعاصي.</td></tr><tr><td>يغشاها: أي: يغطيها.</td><td>بطغواها: أي: بطغيانها.</td></tr><tr><td>طحاها: أي: بسطها ووسعها.</td><td>انبعث: نهض، وخرج بسرعة ونشاط لعقر الناقة.</td></tr><tr><td>سواها: أي: عدل خلقها، وسوى أعضاءها.</td><td>فعقروها: أي: نحروها وقتلوها.</td></tr><tr><td>فجورها: الفجور هو: المعاصي والكفر، والمراد: طريق الشر والضلال والغواية؛ عافانا الله.</td><td>فدمدم: أي: دمر عليهم وأهلكهم عن بكرة أبيهم، والدمدمة: إهلاك باستئصال.</td></tr><tr><td>أفلح: فاز بالمطلوب ونجا من المرهوب.</td><td>عقباها: أي: عاقبتها وتبعتها.</td></tr></table>", "page": 267, "id": "unit-25__lesson-01__b14"}, {"type": "heading", "level": 3, "text": "المعنى الإجمالي:", "page": 267, "id": "unit-25__lesson-01__b15", "role": "overall_meaning"}, {"type": "paragraph", "md": "افتتح الله تعالى هذه السورة الكريمة مقسما بالشمس وبضوئها، وبالقمر إذا تبع الشمس، وبالنهار إذا أظهر الشمس وضوءها، وبالليل إذا غشي الشمس، فذهب بضوئها، وبالسماء وبالذي بناها، وبالأرض وبالذي بسطها من كل جانب. ثم أقسم الله تعالى بكل نفس وبالذي خلقها، وعدل خلقها، فبين الله للنفس طريق الخير والشر، والطاعة والمعصية.", "page": 267, "id": "unit-25__lesson-01__b16"}, {"type": "paragraph", "md": "ثم قال تعالى مؤكدا على أهمية تزكية النفس: قد فاز من طهر نفسه ونقاها من الشرك والكفر والمعاصي، ونماها بالإيمان والعمل الصالح، وقد خسر وشقي من أخفى نفسه وأرداها بالرذائل والعيوب والذنوب.", "page": 267, "id": "unit-25__lesson-01__b17"}, {"type": "paragraph", "md": "ويبين الله سبحانه وتعالى ما حل بالمكذبين السابقين: كذبت ثمود بالحق الذي جاءهم به رسولهم صالح عليه السلام ؛ بسبب طغيانهم، حين نهض أشقى قوم ثمود لعقر الناقة، فقال لهم رسولهم صالح عليه الصلاة والسلام : احذروا ناقة الله أن تمسوها بسوء، واحذروا أن تمنعوها من شرب الماء في يومها الذي جعله الله نصيبا لها، فكذبوا نبيهم صالحا؛ فذبحوا الناقة كفرا وعنادا، فأطبق الله على ثمود العقوبة بسبب عقرهم الناقة، فسوى بينهم جميعا في الهلاك، وعمهم بالعذاب، ولا يخاف الله سبحانه ما يكون من عاقبة وتبعة إهلاكه لثمود.", "page": 267, "id": "unit-25__lesson-01__b18", "inline": [{"t": "text", "s": "ويبين الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ما حل بالمكذبين السابقين: كذبت ثمود بالحق الذي جاءهم به رسولهم صالح "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " ؛ بسبب طغيانهم، حين نهض أشقى قوم ثمود لعقر الناقة، فقال لهم رسولهم صالح "}, {"t": "honorific", "s": "عليه الصلاة والسلام"}, {"t": "text", "s": " : احذروا ناقة الله أن تمسوها بسوء، واحذروا أن تمنعوها من شرب الماء في يومها الذي جعله الله نصيبا لها، فكذبوا نبيهم صالحا؛ فذبحوا الناقة كفرا وعنادا، فأطبق الله على ثمود العقوبة بسبب عقرهم الناقة، فسوى بينهم جميعا في الهلاك، وعمهم بالعذاب، ولا يخاف الله سبحانه ما يكون من عاقبة وتبعة إهلاكه لثمود."}]}, {"type": "heading", "level": 3, "text": "الفوائد التربوية:", "page": 267, "id": "unit-25__lesson-01__b19", "role": "benefits"}, {"type": "paragraph", "md": "1- في قوله تعالى: ﴿وَنَفۡسٖ وَمَا سَوَّىٰهَا﴾ أن الله تعالى خلق تلك النفس أولًا، وذكْر النفس بعد الآيات الكونية من شمس وقمر، وليل ونهار.. لفتٌ إلى وجوب التأمل في تلك المخلوقات؛ لنستلهم منها الدلالة على قدرة خالقها وأنه لا بد لهذا العالم من صانع، ولا بد لهذه المخلوقات أن تفنى وتزول.", "page": 267, "id": "unit-25__lesson-01__b20", "inline": [{"t": "text", "s": "1- في قوله تعالى: "}, {"t": "ayah", "s": "وَنَفۡسٖ وَمَا سَوَّىٰهَا", "ayah": [], "verses": [{"n": 7, "text": "وَنَفۡسٖ وَمَا سَوَّىٰهَا", "surah": 91, "surah_name": "الشمس", "ref": "91:7", "ref_api": "https://api.quran.com/api/v4/verses/by_key/91:7"}], "surah": 91, "ref_api": "https://api.quran.com/api/v4/verses/by_key/91:7", "surah_name": "الشمس", "ayah_canonical": 7, "match": "exact", "ref": "91:7"}, {"t": "text", "s": " أن الله تعالى خلق تلك النفس أولًا، وذكْر النفس بعد الآيات الكونية من شمس وقمر، وليل ونهار.. لفتٌ إلى وجوب التأمل في تلك المخلوقات؛ لنستلهم منها الدلالة على قدرة خالقها وأنه لا بد لهذا العالم من صانع، ولا بد لهذه المخلوقات أن تفنى وتزول."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- التزكية نوعان:", "page": 267, "id": "unit-25__lesson-01__b21", "inline": [{"t": "emphasis", "s": "2- التزكية نوعان:", "role": "emphasis"}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "أ- تزكية محمودة، وهي: أن يزكي العبد نفسه بالفعل؛ أي: بالطاعات.", "page": 267, "id": "unit-25__lesson-01__b22"}, {"type": "paragraph", "md": "ب- وتزكية مذمومة، وتكون بالقول، وهي: أن يمدح الإنسان نفسه، وقد نهى الله عنه بقوله: ﴿فَلَا تُزَكُّوٓاْ أَنفُسَكُمۡۖ﴾؛ فالتزكية المحمودة أن يعمل المسلم عملا صالحا تزكو به نفسه، والمذمومة أن يدل على عمله ليُمدح عليه، كأنه يمن على الله أنه فعل الطاعات؛ يفقول: صليت، وتصدقت، وصمت، وحججت.. الخ؛ فلا يجوز للإنسان أن يزكي نفسه، وهذه هي التزكية المذمومة.", "page": 268, "id": "unit-25__lesson-01__b23", "inline": [{"t": "text", "s": "ب- وتزكية مذمومة، وتكون بالقول، وهي: أن يمدح الإنسان نفسه، وقد نهى الله عنه بقوله: "}, {"t": "ayah", "s": "فَلَا تُزَكُّوٓاْ أَنفُسَكُمۡۖ", "ayah": [], "verses": [{"n": 32, "text": "فَلَا تُزَكُّوٓاْ أَنفُسَكُمۡۖ", "surah": 53, "surah_name": "النجم", "ref": "53:32", "ref_api": "https://api.quran.com/api/v4/verses/by_key/53:32"}], "surah": 53, "ref_api": "https://api.quran.com/api/v4/verses/by_key/53:32", "surah_name": "النجم", "ayah_canonical": 32, "match": "contained", "ref": "53:32"}, {"t": "text", "s": "؛ فالتزكية المحمودة أن يعمل المسلم عملا صالحا تزكو به نفسه، والمذمومة أن يدل على عمله ليُمدح عليه، كأنه يمن على الله أنه فعل الطاعات؛ يفقول: صليت، وتصدقت، وصمت، وحججت.. الخ؛ فلا يجوز للإنسان أن يزكي نفسه، وهذه هي التزكية المذمومة."}]}, {"type": "paragraph", "md": "3- في قوله تعالى: ﴿قَدۡ أَفۡلَحَ مَن زَكَّىٰهَا ۝٩ وَقَدۡ خَابَ مَن دَسَّىٰهَا ۝١٠﴾ أن النفس أمانة عندك، يجب أن ترعاها حق رعايتها، وإذا عصيت ربك فإنك ظالم لنفسك، فالمرء مستخلف في نفسه وماله وحياته كلها.", "page": 268, "id": "unit-25__lesson-01__b24", "inline": [{"t": "text", "s": "3- في قوله تعالى: "}, {"t": "ayah", "s": "قَدۡ أَفۡلَحَ مَن زَكَّىٰهَا ۝٩ وَقَدۡ خَابَ مَن دَسَّىٰهَا ۝١٠", "ayah": [9, 10], "verses": [{"n": 9, "text": "قَدۡ أَفۡلَحَ مَن زَكَّىٰهَا", "surah": 91, "ref_api": "https://api.quran.com/api/v4/verses/by_key/91:9", "surah_name": "الشمس", "ayah_canonical": 9, "match": "exact", "ref": "91:9"}, {"n": 10, "text": "وَقَدۡ خَابَ مَن دَسَّىٰهَا", "surah": 91, "ref_api": "https://api.quran.com/api/v4/verses/by_key/91:10", "surah_name": "الشمس", "ayah_canonical": 10, "match": "exact", "ref": "91:10"}], "surah": null, "ref_api": null}, {"t": "text", "s": " أن النفس أمانة عندك، يجب أن ترعاها حق رعايتها، وإذا عصيت ربك فإنك ظالم لنفسك، فالمرء مستخلف في نفسه وماله وحياته كلها."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- في قوله تعالى: ﴿فَدَمۡدَمَ عَلَيۡهِمۡ رَبُّهُم بِذَنۢبِهِمۡ﴾ تخويف من عاقبة الذنوب؛ فعلى المذنب أن يحذر.", "page": 268, "id": "unit-25__lesson-01__b25", "inline": [{"t": "text", "s": "4- في قوله تعالى: "}, {"t": "ayah", "s": "فَدَمۡدَمَ عَلَيۡهِمۡ رَبُّهُم بِذَنۢبِهِمۡ", "ayah": [], "verses": [{"n": 14, "text": "فَدَمۡدَمَ عَلَيۡهِمۡ رَبُّهُم بِذَنۢبِهِمۡ", "surah": 91, "surah_name": "الشمس", "ref": "91:14", "ref_api": "https://api.quran.com/api/v4/verses/by_key/91:14"}], "surah": 91, "ref_api": "https://api.quran.com/api/v4/verses/by_key/91:14", "surah_name": "الشمس", "ayah_canonical": 14, "match": "contained", "ref": "91:14"}, {"t": "text", "s": " تخويف من عاقبة الذنوب؛ فعلى المذنب أن يحذر."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "الفوائد العلمية واللطائف:", "page": 268, "id": "unit-25__lesson-01__b26", "role": "benefits"}, {"type": "paragraph", "md": "1- في قَسَمِ الله تبارك وتعالى بهذه المخلوقات، بينما نُهِينا نحن عن القسم بغير الله؛ دليل على أن لله تعالى أن يقسم بما شاء من خلقه، وهو سائل غير مسؤول، وأما الإنسان فلا يجوز له أن يُقسم بغير الله.", "page": 268, "id": "unit-25__lesson-01__b27", "inline": [{"t": "text", "s": "1- في قَسَمِ الله "}, {"t": "honorific", "s": "تبارك وتعالى"}, {"t": "text", "s": " بهذه المخلوقات، بينما نُهِينا نحن عن القسم بغير الله؛ دليل على أن لله تعالى أن يقسم بما شاء من خلقه، وهو سائل غير مسؤول، وأما الإنسان فلا يجوز له أن يُقسم بغير الله."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- في قوله تعالى: ﴿وَٱلۡقَمَرِ إِذَا تَلَىٰهَا ۝٢﴾ إشارة إلى أن نور القمر مستفاد من نور الشمس - أي: من توجه أشعة الشمس إلى ما يقابل الأرض من القمر-، وليس نيرا بذاته، وهذا إعجاز علمي في القرآن الكريم.", "page": 268, "id": "unit-25__lesson-01__b28", "inline": [{"t": "text", "s": "2- في قوله تعالى: "}, {"t": "ayah", "s": "وَٱلۡقَمَرِ إِذَا تَلَىٰهَا ۝٢", "ayah": [2], "verses": [{"n": 2, "text": "وَٱلۡقَمَرِ إِذَا تَلَىٰهَا", "surah": 91, "ref_api": "https://api.quran.com/api/v4/verses/by_key/91:2", "surah_name": "الشمس", "ayah_canonical": 2, "match": "exact", "ref": "91:2"}], "surah": null, "ref_api": null}, {"t": "text", "s": " إشارة إلى أن نور القمر مستفاد من نور الشمس - أي: من توجه أشعة الشمس إلى ما يقابل الأرض من القمر-، وليس نيرا بذاته، وهذا إعجاز علمي في القرآن الكريم."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- الأعمال الصالحة تسمى زكاة ﴿زَكَّىٰهَا﴾، فكل ما تزكو به النفوس من مال أو عمل فهو زكاة شرعا، لكن تطلق الزكاة أيضا على المعنى الخاص، أي: أنه يراد بها بعض معانيها كما في قولنا: زكاة المال.", "page": 268, "id": "unit-25__lesson-01__b29", "inline": [{"t": "text", "s": "3- الأعمال الصالحة تسمى زكاة "}, {"t": "ayah", "s": "زَكَّىٰهَا", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "، فكل ما تزكو به النفوس من مال أو عمل فهو زكاة شرعا، لكن تطلق الزكاة أيضا على المعنى الخاص، أي: أنه يراد بها بعض معانيها كما في قولنا: زكاة المال."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- الإنسان يصاب بالمصائب بسببٍ منه؛ قال تعالى: ﴿فَدَمۡدَمَ عَلَيۡهِمۡ رَبُّهُم بِذَنۢبِهِمۡ﴾، أي: بسبب ذنبهم.", "page": 268, "id": "unit-25__lesson-01__b30", "inline": [{"t": "text", "s": "4- الإنسان يصاب بالمصائب بسببٍ منه؛ قال تعالى: "}, {"t": "ayah", "s": "فَدَمۡدَمَ عَلَيۡهِمۡ رَبُّهُم بِذَنۢبِهِمۡ", "ayah": [], "verses": [{"n": 14, "text": "فَدَمۡدَمَ عَلَيۡهِمۡ رَبُّهُم بِذَنۢبِهِمۡ", "surah": 91, "surah_name": "الشمس", "ref": "91:14", "ref_api": "https://api.quran.com/api/v4/verses/by_key/91:14"}], "surah": 91, "ref_api": "https://api.quran.com/api/v4/verses/by_key/91:14", "surah_name": "الشمس", "ayah_canonical": 14, "match": "contained", "ref": "91:14"}, {"t": "text", "s": "، أي: بسبب ذنبهم."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 268, "id": "unit-25__lesson-01__b31", "role": "assessment"}, {"type": "paragraph", "md": "1- اذكر أهم موضوع من موضوعات سورة الشمس.", "page": 268, "id": "unit-25__lesson-01__b32", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ما معنى قوله تعالى: ﴿زَكَّىٰهَا﴾، ﴿دَسَّىٰهَا﴾، ﴿فَدَمۡدَمَ﴾.", "page": 268, "id": "unit-25__lesson-01__b33", "inline": [{"t": "text", "s": "2- ما معنى قوله تعالى: "}, {"t": "ayah", "s": "زَكَّىٰهَا", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "، "}, {"t": "ayah", "s": "دَسَّىٰهَا", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "، "}, {"t": "ayah", "s": "فَدَمۡدَمَ", "ayah": [], "verses": [{"n": 14, "text": "فَدَمۡدَمَ", "surah": 91, "surah_name": "الشمس", "ref": "91:14", "ref_api": "https://api.quran.com/api/v4/verses/by_key/91:14"}], "surah": 91, "ref_api": "https://api.quran.com/api/v4/verses/by_key/91:14", "surah_name": "الشمس", "ayah_canonical": 14, "match": "contained", "ref": "91:14"}, {"t": "text", "s": "."}], "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- اذكر فائدة تربوية واحدة مستخلصة من سورة الشمس.", "page": 268, "id": "unit-25__lesson-01__b34", "item_role": "question", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- من هم القوم الذين تتحدث عنهم السورة، ومن النبي الذي بُعث إليهم.", "page": 268, "id": "unit-25__lesson-01__b35", "item_role": "question", "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "نشاط تفاعلي", "page": 268, "id": "unit-25__lesson-01__b36", "role": "activity"}, {"type": "paragraph", "md": "قم بعمل مقارنة بين موضوعات سورة الشمس وموضوعات سورة الليل.", "page": 268, "id": "unit-25__lesson-01__b37", "item_role": "activity_step"}, {"type": "paragraph", "md": "اذكر بعض الأعمال التي تزكي العبد عند ربه وتجعله من أهل الصلاح واشرحها لزملائك.", "page": 268, "id": "unit-25__lesson-01__b38", "item_role": "activity_step"}, {"type": "paragraph", "md": "اذكر خمسة أشياء أقسم الله سبحانه وتعالى بها وبين ما أهمية هذا القسم.", "page": 268, "id": "unit-25__lesson-01__b39", "inline": [{"t": "text", "s": "اذكر خمسة أشياء أقسم الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " بها وبين ما أهمية هذا القسم."}], "item_role": "activity_step"}]' WHERE id='unit-25__lesson-01';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-25__lesson-02','unit-25',2,'خاتمة الشهادة.. نسأل الله حسنها','الحديث',NULL,0,0,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "عَنِ الْمِقْدَامِ بْنِ مَعْدِ يكَرِبَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم : (لِلشَّهِيدِ عِنْدَ اللَّهِ سِتُّ خِصَالٍ: يُغْفَرُ لَهُ في أَوَّلِ دُفْعَةٍ، وَيُرَى مَقْعَدَهُ مِنَ الْجَنَّةِ، وَيُجَارُ مِنْ عَذَابِ الْقَبْر، وَيَأْمَنُ مِنَ الْفَزَعِ الأَكْبَرِ، وَيُوضَعُ عَلَى رَأْسِهِ تَاجُ الْوَقَارِ؛ الْيَاقُوتَةُ مِنْهَا خَيْرٌ مِنَ الدُّنْيَا وَمَا فِيهَا، وَيُزَوَّجُ اثْنَتَيْنِ وَسَبْعِينَ زَوْجَةً مِنَ الْحُورِ الْعِينِ، وَيُشَفَّعُ في سَبْعِينَ مِنْ أَقَارِبِهِ) [رواه أحمد وصححه الألباني].", "page": 269, "id": "unit-25__lesson-02__b01", "inline": [{"t": "text", "s": "عَنِ الْمِقْدَامِ بْنِ مَعْدِ يكَرِبَ "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قَالَ: قَالَ رَسُولُ اللَّهِ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : (لِلشَّهِيدِ عِنْدَ اللَّهِ سِتُّ خِصَالٍ: يُغْفَرُ لَهُ في أَوَّلِ دُفْعَةٍ، وَيُرَى مَقْعَدَهُ مِنَ الْجَنَّةِ، وَيُجَارُ مِنْ عَذَابِ الْقَبْر، وَيَأْمَنُ مِنَ الْفَزَعِ الأَكْبَرِ، وَيُوضَعُ عَلَى رَأْسِهِ تَاجُ الْوَقَارِ؛ الْيَاقُوتَةُ مِنْهَا خَيْرٌ مِنَ الدُّنْيَا وَمَا فِيهَا، وَيُزَوَّجُ اثْنَتَيْنِ وَسَبْعِينَ زَوْجَةً مِنَ الْحُورِ الْعِينِ، وَيُشَفَّعُ في سَبْعِينَ مِنْ أَقَارِبِهِ) "}, {"t": "citation", "s": "[رواه أحمد وصححه الألباني]", "source": "أحمد"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "عن سهلِ بن سعدٍ رضي الله عنه قال: قالَ رسولُ اللهِ صلى الله عليه وسلم : (إِنَّمَا الْأَعْمَالُ بِالْخَوَاتِيمِ) [رواه البخاري].", "page": 269, "id": "unit-25__lesson-02__b02", "inline": [{"t": "text", "s": "عن سهلِ بن سعدٍ "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قال: قالَ رسولُ اللهِ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : (إِنَّمَا الْأَعْمَالُ بِالْخَوَاتِيمِ) "}, {"t": "citation", "s": "[رواه البخاري]", "source": "البخاري"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "شرح غريب الحديثين وبيان معناهما:", "page": 269, "id": "unit-25__lesson-02__b03", "role": "vocabulary"}, {"type": "paragraph", "md": "- (خصال) جمعُ خَصلةٍ؛ أي الخَلَّةُ فَضيلَةُ أو رَذيلَةُ، وقد غَلَبَ على الفَضيلَةِ؛ فللشهيد ست فضائل.", "page": 269, "id": "unit-25__lesson-02__b04", "inline": [{"t": "text", "s": "- "}, {"t": "emphasis", "s": "(خصال)", "role": "lemma"}, {"t": "text", "s": " جمعُ خَصلةٍ؛ أي الخَلَّةُ فَضيلَةُ أو رَذيلَةُ، وقد غَلَبَ على الفَضيلَةِ؛ فللشهيد ست فضائل."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "1- الخصلة الأولى: أنه (يَغفر الله له) أي الشهيد (في أول دُفعة) وقطرة؛ بضم الدال، أي ما دُفع من إناءٍ أو سقاءٍ فانصب مرة واحدة، كالدفعة من المطر وغيره؛ يقال: جاء القوم دُفعةً واحدةً - بالضم - إذا دخلوا مرةً واحدة. وأما الدَّفعة -بالفتح- فهي المرة الواحدة من الدفع؛ وهو الإزالة بالقوة، فليس مرادًا ها هنا.", "page": 269, "id": "unit-25__lesson-02__b05", "inline": [{"t": "text", "s": "1- الخصلة الأولى: أنه "}, {"t": "emphasis", "s": "(يَغفر الله له)", "role": "lemma"}, {"t": "text", "s": " أي الشهيد "}, {"t": "emphasis", "s": "(في أول دُفعة)", "role": "lemma"}, {"t": "text", "s": " وقطرة؛ بضم الدال، أي ما دُفع من إناءٍ أو سقاءٍ فانصب مرة واحدة، كالدفعة من المطر وغيره؛ يقال: جاء القوم دُفعةً واحدةً - بالضم - إذا دخلوا مرةً واحدة. وأما الدَّفعة -بالفتح- فهي المرة الواحدة من الدفع؛ وهو الإزالة بالقوة، فليس مرادًا ها هنا."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- الثانية: أنه (يُرى) بالبناء للمفعول (مقعدَه) بالنصب على أنه مفعول ثان ليُرَى؛ من الإراءة؛ أي: مقره ومنزله (من الجَنَّة) أي: يريه الله ويطلعه على منزله في الجَنَّة فور مقتله.. فهنيئًا للشهادة.", "page": 269, "id": "unit-25__lesson-02__b06", "inline": [{"t": "text", "s": "2- الثانية: أنه "}, {"t": "emphasis", "s": "(يُرى)", "role": "lemma"}, {"t": "text", "s": " بالبناء للمفعول "}, {"t": "emphasis", "s": "(مقعدَه)", "role": "lemma"}, {"t": "text", "s": " بالنصب على أنه مفعول ثان ليُرَى؛ من الإراءة؛ أي: مقره ومنزله "}, {"t": "emphasis", "s": "(من الجَنَّة)", "role": "lemma"}, {"t": "text", "s": " أي: يريه الله ويطلعه على منزله في الجَنَّة فور مقتله.. فهنيئًا للشهادة."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- الثالثة: أنه (يجار) أي يؤمَّن (من عذاب القبر) وضغطته؛ من الإجارة؛ وهو الأمان والسلامة، (ويأمن) وينجو (من الفزع الأكبر) والهول الأعظم؛ في عرصات القيامة حين البعث، وهما خصلتان يعدان واحدة.", "page": 269, "id": "unit-25__lesson-02__b07", "inline": [{"t": "text", "s": "3- الثالثة: أنه "}, {"t": "emphasis", "s": "(يجار)", "role": "lemma"}, {"t": "text", "s": " أي يؤمَّن "}, {"t": "emphasis", "s": "(من عذاب القبر)", "role": "lemma"}, {"t": "text", "s": " وضغطته؛ من الإجارة؛ وهو الأمان والسلامة، "}, {"t": "emphasis", "s": "(ويأمن)", "role": "lemma"}, {"t": "text", "s": " وينجو "}, {"t": "emphasis", "s": "(من الفزع الأكبر)", "role": "lemma"}, {"t": "text", "s": " والهول الأعظم؛ في عرصات القيامة حين البعث، وهما خصلتان يعدان واحدة."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- الرابعة: أنه (يحلى) من التحلية؛ أي: يُلْبَس (حلة الإيمان) من إضافة المسبب إلى السبب؛ فأضاف الحلة إلى الإيمان؛ بمعنى: أنَّها علامة لإيمان صاحبها، لأنها مسبَّبَة عنه؛ فيزين بحلة سببها إيمانه بالله سبحانه وتعالى .", "page": 269, "id": "unit-25__lesson-02__b08", "inline": [{"t": "text", "s": "4- الرابعة: أنه "}, {"t": "emphasis", "s": "(يحلى)", "role": "lemma"}, {"t": "text", "s": " من التحلية؛ أي: يُلْبَس "}, {"t": "emphasis", "s": "(حلة الإيمان)", "role": "lemma"}, {"t": "text", "s": " من إضافة المسبب إلى السبب؛ فأضاف الحلة إلى الإيمان؛ بمعنى: أنَّها علامة لإيمان صاحبها، لأنها مسبَّبَة عنه؛ فيزين بحلة سببها إيمانه بالله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- الخامسة: أنه (يزوج من الحور العِين)؛ أي: نساء الجنة واحدتها حَوْراء، وهي الشديدة بياض العين الشديدة سوادها، والعِين جمع عيناء وهي الواسعة العين.", "page": 269, "id": "unit-25__lesson-02__b09", "inline": [{"t": "text", "s": "5- الخامسة: أنه "}, {"t": "emphasis", "s": "(يزوج من الحور العِين)", "role": "lemma"}, {"t": "text", "s": "؛ أي: نساء الجنة واحدتها حَوْراء، وهي الشديدة بياض العين الشديدة سوادها، والعِين جمع عيناء وهي الواسعة العين."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6- السادسة: أنه (يشفع في سبعين إنسانًا من أقاربه) ومحارمه؛ أي: يؤذن له في الشفاعة فيهم.", "page": 269, "id": "unit-25__lesson-02__b10", "inline": [{"t": "text", "s": "6- السادسة: أنه "}, {"t": "emphasis", "s": "(يشفع في سبعين إنسانًا من أقاربه)", "role": "lemma"}, {"t": "text", "s": " ومحارمه؛ أي: يؤذن له في الشفاعة فيهم."}], "list": {"type": "ordered", "marker": "6"}}, {"type": "heading", "level": 3, "text": "مسائل الحديث وفوائده:", "page": 269, "id": "unit-25__lesson-02__b11", "role": "benefits"}, {"type": "paragraph", "md": "1- المذكور في الحديث سبع خصال، إلَّا أن يجعل الإجارة والأمن من الفزع واحدة فتكون ستًّا، وجاء في روايات أنها (سبع خصال) فتكون هاتان خصلتات لا واحدة، وكلا اللفظين واردان محتملان.", "page": 269, "id": "unit-25__lesson-02__b12", "inline": [{"t": "text", "s": "1- المذكور في الحديث سبع خصال، إلَّا أن يجعل الإجارة والأمن من الفزع واحدة فتكون ستًّا، وجاء في روايات أنها "}, {"t": "emphasis", "s": "(سبع خصال)", "role": "emphasis"}, {"t": "text", "s": " فتكون هاتان خصلتات لا واحدة، وكلا اللفظين واردان محتملان."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- في الحديث بيان ما اختص الله به الشهيد من الفضائل العظيمة من أول مقتله حتى منتهى مستقرِّه، وهي فصائل لا تتأتى لغيره، ولهذه الفضائل فقد تمنى النبي صلى الله عليه وسلم الشهادة وسألها ربَّه.", "page": 270, "id": "unit-25__lesson-02__b13", "inline": [{"t": "text", "s": "2- في الحديث بيان ما اختص الله به الشهيد من الفضائل العظيمة من أول مقتله حتى منتهى مستقرِّه، وهي فصائل لا تتأتى لغيره، ولهذه الفضائل فقد تمنى النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " الشهادة وسألها ربَّه."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- من إكرام الله للشهيد أن فضله متعدٍّ حتى يشفِّعه الله في سبعين من أهل بيته.", "page": 270, "id": "unit-25__lesson-02__b14", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- يغفر الله كل ذنوب الشهيد ويمحوها عند أول صبَّةٍ من دمه إلا ما استثني منها؛ كمن كان عليه دين فلا يسقط إلا بدفعه، أو يكون عنده نية أداء هذا الدين.", "page": 270, "id": "unit-25__lesson-02__b15", "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- سعى الشهيد في بذل روحه لإعزاز الدِّين ورفعته وتعظيمه؛ فكافأه الله بإلباسه تاج الوقار الذي هو سبب العزة والعظمة والشرف، ففي هذا الحديث معنى قولهم: «الجزاء من جنس العمل».", "page": 270, "id": "unit-25__lesson-02__b16", "inline": [{"t": "text", "s": "5- سعى الشهيد في بذل روحه لإعزاز الدِّين ورفعته وتعظيمه؛ فكافأه الله بإلباسه تاج الوقار الذي هو سبب العزة والعظمة والشرف، ففي هذا الحديث معنى قولهم: "}, {"t": "quote", "s": "الجزاء من جنس العمل"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6- هل عدد الحور العين للكثرة أم التحديد؟ قال الملا علي قاري رحمه الله : «ويزوج أي يعطى بطريق الزوجية ثنتين وسبعين زوجة، وفي التقييد بالثنتين والسبعين إشارة إلى أن المراد به التحديد لا التكثير، ويحمل على أن هذا أقل ما يعطى ولا مانع من التفضل بالزيادة عليها».", "page": 270, "id": "unit-25__lesson-02__b17", "inline": [{"t": "text", "s": "6- هل عدد الحور العين للكثرة أم التحديد؟ قال الملا علي قاري "}, {"t": "honorific", "s": "رحمه الله"}, {"t": "text", "s": " : "}, {"t": "quote", "s": "ويزوج أي يعطى بطريق الزوجية ثنتين وسبعين زوجة، وفي التقييد بالثنتين والسبعين إشارة إلى أن المراد به التحديد لا التكثير، ويحمل على أن هذا أقل ما يعطى ولا مانع من التفضل بالزيادة عليها", "speaker": "الملا علي قاري رحمه الله"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "6"}}, {"type": "paragraph", "md": "7- وقد دل الحديث الثاني على فضل الشهادة؛ من حيثُ أنها الخاتمة الأمثل، فيُبعث المرء يوم القيامة محضبًا بدمائه التي تشهد له صدقه في نصرة الدين، قال العراقي: «فَإِنَّ الْإِنْسَانَ مَحْثُوثٌ عَلَى أَنْ يَخْتِمَ أَعْمَالَهُ بِالصَّالِحَاتِ فِي جَمِيعِ الْأُمُورِ؛ فَإِنَّ الْأَعْمَالَ بِالخَواتِيم»؛ نسأل الله حسن الختام بشهادةٍ زكيةٍ مرضيّةٍ عليِّةٍ يُدخلنا بها الفردوس الأعلى مع النبيين والصديقين والشهداء والصالحين وحسن أولئك رفيقا، والحمد لله في الانتهاء كما حمدته في الابتداء، والصلاة والسلام على خاتم الأنبياء، وآله وصحابته أنجم الاهتداء.", "page": 270, "id": "unit-25__lesson-02__b18", "inline": [{"t": "text", "s": "7- وقد دل الحديث الثاني على فضل الشهادة؛ من حيثُ أنها الخاتمة الأمثل، فيُبعث المرء يوم القيامة محضبًا بدمائه التي تشهد له صدقه في نصرة الدين، قال العراقي: "}, {"t": "quote", "s": "فَإِنَّ الْإِنْسَانَ مَحْثُوثٌ عَلَى أَنْ يَخْتِمَ أَعْمَالَهُ بِالصَّالِحَاتِ فِي جَمِيعِ الْأُمُورِ؛ فَإِنَّ الْأَعْمَالَ بِالخَواتِيم", "speaker": "العراقي"}, {"t": "text", "s": "؛ نسأل الله حسن الختام بشهادةٍ زكيةٍ مرضيّةٍ عليِّةٍ يُدخلنا بها الفردوس الأعلى مع النبيين والصديقين والشهداء والصالحين وحسن أولئك رفيقا، والحمد لله في الانتهاء كما حمدته في الابتداء، والصلاة والسلام على خاتم الأنبياء، وآله وصحابته أنجم الاهتداء."}], "list": {"type": "ordered", "marker": "7"}}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 270, "id": "unit-25__lesson-02__b19", "role": "assessment"}, {"type": "paragraph", "md": "1- اذكر خمس فضائل للشهيد كما حفظتها في هذا الحديث.", "page": 270, "id": "unit-25__lesson-02__b20", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- هل فضل الشهادة متعدٍّ أم قاصر؛ بين ذلك كما علمتَه في هذا الحديث.", "page": 270, "id": "unit-25__lesson-02__b21", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط إثرائي حواري", "page": 270, "id": "unit-25__lesson-02__b22", "role": "activity"}, {"type": "paragraph", "md": "هل تعرف شهيدًا من أقاربك أو جيرانك؟ احكِ لنا قصته وعلاقتك معه، وبين لنا بعضَ مناقبه وأخلاقه، وقم بزيارة أو اتصال لأهله تواسيهم بها؛ قربةً لله تعالى..", "page": 270, "id": "unit-25__lesson-02__b23", "item_role": "activity_step"}]' WHERE id='unit-25__lesson-02';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-25__lesson-03','unit-25',3,'من الأفكار الضالة: العلمانية والديمقراطية','التوحيد والعقيدة',NULL,2,5,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 271, "id": "unit-25__lesson-03__b01", "role": "objectives"}, {"type": "paragraph", "md": "1- التعرف على مصطلحي العلمانية والديمقراطية وبيان ضلالهما وأنهما من العقائد الكفرية في الأصل.", "page": 271, "id": "unit-25__lesson-03__b02", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- بيان معتقد أهل السنة والجماعة في التعامل مع هذه الأفكار الضالة والتحذير منها.", "page": 271, "id": "unit-25__lesson-03__b03", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "أولا؛ العلمانية:", "page": 271, "id": "unit-25__lesson-03__b04", "role": "section"}, {"type": "paragraph", "md": "العَلَمانية SECULARISM ترجمتها الصحيحة: اللادينية أو الدنيوية، وهي: دعوة جاهلية لإقامة الحياة على العلم الوضعي والعقل الإنساني ومراعاة المصلحة الذاتية بعيدًا عن الدين وأوامر الخالق سبحانه وتعالى .", "page": 271, "id": "unit-25__lesson-03__b05", "inline": [{"t": "text", "s": "العَلَمانية SECULARISM ترجمتها الصحيحة: اللادينية أو الدنيوية، وهي: دعوة جاهلية لإقامة الحياة على العلم الوضعي والعقل الإنساني ومراعاة المصلحة الذاتية بعيدًا عن الدين وأوامر الخالق "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "وتعني في جانبها السياسي بالذات: اللادينية في الحكم، وهي اصطلاح لا صلة له بكلمة العلم SCIENCE، وقد ظهرت العلمانية في أوروبا منذ القرن السابع عشر وانتقلت إلى الشرق في بداية القرن التاسع عشر، وقد اختيرت كلمة علمانية لأنها أقل إثارة من كلمة لا دينية؛ فمدلول العَلَمانية المتفق عليه يعني: عزل الدين عن الدولة وحياة المجتمع وإبقائه حبيسًا في ضمير الفرد؛ لا يتجاوز العلاقة الخاصة بينه وبين ربه، فإن سمح له بالتعبير عن نفسه ففي الشعائر التعبدية والمراسم المتعلقة بالزواج والوفاة ونحوهما.", "page": 271, "id": "unit-25__lesson-03__b06", "inline": [{"t": "text", "s": "وتعني في جانبها السياسي بالذات: اللادينية في الحكم، وهي اصطلاح لا صلة له بكلمة العلم SCIENCE، وقد ظهرت العلمانية في أوروبا منذ القرن السابع عشر وانتقلت إلى الشرق في بداية القرن التاسع عشر، وقد اختيرت كلمة علمانية لأنها أقل إثارة من كلمة لا دينية؛ ف"}, {"t": "emphasis", "s": "مدلول العَلَمانية المتفق عليه يعني", "role": "emphasis"}, {"t": "text", "s": ": عزل الدين عن الدولة وحياة المجتمع وإبقائه حبيسًا في ضمير الفرد؛ لا يتجاوز العلاقة الخاصة بينه وبين ربه، فإن سمح له بالتعبير عن نفسه ففي الشعائر التعبدية والمراسم المتعلقة بالزواج والوفاة ونحوهما."}]}, {"type": "paragraph", "md": "وتتفق العلمانية مع الديانة النصرانية في فصل الدين عن الدولة؛ حيث لقيصر سلطة الدولة، ولله سلطة الكنيسة، وهذا واضح فيما ينسبه النصارى إلى عيسى عليه السلام من قوله: «أعطِ ما لقيصر لقيصر وما لله لله».", "page": 271, "id": "unit-25__lesson-03__b07", "inline": [{"t": "text", "s": "وتتفق العلمانية مع الديانة النصرانية في فصل الدين عن الدولة؛ حيث لقيصر سلطة الدولة، ولله سلطة الكنيسة، وهذا واضح فيما ينسبه النصارى إلى عيسى "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " من قوله: "}, {"t": "hadith", "s": "أعطِ ما لقيصر لقيصر وما لله لله", "narrator": null, "source": null, "confidence": "medium", "ref_api": null}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "أما الإسلام فلا يعرف هذه الثنائية؛ فالمسلم كله لله وحياته كلها لله؛ قال تعالى: ﴿قُلۡ إِنَّ صَلَاتِي وَنُسُكِي وَمَحۡيَايَ وَمَمَاتِي لِلَّهِ رَبِّ ٱلۡعَٰلَمِينَ ۝١٦٢﴾؛ فالدين ولله، والوطن لله، والكل لله.", "page": 271, "id": "unit-25__lesson-03__b08", "inline": [{"t": "text", "s": "أما الإسلام فلا يعرف هذه الثنائية؛ فالمسلم كله لله وحياته كلها لله؛ قال تعالى: "}, {"t": "ayah", "s": "قُلۡ إِنَّ صَلَاتِي وَنُسُكِي وَمَحۡيَايَ وَمَمَاتِي لِلَّهِ رَبِّ ٱلۡعَٰلَمِينَ ۝١٦٢", "ayah": [162], "verses": [{"n": 162, "text": "قُلۡ إِنَّ صَلَاتِي وَنُسُكِي وَمَحۡيَايَ وَمَمَاتِي لِلَّهِ رَبِّ ٱلۡعَٰلَمِينَ", "surah": 6, "ref_api": "https://api.quran.com/api/v4/verses/by_key/6:162", "surah_name": "الأنعام", "ayah_canonical": 162, "match": "exact", "ref": "6:162"}], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ فالدين ولله، والوطن لله، والكل لله."}]}, {"type": "paragraph", "md": "الأفكار والمعتقدات:", "page": 271, "id": "unit-25__lesson-03__b09", "inline": [{"t": "emphasis", "s": "الأفكار والمعتقدات:", "role": "emphasis"}]}, {"type": "paragraph", "md": "- كثير من العلمانيين ملاحدة أصلا، وبعضهم يؤمنون بوجود الله لكنهم يعتقدون بعدم وجود أية علاقة بين الله وبين حياة الإنسان؛ فالحياة تقوم على أساس العلم المطلق وتحت سلطان العقل والتجريب.", "page": 271, "id": "unit-25__lesson-03__b10", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- فصل الدين عن السياسة وإقامة الحياة على أساس مادي، وتطبيق مبدأ النفعية على كل شيء في الحياة.", "page": 271, "id": "unit-25__lesson-03__b11", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- اعتماد مبدأ الميكيافيلية في فلسفة الحكم والسياسة والأخلاق.", "page": 271, "id": "unit-25__lesson-03__b12", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- نشر الإباحية والفوضى الأخلاقية وتهديم كيان الأسرة باعتبارها النواة الأولى في البنية الإجتماعية.", "page": 271, "id": "unit-25__lesson-03__b13", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "وإذا كان هناك عذر ما لوجود العلمانية في الغرب فليس هناك أي عذر لوجودها في بلاد المسلمين؛ لأن النصراني إذا حكمه قانون مدني وضعي فلا ينزعج؛ لأنه لا يعطل قانونًا فرضه عليه دينه وليس في دينه ما يعتبر منهجًا للحياة، أما مع المسلم فالأمر مختلف حيث يوجب عليه إيمانُه الاحتكام إلى شرع الله.", "page": 272, "id": "unit-25__lesson-03__b14"}, {"type": "paragraph", "md": "بعض الثمار الخبيثة التي أنتجتها العلمانية في بلاد المسلمين، وإلا فثمارها الخبيثة أكثر من ذلك بكثير:", "page": 272, "id": "unit-25__lesson-03__b15", "inline": [{"t": "emphasis", "s": "بعض الثمار الخبيثة التي أنتجتها العلمانية في بلاد المسلمين، وإلا فثمارها الخبيثة أكثر من ذلك بكثير:", "role": "emphasis"}]}, {"type": "paragraph", "md": "1- الطعن في حقيقة الإسلام والقرآن والنبوة، والزعم بأن الإسلام استنفذ أغراضه وهو عبارة عن طقوس وشعائر روحية، والزعم بأن الإسلام لا يتلاءم مع الحضارة ويدعو إلى التخلف.", "page": 272, "id": "unit-25__lesson-03__b16", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- رفض الحكم بما أنزل الله سبحانه وتعالى ، وإقصاء الشريعة عن كافة مجالات الحياة، والاستعاضة عن الوحي الإلهي المُنزَّل على سيد البشر صلى الله عليه وسلم ، بالقوانين الوضعية التي اقتبسوها عن الكفار المحاربين لله ورسوله صلى الله عليه وسلم ، واعتبار الدعوة إلى العودة إلى الحكم بما أنزل الله وهجر القوانين الوضعية؛ تخلفًا ورجعية وردة عن التقدم والحضارة!، وسببًا في السخرية من أصحاب هذه الدعوة واحتقارهم، وإبعادهم عن تولي الوظائف التي تستلزم الاحتكاك بالشعب والشباب، حتى لا يؤثروا فيهم.", "page": 272, "id": "unit-25__lesson-03__b17", "inline": [{"t": "text", "s": "2- رفض الحكم بما أنزل الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، وإقصاء الشريعة عن كافة مجالات الحياة، والاستعاضة عن الوحي الإلهي المُنزَّل على سيد البشر "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، بالقوانين الوضعية التي اقتبسوها عن الكفار المحاربين لله ورسوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، واعتبار الدعوة إلى العودة إلى الحكم بما أنزل الله وهجر القوانين الوضعية؛ تخلفًا ورجعية وردة عن التقدم والحضارة!، وسببًا في السخرية من أصحاب هذه الدعوة واحتقارهم، وإبعادهم عن تولي الوظائف التي تستلزم الاحتكاك بالشعب والشباب، حتى لا يؤثروا فيهم."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- تشويه الحضارة الإسلامية وتحريف التاريخ الإسلامي وتزييفه، وتصوير العصور الذهبية لحركة الفتوح الإسلامية، على أنها عصور همجية تسودها الفوضى، والمطامع الشخصية.", "page": 272, "id": "unit-25__lesson-03__b18", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- تضخيم حجم الحركات الهدامة في التاريخ الإسلامي والزعم بأنها حركات إصلاح لا هدم.", "page": 272, "id": "unit-25__lesson-03__b19", "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- إذابة الفوارق بين حَمَلة الرسالة الصحيحة، وهم المسلمون، وبين أهل التحريف والتبديل والإلحاد، وصهر الجميع في إطار واحد، وجعلهم جميعًا بمنزلة واحدة من حيث الظاهر، وإن كان في الحقيقة يتم تفضيل أهل الكفر والإلحاد والفسوق والعصيان على أهل التوحيد والطاعة والإيمان، فالمسلم والنصراني واليهودي والشيوعي والمجوسي كل هؤلاء وغيرهم، في ظل هذا الفكر بمنزلة واحدة يتساوون أمام القانون، لا فضل لأحد على الآخر إلا بمقدار الاستجابة لهذا الفكر العلماني.", "page": 272, "id": "unit-25__lesson-03__b20", "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "وفي ظل هذا الفكر لا حرج عندهم أن يكون اليهودي أو النصراني أو غير ذلك من النِحَل الكافرة حاكمًا على بلاد المسلمين، وهم يحاولون ترويج ذلك في بلاد المسلمين تحت ما سموه بـ«الوحدة الوطنية»، بل جعلوا «الوحدة الوطنية» هي الأصل وكل ما خالفها من كتاب الله أو سنة رسوله صلى الله عليه وسلم طرحوه ورفضوه، وقالوا: «هذا يعَرّض الوحدة الوطنية للخطر!!».", "page": 272, "id": "unit-25__lesson-03__b21", "inline": [{"t": "text", "s": "وفي ظل هذا الفكر لا حرج عندهم أن يكون اليهودي أو النصراني أو غير ذلك من النِحَل الكافرة حاكمًا على بلاد المسلمين، وهم يحاولون ترويج ذلك في بلاد المسلمين تحت ما سموه بـ"}, {"t": "quote", "s": "الوحدة الوطنية"}, {"t": "text", "s": "، بل جعلوا "}, {"t": "quote", "s": "الوحدة الوطنية"}, {"t": "text", "s": " هي الأصل وكل ما خالفها من كتاب الله أو سنة رسوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " طرحوه ورفضوه، وقالوا: "}, {"t": "hadith", "s": "هذا يعَرّض الوحدة الوطنية للخطر!!", "narrator": null, "source": "مسلم", "confidence": "high", "ref_api": null}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "8 - الدعوة إلى تحرير المرأة وفق الأسلوب الغربي، ونشر الإباحية والفوضى الأخلاقية، وتهديم بنيان الأسرة باعتبارها النواة الأولى في البنية الاجتماعية، وتشجيع ذلك والحض عليه: وذلك عن طريق:", "page": 272, "id": "unit-25__lesson-03__b22", "list": {"type": "ordered", "marker": "8"}}, {"type": "paragraph", "md": "أ - القوانين التي تبيح الرذيلة ولا تعاقب عليها، وتعتبر ممارسة الزنا والشذوذ من باب الحرية الشخصية!", "page": 272, "id": "unit-25__lesson-03__b23"}, {"type": "paragraph", "md": "ب - وسائل الإعلام المختلفة من صحف ومجلات وإذاعة وتلفاز التي لا تكَلُّ ولا تمَلُّ من محاربة الفضيلة، ونشر الرذيلة بالتلميح مرة، وبالتصريح مرة أخرى ليلًا ونهارًا.", "page": 273, "id": "unit-25__lesson-03__b24"}, {"type": "paragraph", "md": "جـ - محاربة الحجاب وفرض السفور والاختلاط في المدارس والجامعات والمصالح والهيئات.", "page": 273, "id": "unit-25__lesson-03__b25"}, {"type": "paragraph", "md": "9 - محاربة الدعوة الإسلامية عن طريق:", "page": 273, "id": "unit-25__lesson-03__b26", "inline": [{"t": "text", "s": "9 - "}, {"t": "emphasis", "s": "محاربة الدعوة الإسلامية عن طريق:", "role": "emphasis"}], "list": {"type": "ordered", "marker": "9"}}, {"type": "paragraph", "md": "أ - تضييق الخناق على نشر الكتاب الإسلامي، وإفساح المجال للكتب الضالة التي تشكك في الشريعة.", "page": 273, "id": "unit-25__lesson-03__b27"}, {"type": "paragraph", "md": "ب - إفساح المجال في وسائل الإعلام للعلمانيين المنحرفين لمخاطبة أكبر عدد من الناس لنشر الفكر الضال، ولتحريف معاني النصوص الشرعية؛ مع إغلاق وسائل الإعلام في وجه علماء المسلمين.", "page": 273, "id": "unit-25__lesson-03__b28"}, {"type": "paragraph", "md": "10 - مطاردة الدعاة إلى الله، ومحاربتهم، وإلصاق التهم الباطلة بهم، ونعتهم بالأوصاف الذميمة، وتصويرهم على أنهم متخلفون فكريًا، ومتحجرون عقليًا، ورجعيون، يُحاربون كل مخترعات العلم الحديث النافع، ومتطرفون متعصبون لا يفقهون حقيقة الأمور، بل يتمسكون بالقشور ويَدَعون الأصول.", "page": 273, "id": "unit-25__lesson-03__b29", "list": {"type": "ordered", "marker": "10"}}, {"type": "paragraph", "md": "11 - التخلص من المسلمين الذين لا يهادنون العلمانية، وذلك عن طريق النفي أو السجن أو القتل.", "page": 273, "id": "unit-25__lesson-03__b30", "list": {"type": "ordered", "marker": "11"}}, {"type": "paragraph", "md": "12 - إنكار فريضة الجهاد في سبيل الله، ومهاجمتها واعتبارها نوعًا من أنواع الهمجية وقطع الطريق: وذلك أن الجهاد في سبيل الله معناه القتال لتكون كلمة الله هي العليا، وحتى لا يكون في الأرض سلطان له القوة والغلبة والحكم إلا سلطان الإسلام، والقوم -أي العلمانيين- قد عزلوا الدين عن التدخل في شؤون الدنيا، وجعلوا الدين علاقة خاصة بين الإنسان وما يعبد، بحيث لا يكون لهذه العبادة تأثير في أقواله وأفعاله وسلوكه خارج مكان العبادة؛ فكيف يكون عندهم إذن جهاد في سبيل إعلاء كلمة الدين؟!!", "page": 273, "id": "unit-25__lesson-03__b31", "list": {"type": "ordered", "marker": "12"}}, {"type": "paragraph", "md": "والقتال المشروع عند العلمانيين وأذنابهم هو القتال للدفاع عن المال أو الأرض، وأما الدفاع عن الدين والعمل على نشره والقتال لأجله؛ فهذا عندهم من العدوان والهمجية التي تأباها الإنسانية المتمدنة!!", "page": 273, "id": "unit-25__lesson-03__b32"}, {"type": "paragraph", "md": "13 - إحياء الحضارات القديمة، والدعوة إلى القومية أو الوطنية، وهي دعوة تعمل على تجميع الناس تحت جامع وهمي من الجنس أو اللغة أو المكان أو المصالح؛ على ألا يكون الدين عاملًا من عوامل التجميع، بل الدين من منظار هذه الدعوة يُعد عاملًا من أكبر عوامل التفرق والشقاق.", "page": 273, "id": "unit-25__lesson-03__b33", "list": {"type": "ordered", "marker": "13"}}, {"type": "paragraph", "md": "14 - تربية الأجيال تربية لا دينية، وإفساد التعليم وجعله خادمًا لنشر الفكر العلماني وذلك عن طريق:", "page": 273, "id": "unit-25__lesson-03__b34", "list": {"type": "ordered", "marker": "14"}}, {"type": "paragraph", "md": "أ- بث الأفكار العلمانية في ثنايا المواد الدراسية بالنسبة للتلاميذ، والطلاب في مختلف مراحل التعليم.", "page": 273, "id": "unit-25__lesson-03__b35"}, {"type": "paragraph", "md": "ب- تقليص الفترة الزمنية المتاحة للمادة الدينية إلى أقصى حد ممكن.", "page": 273, "id": "unit-25__lesson-03__b36"}, {"type": "paragraph", "md": "جـ - منع تدريس نصوص معينة لأنها واضحة صريحة في كشف باطلهم.", "page": 273, "id": "unit-25__lesson-03__b37"}, {"type": "paragraph", "md": "د- تحريف النصوص الشرعية عن طريق تقديم شروح مبتورة لها؛ فتبدو وكأنها تؤيد الفكر العلماني.", "page": 274, "id": "unit-25__lesson-03__b38"}, {"type": "paragraph", "md": "هـ- إقصاء الأساتذة المتمسكين بدينهم عن التدريس، ومنعهم من الاختلاط بالطلاب.", "page": 274, "id": "unit-25__lesson-03__b39"}, {"type": "paragraph", "md": "و- جعل مادة الدين هامشية؛ موضعها في آخر اليوم الدراسي، وجعلها غير محسوبة في علامات الطلاب.", "page": 274, "id": "unit-25__lesson-03__b40"}, {"type": "paragraph", "md": "14 - اقتباس الأنظمة والمناهج اللادينية عن الغرب ومحاكاته فيها.", "page": 274, "id": "unit-25__lesson-03__b41", "list": {"type": "ordered", "marker": "14"}}, {"type": "paragraph", "md": "لماذا يرفض المسلمون العلمانية؟", "page": 274, "id": "unit-25__lesson-03__b42", "inline": [{"t": "emphasis", "s": "لماذا يرفض المسلمون العلمانية؟", "role": "emphasis"}]}, {"type": "paragraph", "md": "1 - نحن نرفض العلمانية لأنها تُحِل ما حرم الله: إذا كانت الشريعة مُلْزِمة من حيث المبدأ، فإن في داخل هذه الشريعة أحكامًا ثابتة لا تقبل التغيير، وأحكامًا عامة ثابتة في ذاتها، ولكنها تقبل أن تدخل تحتها متغيرات. ومن بين الثوابت: التي لا تقبل التغيير ولا يدخل تحتها متغيرات، أحكام العبادات كلها، والحدود، وعلاقات الجنسين.", "page": 274, "id": "unit-25__lesson-03__b43", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "فماذا فعلت العلمانية بهذه الثوابت؟ إن الأنظمة العلمانية تبيح الزنا برضا الطرفين، و «المتشدد» منها يشترط موافقة الزوج أو الزوجة، والكثير منها يبيح اللواط للبالغين، وكلها يبيح الخمر والخنزير!!", "page": 274, "id": "unit-25__lesson-03__b44", "inline": [{"t": "emphasis", "s": "فماذا فعلت العلمانية بهذه الثوابت؟", "role": "emphasis"}, {"t": "text", "s": " إن الأنظمة العلمانية تبيح الزنا برضا الطرفين، و "}, {"t": "quote", "s": "المتشدد"}, {"t": "text", "s": " منها يشترط موافقة الزوج أو الزوجة، والكثير منها يبيح اللواط للبالغين، وكلها يبيح الخمر والخنزير!!"}]}, {"type": "paragraph", "md": "ففي شريعة العلمانية يكتسب الزنا شرعية حين يقع برضاء الطرفين والصلة بامرأة بالغة برضائها لا تقوم به جريمة إذا لم يقع في ظروف تجعله داخلًا تحت قانون مكافحة الدعارة.", "page": 274, "id": "unit-25__lesson-03__b45"}, {"type": "paragraph", "md": "وتبيح العلمانية ظهور النساء على شواطئ البحر بملابس الاستحمام مع أنها تكشف العورات. فالعِرض في شريعة العلمانية هو مجرد حرية السلوك الجنسي، ولكل شخص في هذه الشريعة أن يتخذ لنفسه السلوك الجنسي الذي يروق له، والأفعال التي يحرّمها قانون العلمانية في جرائم العرض، إنما يحَرّمها لكونها تشكل اعتداء على الحرية الجنسية فحسب لا باعتبارها أمرًا يغضب الله ويحرّمه الدين، فإذا اتخذت الجريمة صورة الاغتصاب أو هتك العرض بالقوة فإن القانون الوضعي يُحرّم ذلك لكونه اعتداءً على الحرية الجنسية، لأن الجاني قد أرغم المجني عليه على سلوك جنسي لم تتجه إليه إرادته ورغبته.", "page": 274, "id": "unit-25__lesson-03__b46"}, {"type": "paragraph", "md": "ونفس الأمر نجده في جريمة الزنا فهي لا تعد جريمة إذا كان الطرفان غير متزوجين، أو إذا ارتكبها الزوج في غير منزل الزوجية، ولا تتحرك الدعوى الجنائية في جريمة الزنا إلا بناء على شكوى من الزوج، وللزوج الحق في التنازل عن الشكوى بعد تقديمها، وبالتالي تنقضي الدعوى الجنائية، وتوقف إجراءات رفع الدعوى الجنائية وللزوج حق وقف تنفيذ العقوبة!!", "page": 274, "id": "unit-25__lesson-03__b47"}, {"type": "paragraph", "md": "ذلك قانون العلمانية، وتلك فلسفته فيما يتعلق بجرائم العِرْض والزنا، وما ذُكِرَ ليس إلا شرحًا لنصوص هذا القانون الذي تُحْكَمُ به محاكمنا، ويدرسه طلاب كلية الحقوق؛ قانون يمجد الحرية الجنسية، ويجعل من الشرطة حاميًا لها، بل وتشرف الدول العلمانية على الملاهي الليلية وتعد لها شُرطة خاصة لحمايتها، وكأنها بيوت رسمية للبغاء، بل هي على الحقيقة كذلك فلا يستطيع إنسان كائنًا مَن كان، مَنْع راقصة من الذهاب إلى هذه الملاهي، وإلا اعتُبِرَ ذلك مَنْعٌ لموظفة من أداء وظيفتها، وتعرض مَنْ منعها للعقوبة الجنائية والمدنية، ولصاحب الملهى حق مقاضاتها ومطالبتها بالتعويض لعدم وفائها بالتزامها!.", "page": 275, "id": "unit-25__lesson-03__b48"}, {"type": "paragraph", "md": "وهكذا تبيح العلمانية الزنا، وتهيئ له الفرص، وتعد له المؤسسات، والحفلات في الملاهي والمسارح.", "page": 275, "id": "unit-25__lesson-03__b49"}, {"type": "paragraph", "md": "وأما الربا فهو عماد الاقتصاد العلماني، تؤسَّسُ عليه البنوك، وتُقَدَّم به القروض، بل ويدخل الناس فيه كرهًا؛ فيحلون ما حرم الله، فكيف بمن يقيمون للربا بنوكًا ويعطون للتعامل به الشرعية الكاملة؟!", "page": 275, "id": "unit-25__lesson-03__b50"}, {"type": "paragraph", "md": "وأما الخمر؛ فالنظم العلمانية تبيح شربها، وتفتح المحلات لبيعها وشرائها، وتجعلها مالًا متقوّمًا يَحْرُم إهداره، بل إن النظم العلمانية تنشئ المصانع لإنتاج الخمور وتعطي على الاجتهاد في إنتاجها جوائز إنتاج، وبالتالي فهي تبيح تصديرها واستيرادها، وعقد الصفقات للتجارة بها، وتحرّم على الأطراف المتعاقدة عدم الالتزام بنصوص العقد أو عدم مطابقتها للمواصفات المتعاقد عليها.. كأي سلعة أخرى!", "page": 275, "id": "unit-25__lesson-03__b51"}, {"type": "paragraph", "md": "فالعلمانية تحل ما حرم الله، وتحرم ما أحله الله. وليس هذا في الزنا والربا والخمر فقط، أو في الحدود والتعازير فقط، أو في مادة أو أكثر من مواد القانون الوضعي العلماني، بل إن قضية تحليل ما حرم الله، وتحريم ما أحله الله هي قضية النظام القانوني العلماني بأكمله، وبجميع جوانبه المختلفة.", "page": 275, "id": "unit-25__lesson-03__b52"}, {"type": "paragraph", "md": "ولما كان تحليل ما حرم الله، وتحريم ما أحل الله كفرًا لمن فعله، ومَن قَبِله، ولنبقى مسلمين يجب علينا أن نرفض الكفر، برفض العلمانية التي تقوم على هذه الشريعة التي تحلّ ما حرم الله، وتحرّم ما أحل الله.", "page": 275, "id": "unit-25__lesson-03__b53"}, {"type": "paragraph", "md": "2- ونحن نرفض العلمانية لأنها كفر بواح: فهي قيام الحياة على غير الدين، أو فصل الدين عن الدولة، وهذا يعني الحكم بغير ما أنزل الله، وتحكيم غير شريعته سبحانه، وقبول الحكم والتشريع من غير الله سبحانه وتعالى ؛ لذلك فالعلمانية هجر لأحكام الله كلها وإيثار أحكام غير حكمه في كتابه وسنة نبيه، وتعطيل لكل ما في الشريعة، بل بلغ الأمر مبلغ الاحتجاج على تفضيل أحكام القانون الموضوع على أحكام الله المنزلة.", "page": 275, "id": "unit-25__lesson-03__b54", "inline": [{"t": "emphasis", "s": "2- ونحن نرفض العلمانية لأنها كفر بواح:", "role": "emphasis"}, {"t": "text", "s": " فهي قيام الحياة على غير الدين، أو فصل الدين عن الدولة، وهذا يعني الحكم بغير ما أنزل الله، وتحكيم غير شريعته سبحانه، وقبول الحكم والتشريع من غير الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ؛ لذلك فالعلمانية هجر لأحكام الله كلها وإيثار أحكام غير حكمه في كتابه وسنة نبيه، وتعطيل لكل ما في الشريعة، بل بلغ الأمر مبلغ الاحتجاج على تفضيل أحكام القانون الموضوع على أحكام الله المنزلة."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3 - نحن نرفض العلمانية لتكون شريعة الله هي العليا: فقد جاء الإسلام ليكون دين البشرية كلها، ولتكون شريعته هي شريعة الناس جميعًا ولتهيمن على ما قبلها من الشرائع، وتكون هي المرجع النهائي، ولتقيم منهج الله لحياة البشرية حتى يرث الله ومن عليها. والمنهج الذي تقوم عليه الحياة في شتى شعبها ونشاطها، والشريعة التي تعيش الحياة في إطارها وتدور حول محورها، وتستمد منها تصورها الاعتقادي، ونظامها الاجتماعي، وآداب سلوكها الفردي والجماعي.", "page": 275, "id": "unit-25__lesson-03__b55", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "الخلاصة: العلمانية دعوة إلى إقامة الحياة على أسس العلم الوضعي والعقل بعيدًا عن الدين الذي يتم فصله عن الدولة وحياة المجتمع وحبسه في ضمير الفرد ولا يصرح بالتعبير عنه إلَّا في أضيق الحدود. وعلى ذلك فإن الذي يؤمن بالعلمانية بديلًا عن الدين ولا يقبل تحكيم الشرعية الإسلامية في كل جوانب الحياة ولا يحرم ما حرم الله يعتبر مرتدًا ولا ينتمي إلى الإسلام.", "page": 276, "id": "unit-25__lesson-03__b56", "inline": [{"t": "emphasis", "s": "الخلاصة", "role": "emphasis"}, {"t": "text", "s": ": العلمانية دعوة إلى إقامة الحياة على أسس العلم الوضعي والعقل بعيدًا عن الدين الذي يتم فصله عن الدولة وحياة المجتمع وحبسه في ضمير الفرد ولا يصرح بالتعبير عنه إلَّا في أضيق الحدود. وعلى ذلك فإن الذي يؤمن بالعلمانية بديلًا عن الدين ولا يقبل تحكيم الشرعية الإسلامية في كل جوانب الحياة ولا يحرم ما حرم الله يعتبر مرتدًا ولا ينتمي إلى الإسلام."}]}, {"type": "paragraph", "md": "والواجب إقامة الحجة عليه واستتابته حتى يدخل في حظيرة الإسلام وإلا جرت عليه أحكام المرتدين المارقين في الحياة وبعد الوفاة.", "page": 276, "id": "unit-25__lesson-03__b57"}, {"type": "heading", "level": 3, "text": "ثانيا؛ الديمقراطية:", "page": 276, "id": "unit-25__lesson-03__b58", "role": "section"}, {"type": "paragraph", "md": "هي حكم الشعب نفسه بنفسه. وهي مناقضة للإسلام؛ فلا ديمقراطية في الإسلام ولا التقاء معها، بل هناك تناقض وتضاد بينهما؛ فحكم الإسلام يسعى لتكون كلمة الله هي العليا، العليا في كل شيء: في الزواج، في الأسرة، في العلاقات الخارجية، والداخلية، في الحدود والجنايات والعقوبات، أما حكم الديمقراطية فهو يسعى لتكون كلمة الشعب هي العليا.. وشتان بين الاثنين كما بين الثريا والثرى وبين الإيمان والكفر.", "page": 276, "id": "unit-25__lesson-03__b59"}, {"type": "paragraph", "md": "الدولة الديمقراطية: تحكم بغير ما أنزل الله، والسيادة فيها للشعب، قال تعالى: ﴿وَمَن لَّمۡ يَحۡكُم بِمَآ أَنزَلَ ٱللَّهُ فَأُوْلَٰٓئِكَ هُمُ ٱلۡكَٰفِرُونَ ۝٤٤﴾، وأما دولة القرآن؛ فتحكم بما أنزل الله ﴿إِنِ ٱلۡحُكۡمُ إِلَّا لِلَّهِ أَمَرَ أَلَّا تَعۡبُدُوٓاْ إِلَّآ إِيَّاهُۚ﴾؛ فالسيادة فيها لله وحده والحكم فيها لكتابه وسنة نبيه صلى الله عليه وسلم .", "page": 276, "id": "unit-25__lesson-03__b60", "inline": [{"t": "text", "s": "الدولة الديمقراطية: تحكم بغير ما أنزل الله، والسيادة فيها للشعب، قال تعالى: "}, {"t": "ayah", "s": "وَمَن لَّمۡ يَحۡكُم بِمَآ أَنزَلَ ٱللَّهُ فَأُوْلَٰٓئِكَ هُمُ ٱلۡكَٰفِرُونَ ۝٤٤", "ayah": [44], "verses": [{"n": 44, "text": "وَمَن لَّمۡ يَحۡكُم بِمَآ أَنزَلَ ٱللَّهُ فَأُوْلَٰٓئِكَ هُمُ ٱلۡكَٰفِرُونَ", "surah": 5, "ref_api": "https://api.quran.com/api/v4/verses/by_key/5:44", "surah_name": "المائدة", "ayah_canonical": 44, "match": "contained", "ref": "5:44"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، وأما دولة القرآن؛ فتحكم بما أنزل الله "}, {"t": "ayah", "s": "إِنِ ٱلۡحُكۡمُ إِلَّا لِلَّهِ أَمَرَ أَلَّا تَعۡبُدُوٓاْ إِلَّآ إِيَّاهُۚ", "ayah": [], "verses": [{"n": 40, "text": "إِنِ ٱلۡحُكۡمُ إِلَّا لِلَّهِ أَمَرَ أَلَّا تَعۡبُدُوٓاْ إِلَّآ إِيَّاهُۚ", "surah": 12, "surah_name": "يوسف", "ref": "12:40", "ref_api": "https://api.quran.com/api/v4/verses/by_key/12:40"}], "surah": 12, "ref_api": "https://api.quran.com/api/v4/verses/by_key/12:40", "surah_name": "يوسف", "ayah_canonical": 40, "match": "contained", "ref": "12:40"}, {"t": "text", "s": "؛ فالسيادة فيها لله وحده والحكم فيها لكتابه وسنة نبيه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "ولا شك في ردة من يرفض تطبيق حكم الإسلام ويطالب بالديمقراطية بمفهومها الغربي الذي هو أساس وضعها؛ فإن الله تعالى يقول: ﴿فَلَا وَرَبِّكَ لَا يُؤۡمِنُونَ حَتَّىٰ يُحَكِّمُوكَ فِيمَا شَجَرَ بَيۡنَهُمۡ ثُمَّ لَا يَجِدُواْ فِيٓ أَنفُسِهِمۡ حَرَجٗا مِّمَّا قَضَيۡتَ وَيُسَلِّمُواْ تَسۡلِيمٗا ۝٦٥﴾، ويقول: ﴿أَفَحُكۡمَ ٱلۡجَٰهِلِيَّةِ يَبۡغُونَۚ وَمَنۡ أَحۡسَنُ مِنَ ٱللَّهِ حُكۡمٗا لِّقَوۡمٖ يُوقِنُونَ ۝٥٠﴾؛ يقول ابن كثير: «فمن ترك الشرع المحكم المنزل على محمد بن عبد الله خاتم الأنبياء وتحاكم إلى غيره من الشرائع المنسوخة؛ كفر، فكيف بمن تحاكم إلى «الياسا» وقدمها عليه؟ من فعل ذلك كفر بإجماع المسلمين»، و«الياسا» و«الياسق» هو شريعة التتار، ومثلها اليوم الدساتير الوضعية.", "page": 276, "id": "unit-25__lesson-03__b61", "inline": [{"t": "text", "s": "ولا شك في ردة من يرفض تطبيق حكم الإسلام ويطالب بالديمقراطية بمفهومها الغربي الذي هو أساس وضعها؛ فإن الله تعالى يقول: "}, {"t": "ayah", "s": "فَلَا وَرَبِّكَ لَا يُؤۡمِنُونَ حَتَّىٰ يُحَكِّمُوكَ فِيمَا شَجَرَ بَيۡنَهُمۡ ثُمَّ لَا يَجِدُواْ فِيٓ أَنفُسِهِمۡ حَرَجٗا مِّمَّا قَضَيۡتَ وَيُسَلِّمُواْ تَسۡلِيمٗا ۝٦٥", "ayah": [65], "verses": [{"n": 65, "text": "فَلَا وَرَبِّكَ لَا يُؤۡمِنُونَ حَتَّىٰ يُحَكِّمُوكَ فِيمَا شَجَرَ بَيۡنَهُمۡ ثُمَّ لَا يَجِدُواْ فِيٓ أَنفُسِهِمۡ حَرَجٗا مِّمَّا قَضَيۡتَ وَيُسَلِّمُواْ تَسۡلِيمٗا", "surah": 4, "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:65", "surah_name": "النساء", "ayah_canonical": 65, "match": "exact", "ref": "4:65"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، ويقول: "}, {"t": "ayah", "s": "أَفَحُكۡمَ ٱلۡجَٰهِلِيَّةِ يَبۡغُونَۚ وَمَنۡ أَحۡسَنُ مِنَ ٱللَّهِ حُكۡمٗا لِّقَوۡمٖ يُوقِنُونَ ۝٥٠", "ayah": [50], "verses": [{"n": 50, "text": "أَفَحُكۡمَ ٱلۡجَٰهِلِيَّةِ يَبۡغُونَۚ وَمَنۡ أَحۡسَنُ مِنَ ٱللَّهِ حُكۡمٗا لِّقَوۡمٖ يُوقِنُونَ", "surah": 5, "ref_api": "https://api.quran.com/api/v4/verses/by_key/5:50", "surah_name": "المائدة", "ayah_canonical": 50, "match": "exact", "ref": "5:50"}], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ يقول ابن كثير: "}, {"t": "quote", "s": "فمن ترك الشرع المحكم المنزل على محمد بن عبد الله خاتم الأنبياء وتحاكم إلى غيره من الشرائع المنسوخة؛ كفر، فكيف بمن تحاكم إلى «الياسا", "speaker": "ابن كثير"}, {"t": "text", "s": " وقدمها عليه؟ من فعل ذلك كفر بإجماع المسلمين»، و"}, {"t": "quote", "s": "الياسا"}, {"t": "text", "s": " و"}, {"t": "quote", "s": "الياسق"}, {"t": "text", "s": " هو شريعة التتار، ومثلها اليوم الدساتير الوضعية."}]}, {"type": "paragraph", "md": "يقول أحمد شاكر رحمه الله : «الأمر في هذه القوانين الوضعية واضحٌ وضوح الشمس؛ هي كفرٌ بَواح، لا خفاء فيه ولا مُداراة، ولا عذر لأحدٍ ممن ينتسب للإسلام كائنًا من كان في العمل بها، أو الخضوع لها، أو إقرارها».", "page": 276, "id": "unit-25__lesson-03__b62", "inline": [{"t": "text", "s": "يقول أحمد شاكر "}, {"t": "honorific", "s": "رحمه الله"}, {"t": "text", "s": " : "}, {"t": "quote", "s": "الأمر في هذه القوانين الوضعية واضحٌ وضوح الشمس؛ هي كفرٌ بَواح، لا خفاء فيه ولا مُداراة، ولا عذر لأحدٍ ممن ينتسب للإسلام كائنًا من كان في العمل بها، أو الخضوع لها، أو إقرارها", "speaker": "أحمد شاكر رحمه الله"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "لكن لو كان المطالب بالديمقراطية جاهلا بمناقضتها للشرع بل ويلبَّس عليه أنها من شرع الله فإنه يعذر بجهله (خاصة وأن مدلول لفظة الديمقراطية أصبح نتيجة للتلبيسات الكثيرة من المسائل الخفية).", "page": 277, "id": "unit-25__lesson-03__b63", "inline": [{"t": "emphasis", "s": "لكن لو كان المطالب بالديمقراطية جاهلا بمناقضتها للشرع", "role": "emphasis"}, {"t": "text", "s": " بل ويلبَّس عليه أنها من شرع الله فإنه يعذر بجهله "}, {"t": "emphasis", "s": "(خاصة وأن مدلول لفظة الديمقراطية أصبح نتيجة للتلبيسات الكثيرة من المسائل الخفية)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ولو كان يعلم بمناقضتها لكن يتخذها وسيلة لتحكيم شرع الله فهو مخطئ آثم؛ لأن الغاية المشروعة لا تبرر الوسيلة غير المشروعة فالوسائل في الإسلام لها حكم الغايات، لكن يعذر بتأويله (والتأويل الخاطئ نوع من أنواع الجهل).. ومن يُكفِّر هذين الصنفين ولا يعذرهم فقد قال بقول الغلاة.", "page": 277, "id": "unit-25__lesson-03__b64", "inline": [{"t": "text", "s": "ولو كان يعلم بمناقضتها لكن يتخذها وسيلة لتحكيم شرع الله فهو مخطئ آثم؛ لأن الغاية المشروعة لا تبرر الوسيلة غير المشروعة فالوسائل في الإسلام لها حكم الغايات، لكن يعذر بتأويله "}, {"t": "emphasis", "s": "(والتأويل الخاطئ نوع من أنواع الجهل)", "role": "emphasis"}, {"t": "text", "s": ".. "}, {"t": "emphasis", "s": "ومن يُكفِّر هذين الصنفين ولا يعذرهم فقد قال بقول الغلاة.", "role": "emphasis"}]}, {"type": "paragraph", "md": "أما من يعرف أن الديمقراطية تناقض الإسلام ويختار الديمقراطية على الإسلام؛ فلا شك في أنه خلع ربقة الإسلام من عنقه ولا عذر له بحال؛ لعدم جهله ولا تأوله، وقد ناقض أصلا في الدين.", "page": 277, "id": "unit-25__lesson-03__b65"}, {"type": "paragraph", "md": "ملاحظة: هناك من أهل العلم المعاصرين من استخدم لفظة «الديمقراطية الإسلامية» قاصدا بها مضمونًا مخالفا لأصل وضعها واستخدامها الغربي مقتربا بها من مضمون الشورى في الإسلام، وهو وإن كان له تأويله في ذلك إلا أن التأمل في نهيه سبحانه عن استعمال كلمة «راعنا» لمَّا استخدمها اليهود قاصدين بها الطعن بالنبي صلى الله عليه وسلم رغم أن الصحابة كانوا يريدون بها معنى صحيحا، يرشدنا أن ترك استخدام المصطلحات التي تؤدي إلى التلبيس مقصد شرعي.. ومثل هذا لا شك أنه لا يُحكم بكفره ولا يُجعل مثل الذي يقول بالديمقراطية في فلسفتها الغربية؛ فشتان بينهما.", "page": 277, "id": "unit-25__lesson-03__b66", "inline": [{"t": "emphasis", "s": "ملاحظة", "role": "emphasis"}, {"t": "text", "s": ": هناك من أهل العلم المعاصرين من استخدم لفظة "}, {"t": "quote", "s": "الديمقراطية الإسلامية"}, {"t": "text", "s": " قاصدا بها مضمونًا مخالفا لأصل وضعها واستخدامها الغربي مقتربا بها من مضمون الشورى في الإسلام، وهو وإن كان له تأويله في ذلك إلا أن التأمل في نهيه سبحانه عن استعمال كلمة "}, {"t": "quote", "s": "راعنا"}, {"t": "text", "s": " لمَّا استخدمها اليهود قاصدين بها الطعن بالنبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " رغم أن الصحابة كانوا يريدون بها معنى صحيحا، يرشدنا أن ترك استخدام المصطلحات التي تؤدي إلى التلبيس مقصد شرعي.. ومثل هذا لا شك أنه لا يُحكم بكفره ولا يُجعل مثل الذي يقول بالديمقراطية في فلسفتها الغربية؛ فشتان بينهما."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 277, "id": "unit-25__lesson-03__b67", "role": "assessment"}, {"type": "paragraph", "md": "1- عرف العلمانية؟ وبين حكمها في ' WHERE id='unit-25__lesson-03';
UPDATE manhaj_lessons SET blocks = blocks || 'الشريعة؟", "page": 277, "id": "unit-25__lesson-03__b68", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ما هي الديمقراطية؟ فصل فيها مبينًا حكم الشريعة لها.", "page": 277, "id": "unit-25__lesson-03__b69", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- لماذا يرفض المسلمون العلمانية والديمقراطية؟ فصل ذلك..", "page": 277, "id": "unit-25__lesson-03__b70", "item_role": "question", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- اذكر بعض الثمار الخبيثة التي أنتجتها العلمانية في بلاد المسلمين؟", "page": 277, "id": "unit-25__lesson-03__b71", "item_role": "question", "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "نشاط دعوي", "page": 277, "id": "unit-25__lesson-03__b72", "role": "activity"}, {"type": "paragraph", "md": "1- للشيخ الدكتور سامي عامري كتابٌ نافع سماه: «العالمانية طاعون العصر - كشف المصطلح وفضح الدلالة» فلنقسمه على مجموعات بحيثُ يقرأ كل فردٍ قسمًا منه ويلخصه لإخوانه في اللقاء القادم.", "page": 277, "id": "unit-25__lesson-03__b73", "inline": [{"t": "text", "s": "1- للشيخ الدكتور سامي عامري كتابٌ نافع سماه: "}, {"t": "quote", "s": "العالمانية طاعون العصر - كشف المصطلح وفضح الدلالة"}, {"t": "text", "s": " فلنقسمه على مجموعات بحيثُ يقرأ كل فردٍ قسمًا منه ويلخصه لإخوانه في اللقاء القادم."}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- نتدارس حول بعض نماذج العلمانيين والديمقراطيين الموجودين في مجتمعاتنا المسلمة ونحذر الناس منهم مع الرد على أبرز شبهاتهم، وتوضيح باطلهم، والحرص على دعوتهم لدين الحق.", "page": 277, "id": "unit-25__lesson-03__b74", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-25__lesson-03';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-25__lesson-04','unit-25',4,'صلاة الكسوفين، والاستسقاء','الفقه',NULL,0,4,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 278, "id": "unit-25__lesson-04__b01", "role": "objectives"}, {"type": "paragraph", "md": "1- بيان الحكمة الإلهية من الكسوف والخسوف، مع ذكر صفة صلاة الكسوفين.", "page": 278, "id": "unit-25__lesson-04__b02", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- بيان حكم صلاة الاستسقاء وسننها.", "page": 278, "id": "unit-25__lesson-04__b03", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "أحكام صلاة الكسوفين:", "page": 278, "id": "unit-25__lesson-04__b04", "role": "rulings"}, {"type": "paragraph", "md": "أي كسوف الشمس وخسوف القمر؛ سُميا بالكسوفين تغليبًا للشمس على القمر.", "page": 278, "id": "unit-25__lesson-04__b05"}, {"type": "paragraph", "md": "وهما آيتَيْن من آيات الله العظمى، والمؤمن يخشى حين يراهما من العذاب؛ لأنهما تخويفٌ من الله لعبيده، ومعنى التخويف: التذكيرُ باليوم الآخِر، إذ يَخْتَلُّ نظام الكَوْن ويزولُ، قال النبي صلى الله عليه وسلم : (إِنَّ الشَّمْسَ وَالْقَمَرَ لاَ يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلاَ لِحَيَاتِهِ، فَإِذَا رَأَيْتُمُوهُما فَادْعُوا اللَّهَ وَصَلُّوا حتَّى تَنْكَشِفَ).", "page": 278, "id": "unit-25__lesson-04__b06", "inline": [{"t": "text", "s": "وهما آيتَيْن من آيات الله العظمى، والمؤمن يخشى حين يراهما من العذاب؛ لأنهما تخويفٌ من الله لعبيده، ومعنى التخويف: التذكيرُ باليوم الآخِر، إذ يَخْتَلُّ نظام الكَوْن ويزولُ، قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إِنَّ الشَّمْسَ وَالْقَمَرَ لاَ يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلاَ لِحَيَاتِهِ، فَإِذَا رَأَيْتُمُوهُما فَادْعُوا اللَّهَ وَصَلُّوا حتَّى تَنْكَشِفَ)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وحُكم هذه الصلاة: سُنّةٌ إذا وقع سببها، وصفتها: أنْ يقرأ الفاتحةَ ويقرأ ما شاء من القرآن، ثم يركع، ثم يقومُ ويقرأ الفاتحةَ وما شاء من القرآن، ثم يركع، ثم يعتدل ثم يسجد، وهكذا يصنَعُ في الرَّكْعة الثانية، ثم يأتي ببقية الصلاة حتى يُسَلِّم. ويُسَنّ إطالة الصلاة حتى تزول الآية. ففي كل رَكْعَةٍ ركوعان وقراءتان.", "page": 278, "id": "unit-25__lesson-04__b07", "inline": [{"t": "emphasis", "s": "وحُكم هذه الصلاة", "role": "emphasis"}, {"t": "text", "s": ": سُنّةٌ إذا وقع سببها، "}, {"t": "emphasis", "s": "وصفتها", "role": "emphasis"}, {"t": "text", "s": ": أنْ يقرأ الفاتحةَ ويقرأ ما شاء من القرآن، ثم يركع، ثم يقومُ ويقرأ الفاتحةَ وما شاء من القرآن، ثم يركع، ثم يعتدل ثم يسجد، وهكذا يصنَعُ في الرَّكْعة الثانية، ثم يأتي ببقية الصلاة حتى يُسَلِّم. ويُسَنّ إطالة الصلاة حتى تزول الآية. ففي كل رَكْعَةٍ ركوعان وقراءتان."}]}, {"type": "paragraph", "md": "وتُسَنُّ جماعةً وجهريةً. ويُنادَى لها بقولهم: الصَّلاةَ جَامِعَةً. ويُسَنُّ لها الخطبة؛ يوعَظُ الناس بها لحديث عائشة رضي الله عنها : (فَخَطَبَ النَّاسَ، فَحَمِدَ اللَّهَ وأَثْنَى عَلَيْهِ، ثُمَّ قالَ...) الحديث.", "page": 278, "id": "unit-25__lesson-04__b08", "inline": [{"t": "text", "s": "وتُسَنُّ جماعةً وجهريةً. ويُنادَى لها بقولهم: الصَّلاةَ جَامِعَةً. ويُسَنُّ لها الخطبة؛ يوعَظُ الناس بها لحديث عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(فَخَطَبَ النَّاسَ، فَحَمِدَ اللَّهَ وأَثْنَى عَلَيْهِ، ثُمَّ قالَ...)", "role": "emphasis"}, {"t": "text", "s": " الحديث."}]}, {"type": "paragraph", "md": "وتُصَلَّى انفرادًا كذلك، لمطلق الحديث: (فَإِذَا رَأَيْتُمُوهُما فَادْعُوا اللَّهَ وَصَلُّوا)، وقد ثَبَتَ عن الصحابة صلاتها فُرادَى كما ثَبَت عن ابن عباسٍ رضي الله عنهما ، ويُصَلِّيها المسافر والمقيم.", "page": 278, "id": "unit-25__lesson-04__b09", "inline": [{"t": "text", "s": "وتُصَلَّى انفرادًا كذلك، لمطلق الحديث: "}, {"t": "emphasis", "s": "(فَإِذَا رَأَيْتُمُوهُما فَادْعُوا اللَّهَ وَصَلُّوا)", "role": "emphasis"}, {"t": "text", "s": "، وقد ثَبَتَ عن الصحابة صلاتها فُرادَى كما ثَبَت عن ابن عباسٍ "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " ، ويُصَلِّيها المسافر والمقيم."}]}, {"type": "paragraph", "md": "وتُسَنُّ الصلاة عند كل آية عظيمة كالزلزلة، قالها الشافعي رحمه الله ، ولم يُسْتَحب الاجتماع لغير الكسوفين، ولكن وقال الشافعي: صَلَّى عليٌّ رضي الله عنه في زلزلة جماعة، وقال: إنْ صَحَّ قُلتُ بهِ.", "page": 278, "id": "unit-25__lesson-04__b10", "inline": [{"t": "text", "s": "وتُسَنُّ الصلاة عند كل آية عظيمة كالزلزلة، قالها الشافعي "}, {"t": "honorific", "s": "رحمه الله"}, {"t": "text", "s": " ، ولم يُسْتَحب الاجتماع لغير الكسوفين، ولكن وقال الشافعي: صَلَّى عليٌّ "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " في زلزلة جماعة، وقال: إنْ صَحَّ قُلتُ بهِ."}]}, {"type": "paragraph", "md": "ويُسَنُّ الذكر والاستغفار والتوبة والتصدّق حال هذه الآية.", "page": 278, "id": "unit-25__lesson-04__b11"}, {"type": "paragraph", "md": "وإنْ أَدْرَكَ المأموم الإمام في الركوع الثاني، قال الشافعي: لم يَكُنْ مُدْرِكًا لتلك الرَّكْعة. وهذا مشهور المذهب. ولكن قال العمراني في البيان: كان مدركًا لتلك الركعة.", "page": 278, "id": "unit-25__lesson-04__b12"}, {"type": "heading", "level": 3, "text": "أحكام صلاة الاستسقاء:", "page": 279, "id": "unit-25__lesson-04__b13", "role": "rulings"}, {"type": "paragraph", "md": "الأصل فيها قوله تعالى: ﴿وَإِذِ ٱسۡتَسۡقَىٰ مُوسَىٰ لِقَوۡمِهِۦ﴾، وعن عائشة رضي الله عنها قالت: «شَكَى النَّاسُ إِلَى رَسُولِ اللَّهِ صلى الله عليه وسلم قُحُوطَ الْمَطَرِ فَأَمَرَ بِمِنْبَرٍ فَوُضِعَ لَهُ فِي الْمُصَلَّى وَوَعَدَ النَّاسَ يَوْمًا يَخْرُجُونَ فِيهِ قَالَتْ عَائِشَةُ فَخَرَجَ رَسُولُ اللَّهِ صلى الله عليه وسلم حِينَ بَدَا حَاجِبُ الشَّمْسِ فَقَعَدَ عَلَى الْمِنْبَرِ فَكَبَّرَ صلى الله عليه وسلم وَحَمِدَ اللَّهَ عز وجل ثُمَّ قَالَ: (إِنَّكُمْ شَكَوْتُمْ جَدْبَ دِيَارِكُمْ وَاسْتِئْخَارَ الْمَطَرِ عَنْ إِبَّانِ زَمَانِهِ عَنْكُمْ، وَقَدْ أَمَرَكُمُ اللَّهُ عز وجل أَنْ تَدْعُوهُ وَوَعَدَكُمْ أَنْ يَسْتَجِيبَ لَكُمْ. ثُمَّ قَالَ: ﴿ٱلۡحَمۡدُ لِلَّهِ رَبِّ ٱلۡعَٰلَمِينَ ۝٢ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ ۝٣ مَٰلِكِ يَوۡمِ ٱلدِّينِ۝٤﴾ لاَ إِلَهَ إِلاَّ اللَّهُ يَفْعَلُ مَا يُرِيدُ، اللَّهُمَّ أَنْتَ اللَّهُ لاَ إِلَهَ إِلاَّ أَنْتَ الْغَنِيُّ وَنَحْنُ الْفُقَرَاءُ، أَنْزِلْ عَلَيْنَا الْغَيْثَ وَاجْعَلْ مَا أَنْزَلْتَ لَنَا قُوَّةً وَبَلاَغًا إِلَى حِينٍ. ثُمَّ رَفَعَ يَدَيْهِ فَلَمْ يَزَلْ فِي الرَّفْعِ حَتَّى بَدَا بَيَاضُ إِبْطَيْهِ ثُمَّ حَوَّلَ عَلَى النَّاسِ ظَهْرَهُ وَقَلَّبَ أَوْ حَوَّلَ رِدَاءَهُ وَهُوَ رَافِعٌ يَدَيْهِ ثُمَّ أَقْبَلَ عَلَى النَّاسِ وَنَزَلَ فَصَلَّى رَكْعَتَيْنِ، فَأَنْشَأَ اللَّهُ سَحَابَةً فَرَعَدَتْ وَبَرَقَتْ ثُمَّ أَمْطَرَتْ بِإِذْنِ اللَّهِ فَلَمْ يَأْتِ مَسْجِدَهُ حَتَّى سَالَتِ السُّيُولُ، فَلَمَّا رَأَى سُرْعَتَهُمْ إِلَى الْكِنِّ ضَحِكَ صلى الله عليه وسلم حَتَّى بَدَتْ نَوَاجِذُهُ فَقَالَ: أَشْهَدُ أَنَّ اللَّهَ عَلَى كُلِّ شَىْءٍ قَدِيرٌ وَأَنِّي عَبْدُ اللَّهِ وَرَسُولُهُ)، وهو حديث جامعٌ لصفة صلاة الاستسقاء، ورد بعضه في البخاري وتتمته عند غيره.", "page": 279, "id": "unit-25__lesson-04__b14", "inline": [{"t": "text", "s": "الأصل فيها قوله تعالى: "}, {"t": "ayah", "s": "وَإِذِ ٱسۡتَسۡقَىٰ مُوسَىٰ لِقَوۡمِهِۦ", "ayah": [], "verses": [{"n": 60, "text": "وَإِذِ ٱسۡتَسۡقَىٰ مُوسَىٰ لِقَوۡمِهِۦ", "surah": 2, "surah_name": "البقرة", "ref": "2:60", "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:60"}], "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:60", "surah_name": "البقرة", "ayah_canonical": 60, "match": "contained", "ref": "2:60"}, {"t": "text", "s": "، وعن عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " قالت: «شَكَى النَّاسُ إِلَى رَسُولِ اللَّهِ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قُحُوطَ الْمَطَرِ فَأَمَرَ بِمِنْبَرٍ فَوُضِعَ لَهُ فِي الْمُصَلَّى وَوَعَدَ النَّاسَ يَوْمًا يَخْرُجُونَ فِيهِ قَالَتْ عَائِشَةُ فَخَرَجَ رَسُولُ اللَّهِ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " حِينَ بَدَا حَاجِبُ الشَّمْسِ فَقَعَدَ عَلَى الْمِنْبَرِ فَكَبَّرَ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وَحَمِدَ اللَّهَ "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ثُمَّ قَالَ: "}, {"t": "emphasis", "s": "(إِنَّكُمْ شَكَوْتُمْ جَدْبَ دِيَارِكُمْ وَاسْتِئْخَارَ الْمَطَرِ عَنْ إِبَّانِ زَمَانِهِ عَنْكُمْ، وَقَدْ أَمَرَكُمُ اللَّهُ", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " أَنْ تَدْعُوهُ وَوَعَدَكُمْ أَنْ يَسْتَجِيبَ لَكُمْ. ثُمَّ قَالَ: "}, {"t": "ayah", "s": "ٱلۡحَمۡدُ لِلَّهِ رَبِّ ٱلۡعَٰلَمِينَ ۝٢ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ ۝٣ مَٰلِكِ يَوۡمِ ٱلدِّينِ۝٤", "ayah": [2, 3, 4], "verses": [{"n": 2, "text": "ٱلۡحَمۡدُ لِلَّهِ رَبِّ ٱلۡعَٰلَمِينَ", "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:2", "surah_name": "الفاتحة", "ayah_canonical": 2, "match": "exact", "ref": "1:2"}, {"n": 3, "text": "ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ", "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:3", "surah_name": "الفاتحة", "ayah_canonical": 3, "match": "exact", "ref": "1:3"}, {"n": 4, "text": "مَٰلِكِ يَوۡمِ ٱلدِّينِ", "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:4", "surah_name": "الفاتحة", "ayah_canonical": 4, "match": "exact", "ref": "1:4"}], "surah": null, "ref_api": null}, {"t": "text", "s": " لاَ إِلَهَ إِلاَّ اللَّهُ يَفْعَلُ مَا يُرِيدُ، اللَّهُمَّ أَنْتَ اللَّهُ لاَ إِلَهَ إِلاَّ أَنْتَ الْغَنِيُّ وَنَحْنُ الْفُقَرَاءُ، أَنْزِلْ عَلَيْنَا الْغَيْثَ وَاجْعَلْ مَا أَنْزَلْتَ لَنَا قُوَّةً وَبَلاَغًا إِلَى حِينٍ. ثُمَّ رَفَعَ يَدَيْهِ فَلَمْ يَزَلْ فِي الرَّفْعِ حَتَّى بَدَا بَيَاضُ إِبْطَيْهِ ثُمَّ حَوَّلَ عَلَى النَّاسِ ظَهْرَهُ وَقَلَّبَ أَوْ حَوَّلَ رِدَاءَهُ وَهُوَ رَافِعٌ يَدَيْهِ ثُمَّ أَقْبَلَ عَلَى النَّاسِ وَنَزَلَ فَصَلَّى رَكْعَتَيْنِ، فَأَنْشَأَ اللَّهُ سَحَابَةً فَرَعَدَتْ وَبَرَقَتْ ثُمَّ أَمْطَرَتْ بِإِذْنِ اللَّهِ فَلَمْ يَأْتِ مَسْجِدَهُ حَتَّى سَالَتِ السُّيُولُ، فَلَمَّا رَأَى سُرْعَتَهُمْ إِلَى الْكِنِّ ضَحِكَ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "حَتَّى بَدَتْ نَوَاجِذُهُ فَقَالَ: أَشْهَدُ أَنَّ اللَّهَ عَلَى كُلِّ شَىْءٍ قَدِيرٌ وَأَنِّي عَبْدُ اللَّهِ وَرَسُولُهُ)", "role": "emphasis"}, {"t": "text", "s": "، وهو حديث جامعٌ لصفة صلاة الاستسقاء، ورد بعضه في البخاري وتتمته عند غيره."}]}, {"type": "paragraph", "md": "وتُسَنُّ عند حصول الجَدْب وانقِطَاع المطر، وهي مُسْتَحَبَّةٌ. وهي كصلاة العيد. ومن سُنَنها أيضًا:", "page": 279, "id": "unit-25__lesson-04__b15", "inline": [{"t": "emphasis", "s": "وتُسَنُّ عند حصول الجَدْب وانقِطَاع المطر", "role": "emphasis"}, {"t": "text", "s": "، وهي مُسْتَحَبَّةٌ. وهي كصلاة العيد. ومن سُنَنها أيضًا:"}]}, {"type": "paragraph", "md": "1- قَلْبُ الرِّدَاءِ: فقد خرج صلى الله عليه وسلم إِلَى الْمُصَلَّى فَاسْتَسْقَى؛ فَاسْتَقْبَلَ الْقِبْلَةَ، وَقَلَبَ رِدَاءَهُ، وَصَلَّى رَكْعَتَيْنِ.", "page": 279, "id": "unit-25__lesson-04__b16", "inline": [{"t": "text", "s": "1- قَلْبُ الرِّدَاءِ: فقد خرج "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " إِلَى الْمُصَلَّى فَاسْتَسْقَى؛ فَاسْتَقْبَلَ الْقِبْلَةَ، وَقَلَبَ رِدَاءَهُ، وَصَلَّى رَكْعَتَيْنِ."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- جَعْلُ ظاهر الكَفَّيْن مما يلي وَجْهَهُ؛ قال أنس رضي الله عنه : «اسْتَسْقَى النَّبِيَّ صلى الله عليه وسلم فَأَشَارَ بِظَهْرِ كَفَّيْهِ إِلَى السَّمَاءِ».", "page": 279, "id": "unit-25__lesson-04__b17", "inline": [{"t": "text", "s": "2- جَعْلُ ظاهر الكَفَّيْن مما يلي وَجْهَهُ؛ قال أنس "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " : "}, {"t": "quote", "s": "اسْتَسْقَى النَّبِيَّ صلى الله عليه وسلم فَأَشَارَ بِظَهْرِ كَفَّيْهِ إِلَى السَّمَاءِ", "speaker": "أنس رضي الله عنه"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- ولا يؤذَّنُ لها ولا يقيم؛ بل يُنادى: الصلاة جامعة، فقط.", "page": 279, "id": "unit-25__lesson-04__b18", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- ويخرج الناس متبذلين متواضعين؛ فعن ابن عباس رضي الله عنهما : «إِنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم خَرَجَ مُتَبَذِّلًا مُتَوَاضِعًا مُتَضَرِّعًا حَتَّى أَتَى الْمُصَلَّى فَلَمْ يَخْطُبْ خُطْبَتَكُمْ هَذِهِ وَلَكِنْ لَمْ يَزَلْ فِي الدُّعَاءِ وَالتَّضَرُّعِ وَالتَّكْبِيرِ وَصَلَّى رَكْعَتَيْنِ كَمَا كَانَ يُصَلِّي فِي الْعِيدِ».", "page": 279, "id": "unit-25__lesson-04__b19", "inline": [{"t": "text", "s": "4- ويخرج الناس متبذلين متواضعين؛ فعن ابن عباس "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " : "}, {"t": "quote", "s": "إِنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم خَرَجَ مُتَبَذِّلًا مُتَوَاضِعًا مُتَضَرِّعًا حَتَّى أَتَى الْمُصَلَّى فَلَمْ يَخْطُبْ خُطْبَتَكُمْ هَذِهِ وَلَكِنْ لَمْ يَزَلْ فِي الدُّعَاءِ وَالتَّضَرُّعِ وَالتَّكْبِيرِ وَصَلَّى رَكْعَتَيْنِ كَمَا كَانَ يُصَلِّي فِي الْعِيدِ"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 279, "id": "unit-25__lesson-04__b20", "role": "assessment"}, {"type": "paragraph", "md": "1- اذكر صفة صلاة الاستسقاء، وصفة صلاة الكسوفين كما تعلمتها في الدرس.", "page": 279, "id": "unit-25__lesson-04__b21", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- هل تُشرع صلاة الاستسقاء والكسوفين سرا أم جهرا؟ بين ذلك تفصيلا..", "page": 279, "id": "unit-25__lesson-04__b22", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط إثرائي حواري", "page": 279, "id": "unit-25__lesson-04__b23", "role": "activity"}, {"type": "paragraph", "md": "نتعلم أداء صلاة الكسوفين والاستسقاء، ونذكر أنفسنا بأدائهما عند مجيء سببهما المشروع", "page": 279, "id": "unit-25__lesson-04__b24", "item_role": "activity_step"}]' WHERE id='unit-25__lesson-04';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-25__lesson-05','unit-25',5,'الثبات على الدين','الأخلاق والآداب',NULL,2,5,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "(يا مقلب القلوب ثبت قلبي على دينك)!", "page": 280, "id": "unit-25__lesson-05__b01", "role": "section"}, {"type": "paragraph", "md": "كثيرًا ما نجد شبابًا يحنُّون إلى البدايات التي كانوا يتفجَّرون فيها حيوية، ويتدفقون حماسًا، ويبالغون في الحرص على دقائق السنن؛ ناهيك عن البعد عن دائرة الحرام والشبهات، ثم ماذا؟ كلَّت النفوس، وفترت الهمم، واكتفى كل شاب بأن يكون واحدًا من عامة المسلمين، وهذا أحسن حالًا ممن انقلبوا على أعقابهم؛ فغَدوا يعادون الدعوة ويسخرون من أهلها ويحذرون من سبيلها.. إنها معركة تقرير المصير بين الارتداد على الأعقاب والثبات.. ونعني بالثبات: الاستمرار في طريق الهداية، والالتزام بمقتضيات هذا الطريق، والمدوامة على الخير، والسعي الدائم للاستزادة، ومهما فتر المرء؛ فهنالك مستوى معين لا يقبل التنازل عنه أو التقصير فيه، وإن زلت قدمه فلا يلبث أن يتوب، وربما كان بعد التوبة خيرًا مما كان قبلها، ذلك هو حال المتصف بخلق الثبات.", "page": 280, "id": "unit-25__lesson-05__b02", "inline": [{"t": "text", "s": "كثيرًا ما نجد شبابًا يحنُّون إلى البدايات التي كانوا يتفجَّرون فيها حيوية، ويتدفقون حماسًا، ويبالغون في الحرص على دقائق السنن؛ ناهيك عن البعد عن دائرة الحرام والشبهات، ثم ماذا؟ كلَّت النفوس، وفترت الهمم، واكتفى كل شاب بأن يكون واحدًا من عامة المسلمين، وهذا أحسن حالًا ممن انقلبوا على أعقابهم؛ فغَدوا يعادون الدعوة ويسخرون من أهلها ويحذرون من سبيلها.. إنها معركة تقرير المصير بين الارتداد على الأعقاب والثبات.. و"}, {"t": "emphasis", "s": "نعني بالثبات", "role": "emphasis"}, {"t": "text", "s": ": الاستمرار في طريق الهداية، والالتزام بمقتضيات هذا الطريق، والمدوامة على الخير، والسعي الدائم للاستزادة، ومهما فتر المرء؛ فهنالك مستوى معين لا يقبل التنازل عنه أو التقصير فيه، وإن زلت قدمه فلا يلبث أن يتوب، وربما كان بعد التوبة خيرًا مما كان قبلها، ذلك هو حال المتصف بخلق الثبات."}]}, {"type": "paragraph", "md": "وللثبات صور تشمل عددا من جوانب حياة المسلم؛ منها الثبات في المعركة كما ثبت الربيون الكثير مع أنبيائهم، وكان قولهم ﴿رَبَّنَا ٱغۡفِرۡ لَنَا ذُنُوبَنَا وَإِسۡرَافَنَا فِيٓ أَمۡرِنَا وَثَبِّتۡ أَقۡدَامَنَا﴾، والفئة الصابرة بإمرة طالوت الذين قال الله فيهم ﴿وَلَمَّا بَرَزُواْ لِجَالُوتَ وَجُنُودِهِۦ قَالُواْ رَبَّنَآ أَفۡرِغۡ عَلَيۡنَا صَبۡرٗا وَثَبِّتۡ أَقۡدَامَنَا﴾ وفي ذلك توجيه للمؤمن أن يلتجئ إلى الله طالبًا منه التثبيت، وخُوطِب أبناءُ هذه الأمة بأمر الله تعالى: ﴿يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ إِذَا لَقِيتُمۡ فِئَةٗ فَٱثۡبُتُواْ﴾، ومن الكبائر في ديننا الفرار من الزحف؛ ولذلك كان من الوصايا العشر التي أوصى بها رسول الله صلى الله عليه وسلم معاذ بن جبل: (وإيَّاك والفرار من الزحف وإن هلك الناس، وإذا أصاب الناس مُوتانٌ وأنت فيهم فاثبُتْ)؛ لأن الثبات يزيد المؤمنين قوة، ويوقع في نفوس العدو رهبة، وتزعزعُ المواقف يخذل الصديق ويُشمِّت العدو، وقد كان رسول الله صلى الله عليه وسلم يعمق هذا المعنى يوم الأحزاب وهو ينقل التراب وقد وارى التراب بطنه وهو يقول: (لولا أنت ما اهتدينا، ولا تصدَّقْنا ولا صلَّينا، فأنزل السكينة علينا، وثبِّت الأقدام إن لاقينا..).", "page": 280, "id": "unit-25__lesson-05__b03", "inline": [{"t": "emphasis", "s": "وللثبات صور تشمل عددا من جوانب حياة المسلم؛", "role": "emphasis"}, {"t": "text", "s": " منها الثبات في المعركة كما ثبت الربيون الكثير مع أنبيائهم، وكان قولهم "}, {"t": "ayah", "s": "رَبَّنَا ٱغۡفِرۡ لَنَا ذُنُوبَنَا وَإِسۡرَافَنَا فِيٓ أَمۡرِنَا وَثَبِّتۡ أَقۡدَامَنَا", "ayah": [], "verses": [{"n": 147, "text": "رَبَّنَا ٱغۡفِرۡ لَنَا ذُنُوبَنَا وَإِسۡرَافَنَا فِيٓ أَمۡرِنَا وَثَبِّتۡ أَقۡدَامَنَا", "surah": 3, "surah_name": "آل عمران", "ref": "3:147", "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:147"}], "surah": 3, "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:147", "surah_name": "آل عمران", "ayah_canonical": 147, "match": "contained", "ref": "3:147"}, {"t": "text", "s": "، والفئة الصابرة بإمرة طالوت الذين قال الله فيهم "}, {"t": "ayah", "s": "وَلَمَّا بَرَزُواْ لِجَالُوتَ وَجُنُودِهِۦ قَالُواْ رَبَّنَآ أَفۡرِغۡ عَلَيۡنَا صَبۡرٗا وَثَبِّتۡ أَقۡدَامَنَا", "ayah": [], "verses": [{"n": 250, "text": "وَلَمَّا بَرَزُواْ لِجَالُوتَ وَجُنُودِهِۦ قَالُواْ رَبَّنَآ أَفۡرِغۡ عَلَيۡنَا صَبۡرٗا وَثَبِّتۡ أَقۡدَامَنَا", "surah": 2, "surah_name": "البقرة", "ref": "2:250", "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:250"}], "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:250", "surah_name": "البقرة", "ayah_canonical": 250, "match": "contained", "ref": "2:250"}, {"t": "text", "s": " وفي ذلك توجيه للمؤمن أن يلتجئ إلى الله طالبًا منه التثبيت، وخُوطِب أبناءُ هذه الأمة بأمر الله تعالى: "}, {"t": "ayah", "s": "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ إِذَا لَقِيتُمۡ فِئَةٗ فَٱثۡبُتُواْ", "ayah": [], "verses": [{"n": 45, "text": "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓاْ إِذَا لَقِيتُمۡ فِئَةٗ فَٱثۡبُتُواْ", "surah": 8, "surah_name": "الأنفال", "ref": "8:45", "ref_api": "https://api.quran.com/api/v4/verses/by_key/8:45"}], "surah": 8, "ref_api": "https://api.quran.com/api/v4/verses/by_key/8:45", "surah_name": "الأنفال", "ayah_canonical": 45, "match": "contained", "ref": "8:45"}, {"t": "text", "s": "، ومن الكبائر في ديننا الفرار من الزحف؛ ولذلك كان من الوصايا العشر التي أوصى بها رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " معاذ بن جبل: "}, {"t": "emphasis", "s": "(وإيَّاك والفرار من الزحف وإن هلك الناس، وإذا أصاب الناس مُوتانٌ وأنت فيهم فاثبُتْ)", "role": "emphasis"}, {"t": "text", "s": "؛ لأن الثبات يزيد المؤمنين قوة، ويوقع في نفوس العدو رهبة، وتزعزعُ المواقف يخذل الصديق ويُشمِّت العدو، وقد كان رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يعمق هذا المعنى يوم الأحزاب وهو ينقل التراب وقد وارى التراب بطنه وهو يقول: "}, {"t": "emphasis", "s": "(لولا أنت ما اهتدينا، ولا تصدَّقْنا ولا صلَّينا، فأنزل السكينة علينا، وثبِّت الأقدام إن لاقينا..)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ولأن مسألة الثبات على الدين قضية تشغل فكر المسلم فإنه يكثر من الدعاء بها، فقد كان رسول الله صلى الله عليه وسلم يكثر من قول: (يا مقلب القلوب ثبت قلبي على دينك)، وقد كان رسول الله صلى الله عليه وسلم يخشى على نفسه في مواجهة الجاهلية أن يداهن أو يلين، ولذلك خاطبه ربنا عز وجل بفضله عليه بأن أخلص ولاءه لله: ﴿وَلَوۡلَآ أَن ثَبَّتۡنَٰكَ لَقَدۡ كِدتَّ تَرۡكَنُ إِلَيۡهِمۡ شَيۡـٔٗا قَلِيلًا ۝٧٤ إِذٗا لَّأَذَقۡنَٰكَ ضِعۡفَ ٱلۡحَيَوٰةِ وَضِعۡفَ ٱلۡمَمَاتِ﴾.", "page": 281, "id": "unit-25__lesson-05__b04", "inline": [{"t": "text", "s": "ولأن مسألة الثبات على الدين قضية تشغل فكر المسلم فإنه يكثر من الدعاء بها، فقد كان رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يكثر من قول: "}, {"t": "emphasis", "s": "(يا مقلب القلوب ثبت قلبي على دينك)", "role": "emphasis"}, {"t": "text", "s": "، وقد كان رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يخشى على نفسه في مواجهة الجاهلية أن يداهن أو يلين، ولذلك خاطبه ربنا "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " بفضله عليه بأن أخلص ولاءه لله: "}, {"t": "ayah", "s": "وَلَوۡلَآ أَن ثَبَّتۡنَٰكَ لَقَدۡ كِدتَّ تَرۡكَنُ إِلَيۡهِمۡ شَيۡـٔٗا قَلِيلًا ۝٧٤ إِذٗا لَّأَذَقۡنَٰكَ ضِعۡفَ ٱلۡحَيَوٰةِ وَضِعۡفَ ٱلۡمَمَاتِ", "ayah": [74], "verses": [{"n": 74, "text": "وَلَوۡلَآ أَن ثَبَّتۡنَٰكَ لَقَدۡ كِدتَّ تَرۡكَنُ إِلَيۡهِمۡ شَيۡـٔٗا قَلِيلًا", "surah": 17, "ref_api": "https://api.quran.com/api/v4/verses/by_key/17:74", "surah_name": "الإسراء", "ayah_canonical": 74, "match": "exact", "ref": "17:74"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "فليحذر الدعاة وهم يواجهون الطغاة من زلزلة الأقدام وزعزعة الولاء؛ فقد حذَّر حذيفةُ العلماءَ العبادَ لأنهم قدوة، فقال: «يا معشر القراء استقيموا، فإن أخذتُم يمينًا وشمالًا لقد ضللتم ضلالًا بعيدًا»، ولو أن ضلال المتذبذب يمينًا وشمالًا يقتصر عليه لهان الأمر، ولكن يفتن بضلاله آخرون.", "page": 281, "id": "unit-25__lesson-05__b05", "inline": [{"t": "text", "s": "فليحذر الدعاة وهم يواجهون الطغاة من زلزلة الأقدام وزعزعة الولاء؛ فقد حذَّر حذيفةُ العلماءَ العبادَ لأنهم قدوة، فقال: "}, {"t": "quote", "s": "يا معشر القراء استقيموا، فإن أخذتُم يمينًا وشمالًا لقد ضللتم ضلالًا بعيدًا"}, {"t": "text", "s": "، ولو أن ضلال المتذبذب يمينًا وشمالًا يقتصر عليه لهان الأمر، ولكن يفتن بضلاله آخرون."}]}, {"type": "paragraph", "md": "وقد كان من وسائل أهل الكتاب في زعزعة صفوف المسلمين أن يتظاهروا بالدخول في الإسلام، ثم يرتدون ليرتد معهم آخرون ﴿وَقَالَت طَّآئِفَةٞ مِّنۡ أَهۡلِ ٱلۡكِتَٰبِ ءَامِنُواْ بِٱلَّذِيٓ أُنزِلَ عَلَى ٱلَّذِينَ ءَامَنُواْ وَجۡهَ ٱلنَّهَارِ وَٱكۡفُرُوٓاْ ءَاخِرَهُۥ لَعَلَّهُمۡ يَرۡجِعُونَ ۝٧٢﴾؛ فالسعيد مَن وفقه الله للثبات، وختم له بخير ومات وهو يعمل عمل أهل الجنة إلى أن يرزقه الله التثبيت حين يسأل.", "page": 281, "id": "unit-25__lesson-05__b06", "inline": [{"t": "text", "s": "وقد كان من وسائل أهل الكتاب في زعزعة صفوف المسلمين أن يتظاهروا بالدخول في الإسلام، ثم يرتدون ليرتد معهم آخرون "}, {"t": "ayah", "s": "وَقَالَت طَّآئِفَةٞ مِّنۡ أَهۡلِ ٱلۡكِتَٰبِ ءَامِنُواْ بِٱلَّذِيٓ أُنزِلَ عَلَى ٱلَّذِينَ ءَامَنُواْ وَجۡهَ ٱلنَّهَارِ وَٱكۡفُرُوٓاْ ءَاخِرَهُۥ لَعَلَّهُمۡ يَرۡجِعُونَ ۝٧٢", "ayah": [72], "verses": [{"n": 72, "text": "وَقَالَت طَّآئِفَةٞ مِّنۡ أَهۡلِ ٱلۡكِتَٰبِ ءَامِنُواْ بِٱلَّذِيٓ أُنزِلَ عَلَى ٱلَّذِينَ ءَامَنُواْ وَجۡهَ ٱلنَّهَارِ وَٱكۡفُرُوٓاْ ءَاخِرَهُۥ لَعَلَّهُمۡ يَرۡجِعُونَ", "surah": 3, "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:72", "surah_name": "آل عمران", "ayah_canonical": 72, "match": "exact", "ref": "3:72"}], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ فالسعيد مَن وفقه الله للثبات، وختم له بخير ومات وهو يعمل عمل أهل الجنة إلى أن يرزقه الله التثبيت حين يسأل."}]}, {"type": "paragraph", "md": "ولو تأملت في أحاديث الحوض من صحيح مسلم لوجدت أناسًا مُنعوا منه ورسول الله صلى الله عليه وسلم يقول: (يا رب أصحابي، فيقال: إنك لا تدري ما أحدثوا بعدك)، فيدعو عليهم رسول الله: (سحقًا سحقًا لمن غير بعدي)، وفي رواية أخرى يقال له: (والله ما برحوا يرجعون على أعقابهم)، فكان ابن أبي مُلَيكة -أحد رواة هذا الحديث- يقول: (اللهم إنا نعوذ بك أن نرجع على أعقابنا أو نفتن عن ديننا)، وكلمة (ما برحوا يرجعون) توحي بالتراجع البطيء المتواصل المؤدي إلى الهاوية. وربما يصعب الرجوع بعد طول الاستدراج؛ فهنيئًا لمن استدرك نفسه لئلا تزل قدمه بعد ثبوتها.", "page": 281, "id": "unit-25__lesson-05__b07", "inline": [{"t": "text", "s": "ولو تأملت في أحاديث الحوض من صحيح مسلم لوجدت أناسًا مُنعوا منه ورسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يقول: "}, {"t": "emphasis", "s": "(يا رب أصحابي، فيقال: إنك لا تدري ما أحدثوا بعدك)", "role": "emphasis"}, {"t": "text", "s": "، فيدعو عليهم رسول الله: "}, {"t": "emphasis", "s": "(سحقًا سحقًا لمن غير بعدي)", "role": "emphasis"}, {"t": "text", "s": "، وفي رواية أخرى يقال له: "}, {"t": "emphasis", "s": "(والله ما برحوا يرجعون على أعقابهم)", "role": "emphasis"}, {"t": "text", "s": "، فكان ابن أبي مُلَيكة -أحد رواة هذا الحديث- يقول: "}, {"t": "emphasis", "s": "(اللهم إنا نعوذ بك أن نرجع على أعقابنا أو نفتن عن ديننا)", "role": "emphasis"}, {"t": "text", "s": "، وكلمة "}, {"t": "emphasis", "s": "(ما برحوا يرجعون)", "role": "emphasis"}, {"t": "text", "s": " توحي بالتراجع البطيء المتواصل المؤدي إلى الهاوية. وربما يصعب الرجوع بعد طول الاستدراج؛ فهنيئًا لمن استدرك نفسه لئلا تزل قدمه بعد ثبوتها."}]}, {"type": "paragraph", "md": "وكان من دعاء عبد الله بن مسعود: «اللهم إني أسألك إيمانًا لا يرتد، ونعيمًا لا ينفد»، وقال شدَّاد بن أَوْسٍ: «كان النبي صلى الله عليه وسلم يُعلِّمنا كلمات ندعو بهن في صلاتنا: اللهم إني أسألك الثبات في الأمر، وعزيمة الرشد».", "page": 281, "id": "unit-25__lesson-05__b08", "inline": [{"t": "text", "s": "وكان من دعاء عبد الله بن مسعود: "}, {"t": "quote", "s": "اللهم إني أسألك إيمانًا لا يرتد، ونعيمًا لا ينفد"}, {"t": "text", "s": "، وقال شدَّاد بن أَوْسٍ: "}, {"t": "quote", "s": "كان النبي صلى الله عليه وسلم يُعلِّمنا كلمات ندعو بهن في صلاتنا: اللهم إني أسألك الثبات في الأمر، وعزيمة الرشد", "speaker": "شداد بن أوس"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ومن صور الثبات في الفتن: الصبر في أيام الصبر التي وصفها رسول الله صلى الله عليه وسلم بقوله: (الصبر فيهن مثل القبض على الجمر)، وفي رواية: (يأتي على الناس زمانٌ الصابر فيه على دينه، كالقابض على الجمر)، ومن ذا الذي يُثَبِّت قابضًا على الجمر؟! لذلك بشَّر رسول الله صلى الله عليه وسلم بأن الثابت من هؤلاء له أجرُ خمسين من الصحابة: (إن من ورائكم أيام الصبر، للمتمسك فيهن يومئذٍ بما أنتم عليه أجر خمسين منكم).", "page": 281, "id": "unit-25__lesson-05__b09", "inline": [{"t": "emphasis", "s": "ومن صور الثبات في الفتن", "role": "emphasis"}, {"t": "text", "s": ": الصبر في أيام الصبر التي وصفها رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بقوله: "}, {"t": "emphasis", "s": "(الصبر فيهن مثل القبض على الجمر)", "role": "emphasis"}, {"t": "text", "s": "، وفي رواية: "}, {"t": "emphasis", "s": "(يأتي على الناس زمانٌ الصابر فيه على دينه، كالقابض على الجمر)", "role": "emphasis"}, {"t": "text", "s": "، ومن ذا الذي يُثَبِّت قابضًا على الجمر؟! لذلك بشَّر رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بأن الثابت من هؤلاء له أجرُ خمسين من الصحابة: "}, {"t": "emphasis", "s": "(إن من ورائكم أيام الصبر، للمتمسك فيهن يومئذٍ بما أنتم عليه أجر خمسين منكم)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وفي أشد ما يلقاه المسلمون من الفتن حين يخرج الدجال ويعيث يمينًا وشمالًا؛ كانت الوصية الأساسية لرسول الله صلى الله عليه وسلم التي أوصى بها أمته حينئذٍ: (يا عباد الله، اثبتوا).", "page": 281, "id": "unit-25__lesson-05__b10", "inline": [{"t": "text", "s": "وفي أشد ما يلقاه المسلمون من الفتن حين يخرج الدجال ويعيث يمينًا وشمالًا؛ كانت الوصية الأساسية لرسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " التي أوصى بها أمته حينئذٍ: "}, {"t": "emphasis", "s": "(يا عباد الله، اثبتوا)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ومن أهم عوامل الثبات: المداومة على الطاعات؛ فالمطلوب في بعضها المثابرة عليها، يروي الترمذي: (مَن ثابر ثنتَي عشرة ركعة من السُّنة بنَى الله له بيتًا في الجنة)، وعند مسلم تقولُ أم حبيبة راوية الحديث، ويقول كلٌّ من عمرو بن أوس والنعمان بن ثابت -من رجال السند-: «ما تركتهن منذ سمعتهن».", "page": 282, "id": "unit-25__lesson-05__b11", "inline": [{"t": "emphasis", "s": "ومن أهم عوامل الثبات", "role": "emphasis"}, {"t": "text", "s": ": المداومة على الطاعات؛ فالمطلوب في بعضها المثابرة عليها، يروي الترمذي: "}, {"t": "emphasis", "s": "(مَن ثابر ثنتَي عشرة ركعة من السُّنة بنَى الله له بيتًا في الجنة)", "role": "emphasis"}, {"t": "text", "s": "، وعند مسلم تقولُ أم حبيبة راوية الحديث، ويقول كلٌّ من عمرو بن أوس والنعمان بن ثابت -من رجال السند-: "}, {"t": "quote", "s": "ما تركتهن منذ سمعتهن"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وتقول عائشة رضي الله عنها عن رسول الله صلى الله عليه وسلم : (وكان أحب الدين إليه ما داوم عليه صاحبه)، وعند مسلم كذلك: «وكانت عائشة إذا عملت العمل لزمته»، وحين سئل رسول الله صلى الله عليه وسلم : أي العمل أحب الى الله؟ قال: (أدومه وإن قل)، (وكان آل محمد صلى الله عليه وسلم إذا عملوا عملًا أثبتوه)؛ يقول النووي: «أي لازموه وداوموا عليه».", "page": 282, "id": "unit-25__lesson-05__b12", "inline": [{"t": "text", "s": "وتقول عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " عن رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(وكان أحب الدين إليه ما داوم عليه صاحبه)", "role": "emphasis"}, {"t": "text", "s": "، وعند مسلم كذلك: "}, {"t": "hadith", "s": "وكانت عائشة إذا عملت العمل لزمته", "narrator": "رسول الله", "source": "مسلم", "confidence": "high", "ref_api": null}, {"t": "text", "s": "، وحين سئل رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : أي العمل أحب الى الله؟ قال: "}, {"t": "emphasis", "s": "(أدومه وإن قل)", "role": "emphasis"}, {"t": "text", "s": "، "}, {"t": "emphasis", "s": "(وكان آل محمد", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "إذا عملوا عملًا أثبتوه)", "role": "emphasis"}, {"t": "text", "s": "؛ يقول النووي: "}, {"t": "hadith", "s": "أي لازموه وداوموا عليه", "narrator": "رسول الله", "source": "مسلم", "confidence": "high", "ref_api": null}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "والثبات مظهر بارز للاستقامة؛ لأن المذبذب المتقلِّب لا يقدر على الثبات، ولا يقوى على الاستقامة، فقد كان الواحد من الصحابة يقول: يا رسول الله، حدِّثني بعملٍ أستقيم عليه وأعمله، فأجابه بأوجب الواجبات وقتها: (عليك بالهجرة فإنه لا مثل لها).", "page": 282, "id": "unit-25__lesson-05__b13", "inline": [{"t": "text", "s": "والثبات مظهر بارز للاستقامة؛ لأن المذبذب المتقلِّب لا يقدر على الثبات، ولا يقوى على الاستقامة، فقد كان الواحد من الصحابة يقول: يا رسول الله، حدِّثني بعملٍ أستقيم عليه وأعمله، فأجابه بأوجب الواجبات وقتها: "}, {"t": "emphasis", "s": "(عليك بالهجرة فإنه لا مثل لها)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وكان من دقيق ملاحظة الصحابة لظاهرة الثبات في سلوك كل فرد أن بريدة بن الحصيب لقي سلمة بن الأكوع قادمًا من البادية؛ فظن أنه قطع هجرته إلى المدينة وأقام خارجها، فقال له: «ارتددتَ عن هجرتك يا سليمة؟! فقال مسلمة: معاذ الله إني في إذنٍ من رسول الله صلى الله عليه وسلم ».", "page": 282, "id": "unit-25__lesson-05__b14", "inline": [{"t": "text", "s": "وكان من دقيق ملاحظة الصحابة لظاهرة الثبات في سلوك كل فرد أن بريدة بن الحصيب لقي سلمة بن الأكوع قادمًا من البادية؛ فظن أنه قطع هجرته إلى المدينة وأقام خارجها، فقال له: "}, {"t": "quote", "s": "ارتددتَ عن هجرتك يا سليمة؟! فقال مسلمة: معاذ الله إني في إذنٍ من رسول الله صلى الله عليه وسلم"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ومن الملعونين على لسان رسول الله صلى الله عليه وسلم : (المرتد أعرابيًّا بعد هجرته)، هذه صورة الجيل الفريد كيف يحرِص على الثبات ويتواصى به، ويخشى الانقلاب على الأعقاب، وإلى عام (حجة الوداع) والرسول صلى الله عليه وسلم يدعو للصحابة بالثبات على هجرتهم إلى المدينة لتقوى بهم الدولة الناشئة: (اللهم أمضِ لأصحابي هجرتهم، ولا تردَّهم على أعقابهم).", "page": 282, "id": "unit-25__lesson-05__b15", "inline": [{"t": "text", "s": "ومن الملعونين على لسان رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(المرتد أعرابيًّا بعد هجرته)", "role": "emphasis"}, {"t": "text", "s": "، هذه صورة الجيل الفريد كيف يحرِص على الثبات ويتواصى به، ويخشى الانقلاب على الأعقاب، وإلى عام "}, {"t": "emphasis", "s": "(حجة الوداع)", "role": "emphasis"}, {"t": "text", "s": " والرسول "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يدعو للصحابة بالثبات على هجرتهم إلى المدينة لتقوى بهم الدولة الناشئة: "}, {"t": "emphasis", "s": "(اللهم أمضِ لأصحابي هجرتهم، ولا تردَّهم على أعقابهم)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "والخلاصة: أنَّ القول الجامع لرسول الله صلى الله عليه وسلم في بيان حقيقة الإسلام: إيمان وثبات؛ فقد سأله أحد الصحابة: قُل لي في الإسلام قولًا لا أسال عنه أحدًا بعدك، فقال: (قل آمنتُ بالله ثم استقم).", "page": 282, "id": "unit-25__lesson-05__b16", "inline": [{"t": "emphasis", "s": "والخلاصة:", "role": "emphasis"}, {"t": "text", "s": " أنَّ القول الجامع لرسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " في بيان حقيقة الإسلام: إيمان وثبات؛ فقد سأله أحد الصحابة: قُل لي في الإسلام قولًا لا أسال عنه أحدًا بعدك، فقال: "}, {"t": "emphasis", "s": "(قل آمنتُ بالله ثم استقم)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 282, "id": "unit-25__lesson-05__b17", "role": "assessment"}, {"type": "paragraph", "md": "1- ما معنى الثبات؟ عدد بعض الوسائل المعينة عليه.", "page": 282, "id": "unit-25__lesson-05__b18", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- اذكر ثلاثة أدعية معلقة بالثبات.", "page": 282, "id": "unit-25__lesson-05__b19", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط سماعي إثرائي", "page": 282, "id": "unit-25__lesson-05__b20", "role": "activity"}, {"type": "paragraph", "md": "نستمع إلى محاضرة «وسائل الثبات على الدين» للشيخ محمد صالح المنجد، ونذكر فوائدها", "page": 282, "id": "unit-25__lesson-05__b21", "inline": [{"t": "text", "s": "نستمع إلى محاضرة "}, {"t": "quote", "s": "وسائل الثبات على الدين"}, {"t": "text", "s": " للشيخ محمد صالح المنجد، ونذكر فوائدها"}], "item_role": "activity_step"}]' WHERE id='unit-25__lesson-05';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-01','unit-26',1,'1- يا بِنتي','الأسرة والمرأة',NULL,0,0,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "للشيخ الأديب: عليّ الطنطاوي", "page": 286, "id": "unit-26__lesson-01__b01", "role": "section"}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 286, "id": "unit-26__lesson-01__b02", "role": "objectives"}, {"type": "paragraph", "md": "1- إسداء نصيحة أولية للفتاة والمرأة المسلمة.", "page": 286, "id": "unit-26__lesson-01__b03", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- التعرف على الشيخ علي الطنطاوي الأديب الفقيه الدمشقي.", "page": 286, "id": "unit-26__lesson-01__b04", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "يا بنتي!", "page": 286, "id": "unit-26__lesson-01__b05", "role": "section"}, {"type": "paragraph", "md": "أنا رجل يمشي إلى الخمسين، قد فارق الشباب وودّع أحلامَه وأوهامَه، ثم إني سِحْتُ في البلدان ولقيت الناس وخَبِرتُ الدنيا، فاسمعي مني كلمة صحيحة صريحة من سني وتجاربي لم تسمعيها من غيري.", "page": 286, "id": "unit-26__lesson-01__b06"}, {"type": "paragraph", "md": "لقد كتبنا ونادينا ندعو إلى تقويم الأخلاق ومحو الفساد وقهر الشهوات، حتى كَلَّتْ منّا الأقلامُ ومَلَّت الألسنة، وما صنعنا شيئًا ولا أزلنا منكرًا، بل إن المنكرات لتزداد والفساد ينتشر، والسفور والحسور والتكشف تقوى شِرَّته وتتسع رقعته، ويمتد من بلد إلى بلد، حتى لم يبقَ بلد إسلامي -فيما أحسب- في نَجْوَة منه. حتى الشام التي كانت فيها الملاءة السابغة، وفيها الغلوّ في حفظ الأعراض وستر العورات، قد خرج نساؤها سافرات حاسرات كاشفات السواعد والنحور!", "page": 286, "id": "unit-26__lesson-01__b07"}, {"type": "paragraph", "md": "ما نجحنا وما أظن أننا سننجح.. أتدرين لماذا؟ لأننا لم نَهْتَدِ -إلى اليوم- إلى باب الإصلاح ولم نعرف طريقه.. إن باب الإصلاح أمامك أنت يا بنتي ومفتاحه بيدك؛ فإذا آمنت بوجوده وعملت على دخوله صلحت الحال؛ صحيح أن الرجل هو الذي يخطو الخطوة الأولى في طريق الإثم، لا تخطوها المرأة أبدًا، ولكن لولا رضاك ما أقدم ولولا لينك ما اشتدّ؛ أنت فتحت له وهو الذي دخل، قلت للّص: تفضل. فلما سرقك اللص صرختِ: أغيثوني يا ناس، سُرِقتُ!", "page": 286, "id": "unit-26__lesson-01__b08"}, {"type": "paragraph", "md": "ولو عرفت أن الرجال جميعًا ذئاب وأنت النعجة لفررت منهم فرار النعجة من الذئب، وأنهم جميعًا لصوص لاحترست منهم احتراس الشحيح من اللص. وإذا كان الذئب لا يريد من النعجة إلا لحمها، فالذي يريده منك الرجل أعزّ عليك من اللحم على النعجة، وشر عليك من الموت عليها. يريد منك أعزّ شيء عليك: عفافك الذي به تَشْرُفين، وبه تفخرين، وبه تعيشين. وحياة البنت التي فجعها الرجل بعفافها أشد عليها بمئة مرة من الموت على النعجة التي فجعها الذئب بلحمها، إي والله.", "page": 286, "id": "unit-26__lesson-01__b09"}, {"type": "paragraph", "md": "وما رأى شاب فتاة إلا جرّدها بخياله من ثيابها ثم تصورها بلا ثياب. إي والله، أحلف لك مرة ثانية. ولا تصدقي ما يقوله لك بعض الرجال من أنهم لا يرون في البنت إلا خلقها وأدبها، وأنهم يكلمونها كلام الرفيق ويودّونها ودّ الصديق. كذبٌ والله، ولو سمعتِ أحاديثَ الشباب في خلواتهم لسمعت مهولًا مرعبًا. وما يبسم لك الشاب بسمة، ولا يلين لك كلمة، ولا يقدم لك خدمة، إلا وهي عنده تمهيد لما يريد، أو هي -على الأقل- إيهام لنفسه أنها تمهيد!", "page": 287, "id": "unit-26__lesson-01__b10"}, {"type": "paragraph", "md": "وماذا بعد؟ ماذا يا بنت؟ فكّري: تَشْتَرِكان في لذة ساعة، ثم ينسى هو، وتظلين أنت أبدًا تتجرعين غصصها. يمضي «خفيفًا» يفتش عن مغفَّلة أخرى يسرق منها عرضها، وينوء بكِ أنت «ثِقَلُ» الحمل في بطنك، والهم في نفسك، والوصمة على جبينك. يغفر له هذا المجتمعُ الظالم ويقول: شاب ضَلّ ثم تاب، وتبقين أنت في حمأة الخزي والعار طول الحياة، لا يغفر لك المجتمع أبدًا.", "page": 287, "id": "unit-26__lesson-01__b11", "inline": [{"t": "text", "s": "وماذا بعد؟ ماذا يا بنت؟ فكّري: تَشْتَرِكان في لذة ساعة، ثم ينسى هو، وتظلين أنت أبدًا تتجرعين غصصها. يمضي "}, {"t": "quote", "s": "خفيفًا"}, {"t": "text", "s": " يفتش عن مغفَّلة أخرى يسرق منها عرضها، وينوء بكِ أنت "}, {"t": "quote", "s": "ثِقَلُ"}, {"t": "text", "s": " الحمل في بطنك، والهم في نفسك، والوصمة على جبينك. يغفر له هذا المجتمعُ الظالم ويقول: شاب ضَلّ ثم تاب، وتبقين أنت في حمأة الخزي والعار طول الحياة، لا يغفر لك المجتمع أبدًا."}]}, {"type": "paragraph", "md": "ولو أنك -إذ لقيتِه- نصبت له صدرك وزويت عنه بصرك وأريتِه الحزم والإعراض، فإذا لم يصرفه عنك هذا الصد، وإذا بلغت به الوقاحة أن ينال منك بلسان أو يد، نزعت حذاءك من رجلك ونزلت به على رأسه... لو أنك فعلت هذا لرأيت مِن كل مَن يمرّ في الطريق عونًا لك عليه، ولَمَا جرؤ بعدها فاجر على ذات سِوار، ولجاءك -إن كان صالحًا- تائبًا مستغفرًا يسأل الصلة بالحلال؛ جاءك يطلب الزواج.", "page": 287, "id": "unit-26__lesson-01__b12"}, {"type": "paragraph", "md": "والبنت -مهما بلغت من المنزلة والغنى والشهرة والجاه- لا تجد أملها الأكبر وسعادتها إلا في الزواج، في أن تكون زوجًا صالحة وأمًا موقَّرة وربة بيت. سواء في ذلك الملكات والأميرات وممثلات هوليود ذوات الشهرة والبريق الذي يخدع كثيرات من النساء. وأنا أعرف أديبتين كبيرتين في مصر والشام، أديبتين حقًا، جُمع لهما المال والمجد الأدبي، ولكنهما فقدتا الزوج ففقدتا العقل وصارتا مجنونتين، ولا تحرجيني بسؤالي عن الأسماء فإنها معروفة.", "page": 287, "id": "unit-26__lesson-01__b13"}, {"type": "paragraph", "md": "الزواج أقصى أمانيِّ المرأة، ولو صارت عضوة البرلمان وصاحبة السلطان. والفاسقة المستهترة لا يتزوجها أحد، حتى الذي يغوي البنت الشريفة بوعد الزواج، إن هي غوت وسقطت تركها وذهب -إذا أراد الزواج- فتزوّج غيرها من الشريفات، لأنه لا يرضى أن تكون ربة بيته وأم ابنته امرأة ساقطة!", "page": 287, "id": "unit-26__lesson-01__b14"}, {"type": "paragraph", "md": "والرجل وإن كان فاسقًا داعرًا، إذا لم يجد في سوق اللذات بنتًا ترضى أن تريق كرامتها على قدميه وأن تكون لعبة بين يديه، إذا لم يجد البنت الفاسقة أو البنت المغفَّلة التي تشاركه في الزواج على دين إبليس وشريعة القطط في شباط، طلب مَن تكون زوجته على سنّة الإسلام. فكساد سوق الزواج منكن يا بنات، لو لم يكن منكنّ الفاسقات ما كسدت سوق الزواج ولا راجت سوق الفجور، فلماذا لا تعملنَ، لماذا لا تعمل شريفات النساء على محاربة هذا البلاء؟ أنتنّ أولى به وأقدر عليه منا لأنكن أعرف بلسان المرأة وطرق إفهامها، ولأنه لا يذهب ضحيةَ هذا الفساد إلا أنتن: البنات العفيفات الشريفات البنات الصيّنات الديّنات.", "page": 288, "id": "unit-26__lesson-01__b15"}, {"type": "paragraph", "md": "في كل بيت من بيوت الشام بنات في سن الزواج لا يجدن زوجًا، لأن الشباب وجدوا من الخليلات ما يغني عن الحليلات. ولعل مثل هذا في غير الشام أيضًا، فألِّفْنَ جماعات منكن من الأديبات والمتعلمات ومدّرسات المدرسة وطالبات الجامعة تعيد أخواتكن الضالاّت إلى الجادّة، خوّفْنَهنّ الله، فإن كُنّ لا يخَفْنَه فحذِّرْنَهنّ المرض، فإن كنّ لا يَحْذَرْنَه فخاطبْنَهنّ بلسان الواقع، قلنَ لهنّ: إنكن صبايا جميلات، فلذلك يُقبل الشباب عليكنّ ويحومون حولكن، ولكن هل يدوم عليكنّ الصبا والجمال؟ وهل دام في الدنيا شيء حتى يدوم على الصبيّة صباها وعلى الجميلة جمالُها؟ فكيف بكنّ إذا صرتن عجائز محنيّات الظهور مجعَّدات الوجوه؟ من يهتم يومئذ بكنّ ومن يسأل عنكنّ؟ أتعرفنَ من يهتم بالعجوز ويكرمها ويوقرها؟ أولادها وبناتها وحَفَدتها وحفيداتها. هنالك تكون العجوز ملكة في رعيتها ومتوجَّة على عرشها، على حين تكون «الأخرى».. أنتنّ أعرف بما تكون عليه!", "page": 288, "id": "unit-26__lesson-01__b16", "inline": [{"t": "text", "s": "في كل بيت من بيوت الشام بنات في سن الزواج لا يجدن زوجًا، لأن الشباب وجدوا من الخليلات ما يغني عن الحليلات. ولعل مثل هذا في غير الشام أيضًا، فألِّفْنَ جماعات منكن من الأديبات والمتعلمات ومدّرسات المدرسة وطالبات الجامعة تعيد أخواتكن الضالاّت إلى الجادّة، خوّفْنَهنّ الله، فإن كُنّ لا يخَفْنَه فحذِّرْنَهنّ المرض، فإن كنّ لا يَحْذَرْنَه فخاطبْنَهنّ بلسان الواقع، قلنَ لهنّ: إنكن صبايا جميلات، فلذلك يُقبل الشباب عليكنّ ويحومون حولكن، ولكن هل يدوم عليكنّ الصبا والجمال؟ وهل دام في الدنيا شيء حتى يدوم على الصبيّة صباها وعلى الجميلة جمالُها؟ فكيف بكنّ إذا صرتن عجائز محنيّات الظهور مجعَّدات الوجوه؟ من يهتم يومئذ بكنّ ومن يسأل عنكنّ؟ أتعرفنَ من يهتم بالعجوز ويكرمها ويوقرها؟ أولادها وبناتها وحَفَدتها وحفيداتها. هنالك تكون العجوز ملكة في رعيتها ومتوجَّة على عرشها، على حين تكون "}, {"t": "quote", "s": "الأخرى"}, {"t": "text", "s": ".. أنتنّ أعرف بما تكون عليه!"}]}, {"type": "paragraph", "md": "رأيت في بروكسل عند ملتقى طريقين -وقد فُتح الطريق للمارة- عجوزًا لا تحملها ساقاها، تضطرب من الكبر أعضاؤها، تريد أن تجتاز والسيارات من حولها تكاد تدعسها، ولا يمسك أحدٌ بيدها. فقلت لمَن كان معي من الشباب: ليذهب أحدكم فليساعدها. وكان معنا الصديق الأستاذ نديم ظبيان، وهو مقيم في بروكسل من أكثر من أربعين سنة، فقال لي: أتدري أن هذه العجوز كانت يومًا جميلةَ البلد وفتنة الناس، وكان الرجال يلقون بقلوبهم وما في جيوبهم على قدميها ليفوزوا بنظرة أو لمسة منها، فلما ذهب شبابها وزوى جمالها لم تعد تجد من يمسك بيدها!", "page": 288, "id": "unit-26__lesson-01__b17"}, {"type": "paragraph", "md": "فهل تساوي هذه اللذةُ تلك الآلامَ؟ وهل تُشترى بهذه البداية تلك النهاية؟", "page": 288, "id": "unit-26__lesson-01__b18"}, {"type": "paragraph", "md": "وأمثال هذا الكلام. لا تحتجن إلى من يدلكنّ عليه، ولا تعدمنَ وسيلة إلى هداية أخواتكن المسكينات الضالات، فإن لم تستطعن ذلك معهن فاعملن على وقاية السالمات من مرضهن، والناشئات الغافلات من أن يسلكن طريقهن.", "page": 289, "id": "unit-26__lesson-01__b19"}, {"type": "paragraph", "md": "وأنا لا أطلب منكن أن تَعُدْنَ بالمرأة المسلمة اليوم بوثبة واحدة إلى مثل ما كانت عليه المرأة المسلمة حقًا، لا، وإني لأعلم أن الطفرة مستحيلة في العادة (فالليل أسود مظلم والضحى مشرق وضّاح، ولكن الله ما نقلنا من الظلام إلى النور في لحظة، بل هو يولج النهار في الليل فلا تحسّ بهذه النقلة؛ كالعقرب الصغير في الساعة: تراه واقفًا لا يحرك، ولكن عُدْ إليه بعد ساعتين تَرَه قد مشى. وكذلك ينتقل الإنسان من الطفولة إلى الصبا ومن الشباب إلى الشيخوخة، وكذلك يكون تبدل الأمم وتحولها من حال إلى حال)، ولكن أن ترجعن إلى الخير خطوة خطوة كما أقبلتنّ على الشر خطوة خطوة. إنكنّ قَصَّرْتُنّ الثيابَ ورفعتنّ الحجابَ شعرة شعرة، وصبرتُنّ الدهر الأطول تعملنَ لهذا الانتقال، والرجل الفاضل لا يشعر به، والمجلات الداعرة تحثّ عليه، والفُسّاق يفرحون به، حتى وصلنا إلى حال لا يرضى بها الإسلام ولا ترضى بها النصرانية، ولم يعملها المجوس الذين نقرأ أخبارهم في التاريخ، إلى حال تأباها الحيوانات.", "page": 289, "id": "unit-26__lesson-01__b20", "inline": [{"t": "text", "s": "وأنا لا أطلب منكن أن تَعُدْنَ بالمرأة المسلمة اليوم بوثبة واحدة إلى مثل ما كانت عليه المرأة المسلمة حقًا، لا، وإني لأعلم أن الطفرة مستحيلة في العادة "}, {"t": "emphasis", "s": "(فالليل أسود مظلم والضحى مشرق وضّاح، ولكن الله ما نقلنا من الظلام إلى النور في لحظة، بل هو يولج النهار في الليل فلا تحسّ بهذه النقلة؛ كالعقرب الصغير في الساعة: تراه واقفًا لا يحرك، ولكن عُدْ إليه بعد ساعتين تَرَه قد مشى. وكذلك ينتقل الإنسان من الطفولة إلى الصبا ومن الشباب إلى الشيخوخة، وكذلك يكون تبدل الأمم وتحولها من حال إلى حال)", "role": "emphasis"}, {"t": "text", "s": "، ولكن أن ترجعن إلى الخير خطوة خطوة كما أقبلتنّ على الشر خطوة خطوة. إنكنّ قَصَّرْتُنّ الثيابَ ورفعتنّ الحجابَ شعرة شعرة، وصبرتُنّ الدهر الأطول تعملنَ لهذا الانتقال، والرجل الفاضل لا يشعر به، والمجلات الداعرة تحثّ عليه، والفُسّاق يفرحون به، حتى وصلنا إلى حال لا يرضى بها الإسلام ولا ترضى بها النصرانية، ولم يعملها المجوس الذين نقرأ أخبارهم في التاريخ، إلى حال تأباها الحيوانات."}]}, {"type": "paragraph", "md": "إن الديكين إذا اجتمعا على الدجاجة اقتتلا غيرةً عليها وذودًا عنها، وعلى الشواطئ في الإسكندرية وبيروت رجال مسلمون لا يغارون على نسائهم المسلمات أن يراهُنّ الأجنبي. لا أن يرى وجهوهنّ ولا أكفهنّ ولا نحورهنّ، بل كل شيء فيهن! كل شيء إلا الشيء الذي يقبح مرآه ويجمل ستره، وهو حلقتا العورتين وحلمتا الثديين! وفي النوادي والسهرات «التقدمية الراقية» رجال مسلمون يقدّمون نساءهم المسلمات للأجنبي ليراقصهن، يضمّهنّ حتى يلامس الصدرُ الصدرَ والبطنُ البطنَ والفمُ الخدَّ، والذراع ملتوية على الجسد، ولا ينكر ذلك أحد! وفي الجامعات المسلمة شباب مسلمون يجالسون بنات مسلمات متكشّفات باديات العورات، ولا ينكر ذلك الآباء المسلمون ولا الأمهات المسلمات!", "page": 289, "id": "unit-26__lesson-01__b21", "inline": [{"t": "text", "s": "إن الديكين إذا اجتمعا على الدجاجة اقتتلا غيرةً عليها وذودًا عنها، وعلى الشواطئ في الإسكندرية وبيروت رجال مسلمون لا يغارون على نسائهم المسلمات أن يراهُنّ الأجنبي. لا أن يرى وجهوهنّ ولا أكفهنّ ولا نحورهنّ، بل كل شيء فيهن! كل شيء إلا الشيء الذي يقبح مرآه ويجمل ستره، وهو حلقتا العورتين وحلمتا الثديين! وفي النوادي والسهرات "}, {"t": "quote", "s": "التقدمية الراقية"}, {"t": "text", "s": " رجال مسلمون يقدّمون نساءهم المسلمات للأجنبي ليراقصهن، يضمّهنّ حتى يلامس الصدرُ الصدرَ والبطنُ البطنَ والفمُ الخدَّ، والذراع ملتوية على الجسد، ولا ينكر ذلك أحد! وفي الجامعات المسلمة شباب مسلمون يجالسون بنات مسلمات متكشّفات باديات العورات، ولا ينكر ذلك الآباء المسلمون ولا الأمهات المسلمات!"}]}, {"type": "paragraph", "md": "وأمثال هذا كثير، لا يُدفَع في يوم واحد ولا بوثبة عاجلة، بل بأن نعود إلى الحق من الطريق الذي وصلنا منه إلى الباطل، ولو وجدناه الآن طويلًا... وإنّ مَن لا يسلك الطريقَ الطويل الذي لا يجد غيرَه لا يصل أبدًا. وأن نبدأ بمحاربة الاختلاط. والاختلاط غير السفور، وأنا لا أمنع من كشف الوجه إن كان لا يتحقق بكشفه الضرر على الفتاة والعدوان على عفافها، وأراه -عند أمن الفتنة- خيرًا من هذا الذي نسمّيه في بلاد الشام حجابًا، وما هو إلا ستر للمعايب وتجسيم للجمال وإغراء للناظر.", "page": 289, "id": "unit-26__lesson-01__b22"}, {"type": "paragraph", "md": "السفور إن اقتصر على الوجه -كما خلق الله الوجهَ- نقبل به، وإن كنا نرى الستر أحسن وأَولى، أما الاختلاط فشيء آخر. وليس يلزم من السفور أن تختلط الفتاة بغير محارمها، وأن تستقبل الزوجةُ السافرة صديقَ زوجها في بيتها، أو أن تحييّه إن قابلته في الترام أو لقيته في الشارع، وأن تصافح البنتُ رفيقَها في الجامعة، أو أن تصل الحديثَ بينها وبينه، أو أن تمشي معه في الطريق وتستعدّ معه للامتحان، وتنسى أن الله جعلها أنثى وجعله ذكرًا وركّب في كلٍّ الميلَ إلى الآخر، فلا تستطيع هي ولا هو ولا أهل الأرض جميعًا أن يغيروا خلقة الله وأن «يساووا» بين الجنسين، أو أن يمحوا من نفوسهم هذا الميل.", "page": 290, "id": "unit-26__lesson-01__b23", "inline": [{"t": "text", "s": "السفور إن اقتصر على الوجه -كما خلق الله الوجهَ- نقبل به، وإن كنا نرى الستر أحسن وأَولى، أما الاختلاط فشيء آخر. وليس يلزم من السفور أن تختلط الفتاة بغير محارمها، وأن تستقبل الزوجةُ السافرة صديقَ زوجها في بيتها، أو أن تحييّه إن قابلته في الترام أو لقيته في الشارع، وأن تصافح البنتُ رفيقَها في الجامعة، أو أن تصل الحديثَ بينها وبينه، أو أن تمشي معه في الطريق وتستعدّ معه للامتحان، وتنسى أن الله جعلها أنثى وجعله ذكرًا وركّب في كلٍّ الميلَ إلى الآخر، فلا تستطيع هي ولا هو ولا أهل الأرض جميعًا أن يغيروا خلقة الله وأن "}, {"t": "quote", "s": "يساووا"}, {"t": "text", "s": " بين الجنسين، أو أن يمحوا من نفوسهم هذا الميل."}]}, {"type": "paragraph", "md": "وإن دعاة المساواة والاختلاط باسم المدنيّة قوم كذّابون من جهتين: كذابون لأنهم ما أرادوا بذلك كله إلا متاع جوارحهم وإرضاء ميولهم، وإعطاء نفوسهم حظها من لذة النظر وما يأملون من لذائذ أُخَر، ولكنهم لم يجدوا الجرأة على التصريح به فلبّسوه بهذا الذي يهرفون به، بهذه الألفاظ الطنّانة التي ليس وراءها شيء: التقدمية، والتمدن، والحياة الجامعية... وهذا الكلام الفارغ -على دَوِيّه- من المعنى، فكأنه الطبل!", "page": 290, "id": "unit-26__lesson-01__b24"}, {"type": "paragraph", "md": "وكذّابون لأن أوربا التي يأتمّون بها ويهتدون بهديها، ولا يعرفون الحق إلا بدمغتها عليه، فليس الحق عندهم الذي يقابل الباطل ولكن الحق ما جاء من هناك: من باريس ولندن وبرلين ونيويورك، ولو كان الرقصَ والخلاعة والاختلاط في الجامعة والتكشف في الملعب والعري على الساحل، (6) والباطل ما جاء من هنا: من الأزهر والأموي وهاتيك المدارس الشرقية والمساجد الإسلامية، ولو كان الشرفَ والهدى والعفاف والطهارة، طهارة القلب وطهارة الجسد... إن في أوروبا وفي أميركا -كما قرأنا وحدّثَنا مَن ذهب إليهما- أسرًا كثيرات لا ترضى بهذا الاختلاط ولا تُسيغه، وإن في باريس... في باريس يا ناس، آباء وأمهات لا يسمحون لبناتهم الكبيرات أن يَسِرْنَ مع شاب أو يصحبنَه إلى السينما، بل هم لا يدخلونهنّ إلاّ إلى روايات عرفوها وأيقنوا بسلامتها من الفحش والفجور، اللذين لا يخلو منهما مع الأسف واحدٌ من هذه «التهريجات» والصبيانيات السخيفة التي تسميها شركاتُ مصر الهزيلةُ الرقيعةُ، الجاهلةُ بالفن السينمائي مثلَ جهلها بالدين... تسميها أفلامًا!", "page": 290, "id": "unit-26__lesson-01__b25", "inline": [{"t": "text", "s": "وكذّابون لأن أوربا التي يأتمّون بها ويهتدون بهديها، ولا يعرفون الحق إلا بدمغتها عليه، فليس الحق عندهم الذي يقابل الباطل ولكن الحق ما جاء من هناك: من باريس ولندن وبرلين ونيويورك، ولو كان الرقصَ والخلاعة والاختلاط في الجامعة والتكشف في الملعب والعري على الساحل، (6) والباطل ما جاء من هنا: من الأزهر والأموي وهاتيك المدارس الشرقية والمساجد الإسلامية، ولو كان الشرفَ والهدى والعفاف والطهارة، طهارة القلب وطهارة الجسد... إن في أوروبا وفي أميركا -كما قرأنا وحدّثَنا مَن ذهب إليهما- أسرًا كثيرات لا ترضى بهذا الاختلاط ولا تُسيغه، وإن في باريس... في باريس يا ناس، آباء وأمهات لا يسمحون لبناتهم الكبيرات أن يَسِرْنَ مع شاب أو يصحبنَه إلى السينما، بل هم لا يدخلونهنّ إلاّ إلى روايات عرفوها وأيقنوا بسلامتها من الفحش والفجور، اللذين لا يخلو منهما مع الأسف واحدٌ من هذه "}, {"t": "quote", "s": "التهريجات"}, {"t": "text", "s": " والصبيانيات السخيفة التي تسميها شركاتُ مصر الهزيلةُ الرقيعةُ، الجاهلةُ بالفن السينمائي مثلَ جهلها بالدين... تسميها أفلامًا!"}]}, {"type": "paragraph", "md": "يقولون: إن الاختلاط يكسر شِرَّة الشهوة ويهذب الخلق وينزع من النفس هذا الجنون الجنسي، وأنا أحيل في الجواب على من جرّب الاختلاط في المدارس، روسيا التي لا تعود إلى دين ولا تسمع رأي شيخ ولا قسّيس. ألم ترجع عن هذه التجربة لمّا رأت فسادها؟", "page": 290, "id": "unit-26__lesson-01__b26"}, {"type": "paragraph", "md": "وأميركا، ألم تقرؤوا أن من جملة مشكلات أميركا مشكلة ازدياد نسبة «الحاملات» من الطالبات؟ فمن يسرّه أن يكون في جامعات مصر والشام وسائر بلاد الإسلام مثل هذه المشكلة؟", "page": 291, "id": "unit-26__lesson-01__b27", "inline": [{"t": "text", "s": "وأميركا، ألم تقرؤوا أن من جملة مشكلات أميركا مشكلة ازدياد نسبة "}, {"t": "quote", "s": "الحاملات"}, {"t": "text", "s": " من الطالبات؟ فمن يسرّه أن يكون في جامعات مصر والشام وسائر بلاد الإسلام مثل هذه المشكلة؟"}]}, {"type": "paragraph", "md": "لذلك صاروا يدرّسون «الثقافة الجنسية» في المدارس، أي أنهم يصبّون البنزين على النار؛ يصفون للفتاة الغافلة البريئة ما خفي من سوأة الرجل وماذا يصنع إذا خلا بأنثى! ووُجد فينا من شياطين الإنس مَن يدعونا إلى أن نصنع في ذلك مثلَ صنيعهم. كما أنهم صاروا يدرّبون طالبات المدارس المتوسطة على استعمال حبوب منع الحمل!", "page": 291, "id": "unit-26__lesson-01__b28", "inline": [{"t": "text", "s": "لذلك صاروا يدرّسون "}, {"t": "quote", "s": "الثقافة الجنسية"}, {"t": "text", "s": " في المدارس، أي أنهم يصبّون البنزين على النار؛ يصفون للفتاة الغافلة البريئة ما خفي من سوأة الرجل وماذا يصنع إذا خلا بأنثى! ووُجد فينا من شياطين الإنس مَن يدعونا إلى أن نصنع في ذلك مثلَ صنيعهم. كما أنهم صاروا يدرّبون طالبات المدارس المتوسطة على استعمال حبوب منع الحمل!"}]}, {"type": "paragraph", "md": "أنا لا أخاطب الشباب ولا أطمع في أن يسمعوا لي، وأنا أعلم أنهم قد يردّون عليّ ويسفّهون رأيي لأني أحرمهم من لذائذ ما صدّقوا أنهم قد وصلوا إليها حقًا، ولكن أخاطبكنّ أنتنّ، أنتنّ يا بناتي المؤمنات الديّنات، يا بناتي الشريفات العفيفات: إنه لا يكون الضحية إلا أنتنّ، فلا تقدّمنَ نفوسكنّ ضحايا على مذبح إبليس، لا تسمعنَ كلامَ هؤلاء الذين يزيّنون لكنّ حياة الاختلاط باسم الحرية والمدنية والتقدمية والروح الجامعية، فإن أكثر هؤلاء الملاعين لا زوجة له ولا ولد، ولا يهمّه منكن جميعًا إلا اللذة العارضة! أما أنا فإني أبو أربع بنات؛ فأنا حين أدافع عنكنّ أدافع عن بناتي، وأنا أريد لكُنّ من الخير ما أريده لهنّ.", "page": 291, "id": "unit-26__lesson-01__b29"}, {"type": "paragraph", "md": "إنه لا شيء مما يهرف به هؤلاء يَرُدّ على البنت عِرْضَها الذاهب، ولا يرجع لها شرفها المثلوم ولا يعيد لها كرامتها الضائعة. وإذا سقطت البنت لم تجد واحدًا يأخذ بيدها أو يرفعها من سقطتها، إنما تجدهم جميعًا يتزاحمون على جمالها ما بقي فيها جمال، فإذا ولّى ولَّوا عنها كما تولّي الكلاب عن الجيفة التي لم يبقَ فيها مِزْعة لحم!", "page": 291, "id": "unit-26__lesson-01__b30"}, {"type": "paragraph", "md": "هذه نصيحتي إليك يا بنتي، وهذا هو الحق فلا تسمعي غيره، واعلمي أن بيدك أنت لا بأيدينا معشرَ الرجال، بيدك مفتاح باب الإصلاح، فإذا شئت أصلحت نفسك وأصلحت بصلاحك الأمةَ كلها.", "page": 291, "id": "unit-26__lesson-01__b31"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 291, "id": "unit-26__lesson-01__b32", "role": "assessment"}, {"type": "paragraph", "md": "1- لخصي ثلاث نصائح ذكرها الشيخ علي الطنطاوي في هذه الكلمة.", "page": 291, "id": "unit-26__lesson-01__b33", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- هل النساء يمثلن أساس الإصلاح المجتمعي أم الرجال.. بيني ذلك كما فهمتِه من كلام الشيخ.", "page": 291, "id": "unit-26__lesson-01__b34", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط حواري دعوي", "page": 291, "id": "unit-26__lesson-01__b35", "role": "activity"}, {"type": "paragraph", "md": "1- نبحث عن سيرة الشيخ الأديب الفقيه: علي الطنطاوي، ونقرأها بتمعن، ونستفيد من كتبه", "page": 291, "id": "unit-26__lesson-01__b36", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- نُعطي مضمون هذا الدرس لعدد من الأخوات القريبات منا حسب ما فهمناه ووعيناه..", "page": 291, "id": "unit-26__lesson-01__b37", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-26__lesson-01';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-02','unit-26',2,'سر البيت بصلاح الوالدين','الأسرة والمرأة',NULL,0,0,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "للشيخ: أبي قتادة عمر محمود", "page": 292, "id": "unit-26__lesson-02__b01", "role": "section"}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 292, "id": "unit-26__lesson-02__b02", "role": "objectives"}, {"type": "paragraph", "md": "1- معرفة أن بداية إصلاح الأسرة المسلمة يكون بصلاح الأبوين على الوجه الذي يحبه الله.", "page": 292, "id": "unit-26__lesson-02__b03", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- التعرف على آليات صناعة المسلم المقاوم للفساد الأخلاقي والاجتماعي والعقدي.", "page": 292, "id": "unit-26__lesson-02__b04", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "أهمية سلوك الأبوين في بناء الأسرة:", "page": 292, "id": "unit-26__lesson-02__b05", "role": "section"}, {"type": "paragraph", "md": "أغلب أمراض الشباب والناس تنتج مع الخطوات الأولى داخل الأسرة، وتتشكل الشخصية المريضة والفاسدة من الأب والأم ومن معهما من الأخوة والأخوات الكبار، وتستطيع الجزم أن سوء الخلق، وفساد السلوك، واضطراب الشخصية منتج من سلوك أسري فاسد (فأبواه يهودانه أو ينصرانه أو يمجسانه) ومع الخطوات السلوكية الأولى تتشكل عمد الشخصية، ولو أرادت التغيير بعد ذلك شقّ عليها واحتاجت لعلم خاص ومجاهدة عالية.", "page": 292, "id": "unit-26__lesson-02__b06", "inline": [{"t": "text", "s": "أغلب أمراض الشباب والناس تنتج مع الخطوات الأولى داخل الأسرة، وتتشكل الشخصية المريضة والفاسدة من الأب والأم ومن معهما من الأخوة والأخوات الكبار، وتستطيع الجزم أن سوء الخلق، وفساد السلوك، واضطراب الشخصية منتج من سلوك أسري فاسد "}, {"t": "emphasis", "s": "(فأبواه يهودانه أو ينصرانه أو يمجسانه)", "role": "emphasis"}, {"t": "text", "s": " ومع الخطوات السلوكية الأولى تتشكل عمد الشخصية، ولو أرادت التغيير بعد ذلك شقّ عليها واحتاجت لعلم خاص ومجاهدة عالية."}]}, {"type": "paragraph", "md": "العلاقة بين الأبوين وخصال كل واحد منهما تجاه الآخر، وتجاه الأطفال هي من يشكل أخلاق الإنسان في حياته كلها إلا أن تطرأ عليه طروء تغير له هذا المسلك.", "page": 292, "id": "unit-26__lesson-02__b07"}, {"type": "paragraph", "md": "ما نحتاجه هو تقويم سلوك الأبوين، وإنشاء علاقة متوازنة تقوم على المودة والسكينة والاحترام، ومراقبة حركة النفس وكلامها ومواقفها، لأن هذا هو البيئة التي تصنع الطفل وحياته كلها بعد ذلك.", "page": 292, "id": "unit-26__lesson-02__b08"}, {"type": "paragraph", "md": "من هنا تكمن أهمية أخلاق الأبوين، وسلوكهما تجاه بعضهما البعض في حياة الإنسان والمجتمع، وأي خطأ منهما سينعكس أثرًا حقيقيًا على فهم الإنسان ومواقفه في حياته كلها.", "page": 292, "id": "unit-26__lesson-02__b09"}, {"type": "paragraph", "md": "كل هذا الكلام نفهمه نظريًا، ولكن غمرات الحياة تنسينا أنفسنا حتى تنهار قيمنا وأخلاقنا في داخل بيوتنا وبين الأسرة الواحدة، ثم نستمريء هذه الأخلاق السيئة، وبالتالي لا نشعر بأنفسنا كالمخبول الذي لا يدرك جنونه واضطرابه.", "page": 292, "id": "unit-26__lesson-02__b10"}, {"type": "paragraph", "md": "من هنا تأتي أهمية رفع المرايا، وتوالي التذكير ليحس المرء بمقدار انحرافه عن الجادة.", "page": 292, "id": "unit-26__lesson-02__b11"}, {"type": "paragraph", "md": "مع الطفل إذا استقام العود استقام الظل، وإذا اعوج العود اعوج الظل، والطفل هو ظل أخلاق الوالدين، وما لا تستشعره من نفسك يستشعره الطفل والصغير، ويدركه بوعي مرتفع عن وعيك، فيبدأ التمثل واعيًا أنه يسير أمام مثاله الذي يقلده ويراه.", "page": 293, "id": "unit-26__lesson-02__b12"}, {"type": "paragraph", "md": "مع الغفلة يمكن للكبير أن يقع في عظائم الشرور دون إحساس بقذارتها وقبحها، لأن صورة النفس مشوهة ومغيبة، ولكن الطفل لسلامة آلته يتحرك مقلدًا على وعي لحركتك وسلوكك، ولذلك هو أعقل منك في فهمه لحركات أخلاقه.", "page": 293, "id": "unit-26__lesson-02__b13"}, {"type": "paragraph", "md": "تتغير هذه الصورة الواعية عند الطفل عندما يرى النفاق فيمن حوله، فهم يدعون ويتكلمون عن شيء ويمارسون ضده، فيبدأ الاضطراب في نفس الطفل، وبهذا يتكون الشذوذ والفساد.", "page": 293, "id": "unit-26__lesson-02__b14"}, {"type": "paragraph", "md": "عمدة استقرار البيت: رجل كامل الرجولة، يجمع الشجاعة والكرم والحياء والصدق والأمانة، وامرأة وفية صادقة عاقلة مفعمة بالأنوثة والحكمة، وأي اختلال في هذه القسمة من سقوط صفات الرجولة لتنتقل إلى الجانب الآخر يعني اختلال في بنية البيت الصحيح.", "page": 293, "id": "unit-26__lesson-02__b15", "inline": [{"t": "emphasis", "s": "عمدة استقرار البيت", "role": "emphasis"}, {"t": "text", "s": ": رجل كامل الرجولة، يجمع الشجاعة والكرم والحياء والصدق والأمانة، وامرأة وفية صادقة عاقلة مفعمة بالأنوثة والحكمة، وأي اختلال في هذه القسمة من سقوط صفات الرجولة لتنتقل إلى الجانب الآخر يعني اختلال في بنية البيت الصحيح."}]}, {"type": "paragraph", "md": "وتنشأ على ضفاف هذا الكمال في القسمة نماذج شاذة أبرزها صورة مطلب رجل، يريد احترام الآخرين له كرجل وهو ناقص القيم الرئيسية من الشجاعة والكرم والحياء، وهذا أبرز معالم الشذوذ في مجتمعنا، يقابله سفاهة امرأة، تريد تمثيل دور الرجل مع نقص أنوثتها، وبهذا يفسد البيت.", "page": 293, "id": "unit-26__lesson-02__b16"}, {"type": "heading", "level": 3, "text": "صلاح الآباء يؤدي إلى صلاح الأبناء:", "page": 293, "id": "unit-26__lesson-02__b17", "role": "section"}, {"type": "paragraph", "md": "لا يستقيم البيت إلا بصلاح أهله، وقيام الوالدين على العبادة والذكر والدعاء؛ فسمات الصلاح سمات يحبها الخلق جميعًا، ولقد رأيت هذا حتى في الكفار، فإنهم يهابون المتدين والذاكر والمصلي والداعي، ويرونه يستحق الاحترام، ومن علم من زوجته محبة الصلاح وسعيها لتحقيقه أحبها واحترمها، وكذلك إذا رأت الزوجة في زوجها العبادة ومحبة الذكر، وقيامه على الفرائض بحرص، وكذا مواظبته على نوافل العبادات من صلاة الضحى وقيام الليل ودوام الذكر فإنها تعظمه في نفسها وتحترمه أشد الاحترام.. فهذه قاعدة مضطردة فإن وجد خرم لها في آحاد من الناس لم تبطل، لكن الناس يرونها سنة جارية في حياتهم.", "page": 293, "id": "unit-26__lesson-02__b18"}, {"type": "paragraph", "md": "وكذا الأولاد، فيجب على المرء أن يراعي حاله معهم أشد من مراعاته الغريب والأجنبي؛ فبعض الجهلة يتزيا بكل زي جميل مع الناس خارج بيته، ويحسن خلقه معهم حتى إذا دخل بيته أساء وأظهر غير ذلك، فهذا من أجهل الخلق، وأفسد أعظم ما عنده من أهل وولد، إذ يجب أن يحسن إحسانًا مضاعفًا في بيته ومع أهله، ويجب عليه التخلق بأحسن الصفات معهم.", "page": 293, "id": "unit-26__lesson-02__b19"}, {"type": "paragraph", "md": "الأولاد لهم مجسات عظيمة وكذا الزوجة والزوج؛ يراقبون كل حركة، ويعلمون من والدهم ووالدتهم كما تعلم الزوجة من الزوج، والزوج من الزوجة: خباياهم في السر، ومن هنا تأتي قيمة عبادة السر في صلاح الأولاد.. كرمك يراقبونه ويرونه عند كل منعطف وسؤال، وكذا شجاعتك، وكذا حسن لفظك، فهم أدرى الناس به، ويضعونك تحت المجهر في هذا، وتكون أنت كنافخ الكير أو حامل المسك.", "page": 294, "id": "unit-26__lesson-02__b20"}, {"type": "paragraph", "md": "يتحدث لي بعضهم أن زوجته تسيء في ظنها به، وربما مرت امرأة من أمامهم فاتهمته زوجته بالنظر إليها، وهو يتهم غيرتها الشديدة في ذلك، وحينها يبدأ الخصومة أمام الأولاد، وتسيل الأخلاق السيئة من ألفاظ ومواقف، وأنا أقول: لن يحصل هذا لو علمت المرأة من زوجها دينا عظيما في غض البصر ومداومة الذكر.", "page": 294, "id": "unit-26__lesson-02__b21"}, {"type": "paragraph", "md": "وأنا أرى البيت كله ظلًا للرجل: الزوجة والأولاد، حتى نساء الأولاد إن سكنوا قريبًا من الوالدين؛ فالمسؤولية الأعظم في خصال البيت وأخلاق أهله ومزاجهم هي ظل خلق الأب والرجل، إن كان رجلًا قبل كل شيء، ثم صالحًا وعابدًا صادقًا كان البيت ظلًا له في سمته وحياته.", "page": 294, "id": "unit-26__lesson-02__b22", "inline": [{"t": "emphasis", "s": "وأنا أرى البيت كله ظلًا للرجل", "role": "emphasis"}, {"t": "text", "s": ": الزوجة والأولاد، حتى نساء الأولاد إن سكنوا قريبًا من الوالدين؛ فالمسؤولية الأعظم في خصال البيت وأخلاق أهله ومزاجهم هي ظل خلق الأب والرجل، إن كان رجلًا قبل كل شيء، ثم صالحًا وعابدًا صادقًا كان البيت ظلًا له في سمته وحياته."}]}, {"type": "paragraph", "md": "وأنا هنا أتكلم عن سمت البيت في داخله، ومزاجه العام فيما هو عليه، وقد يخرج الابن إلى حياة خارج البيت فتأتيه خصال غير ما عليه البيت؛ فيفسد ويتغير، لكن يبقى هو في البيت على خصال سيده وهو الأب..", "page": 294, "id": "unit-26__lesson-02__b23"}, {"type": "paragraph", "md": "كل عمل تأتي به الزوجة صلاحًا أو فسادًا يأتي على البيت، وكل عمل يأتي به الزوج صلاحًا أو فسادًا يأتي على البيت.. سر البيت بصلاح الوالدين.", "page": 294, "id": "unit-26__lesson-02__b24", "inline": [{"t": "text", "s": "كل عمل تأتي به الزوجة صلاحًا أو فسادًا يأتي على البيت، وكل عمل يأتي به الزوج صلاحًا أو فسادًا يأتي على البيت.. "}, {"t": "emphasis", "s": "سر البيت بصلاح الوالدين.", "role": "emphasis"}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 294, "id": "unit-26__lesson-02__b25", "role": "assessment"}, {"type": "paragraph", "md": "1- ما أثر عبادة الوالدين في صلاح الأولاد وقربهم من الله تعالى؟", "page": 294, "id": "unit-26__lesson-02__b26", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- «البيت كله ظل للرجل» اشرحي هذه العبارة وبيني معناها بصورة واضحة.", "page": 294, "id": "unit-26__lesson-02__b27", "inline": [{"t": "text", "s": "2- "}, {"t": "quote", "s": "البيت كله ظل للرجل"}, {"t": "text", "s": " اشرحي هذه العبارة وبيني معناها بصورة واضحة."}], "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط حواري دعوي", "page": 294, "id": "unit-26__lesson-02__b28", "role": "activity"}, {"type": "paragraph", "md": "1- نبحث عن سيرة فضيلة الشيخ المجاهد: عمر محمود أبو عمر، ونقرأ كتابه «مع صبغة الله الصمد».", "page": 294, "id": "unit-26__lesson-02__b29", "inline": [{"t": "text", "s": "1- نبحث عن سيرة فضيلة الشيخ المجاهد: عمر محمود أبو عمر، ونقرأ كتابه "}, {"t": "quote", "s": "مع صبغة الله الصمد"}, {"t": "text", "s": "."}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- نُعطي مضمون هذا الدرس لزوجنا وأولادنا وعدد من معارفنا من الأخوات؛ كما ما فهمناه..", "page": 294, "id": "unit-26__lesson-02__b30", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-26__lesson-02';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-03','unit-26',3,'الدعاء وأثره في صلاح الأولاد','الأسرة والمرأة',NULL,0,8,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 295, "id": "unit-26__lesson-03__b01", "role": "objectives"}, {"type": "paragraph", "md": "1- معرفة أن من أهم سبل إصلاح الأسرة المسلمة: الدعاء بصلاح الأولاد والأسرة.", "page": 295, "id": "unit-26__lesson-03__b02", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- التعرف على آليات صناعة المسلم المقاوم للفساد الأخلاقي والاجتماعي والعقدي.", "page": 295, "id": "unit-26__lesson-03__b03", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "أهمية سلوك الأبوين في بناء الأسرة:", "page": 295, "id": "unit-26__lesson-03__b04", "role": "section"}, {"type": "paragraph", "md": "إن من أعظم سبل استقرار البيت واستقامته الدعاء، وهو عمل يغفل عنه الكثيرون، ولو علم الناس قيمته لأكثروا منه كل يوم مرات ومرات، وبعض المسلمين يظن أن الدعاء لتحصيل أمر يكون مرة واحدة، فيستحاب له فيه، فهو تارك له على الدوام إلا مرة أو مرتين، وهذا خطأ كبير جدًا، فالدعاء كالطعام -ولا أقول كالدواء- يحتاجه المرء في كل يوم مرات، ومواظبة النبي صلى الله عليه وسلم في كل يوم وفي كل حال يوافقه على الدعاء يعني هذا المعنى.", "page": 295, "id": "unit-26__lesson-03__b05", "inline": [{"t": "text", "s": "إن من أعظم سبل استقرار البيت واستقامته الدعاء، وهو عمل يغفل عنه الكثيرون، ولو علم الناس قيمته لأكثروا منه كل يوم مرات ومرات، وبعض المسلمين يظن أن الدعاء لتحصيل أمر يكون مرة واحدة، فيستحاب له فيه، فهو تارك له على الدوام إلا مرة أو مرتين، وهذا خطأ كبير جدًا، فالدعاء كالطعام -ولا أقول كالدواء- يحتاجه المرء في كل يوم مرات، ومواظبة النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " في كل يوم وفي كل حال "}, {"t": "emphasis", "s": "يوافقه على الدعاء", "role": "emphasis"}, {"t": "text", "s": " يعني هذا المعنى."}]}, {"type": "paragraph", "md": "كلما خرجت من بيتك تحتاجه، وكلما استيقظت من نومك تحتاجه، وكلما خفت وتعبت تحتاجه، وكلما احتجت أتيته، وهكذا هو في كل يوم: يدعى مرارًا؛ فمِن غير هذا لا يحصل لك في يومك مطلبك، كدعاء السجود في قيام الليل: (اللهم اجعل في قلبي نورًا..) الحديث.", "page": 295, "id": "unit-26__lesson-03__b06", "inline": [{"t": "text", "s": "كلما خرجت من بيتك تحتاجه، وكلما استيقظت من نومك تحتاجه، وكلما خفت وتعبت تحتاجه، وكلما احتجت أتيته، وهكذا هو في كل يوم: يدعى مرارًا؛ فمِن غير هذا لا يحصل لك في يومك مطلبك، كدعاء السجود في قيام الليل: "}, {"t": "emphasis", "s": "(اللهم اجعل في قلبي نورًا..)", "role": "emphasis"}, {"t": "text", "s": " الحديث."}]}, {"type": "paragraph", "md": "ودعاؤك كثيرًا: ﴿رَبَّنَآ ءَاتِنَا فِي ٱلدُّنۡيَا حَسَنَةٗ وَفِي ٱلۡأٓخِرَةِ حَسَنَةٗ وَقِنَا عَذَابَ ٱلنَّارِ ۝٢٠١﴾ ودعاؤك: (يا مقلب القلوب ثبت قلبي على دينك) ودعاء: (اللهم إني أسألك اليقين والعافية)، وهكذا؛ فالدعاء كالطعام: له مدته، تحتاجه كل يوم وفي كل يوم مرات حتى يتحقق لك مطلبك في كل يوم وفي كل لحظة، فانتبه لهذا.", "page": 295, "id": "unit-26__lesson-03__b07", "inline": [{"t": "text", "s": "ودعاؤك كثيرًا: "}, {"t": "ayah", "s": "رَبَّنَآ ءَاتِنَا فِي ٱلدُّنۡيَا حَسَنَةٗ وَفِي ٱلۡأٓخِرَةِ حَسَنَةٗ وَقِنَا عَذَابَ ٱلنَّارِ ۝٢٠١", "ayah": [201], "verses": [{"n": 201, "text": "رَبَّنَآ ءَاتِنَا فِي ٱلدُّنۡيَا حَسَنَةٗ وَفِي ٱلۡأٓخِرَةِ حَسَنَةٗ وَقِنَا عَذَابَ ٱلنَّارِ", "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:201", "surah_name": "البقرة", "ayah_canonical": 201, "match": "contained", "ref": "2:201"}], "surah": null, "ref_api": null}, {"t": "text", "s": " ودعاؤك: "}, {"t": "emphasis", "s": "(يا مقلب القلوب ثبت قلبي على دينك)", "role": "emphasis"}, {"t": "text", "s": " ودعاء: "}, {"t": "emphasis", "s": "(اللهم إني أسألك اليقين والعافية)", "role": "emphasis"}, {"t": "text", "s": "، وهكذا؛ فالدعاء كالطعام: له مدته، تحتاجه كل يوم وفي كل يوم مرات حتى يتحقق لك مطلبك في كل يوم وفي كل لحظة، فانتبه لهذا."}]}, {"type": "paragraph", "md": "وأهلك وبيتك وأبناؤك يحتاجون الدعاء منك كل يوم؛ فالله يقول عن عباده: ﴿وَعِبَادُ ٱلرَّحۡمَٰنِ﴾، ويصفهم بقوله: ﴿وَٱلَّذِينَ يَقُولُونَ رَبَّنَا هَبۡ لَنَا مِنۡ أَزۡوَٰجِنَا وَذُرِّيَّٰتِنَا قُرَّةَ أَعۡيُنٖ وَٱجۡعَلۡنَا لِلۡمُتَّقِينَ إِمَامًا ۝٧٤﴾، و﴿يَقُولُونَ﴾ دال على التكرار والكثرة حتى وصفوا بهذا الفعل.", "page": 295, "id": "unit-26__lesson-03__b08", "inline": [{"t": "text", "s": "وأهلك وبيتك وأبناؤك يحتاجون الدعاء منك كل يوم؛ فالله يقول عن عباده: "}, {"t": "ayah", "s": "وَعِبَادُ ٱلرَّحۡمَٰنِ", "ayah": [], "verses": [{"n": 63, "text": "وَعِبَادُ ٱلرَّحۡمَٰنِ", "surah": 25, "surah_name": "الفرقان", "ref": "25:63", "ref_api": "https://api.quran.com/api/v4/verses/by_key/25:63"}], "surah": 25, "ref_api": "https://api.quran.com/api/v4/verses/by_key/25:63", "surah_name": "الفرقان", "ayah_canonical": 63, "match": "contained", "ref": "25:63"}, {"t": "text", "s": "، ويصفهم بقوله: "}, {"t": "ayah", "s": "وَٱلَّذِينَ يَقُولُونَ رَبَّنَا هَبۡ لَنَا مِنۡ أَزۡوَٰجِنَا وَذُرِّيَّٰتِنَا قُرَّةَ أَعۡيُنٖ وَٱجۡعَلۡنَا لِلۡمُتَّقِينَ إِمَامًا ۝٧٤", "ayah": [74], "verses": [{"n": 74, "text": "وَٱلَّذِينَ يَقُولُونَ رَبَّنَا هَبۡ لَنَا مِنۡ أَزۡوَٰجِنَا وَذُرِّيَّٰتِنَا قُرَّةَ أَعۡيُنٖ وَٱجۡعَلۡنَا لِلۡمُتَّقِينَ إِمَامًا", "surah": 25, "ref_api": "https://api.quran.com/api/v4/verses/by_key/25:74", "surah_name": "الفرقان", "ayah_canonical": 74, "match": "exact", "ref": "25:74"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، و"}, {"t": "ayah", "s": "يَقُولُونَ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": " دال على التكرار والكثرة حتى وصفوا بهذا الفعل."}]}, {"type": "paragraph", "md": "والمرء لا يطلب مطلق الولد، بل الصالحون يطلبون ولدًا بصفة يحبونها، ويحبها الله تعالى، كما قال زكريا عليه السلام : ﴿قَالَ رَبِّ هَبۡ لِي مِن لَّدُنكَ ذُرِّيَّةٗ طَيِّبَةًۖ﴾؛ فهي مقيدة بهذا الوصف الجميل ﴿ذُرِّيَّةٗ طَيِّبَةًۖ﴾، فكان يحيى عليه السلام . وهذا أبو الأنبياء عليه السلام يقول ﴿رَبِّ ٱجۡعَلۡنِي مُقِيمَ ٱلصَّلَوٰةِ وَمِن ذُرِّيَّتِيۚ رَبَّنَا وَتَقَبَّلۡ دُعَآءِ ۝٤٠﴾؛ فهو يدعو لذريته بإقامة الصلاة، وهذا سؤال لنا: كم مرة دعونا بهذا الدعاء؟، وتذكروا أن أبناءه كانوا يقيمون الصلاة، فهو دعاء للاستمرار والمواظبة، كما يدعو لنفسه بهذا المعنى.", "page": 296, "id": "unit-26__lesson-03__b09", "inline": [{"t": "text", "s": "والمرء لا يطلب مطلق الولد، بل الصالحون يطلبون ولدًا بصفة يحبونها، ويحبها الله تعالى، كما قال زكريا "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " : "}, {"t": "ayah", "s": "قَالَ رَبِّ هَبۡ لِي مِن لَّدُنكَ ذُرِّيَّةٗ طَيِّبَةًۖ", "ayah": [], "verses": [{"n": 38, "text": "قَالَ رَبِّ هَبۡ لِي مِن لَّدُنكَ ذُرِّيَّةٗ طَيِّبَةًۖ", "surah": 3, "surah_name": "آل عمران", "ref": "3:38", "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:38"}], "surah": 3, "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:38", "surah_name": "آل عمران", "ayah_canonical": 38, "match": "contained", "ref": "3:38"}, {"t": "text", "s": "؛ فهي مقيدة بهذا الوصف الجميل "}, {"t": "ayah", "s": "ذُرِّيَّةٗ طَيِّبَةًۖ", "ayah": [], "verses": [{"n": 38, "text": "ذُرِّيَّةٗ طَيِّبَةًۖ", "surah": 3, "surah_name": "آل عمران", "ref": "3:38", "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:38"}], "surah": 3, "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:38", "surah_name": "آل عمران", "ayah_canonical": 38, "match": "contained", "ref": "3:38"}, {"t": "text", "s": "، فكان يحيى "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " . وهذا أبو الأنبياء "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " يقول "}, {"t": "ayah", "s": "رَبِّ ٱجۡعَلۡنِي مُقِيمَ ٱلصَّلَوٰةِ وَمِن ذُرِّيَّتِيۚ رَبَّنَا وَتَقَبَّلۡ دُعَآءِ ۝٤٠", "ayah": [40], "verses": [{"n": 40, "text": "رَبِّ ٱجۡعَلۡنِي مُقِيمَ ٱلصَّلَوٰةِ وَمِن ذُرِّيَّتِيۚ رَبَّنَا وَتَقَبَّلۡ دُعَآءِ", "surah": 14, "ref_api": "https://api.quran.com/api/v4/verses/by_key/14:40", "surah_name": "ابراهيم", "ayah_canonical": 40, "match": "exact", "ref": "14:40"}], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ فهو يدعو لذريته بإقامة الصلاة، وهذا سؤال لنا: كم مرة دعونا بهذا الدعاء؟، وتذكروا أن أبناءه كانوا يقيمون الصلاة، فهو دعاء للاستمرار والمواظبة، كما يدعو لنفسه بهذا المعنى."}]}, {"type": "paragraph", "md": "لا يوجد باب أعظم من الدعاء لصلاح الأولاد والأهل، ومن ظن أن دعا عشرات المرات لهم كاف ليتحقق منه معنى الداعي لهم فهو مخطيء، بل هو كل ليلة، وهذا أقل القليل.", "page": 296, "id": "unit-26__lesson-03__b10"}, {"type": "paragraph", "md": "وندعو لهم بالمغفرة ليحصل لهم الصلاح ﴿وَأَصۡلِحۡ لِي فِي ذُرِّيَّتِيٓۖ﴾ كما يدعو الصالحون.", "page": 296, "id": "unit-26__lesson-03__b11", "inline": [{"t": "text", "s": "وندعو لهم بالمغفرة ليحصل لهم الصلاح "}, {"t": "ayah", "s": "وَأَصۡلِحۡ لِي فِي ذُرِّيَّتِيٓۖ", "ayah": [], "verses": [{"n": 15, "text": "وَأَصۡلِحۡ لِي فِي ذُرِّيَّتِيٓۖ", "surah": 46, "surah_name": "الأحقاف", "ref": "46:15", "ref_api": "https://api.quran.com/api/v4/verses/by_key/46:15"}], "surah": 46, "ref_api": "https://api.quran.com/api/v4/verses/by_key/46:15", "surah_name": "الأحقاف", "ayah_canonical": 15, "match": "contained", "ref": "46:15"}, {"t": "text", "s": " كما يدعو الصالحون."}]}, {"type": "paragraph", "md": "وإياك والدعاء عليه، حتى بإمرار الكلام على لسانك، واضبط نفسك عند الغضب عليه، واجعل تنفيس غضبك بالدعاء له لا عليه، ومن المشهور عن رجلٍ شكى لابن المبارك عقوق ابنه، فسأله: أدعوت عليه؟، قال: نعم! قال ابن المبارك: أنت أفسدته.", "page": 296, "id": "unit-26__lesson-03__b12"}, {"type": "paragraph", "md": "والفضيل بن عياض اشتهر عنه دعاءه الكثير لابنه، ويقول فيه: اجتهدت في تربية ابني فلم أقدر، فربه أنت لي.. وأكثر من ذاك حتى أصابه خير الدعاء.", "page": 296, "id": "unit-26__lesson-03__b13"}, {"type": "paragraph", "md": "وفي الحديث: (لا تدعوا على أبنائكم)، ودعاء الوالدين مستجاب فادع لهم بخير ورحمة.", "page": 296, "id": "unit-26__lesson-03__b14", "inline": [{"t": "text", "s": "وفي الحديث: "}, {"t": "emphasis", "s": "(لا تدعوا على أبنائكم)", "role": "emphasis"}, {"t": "text", "s": "، ودعاء الوالدين مستجاب فادع لهم بخير ورحمة."}]}, {"type": "paragraph", "md": "والدعاء بالصلاح يعني حب الصلاح نفسه، والناس يدعون بالثراء والغنى وطول العمر، لأن هذا هو المقدم عندهم، ولو كانت الصلاة عظيمة في نفوسهم لدعوا الله أن يكونوا وأهلهم من أهلها.. اعلم أن أعظم سبل التربية هو الدعاء.", "page": 296, "id": "unit-26__lesson-03__b15", "inline": [{"t": "text", "s": "والدعاء بالصلاح يعني حب الصلاح نفسه، والناس يدعون بالثراء والغنى وطول العمر، لأن هذا هو المقدم عندهم، ولو كانت الصلاة عظيمة في نفوسهم لدعوا الله أن يكونوا وأهلهم من أهلها.. اعلم أن "}, {"t": "emphasis", "s": "أعظم سبل التربية هو الدعاء.", "role": "emphasis"}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 296, "id": "unit-26__lesson-03__b16", "role": "assessment"}, {"type": "paragraph", "md": "1- ما أثر الدعاء للأولاد في في صلاحهم وقربهم من الله تعالى وحسن تربيتهم؟", "page": 296, "id": "unit-26__lesson-03__b17", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- اشرح هذا الحديث: (لا تدعوا على أبنائكم) ودلل عليه من الآثار الواردة عن السلف.", "page": 296, "id": "unit-26__lesson-03__b18", "inline": [{"t": "text", "s": "2- اشرح هذا الحديث: "}, {"t": "emphasis", "s": "(لا تدعوا على أبنائكم)", "role": "emphasis"}, {"t": "text", "s": " ودلل عليه من الآثار الواردة عن السلف."}], "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط حواري دعوي", "page": 296, "id": "unit-26__lesson-03__b19", "role": "activity"}, {"type": "paragraph", "md": "1- جاء في الحديث أن (الدعاء هو العبادة..) بين معناه، وأثر الدعاء في الصلاح والفساد.", "page": 296, "id": "unit-26__lesson-03__b20", "inline": [{"t": "text", "s": "1- جاء في الحديث أن "}, {"t": "emphasis", "s": "(الدعاء هو العبادة..)", "role": "emphasis"}, {"t": "text", "s": " بين معناه، وأثر الدعاء في الصلاح والفساد."}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- يسن التزام الدعاء بما ورد في القرآن والسنة؛ اجمعي لنا عشرة أدعية وردت في القرآن والسنة.", "page": 296, "id": "unit-26__lesson-03__b21", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-26__lesson-03';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-04','unit-26',4,'مراعاة ذكاء الطفل واحترام الزوج
نصيحةٌ للزوجِ..','الأسرة والمرأة',NULL,0,0,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 297, "id": "unit-26__lesson-04__b01", "role": "objectives"}, {"type": "paragraph", "md": "1- التعرف على أحوال الأطفال وتنوعهم في الذكاء وأثر ذلك في حسن تربيتهم.", "page": 297, "id": "unit-26__lesson-04__b02", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- بيان سلبيات احتقار الأم أو الأب أمام الأطفال وأثر ذلك السلبي على الأسرة.", "page": 297, "id": "unit-26__lesson-04__b03", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "أهمية سلوك الأبوين في بناء الأسرة:", "page": 297, "id": "unit-26__lesson-04__b04", "role": "section"}, {"type": "paragraph", "md": "مراعاة ذكاء الطفل أصل في فهم بنائه الخلقي، وكل ظن ولو يسير أن الطفل غير ذكي في موضوع المراقبة والملاحظة والتمثل بما يراه ويسمعه: جهل وغلط، بل يجب اعتبار ذكائه واهتمامه.. الطفل عنده والده وأمه أعظم الخلق، وهم أجدر بالتمثل والأسوة، ومن أمراض الآباء والأمهات تصرفهم كأحرار أو صغار، والمرء لا تهرم نفسه، بل تبقى تشتهي وتطلب وتتمنى، وهذه حالة صبيانية، فيجب ردعها وتقييدها، وعدم متابعتها، وهذا نوع مجاهدة في الله تعالى، والمرء لا يحس في نفسه وهو أب ووالد وكذا الأم كما كان يعرف من نفسه وهو ينظر لوالده وأمه، وأنهم كل الحياة، بل يظن أن ابنه يظنه صديقًا مقاربًا له في النفس والسلوك، وهذا من الوهم الذي يحب الحذر منه.", "page": 297, "id": "unit-26__lesson-04__b05"}, {"type": "paragraph", "md": "الوالد كبير في نظر أبنائه، وكذا الأم، فيجب مراعاة سلوكه كأهم ما يكون، وكما تحذر الأم وهي ترضع طفلها من طعام يؤذيه يدخل إليه من خلال لبنها فكذلك يجب الحذر من أخلاق لا يحبونها من أنفسهم تسري إلى ابنهم وابنتهم.", "page": 297, "id": "unit-26__lesson-04__b06"}, {"type": "paragraph", "md": "الصراخ بين الزوجين مدمر لتوازن الطفل، والخصومات التي يدركها الابن حتى وهي صامتة كذلك هي مدمرة وساحقه لتوازنه وسلوكه، ولذلك يجب قطعها تمامًا من البيت بين الزوجين.. كل الخصومات والتنافر بين الزوجين هي أمراض مهلكة للطفل، وأعظم ما يصنع توازن الطفل هو الاحترام المتبادل بين الزوجين.", "page": 297, "id": "unit-26__lesson-04__b07"}, {"type": "paragraph", "md": "إياك أن تحقر زوجتك أبدًا، لا أمام الأولاد ولا خلفهم، وللأسف هذا خلق منتشر بين الأزواج في بلاد المسلمين، وهو احتقار وتقليل الشأن من الزوج للزوجة.. والزوجة لسوئها تحقر زوجها إن غاب، وتتكلم فيه كلام السوء أمام أولادها، وتصفه بأقذر الألقاب والصفات، وهذا من الزوجين مدمر للإنسان الذي هو ابنهم وابنتهم.", "page": 298, "id": "unit-26__lesson-04__b08"}, {"type": "paragraph", "md": "إنشاء الطرف والنكات التي تسخر من الزوجة سوء خلق فاسد، يجب على الزوج تركه أبدًا، بل يجب احترامها كأعظم إنسان، فهي من تخدمك وتقوم بطعامك وشرابك، وتربي أولادك، وتحفظ عرضك، فالزوجة قيمة عظيمة هي من أهم قيم الحياة، وتحقيرها دمار لها، وهي ستبادلك هذا الفعل حين تكثر منه، فإن ذكرت أمامها بعيدًا عنك في غيبتك قالت فيك الشر ثم تقوى فتبادلك السب بالسب، والنتيجة ابن سيء الخلق، غير متوازن.", "page": 298, "id": "unit-26__lesson-04__b09"}, {"type": "paragraph", "md": "انتبه لنفسك: لا تذم طعاما لزوجتك، فإن أعجبك فكل وإلا اتركه كما كان يفعل الحبيب صلى الله عليه وسلم . لا تذم ما هو اختصاص لها، فإن قصرت نبهت بحب واحترام وتقدير، فهناك قضايا هي لها كداخل البيت ونظافته والمطبخ، فهذه مملكتها، فلا تدمرها على رأسها، دون أن تحترم ضعفها وحاجتها لرعايتك وحبك وتقديرك ونصحك.", "page": 298, "id": "unit-26__lesson-04__b10", "inline": [{"t": "emphasis", "s": "انتبه لنفسك", "role": "emphasis"}, {"t": "text", "s": ": لا تذم طعاما لزوجتك، فإن أعجبك فكل وإلا اتركه كما كان يفعل الحبيب "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " . لا تذم ما هو اختصاص لها، فإن قصرت نبهت بحب واحترام وتقدير، فهناك قضايا هي لها كداخل البيت ونظافته والمطبخ، فهذه مملكتها، فلا تدمرها على رأسها، دون أن تحترم ضعفها وحاجتها لرعايتك وحبك وتقديرك ونصحك."}]}, {"type": "paragraph", "md": "بعض الرجال يكتب عليهم الإثم وهم لا يشعرون، ومثاله: ضرب الابن بلا سبب تربوي، بل هو تنفيس غضب، فهذا ضرب آثم لا يجوز، فلا يعني كونه ابنك أن لك الحق مطلقًابضربه، وإغضابك في شهواتك ليس سببًا شرعيا لضربك له، بل لا بد من سبب شرعي مجيز للضرب الصحيح الملائم، وكذا سوء القول في الزوجة والولد، فسبه وسبها إثم، وتحقيرها كذلك، وإيذاؤها معصية، كما من المعاصي أن تؤذيك هي: (لا تؤذوا المسلمين).", "page": 298, "id": "unit-26__lesson-04__b11", "inline": [{"t": "emphasis", "s": "بعض الرجال يكتب عليهم الإثم وهم لا يشعرون، ومثاله:", "role": "emphasis"}, {"t": "text", "s": " ضرب الابن بلا سبب تربوي، بل هو تنفيس غضب، فهذا ضرب آثم لا يجوز، فلا يعني كونه ابنك أن لك الحق مطلقًابضربه، وإغضابك في شهواتك ليس سببًا شرعيا لضربك له، بل لا بد من سبب شرعي مجيز للضرب الصحيح الملائم، وكذا سوء القول في الزوجة والولد، فسبه وسبها إثم، وتحقيرها كذلك، وإيذاؤها معصية، كما من المعاصي أن تؤذيك هي: "}, {"t": "emphasis", "s": "(لا تؤذوا المسلمين)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ومن الإيذاء تهديدها بالزواج، حتى كأن الزواج من الثانية عقاب لها لسوء خلقها، وليس لإباحة الشارع له؛ فالذين يتخذون التهديد بالزواج أو جعل الكلام فيه سبب إيذاء لها جريمة في الشرع، إذ فيه إيذاء على معنى نيته، وفيه كذلك تقبيح لما أحله الله في نفس الناس والزوجة، وكأنه عقوبة أو حد من حدود الله يعاقب به العاصي، وهو ليس كذلك .", "page": 299, "id": "unit-26__lesson-04__b12"}, {"type": "paragraph", "md": "حديث الرجل عن قبح زوجته، إما كذبًا أو تعليقًا، فهذا إفساد للاحترام والمحبة، وسبب الخصومات التي تفسد النساء، فهذه الزوجة التي أنجبت لك الأولاد كيف لك أن تقارنها ببنت صغيرة قد بلغت لتوها، قد أثمت بالنظر إليها، وأثمت باشتهائها، وأثمت بوصفها لغيرك حتى زوجتك، أقول كيف تقارنها بمن عاشت معك وصبرت عليك وخدمتك وجاءت لك بالولد؟.", "page": 299, "id": "unit-26__lesson-04__b13"}, {"type": "paragraph", "md": "بعض الرجال كسفاهة الأطفال، لا يعرف قيمة ما في يده، ويشتهي كل شيء لا يملكه، حتى إذا ملكه ذهبت قيمته.", "page": 299, "id": "unit-26__lesson-04__b14"}, {"type": "paragraph", "md": "كيف لهذا السفيه أن يعير زوجته بمرضها إذا مرضت، أو بتعبها إذا تعبت، وبحالها العجيب وهي حامل أو فيها ما في النساء من طبائع؟!", "page": 299, "id": "unit-26__lesson-04__b15"}, {"type": "paragraph", "md": "(إنما هن عوان عندكم) يا الله، كم هي عظيمة هذه الكلمة النبوية، تثير في قلب الرجل العظيم الحب والرأفة والشفقة، فيحسن منه لها القول والفعل والمصاحبة.", "page": 299, "id": "unit-26__lesson-04__b16", "inline": [{"t": "emphasis", "s": "(إنما هن عوان عندكم)", "role": "emphasis"}, {"t": "text", "s": " يا الله، كم هي عظيمة هذه الكلمة النبوية، تثير في قلب الرجل العظيم الحب والرأفة والشفقة، فيحسن منه لها القول والفعل والمصاحبة."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 299, "id": "unit-26__lesson-04__b17", "role": "assessment"}, {"type": "paragraph", "md": "1- كيف نراعي ذكاء الطفل ونحسب حسابًا لأقوالنا وأفعالنا أمامه؛ بيني ذلك باستفاضة.", "page": 299, "id": "unit-26__lesson-04__b18", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- اشرحي هذا الحديث: (إنما هن عوانٍ عندكم) ودللي عليه كما جاء في الشرغ.", "page": 299, "id": "unit-26__lesson-04__b19", "inline": [{"t": "text", "s": "2- اشرحي هذا الحديث: "}, {"t": "emphasis", "s": "(إنما هن عوانٍ عندكم)", "role": "emphasis"}, {"t": "text", "s": " ودللي عليه كما جاء في الشرغ."}], "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط حواري دعوي", "page": 299, "id": "unit-26__lesson-04__b20", "role": "activity"}, {"type": "paragraph", "md": "1- تجلس المراة مع زوجها ومع بعض كبيرات السن أو الخبيرات في التربية، ونسأل عن آليات مراعاة ذكاء الطفل، ثم ننقل التجربة للأخوات معنا في الحلقة ونستفيد من تلاقح الأفكار.", "page": 299, "id": "unit-26__lesson-04__b21", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- كيف نحرصُ على تنمية ذكاء الأطفال وقدراتهم العقلية.. ثمة أساليب كثيرة لهذا؛ كتعويدهم على استقبال الضيوف، وشراء الأغراض للبيت.. نذكر خمسة أمور مثل ذلك.", "page": 299, "id": "unit-26__lesson-04__b22", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-26__lesson-04';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-05','unit-26',5,'بناء الطفل المقاوم للفساد','الأسرة والمرأة',NULL,0,0,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 300, "id": "unit-26__lesson-05__b01", "role": "objectives"}, {"type": "paragraph", "md": "التعرف على واقع المجتمع، وآليات صناعة المسلم المقاوم للفساد الأخلاقي والاجتماعي والعقدي.", "page": 300, "id": "unit-26__lesson-05__b02"}, {"type": "heading", "level": 3, "text": "ظاهرة تفلت أبناء الملتزمين:", "page": 300, "id": "unit-26__lesson-05__b03", "role": "section"}, {"type": "paragraph", "md": "من الظواهر المؤلمة: ظاهرة أبناء المتدينين، وانحرافهم عما رباهم عليه آباؤهم في الصغر.. فما العلاج؟!", "page": 300, "id": "unit-26__lesson-05__b04"}, {"type": "paragraph", "md": "الآباء المتدينون يعتنون بأبنائهم في الصغر؛ فيحرصون على حفظهم للقرآن، ويجنبونهم المدارس السيئة، ويحاولون تربيتهم كأحسن ما يكون، ثم بعد اقتراب البلوغ يخرجون لهذه الحياة فيبدأ انهيارهم وتغيرهم، وهذا يحصل مع كثيرين، حتى استحقت اسم «الظاهرة»؛ مما يؤلم الآباء، ويكون فجور هؤلاء في بعض مظاهره وصوره وأحواله أكثر من غيرهم، وهذا أمر يستحق التفكر والنظر، وبحث السبل التي تمنعه.", "page": 300, "id": "unit-26__lesson-05__b05", "inline": [{"t": "text", "s": "الآباء المتدينون يعتنون بأبنائهم في الصغر؛ فيحرصون على حفظهم للقرآن، ويجنبونهم المدارس السيئة، ويحاولون تربيتهم كأحسن ما يكون، ثم بعد اقتراب البلوغ يخرجون لهذه الحياة فيبدأ انهيارهم وتغيرهم، وهذا يحصل مع كثيرين، حتى استحقت اسم "}, {"t": "quote", "s": "الظاهرة"}, {"t": "text", "s": "؛ مما يؤلم الآباء، ويكون فجور هؤلاء في بعض مظاهره وصوره وأحواله أكثر من غيرهم، وهذا أمر يستحق التفكر والنظر، وبحث السبل التي تمنعه."}]}, {"type": "paragraph", "md": "مما لا شك فيه أن البيئة سيئة، والمجتمعات فقدت الدين والخلق في شوارعها ومدارسها وتجمعاتها، والمعاصي مبذولة ظاهرة، والشيطان في مجتمعاتنا له الغلبة فيما هو ظاهر، والشاب فيه غرائز، وفيها قوة، وهو ضعيف بسبب قوة الغرائز أمام هذه الشهوات، فيسقط، ولذلك جاء في الحديث مع ضعف فيه: (عجب ربنا لشاب ليس له صبوة)، وهذا لأن الشهوة غالبة على امرئٍ قوي الهوى، ضعيف التجربة، قليل الحكمة، فاقد للتجارب.. فهذا حال لا ينكر، ولكن لا يجوز لنا الاستسلام بتسويغ هذا السقوط والتغير.", "page": 300, "id": "unit-26__lesson-05__b06", "inline": [{"t": "text", "s": "مما لا شك فيه أن البيئة سيئة، والمجتمعات فقدت الدين والخلق في شوارعها ومدارسها وتجمعاتها، والمعاصي مبذولة ظاهرة، والشيطان في مجتمعاتنا له الغلبة فيما هو ظاهر، والشاب فيه غرائز، وفيها قوة، وهو ضعيف بسبب قوة الغرائز أمام هذه الشهوات، فيسقط، ولذلك جاء في الحديث مع ضعف فيه: "}, {"t": "emphasis", "s": "(عجب ربنا لشاب ليس له صبوة)", "role": "emphasis"}, {"t": "text", "s": "، وهذا لأن الشهوة غالبة على امرئٍ قوي الهوى، ضعيف التجربة، قليل الحكمة، فاقد للتجارب.. فهذا حال لا ينكر، ولكن لا يجوز لنا الاستسلام بتسويغ هذا السقوط والتغير."}]}, {"type": "paragraph", "md": "يمكن أن نفسر بعض هذه الظاهرة بطرقنا غير الصحيحة في تربية الأولاد؛ فالمدارس الدينية تفقد جانب اللهو المباح، والسعة التي توجد في غيرها، فالحرمان التام يصنع الجوع الشديد، ثم في أول الطريق يتم الانفلات والهروب وهو السقوط، ولذلك نجد الشباب الذي ينشؤون في مدارس فيها سعة من اللهو والفرح والمتعة التي يحتاجها الطفل يقل خروجهم عن جادة الدين بعد ذلك.", "page": 300, "id": "unit-26__lesson-05__b07", "inline": [{"t": "text", "s": "يمكن أن نفسر بعض هذه الظاهرة بطرقنا غير الصحيحة في تربية الأولاد؛ "}, {"t": "emphasis", "s": "فالمدارس الدينية تفقد جانب اللهو المباح، والسعة التي توجد في غيرها", "role": "emphasis"}, {"t": "text", "s": "، فالحرمان التام يصنع الجوع الشديد، ثم في أول الطريق يتم الانفلات والهروب وهو السقوط، ولذلك نجد الشباب الذي ينشؤون في مدارس فيها سعة من اللهو والفرح والمتعة التي يحتاجها الطفل يقل خروجهم عن جادة الدين بعد ذلك."}]}, {"type": "paragraph", "md": "وهذا المعنى الذي نقوله عن المدارس والمؤسسات الدينية نقوله في بيوت المتدينين؛ فبعض البيوت يقوم أصحابها عليها بالمنع المطلق والحرمان التام لكل سعة من مباحات، وهي في قلبها تؤدي إلى كرهها ومحاولة الخروج منها، حتى إذا جاءت الفرصة حصل ما نكره.. وهذا يدل على جهل هؤلاء، وعدم مراعاتهم البيئة وما فيها من صور مغرية.", "page": 300, "id": "unit-26__lesson-05__b08"}, {"type": "paragraph", "md": "وبعضهم يحتج بقلة ذات اليد، والصحيح هو قلة العقل، وسوء التصرف، وإلا فتحقيق بعض السعة المباحة مقدور عليه بأقل القليل.. ويمكن تفسير هذه الظاهرة بسوء خلق المتدينين من آباء ومدرسين، وهذا نراه حتى في مساجدنا من غلظة وسوء خلق في التعامل مع الأطفال، والحياة مليئة بالمغريات، فهو عرض لصورتين: إحداهما دين مع عصا وعقوبات وصراخ وألم وتهديد وعبوس وجه، والثانية: بسمات ومرح وفرح وشهوات تختلط مع المعاصي والتفلت من الطاعة، والبون شاسع بينهما، والمعركة تدور حول شاب مسكين، شهواته أقوى من عقله.", "page": 301, "id": "unit-26__lesson-05__b09", "inline": [{"t": "emphasis", "s": "وبعضهم يحتج بقلة ذات اليد", "role": "emphasis"}, {"t": "text", "s": "، والصحيح هو قلة العقل، وسوء التصرف، وإلا فتحقيق بعض السعة المباحة مقدور عليه بأقل القليل.. ويمكن تفسير هذه الظاهرة بسوء خلق المتدينين من آباء ومدرسين، وهذا نراه حتى في مساجدنا من غلظة وسوء خلق في التعامل مع الأطفال، والحياة مليئة بالمغريات، فهو عرض لصورتين: إحداهما دين مع عصا وعقوبات وصراخ وألم وتهديد وعبوس وجه، والثانية: بسمات ومرح وفرح وشهوات تختلط مع المعاصي والتفلت من الطاعة، والبون شاسع بينهما، والمعركة تدور حول شاب مسكين، شهواته أقوى من عقله."}]}, {"type": "paragraph", "md": "كل هذا موجود، لكن هناك قضية أراها مهمة، وهي ضرورية حتى لو وجد حسن تربية من المؤسسة والمدرسة والبيت من جهتين: البيئة والقائمين عليها، وهي تتعلق بطريقة تربية الأبناء، وما هي الصيغة التي نتعامل معهم فيها، وما هو مطلبنا منهم؟! وهذا المطلب يحدد طريقة صياغتنا لمعلوماتنا ونحن نلقيها عليهم، وأعتقد أن ما ينبغي علينا بناءه فيهم هو المسلم المقاوم.", "page": 301, "id": "unit-26__lesson-05__b10"}, {"type": "paragraph", "md": "نحن لا نعيش بيئة مسالمة، وهي صفة تدل على الخير الكثير، والشر كامن مخفي مستتر، لا يصل الناس إليه إلا ببحث وتنقيب، وهي بيئة يصلح معها ما سماه علماؤنا بالعزلة، إذ يمكن للمرء فيها أن يحصل عزلة جزئية تقوي عنده الطاعات الخاصة، والدين المميز والعلم الكثير.", "page": 301, "id": "unit-26__lesson-05__b11", "inline": [{"t": "emphasis", "s": "نحن لا نعيش بيئة مسالمة", "role": "emphasis"}, {"t": "text", "s": "، وهي صفة تدل على الخير الكثير، والشر كامن مخفي مستتر، لا يصل الناس إليه إلا ببحث وتنقيب، وهي بيئة يصلح معها ما سماه علماؤنا بالعزلة، إذ يمكن للمرء فيها أن يحصل عزلة جزئية تقوي عنده الطاعات الخاصة، والدين المميز والعلم الكثير."}]}, {"type": "paragraph", "md": "والكثير منا يبني طفله من خلال هذه الرؤية، فهو يعيش حالة عزلة عن المجتمع، لعقله وتدينه، ويريد لطفله أن يعيشها كذلك.. وهذا يمكن إذا كان الشر مستترًا، مخفيًا، لا يصل إليه أحد إلا بطلبه، لكنك اليوم تعيش جاهلية مهاجمة، حاضرة، داعية، مبذولة، ولها سلطان وجنود ودعاة، فكيف تحصل هذه العزلة الجزئية في الطفل المسكين.. فما الحل إذًا؟!", "page": 301, "id": "unit-26__lesson-05__b12"}, {"type": "paragraph", "md": "في ظني أننا بحاجة لصناعة الطفل المهاجم والمقاوم لهذه البيئة حتى نحصل شابا مهديًا.. تذكر دائما أن أعظم التربية التي تحصلها لطفلك تكون بالدعاء، فإن لم يهد الله ابنك فلن تهديه بكل الطرق التي تتقفرها سعيا منك، فاحرص على الدعاء في كل يوم، ومرات كثيرة في اليوم الواحد ما قدرت.", "page": 301, "id": "unit-26__lesson-05__b13"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 301, "id": "unit-26__lesson-05__b14", "role": "assessment"}, {"type": "paragraph", "md": "1- هل الحل في اعتزال المجتمع أم مقاومته.. وضحي. 2- الحرمان من أسباب الفساد؛ وضحي!", "page": 301, "id": "unit-26__lesson-05__b15", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "heading", "level": 3, "text": "نشاط حواري بحثي", "page": 301, "id": "unit-26__lesson-05__b16", "role": "activity"}, {"type": "paragraph", "md": "جاء في الحديث أن مخالطة الناس والصبر على أذاهم أفضل من اعتزالهم؛ اذكري الحديث وبيني أثره في التربية", "page": 301, "id": "unit-26__lesson-05__b17", "item_role": "activity_step"}]' WHERE id='unit-26__lesson-05';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-06','unit-26',6,'مخالط مقاوم.. خير من معتزل','الأسرة والمرأة',NULL,0,2,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 302, "id": "unit-26__lesson-06__b01", "role": "objectives"}, {"type": "paragraph", "md": "التعرف على آلية صانعة الطفل المقاوم للجاهلية في ظل المجتمع المليء بالفساد.", "page": 302, "id": "unit-26__lesson-06__b02"}, {"type": "heading", "level": 3, "text": "تربية الأولاد على مقاومة الجاهلية:", "page": 302, "id": "unit-26__lesson-06__b03", "role": "section"}, {"type": "paragraph", "md": "أغلبنا يعيش مع أبنائه من خلال موقف الحذر، وتجنيبه فساد المجتمع ومشكلات الأفكار الجاهلية؛ فسلوكنا محكوم بهذه النظرة مع أبنائنا، وهذا ما أظن أنه يحتاج لتقويم وتغيير .", "page": 302, "id": "unit-26__lesson-06__b04"}, {"type": "paragraph", "md": "مما لا شك فيه أن مرحلة التكوين تحتاج لبناء الحق في نفس الطفل، لتصلح سدًا أمام الفساد، والحديث يدور حول كيفية الحق هذا، وأنا أتكلم عن مرحلة الطفل المميز، حين تبدأ أفكاره وعقليته بالتشكل، وما نحتاجه أن نُعلِّمه الباطلَ كما نعلمه الحق.", "page": 302, "id": "unit-26__lesson-06__b05"}, {"type": "paragraph", "md": "مما ينبغي أن نوجده في نفس الفتى في هذه الفترة: أن يعرف الباطل، ويعرض عليه، ويتكلم عنه بصراحة، وذلك من خلال عرضه أمامه كعدو حقيقي يجب مقاتلته ومواجهته، وذلك من خلال طريقة القرآن في عرض الباطل والرد عليه وتحقيره؛ فهو موجود قدري لا انفكاك لنا منه، والهروب ليس حلًا، والاكتفاء بتعليم الحق دون تعرية الجاهلية من جهتيها الشهوات والشبهات.", "page": 302, "id": "unit-26__lesson-06__b06"}, {"type": "paragraph", "md": "ما نمارسه هو أننا نعلمه القرآن والحديث مع حذر من سماع الباطل، وهو معروض بشدة خارج قاعة الدرس، ورغم أنوفنا يصل إليه بعض ريحه، وبعض أثره، ونفس الطفل تواقة، تحب اللعب واللهو، والتكاليف عليه شاقة شديدة، لم يتدرب على تنمية إرادته، وهذا حله بفتح باب اللعب المباح، واللهو الذي لا يخالف الشرع، ولكن ما تعلق بالمعاصي الفكرية والسلوكية يجب عرضها من خلال الرد العلمي عليها ومن خلال تحقيرها.", "page": 302, "id": "unit-26__lesson-06__b07"}, {"type": "paragraph", "md": "من أسباب السقوط: المفاجأة التي تحصل في حياة الفتى، فتأتيه الأفكار التي لم يسمع بها من قبل، وتعرض عليه الشهوات وهو ضعيف في معرفة آثارها السيئة، وبالتالي يقع السقوط من خلال ضعف التحصين في المواجهة، والطريق المؤدي للمخرج أن نعرض عليه الباطل في الأفكار وخاصة الإلحادية بالعلم والعرض الموافق لقدراته العقلية، وذكر أسماء المذاهب ورجالها، وهذا يحتاج لوضع علوم الرد على الشبهات الذي يلائم نفسية الفتيان.", "page": 303, "id": "unit-26__lesson-06__b08", "inline": [{"t": "emphasis", "s": "من أسباب السقوط:", "role": "emphasis"}, {"t": "text", "s": " المفاجأة التي تحصل في حياة الفتى، فتأتيه الأفكار التي لم يسمع بها من قبل، وتعرض عليه الشهوات وهو ضعيف في معرفة آثارها السيئة، وبالتالي يقع السقوط من خلال ضعف التحصين في المواجهة، والطريق المؤدي للمخرج أن نعرض عليه الباطل في الأفكار وخاصة الإلحادية بالعلم والعرض الموافق لقدراته العقلية، وذكر أسماء المذاهب ورجالها، وهذا يحتاج لوضع علوم الرد على الشبهات الذي يلائم نفسية الفتيان."}]}, {"type": "paragraph", "md": "وهذا شيء ربما نفقد الكمية اللازمة لملء الفراغ، وقليل جدًا في حالتنا الإسلامية.", "page": 303, "id": "unit-26__lesson-06__b09"}, {"type": "paragraph", "md": "ومن ذلك تعليمهم المناظرات للمخالفين من الزنادقة، وكيفية مواجهتهم، وهذا يصنع حالة استعلاء في نفس الفتى، كما يصنع حالة عداء لهذه الأفكار، وهذا ما قصدته من المسلم المقاتل.", "page": 303, "id": "unit-26__lesson-06__b10"}, {"type": "paragraph", "md": "دائما كنت أفكر في سبب كثرة عرض القرآن لما جرى في السماء بين آدم وإبليس، ووجدت أن أعظم مقاصد هذا العرض هو صناعة العداء بين بني آدم وإبليس، وهذه الحالة ضرورية في بناء النفسية التي تقاوم المعصية، باعتبار المعصية حالة هزيمة، وبها يتم انتصار الشيطان عليك، فالقضية هي معركة بينك وبين عدو قذر شرس، لك معه تجربة أدت بهذه النتيجة من خروجه من الجنة: ﴿إِنَّ ٱلشَّيۡطَٰنَ لَكُمۡ عَدُوّٞ فَٱتَّخِذُوهُ عَدُوًّاۚ﴾، ﴿يَٰبَنِيٓ ءَادَمَ لَا يَفۡتِنَنَّكُمُ ٱلشَّيۡطَٰنُ كَمَآ أَخۡرَجَ أَبَوَيۡكُم مِّنَ ٱلۡجَنَّةِ﴾.", "page": 303, "id": "unit-26__lesson-06__b11", "inline": [{"t": "text", "s": "دائما كنت أفكر في سبب كثرة عرض القرآن لما جرى في السماء بين آدم وإبليس، ووجدت أن أعظم مقاصد هذا العرض هو صناعة العداء بين بني آدم وإبليس، وهذه الحالة ضرورية في بناء النفسية التي تقاوم المعصية، باعتبار المعصية حالة هزيمة، وبها يتم انتصار الشيطان عليك، فالقضية هي معركة بينك وبين عدو قذر شرس، لك معه تجربة أدت بهذه النتيجة من خروجه من الجنة: "}, {"t": "ayah", "s": "إِنَّ ٱلشَّيۡطَٰنَ لَكُمۡ عَدُوّٞ فَٱتَّخِذُوهُ عَدُوًّاۚ", "ayah": [], "verses": [{"n": 6, "text": "إِنَّ ٱلشَّيۡطَٰنَ لَكُمۡ عَدُوّٞ فَٱتَّخِذُوهُ عَدُوًّاۚ", "surah": 35, "surah_name": "فاطر", "ref": "35:6", "ref_api": "https://api.quran.com/api/v4/verses/by_key/35:6"}], "surah": 35, "ref_api": "https://api.quran.com/api/v4/verses/by_key/35:6", "surah_name": "فاطر", "ayah_canonical": 6, "match": "contained", "ref": "35:6"}, {"t": "text", "s": "، "}, {"t": "ayah", "s": "يَٰبَنِيٓ ءَادَمَ لَا يَفۡتِنَنَّكُمُ ٱلشَّيۡطَٰنُ كَمَآ أَخۡرَجَ أَبَوَيۡكُم مِّنَ ٱلۡجَنَّةِ", "ayah": [], "verses": [{"n": 27, "text": "يَٰبَنِيٓ ءَادَمَ لَا يَفۡتِنَنَّكُمُ ٱلشَّيۡطَٰنُ كَمَآ أَخۡرَجَ أَبَوَيۡكُم مِّنَ ٱلۡجَنَّةِ", "surah": 7, "surah_name": "الأعراف", "ref": "7:27", "ref_api": "https://api.quran.com/api/v4/verses/by_key/7:27"}], "surah": 7, "ref_api": "https://api.quran.com/api/v4/verses/by_key/7:27", "surah_name": "الأعراف", "ayah_canonical": 27, "match": "contained", "ref": "7:27"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "هذا ما نحتاج بناءه مع أبنائنا:", "page": 303, "id": "unit-26__lesson-06__b12", "inline": [{"t": "emphasis", "s": "هذا ما نحتاج بناءه مع أبنائنا:", "role": "emphasis"}]}, {"type": "paragraph", "md": "نكشف لهم الحياة كما هي، ونحرضهم من خلال تاريخ الجاهلية المعاصر، فيحصل كرهه والاستعلاء عليه، وكذا تحقيره وتحقير أهله.", "page": 303, "id": "unit-26__lesson-06__b13"}, {"type": "paragraph", "md": "وهذا هو مدخلنا لتحصينه وحصول المناعة لديه من جهة الأفكار الحاضرة، وكذا هو لتحصينه - ما قدرنا ووسعنا - أمام الشهوات.", "page": 303, "id": "unit-26__lesson-06__b14"}, {"type": "paragraph", "md": "الهجوم خير وسيلة للدفاع، والبيان يطرد الشيطان، فيجب علينا أن لا نترك شيئًا في نفس الطفل يقع على وجه المفاجأة، فهذه المفاجأة تحقق لحظات الإضطراب وهي أسرع طريقة للسقوط، وأمثل طريقة للشيطان في تحصيله المراد من عدوه الإنسان، والمطلوب منع هذه المفاجأة.", "page": 303, "id": "unit-26__lesson-06__b15", "inline": [{"t": "emphasis", "s": "الهجوم خير وسيلة للدفاع", "role": "emphasis"}, {"t": "text", "s": "، والبيان يطرد الشيطان، فيجب علينا أن لا نترك شيئًا في نفس الطفل يقع على وجه المفاجأة، فهذه المفاجأة تحقق لحظات الإضطراب وهي أسرع طريقة للسقوط، وأمثل طريقة للشيطان في تحصيله المراد من عدوه الإنسان، والمطلوب منع هذه المفاجأة."}]}, {"type": "paragraph", "md": "نحن لا نعيش بيئة صالحة، وليست حالة المجتمع مما يعيننا في شيء، ومجتمعاتنا الإسلامية وصلت عوامل النخر والتدمير إلى عمقها، وهذا قد تم من خلال الزمن والتخطيط والقوانين والقوة، ومبدأ هذا الحال هو أن الناجين من سلطان هذه الجاهلية الأخلاقية هم النخبة والصفوة، ولا يتم مواجهتها إلا من خلال القليل الذي نصنعه في بيوتنا؛ أقصد المتدينين، ومن نستطيع استخلاصه من هذه المجتمعات، ولذلك ما نطلبه هو تدين خاص لهذه النخبة، ومعنى النخبة لا يتحقق إلا بكونها قادرة على الهجوم، وليس العزلة والهروب.", "page": 304, "id": "unit-26__lesson-06__b16"}, {"type": "paragraph", "md": "البيئات الصالحة، وهي موجودة في بعض المناطق الإسلامية في الهوامش هي التي نكتفي فيها بعرض الحق في الأفكار، وعدم إثارة سبل الشهوات وقنواتها، لكن المناطق التي اهتمت الجاهلية بحرفها منذ احتلال نابليون لمصر، فصار همهم صناعة المجتمعات الإسلامية بلا دين ونشر العلمانية لا استعمارها فقط، فاهتموا بتركيا ومصر وبلاد الشام والعراق وبلاد المغرب الإسلامي،فهذه المناطق لا تصلح لها العزلة، ولا ما كان في معناها من عزل الفتى عنها خوفًا من ملامستها والإقتراب منها، بل ما يصلح هو المواجهة، ليكون المسلم جنديا مقاتلًا لهذه الجاهلية..", "page": 304, "id": "unit-26__lesson-06__b17"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 304, "id": "unit-26__lesson-06__b18", "role": "assessment"}, {"type": "paragraph", "md": "1- لماذا يكثر القرآن الكريم من ذكر قصة آدم وموسى.. بيني أثر ذلك في التربية.", "page": 304, "id": "unit-26__lesson-06__b19", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- هل نستطيع غض نظرنا عن الجاهلية ومظاهرها من التبرج والكفر والقوانين الوضعية.. إن كان الجواب بلا؛ فما هي السبل لتحصين أولادنا من ألا يقعوا في حبائلها كما تعلمناه في الدرس؟", "page": 304, "id": "unit-26__lesson-06__b20", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- «الهجوم خير وسيلة للدفاع» هل لهذه القاعدة أثر في حفظ أولادنا من الفساد؟! بيني ذلك.", "page": 304, "id": "unit-26__lesson-06__b21", "inline": [{"t": "text", "s": "3- "}, {"t": "quote", "s": "الهجوم خير وسيلة للدفاع"}, {"t": "text", "s": " هل لهذه القاعدة أثر في حفظ أولادنا من الفساد؟! بيني ذلك."}], "item_role": "question", "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "نشاط حواري بحثي", "page": 304, "id": "unit-26__lesson-06__b22", "role": "activity"}, {"type": "paragraph", "md": "1- نرجع إلى كتاب «أبناء الملتزمين.. توريث الالتزام؛ آباء تهوى وأبناء تأبى» الذي يعالج ظاهرة انحراف أبناء الملتزمين، ونوزعه فيما بيننا، ونتدارس أسباب علاج هذه الظاهرة.", "page": 304, "id": "unit-26__lesson-06__b23", "inline": [{"t": "text", "s": "1- نرجع إلى كتاب "}, {"t": "quote", "s": "أبناء الملتزمين.. توريث الالتزام؛ آباء تهوى وأبناء تأبى"}, {"t": "text", "s": " الذي يعالج ظاهرة انحراف أبناء الملتزمين، ونوزعه فيما بيننا، ونتدارس أسباب علاج هذه الظاهرة."}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- يربي الطفل في الزمان الحالي كثر غيرنا؛ مثل المدرسة، والهاتف، والأصدقاءـ، والشارع.. ما هي السبل التي تجعلنا نضمن أن هذه الوسائل لن تربي أولادنا على الفساد؟!", "page": 304, "id": "unit-26__lesson-06__b24", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-26__lesson-06';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-07','unit-26',7,'تعرية الجاهلية.. تصنع التربية','الأسرة والمرأة',NULL,1,2,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 305, "id": "unit-26__lesson-07__b01", "role": "objectives"}, {"type": "paragraph", "md": "- بيان حقيقة الجاهلية أمام الأطفال وأثر ذلك في تربيتهم، وكيف نصنع صورة الحق أمامهم؟", "page": 305, "id": "unit-26__lesson-07__b02", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "كيف نعري الجاهلية أمام أبنائنا؟!", "page": 305, "id": "unit-26__lesson-07__b03", "role": "section"}, {"type": "paragraph", "md": "عن المستظل بن حصين البارقى قال: «خطبنا عمر بن الخطاب فقال: قد علمت ورب الكعبة متى تهلك العرب، فقام رجل من المسلمين إليه فقال: متى يا أمير المؤمنين؟ قال: حين يسوس أمرهم من لم يعالج أمر الجاهلية ولم يصحب الرسول صلى الله عليه وسلم »، واشتهر بلفظ: «تنتقض عرى الإسلام عروة عروة إذا نشأ في الإسلام من لم يعرف الجاهلية».. أعتقد أن هذا شعار المرحلة، وواقع الحال أن عمق المرء في معرفة الباطل دليل على ثقته بالحق الذي عليه رسول الله صلى الله عليه وسلم .", "page": 305, "id": "unit-26__lesson-07__b04", "inline": [{"t": "text", "s": "عن المستظل بن حصين البارقى قال: "}, {"t": "quote", "s": "خطبنا عمر بن الخطاب فقال: قد علمت ورب الكعبة متى تهلك العرب، فقام رجل من المسلمين إليه فقال: متى يا أمير المؤمنين؟ قال: حين يسوس أمرهم من لم يعالج أمر الجاهلية ولم يصحب الرسول صلى الله عليه وسلم"}, {"t": "text", "s": "، واشتهر بلفظ: "}, {"t": "hadith", "s": "تنتقض عرى الإسلام عروة عروة إذا نشأ في الإسلام من لم يعرف الجاهلية", "narrator": "المستظل بن حصين البارقى", "source": "مسلم", "confidence": "high", "ref_api": null}, {"t": "text", "s": ".. أعتقد أن هذا شعار المرحلة، وواقع الحال أن عمق المرء في معرفة الباطل دليل على ثقته بالحق الذي عليه رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "حين تعرض على أبنائنا أمراض المعاصي التي تحياها البشرية، ونبدأ بكشفها ابتداءً من مادية الأمراض التي تسري بسببها إلى أمراض القلوب حتى خواتيم الخلق يوم القيامة، فإن هذا من العلم بالجاهلية، وعلم بعواقبها، وهذا العلم ينشيء النفرة منها والكراهية لها، ومن ثم الإعراض عنها ومقاومتها.", "page": 305, "id": "unit-26__lesson-07__b05"}, {"type": "paragraph", "md": "التجريد لا ينفع مع الأطفال؛ لأنه فوق مستواهم، بل لا بد من مثل مادية حاضرة، ولذلك لا بد من مناهج تتحدث عن ماديات الفساد وآثاره العملية على الإنسان والحياة، ويجب على الدعاة امتلاكها، ثم يرتفع الحديث من المثل المنصوبة للعيان إلى التجريد، ذلك لأن التجريد إنما هو للكبار ممن يعقلونها بتصوراتهم العالية من خلال التربية والترقي.", "page": 305, "id": "unit-26__lesson-07__b06"}, {"type": "paragraph", "md": "والمقصود بالتجريد: الحديث عن المعاني؛ مما يتعلق بالذهن والتصور، كالحديث عن المعقولات والعقائد الغيبية، فهذا مرتبة تالية بالنسبة للأطفال والأبناء، ونحن في كثير من أعمالنا نجابهه بالتجريد فيسهل مسحها ومجابهتها بعد ذلك، لكن لو بنيت على المثل المنصوبة ابتداءً كما يمثل القرآن للمعاني بها كما مثل للمنافق بالمثل المائي والناري كما في سورة البقرة ﴿مَثَلُهُمۡ كَمَثَلِ ٱلَّذِي ٱسۡتَوۡقَدَ نَارٗا﴾، ومثَّل للكفر ونوعيه بقوله في سورة الحج: ﴿فَتَخۡطَفُهُ ٱلطَّيۡرُ أَوۡ تَهۡوِي بِهِ ٱلرِّيحُ فِي مَكَانٖ سَحِيقٖ ۝٣١﴾، وذلك في كفر الحيرة وكفر القرار على معنى منه.", "page": 305, "id": "unit-26__lesson-07__b07", "inline": [{"t": "text", "s": "والمقصود بالتجريد: الحديث عن المعاني؛ مما يتعلق بالذهن والتصور، كالحديث عن المعقولات والعقائد الغيبية، فهذا مرتبة تالية بالنسبة للأطفال والأبناء، ونحن في كثير من أعمالنا نجابهه بالتجريد فيسهل مسحها ومجابهتها بعد ذلك، لكن لو بنيت على المثل المنصوبة ابتداءً كما يمثل القرآن للمعاني بها كما مثل للمنافق بالمثل المائي والناري كما في سورة البقرة "}, {"t": "ayah", "s": "مَثَلُهُمۡ كَمَثَلِ ٱلَّذِي ٱسۡتَوۡقَدَ نَارٗا", "ayah": [], "verses": [{"n": 17, "text": "مَثَلُهُمۡ كَمَثَلِ ٱلَّذِي ٱسۡتَوۡقَدَ نَارٗا", "surah": 2, "surah_name": "البقرة", "ref": "2:17", "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:17"}], "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:17", "surah_name": "البقرة", "ayah_canonical": 17, "match": "contained", "ref": "2:17"}, {"t": "text", "s": "، ومثَّل للكفر ونوعيه بقوله في سورة الحج: "}, {"t": "ayah", "s": "فَتَخۡطَفُهُ ٱلطَّيۡرُ أَوۡ تَهۡوِي بِهِ ٱلرِّيحُ فِي مَكَانٖ سَحِيقٖ ۝٣١", "ayah": [31], "verses": [{"n": 31, "text": "فَتَخۡطَفُهُ ٱلطَّيۡرُ أَوۡ تَهۡوِي بِهِ ٱلرِّيحُ فِي مَكَانٖ سَحِيقٖ", "surah": 22, "ref_api": "https://api.quran.com/api/v4/verses/by_key/22:31", "surah_name": "الحج", "ayah_canonical": 31, "match": "contained", "ref": "22:31"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، وذلك في كفر الحيرة وكفر القرار على معنى منه."}]}, {"type": "paragraph", "md": "وهذا يدل أن الإنسان يتعقل أكثر بالمثل المنصوبة الحاضرة، وهي طريق تحصيل المعاني العالية العلمية والذهنية. وهذا ما يجب أن نتعامل به مع أبنائنا، وذلك بإحضار صور الباطل وفساده ونتائجه؛ ففيلم واحد يؤثر فيهم أكثر من دروس متعددة، كفيلم عن المجاهدين أو عن إجرام الكافرين، أو عن أمراض الزنا أو شرب الخمر، وكم من مجاهد نفر لأرض الجهاد بشريط كجحيم الروس مثلًا؟!", "page": 306, "id": "unit-26__lesson-07__b08"}, {"type": "paragraph", "md": "بالنسبة للواقع ومجابهته ومصادمة الجاهلية فإن ما يصنعه هو الواقع نفسه، وهذا ما يجب إحضاره نموذجًا تربويا في تحصين أبنائنا ضد الجاهلية؛ الصورة عوالم مهمة في صناعة الإنسان، والكفار يفهمون هذا جيدًا، ولذلك يعتنون به أشد العناية، وأثر الصورة أطول زمنًا من غيرها كالكلمات والمواعظ.", "page": 306, "id": "unit-26__lesson-07__b09", "inline": [{"t": "emphasis", "s": "بالنسبة للواقع ومجابهته ومصادمة الجاهلية فإن ما يصنعه هو الواقع نفسه، وهذا ما يجب إحضاره نموذجًا تربويا في تحصين أبنائنا ضد الجاهلية؛", "role": "emphasis"}, {"t": "text", "s": " الصورة عوالم مهمة في صناعة الإنسان، والكفار يفهمون هذا جيدًا، ولذلك يعتنون به أشد العناية، وأثر الصورة أطول زمنًا من غيرها كالكلمات والمواعظ."}]}, {"type": "paragraph", "md": "تجميل صورة الدين وأهله، ونشر صور الحق والهدى، وتقبيح أهل الشرك والمعاصي من خلال الصورة والمثال فن عميق وقدرات وصل أهل الدعاية فيه مبلغًا عجيبًا لا يستهين به إلا الجهلة، وما الناس اليوم بأفكارهم ورؤاهم إلا صناعة الصور لا الكتب ولا المواعظ.", "page": 306, "id": "unit-26__lesson-07__b10", "inline": [{"t": "emphasis", "s": "تجميل صورة الدين وأهله", "role": "emphasis"}, {"t": "text", "s": "، ونشر صور الحق والهدى، وتقبيح أهل الشرك والمعاصي من خلال الصورة والمثال فن عميق وقدرات وصل أهل الدعاية فيه مبلغًا عجيبًا لا يستهين به إلا الجهلة، وما الناس اليوم بأفكارهم ورؤاهم إلا صناعة الصور لا الكتب ولا المواعظ."}]}, {"type": "paragraph", "md": "فعرض الجاهلية على أبنائنا مهم، ولذلك لما سمعت أن جماعة ما منعت النت في المنطقة التي تسيطر عليها علمت مقدار الجهل فينا؛ فكأن عالمنا اليوم عالم صلاح وتقوى، والفساد طارئ ومحصور، فنحن نصنع الحماية لأمتنا منه.. هذا وهم وجهل، وتطبيق لنصائح من علمائنا لا يعيشون واقعنا، ولا يعرفون حال المتدينين وغربتهم، وبالتالي نصنع بهذه الطرق نماذج هشة، تكسر بمجرد اختلاف البيئة عليها.", "page": 306, "id": "unit-26__lesson-07__b11"}, {"type": "paragraph", "md": "لقد رأيت الشباب المسلم المتدين في الغرب أقوى وأصلب من غيره في كره الجاهلية، ويعرفها أكثر من أهل بلادنا، ويهاجمها بوعي وقوة وعلم، وما ذلك إلا لهذا المعنى الذي ذكرته، وهذا لا يعني عدم وجود أمراض خاصة بالمتدينين هناك، ولكن القصد عرض الصورتين في قضية مواجهة الباطل والجاهلية.", "page": 306, "id": "unit-26__lesson-07__b12"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 306, "id": "unit-26__lesson-07__b13", "role": "assessment"}, {"type": "paragraph", "md": "1- هل منع النت هو الحل مع أبنائنا؟ أم السماح لهم به مع ترشيدهم للصواب فيه؟!", "page": 306, "id": "unit-26__lesson-07__b14", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- عرض الجاهلية وفسادها على أبنائنا.. لأجل محاربتها؛ مهم للغاية.. وضحي ذلك كما مر معك.", "page": 306, "id": "unit-26__lesson-07__b15", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط حواري بحثي", "page": 306, "id": "unit-26__lesson-07__b16", "role": "activity"}, {"type": "paragraph", "md": "نرجع إلى بعض الشروحات لحديث: «تنتنقض عرى الإسلام عروة عروة..» ونفهمه على وجهه", "page": 306, "id": "unit-26__lesson-07__b17", "inline": [{"t": "text", "s": "نرجع إلى بعض الشروحات لحديث: "}, {"t": "quote", "s": "تنتنقض عرى الإسلام عروة عروة.."}, {"t": "text", "s": " ونفهمه على وجهه"}], "item_role": "activity_step"}]' WHERE id='unit-26__lesson-07';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-08','unit-26',8,'تعليم الأولاد في المدارس النظامية','الأسرة والمرأة',NULL,0,1,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 307, "id": "unit-26__lesson-08__b01", "role": "objectives"}, {"type": "paragraph", "md": "- إصلاح بعض المفاهيم المغلوطة في العملية التعليمية النظامية.", "page": 307, "id": "unit-26__lesson-08__b02", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "هل ندرس أبناءنا في المدارس النظامية.. أم نعتزلها؟!", "page": 307, "id": "unit-26__lesson-08__b03", "role": "section"}, {"type": "paragraph", "md": "مما لا شك فيه أن الجواب هنا يقوم على المقاربة؛ فالشر والخير يتداخلان، ويتنازعان في موطن واحد، إذ الواقع قدر لا يتجاوزه المرء إلا بالمواجهة والتعامل معه ضمن خير الخيرين وشر الشرين، وكذا البحث عن مآلات التصرفات خاصة حين تضطرد وتصبح ظاهرة لا تخفى؛ أقصد المآلات للفتوى والإختيار.", "page": 307, "id": "unit-26__lesson-08__b04"}, {"type": "paragraph", "md": "ونحن هنا أمام حالة لا يمكن تحصيل الخير إلا ببعض شر، وهذا إن أمكن الاستغناء عن هذا الخير ولم يكن واجبًا وضروريا ترك لعدم إصابة الشر، لكن إن كان الخير واجبًا وضروريًا وجب الموازنة بينه وبين الشر؛ فبعض الجواهر في زماننا مكانها الذي استقرت فيه كالعذرة في نجاسته وقذارته، فأنت مضطر لإحضار هذه الجمرة، والتلبس بالنجاسة حينا والاستغفار ليزول أثرها.", "page": 307, "id": "unit-26__lesson-08__b05"}, {"type": "paragraph", "md": "نحن هنا لا نتحدث عن بيئة يمكن تحصيل الخير من الدين وعلومه مع بقاء المرء سويًا في حياته ومسيرتها؛ كبعض البلاد التي ينشأ فيها علماء، ويمكن لهم بعد ذلك الذهاب لعلوم الصناعات وتحصيل سبل حياتهم لها، بل حديثنا عن بلاد توجب الحياة فيها الدخول في مسارات تعليم للصناعات، تنازع التعليم الديني تمامًا، ولا يمكن للمرء أن يستقر له سبل عيش إلا من خلالها.", "page": 307, "id": "unit-26__lesson-08__b06"}, {"type": "paragraph", "md": "ثم إننا نتحدث عن فتوى تلائم الأمة، وليس الحديث عن واحد واثنين أو عشرة وعشرين، يخلصان للتعليم الديني السليم، ولا يؤثر خروجهم على علم الصناعات في حياة البشر، والقيام بالواجب الكفائي لها.", "page": 307, "id": "unit-26__lesson-08__b07"}, {"type": "paragraph", "md": "فمثلًا، يرى بعض الآباء أن الخير لابنه أن يخرجه للتعليم الديني فقط، غير ملزم للناس هذا الطريق، محبة لأن يسلك ابنه هذا الطريق، وقيامه على ما هو ضعيف في حياتنا المعاصرة من قلة الاهتمام بالتعليم الديني في بيئات إسلامية ما، مع أن هذا قليل، فالمتعلمون دينيا كثيرون والحمد لله.", "page": 307, "id": "unit-26__lesson-08__b08"}, {"type": "paragraph", "md": "الفتوى العامة لا تصلح ما يصلح للقلة؛ فهجران المدارس المعاصرة من عموم الأمة غير سديد، ويترتب عليه مفاسد، ولإصلاح المفاسد في هذه المدارس يكون بإيجاد البدائل، وهذا طريق طويل، ويحتاج لزمن حتى يستوي على سوقه، ومثله إصلاح نظام التعليم، وهذا طريق انتظار حتى تصلح نظم الحكم في بلادنا وتكون بيد الصالحين.. والأمر الأول من إيجاد البدائل قام به صالحون كثيرون من قديم، لكنه إما يقضى عليه من مسالحة الطواغيت وجنود إبليس، وإما يعوق كثيرًا ليحقق هدفه، وإما يحرف ويبدل من خلال النظم والقوانين والتشديد.", "page": 308, "id": "unit-26__lesson-08__b09"}, {"type": "paragraph", "md": "فنظام التعليم الذي يتعلق بعموم الأمة قضية كبيرة، وتحتاج لصبر، وربما تبذل جهودًا عظيمة حتى يكون لها بعض أثر فيأتي جنود إبليس فينهونها في لحظات، وهذا أمر مشهود.. من هنا وجبت المقاربة، ووجب الاعتناء اليوم بالأبناء أكثر من أي ظرف آخر، لأن شرور المناهج التعليمية في بلادنا كثير، ونظم الإدارة فاسد ومعوق... العزل لا ينفع، حتى لو عزلناه من مدارس التعليم المعاصر لهذه المفاسد فالمجتمع أكثر فسادًا من هذه المدارس، والحارات وشبابها مليئة بذلك، ووسائل الإعلام كذلك، وشبكات النت باب من الشر أوسع من محيطات العالم.. ماذا نفعل إذًا؟!", "page": 308, "id": "unit-26__lesson-08__b10"}, {"type": "paragraph", "md": "الجواب: هو أن نحصنهم لا نعزلهم، وأن ننشيء لديهم المناعة لا مجرد الوقاية، فهذا هو الطريق.", "page": 308, "id": "unit-26__lesson-08__b11", "inline": [{"t": "emphasis", "s": "الجواب: هو أن نحصنهم لا نعزلهم، وأن ننشيء لديهم المناعة لا مجرد الوقاية، فهذا هو الطريق.", "role": "emphasis"}]}, {"type": "paragraph", "md": "كلامي للعموم: ليعش ابنك هذه الحياة فهي قدرنا الذي إن نجونا منه من جهة أصابنا بحقيقته ومصائبه من جهات أخرى متعددة، ولذلك فليس الحل منع شبابنا من التنفس لانتشار الجراثيم والأوبئة، ولكن الحل أن يعيشوا هذه المجتمعات وصناعة المناعة فيهم.", "page": 308, "id": "unit-26__lesson-08__b12", "inline": [{"t": "text", "s": "كلامي للعموم: "}, {"t": "emphasis", "s": "ليعش ابنك هذه الحياة فهي قدرنا الذي إن نجونا منه من جهة أصابنا بحقيقته ومصائبه من جهات أخرى متعددة", "role": "emphasis"}, {"t": "text", "s": "، ولذلك فليس الحل منع شبابنا من التنفس لانتشار الجراثيم والأوبئة، ولكن الحل أن يعيشوا هذه المجتمعات وصناعة المناعة فيهم."}]}, {"type": "paragraph", "md": "لا أريد أن أتحدث عن أمراض المدارس الدينية، فهذا شيء نعرفه، سواء تعلق بالأسلوب في التعليم أو نوع العلوم التي يتلقونها، أو البيئة التي يعيش فيها الطلاب هناك، فهي لا تصلح لمواجهة هذه الجاهلية الشرسة، ولا يحفظ بها إلا القلة من الناس، والذين هم نخبة وقلة.. ليعيشوا في هذه الحياة، ونشرح لهم الشر، ونكشف لهم الغلط، ونعري لهم الباطل، وليتعلموا كيف لا يخافون من الشر، بل يواجهونه.", "page": 308, "id": "unit-26__lesson-08__b13"}, {"type": "paragraph", "md": "الشر يجتنب ما اجتنبنا، لكنه يحاربنا، ويتسلل إلينا بمكر وخبث، فالعزلة عنه هزيمة، وتركه دون مواجهة بقوة وشجاعة يعني انتصاره، وهذا ضد دين الله ﴿وَإِمَّا تَخَافَنَّ مِن قَوۡمٍ خِيَانَةٗ فَٱنۢبِذۡ إِلَيۡهِمۡ عَلَىٰ سَوَآءٍۚ﴾.", "page": 308, "id": "unit-26__lesson-08__b14", "inline": [{"t": "text", "s": "الشر يجتنب ما اجتنبنا، لكنه يحاربنا، ويتسلل إلينا بمكر وخبث، فالعزلة عنه هزيمة، وتركه دون مواجهة بقوة وشجاعة يعني انتصاره، وهذا ضد دين الله "}, {"t": "ayah", "s": "وَإِمَّا تَخَافَنَّ مِن قَوۡمٍ خِيَانَةٗ فَٱنۢبِذۡ إِلَيۡهِمۡ عَلَىٰ سَوَآءٍۚ", "ayah": [], "verses": [{"n": 58, "text": "وَإِمَّا تَخَافَنَّ مِن قَوۡمٍ خِيَانَةٗ فَٱنۢبِذۡ إِلَيۡهِمۡ عَلَىٰ سَوَآءٍۚ", "surah": 8, "surah_name": "الأنفال", "ref": "8:58", "ref_api": "https://api.quran.com/api/v4/verses/by_key/8:58"}], "surah": 8, "ref_api": "https://api.quran.com/api/v4/verses/by_key/8:58", "surah_name": "الأنفال", "ayah_canonical": 58, "match": "contained", "ref": "8:58"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "هذه نصيحتي لكل أب يريد لأبنائه درجة الهداة المهديين، والصالحين والمصلحين، والله أعلم..", "page": 308, "id": "unit-26__lesson-08__b15"}, {"type": "paragraph", "md": "سؤال تقويمي: ما هو جواب سؤال الباب؛ أندخل المدارس العامة أم نتركها؟ بيني بوضوح.", "page": 308, "id": "unit-26__lesson-08__b16"}]' WHERE id='unit-26__lesson-08';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-09','unit-26',9,'مواجهة إعلام الجاهلية','الأسرة والمرأة',NULL,0,0,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 309, "id": "unit-26__lesson-09__b01", "role": "objectives"}, {"type": "paragraph", "md": "- بيان سبل مواجهة إعلام الجاهلية في واقع تربية الأطفال وأثر ذلك في تربيتهم.", "page": 309, "id": "unit-26__lesson-09__b02", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "أثر وسائل الإعلام في الفساد وكيفة مواجهة ذلك:", "page": 309, "id": "unit-26__lesson-09__b03", "role": "section"}, {"type": "paragraph", "md": "أهل الدين والتقوى في مواجهة صريحة وقاسية مع وسائل الإعلام والاتصال؛ فهي التي توجه اليوم الحياة والمجتمع، وتأثيرها هو الأشد، وكل الأفكار التي تنتشر وتقوى ويصبح لها الأتباع والدعاة ساحتها الدعوية هي هذه الوسائل، والحال أن الإسلام اليوم يفقد المنابر القوية التي تقوي الحق فوق قوته الذاتية، فالمواجهة بين حق في ذاته، لكنه ضعيف الأدوات، وبين باطل في ذاته يملك القوة والمال والتأثير، مع وجود أرضية ضعيفة من العلم أمام الشبهات، ونفسية هشة أمام الشهوات.", "page": 309, "id": "unit-26__lesson-09__b04"}, {"type": "paragraph", "md": "وعالم الإعلام بكل مكوناته الكثيرة جدًا هو بين يدي الجاهلية؛ فالدول والمؤسسات والشركات إما موجهة بذكاء إبليسي وإما تجري لتلاحق الرغبات لتجني المنافع والمال من خلال الانتشار، وهذه الرغبات حقيقتها هي المعاصي.. نحن أمام معركة شرسة، تجعل من المتدين غريبًا، ويعاني الغربة، ويعيش منعزلًا في جزر عن المجتمع الذي تنخر فيه المعاصي.", "page": 309, "id": "unit-26__lesson-09__b05", "inline": [{"t": "text", "s": "وعالم الإعلام بكل مكوناته الكثيرة جدًا هو بين يدي الجاهلية؛ فالدول والمؤسسات والشركات إما موجهة بذكاء إبليسي وإما تجري لتلاحق الرغبات لتجني المنافع والمال من خلال الانتشار، وهذه الرغبات حقيقتها هي المعاصي.. "}, {"t": "emphasis", "s": "نحن أمام معركة شرسة، تجعل من المتدين غريبًا، ويعاني الغربة، ويعيش منعزلًا في جزر عن المجتمع الذي تنخر فيه المعاصي.", "role": "emphasis"}]}, {"type": "paragraph", "md": "لا يستطيع المرء أن يضع خطة متكاملة تحقق النصر في هذه المعركة، لكن يمكن تحقيق اختراقات في هذه الآلة الجاهلية.. عالم الشهوة يقوم كثيرًا على إلغاء الواقع في عقل ونفس الناظر والمتابع، وهو مقصد إبليسي وجاهلي، والدين قضية حياة، يعني كلما ارتبط المرء بالحقيقة على وجه صحيح كلما اقترب من الحق، ولذلك فأعظم مدخل في تحصين المسلمين هو إشغالهم بقضايا الحياة، والتي تربط بسهولة مع الدين والحق الذي جاء له؛ يمكن في وقت انتشار الشهوات والثراء أن يتحقق بعض نصر للجاهلية.", "page": 309, "id": "unit-26__lesson-09__b06"}, {"type": "paragraph", "md": "لكن مجتمعاتنا تعاني الفقر وتعاني الظلم وتعاني مؤسسات الدول الفساد، وبالتالي يعيش المرء في بلادنا ظروفًا سيئة، لا تحقق نصرًا في هذه المعركة، وبالتالي يجب إبقاء حضور هذا المسلم في هذه المجتمعات في حالة وعي على واقعه؛ فإن انتصرت وسيلة الإعلام في تغييبه لساعات رجع إلى معركته التي تهمه على وجه الحقيقة.. هنا تكون الحياة وما فيها منفذًا عظيمًا للدين!", "page": 309, "id": "unit-26__lesson-09__b07"}, {"type": "paragraph", "md": "نحن نتكلم عن استقبال عوالم الظلم والجهل والفساد للصحابة والدعاة؛ فحصل إسلام أمم لما رأوا العدل والعلم والهداية في هذا الدين، فأقبلوا عليه إقبالًا شديدا، وهذا يعترف به المسلم ويقوله الكافر كذلك؛ أي أن عالم الكفر القذر هو من عرَّف الإنسان عالم الإسلام الجميل؛ فأقوى وسيلة لحماية الأمة من الفساد هو الفساد نفسه ووجوده على هذا المعنى والواقع الذي يعيشه، ولذلك يجب إبقاء حضوره في أذهان الناس لبغضهم فيه وحب الدين وشريعته.", "page": 310, "id": "unit-26__lesson-09__b08"}, {"type": "paragraph", "md": "كنت أنظر في التلفزيون إلى مؤتمر مدريد سنة١٩٩١ ميلادية، وبدا أن هناك مرحلة جديدة، يتم فيها قبول اليهود بين العرب وفي المنطقة، كان شحم تمرير هذه القضية ما يسمى بوعود السلام، يعني الرخاء والثراء والهدوء والأمان والسعادة.. ما زلت أذكر ما الذي كان يشغلني وأنا أنظر إلى خطب الحضور في هذا المؤتمر! كان يشغلني التالي: لو تحققت هذه الوعود سيكون من الصعوبة بمكان قبول الناس لدعوة الجهاد، وسيكون من المشقة التحريض الذي يمارسه داعي الجهاد، فالثراء والمتع والشهوات وحضورها مانع لقبول هذه الدعوة. لم أكن يومها أبصر مكر الله وحكمته في أن يكون الشر هو من يدمر نفسه، ولذلك فعالم الشر مع وجود الدعاة وثباتهم ووقوفهم سيكون في مألاته مقويا للخير وناشرًا للحق.", "page": 310, "id": "unit-26__lesson-09__b09"}, {"type": "paragraph", "md": "يمكن لسفاهة الشر أن تُشكر في هذا الباب!! لا ينشئ الشر بسفاهته الخير دون وجود ثبات ودعوة لأهل الحق، ولذلك فعالم الجاهلية في بلادنا من فساد هو من يجب أن يعيننا في جلب العيون للصلاح والتقوى.", "page": 310, "id": "unit-26__lesson-09__b10"}, {"type": "paragraph", "md": "وهنا نقطة مهمة: ثقتنا بأننا جند الله، وأنه ناصر دينه، وأن عوامل الحق التي تعيننا ضد سطوة وقوة الجاهلية هي أقوى مما معهم من ماديات.. تفكروا لو كان هناك ديمقراطية حقيقية في بلادنا، ونزاهة، ومقاومة فساد، وطهر وظيفي من الولاة والحكام، فكيف لك أن تكشف وجه الجاهلية؟", "page": 310, "id": "unit-26__lesson-09__b11", "inline": [{"t": "emphasis", "s": "وهنا نقطة مهمة", "role": "emphasis"}, {"t": "text", "s": ": ثقتنا بأننا جند الله، وأنه ناصر دينه، وأن عوامل الحق التي تعيننا ضد سطوة وقوة الجاهلية هي أقوى مما معهم من ماديات.. تفكروا لو كان هناك ديمقراطية حقيقية في بلادنا، ونزاهة، ومقاومة فساد، وطهر وظيفي من الولاة والحكام، فكيف لك أن تكشف وجه الجاهلية؟"}]}, {"type": "paragraph", "md": "أنت تملك مع طفلك وولدك الفطرة والتوفيق الإلهي والدعاء، فلا تيأس..", "page": 310, "id": "unit-26__lesson-09__b12"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 310, "id": "unit-26__lesson-09__b13", "role": "assessment"}, {"type": "paragraph", "md": "1- ما هي أهم وسيلة لمواجهة إعلام الجاهلية؟ اذكريها كما جاء في الدرس.", "page": 310, "id": "unit-26__lesson-09__b14", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- «أعظم مدخل لتحصين شباب المسلمين وبناتهم هو إشغالهم بواقع الحياة..» اشرحي العبارة..", "page": 310, "id": "unit-26__lesson-09__b15", "inline": [{"t": "text", "s": "2- "}, {"t": "quote", "s": "أعظم مدخل لتحصين شباب المسلمين وبناتهم هو إشغالهم بواقع الحياة.."}, {"t": "text", "s": " اشرحي العبارة.."}], "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط حواري بحثي", "page": 310, "id": "unit-26__lesson-09__b16", "role": "activity"}, {"type": "paragraph", "md": "نرجع إلى كتاب «الإعلام الإسلامي رسالة وهدف» ونذكر خمسة من فوائده في هذا الباب..", "page": 310, "id": "unit-26__lesson-09__b17", "inline": [{"t": "text", "s": "نرجع إلى كتاب "}, {"t": "quote", "s": "الإعلام الإسلامي رسالة وهدف"}, {"t": "text", "s": " ونذكر خمسة من فوائده في هذا الباب.."}], "item_role": "activity_step"}]' WHERE id='unit-26__lesson-09';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-10','unit-26',10,'أدركوا قيمة ما بين أيديكم','الأسرة والمرأة',NULL,0,0,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 311, "id": "unit-26__lesson-10__b01", "role": "objectives"}, {"type": "paragraph", "md": "- بيان أن إدراك قيمة الزواج، وقيمة الزوج والزوجة.. من أعظم ما يحافظ على بناء الأسرة.", "page": 311, "id": "unit-26__lesson-10__b02", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- ذكر أهمية القاومة في المحافظة على بناء الأسرة المسلمة.", "page": 311, "id": "unit-26__lesson-10__b03", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "رسالة ختامية مذكرة حول ضرورة احترام الزوجين لبعضهما:", "page": 311, "id": "unit-26__lesson-10__b04", "role": "section"}, {"type": "paragraph", "md": "عماد البيت الصحيح والذي ينتج أبناء متوازنين أصحاء في نفوسهم هو: قيام البيت على الاحترام والتقدير من الزوج لزوجته، وهنا لا أقول: احترام الزوجة لزوجها لأن هذا ظل وأثر من احترام الزوج لزوجته!", "page": 311, "id": "unit-26__lesson-10__b05", "inline": [{"t": "emphasis", "s": "عماد البيت الصحيح والذي ينتج أبناء متوازنين أصحاء في نفوسهم هو:", "role": "emphasis"}, {"t": "text", "s": " قيام البيت على الاحترام والتقدير من الزوج لزوجته، وهنا لا أقول: احترام الزوجة لزوجها لأن هذا ظل وأثر من احترام الزوج لزوجته!"}]}, {"type": "paragraph", "md": "قوامة الرجل شرعًا يعني أنه هو البيت، وكل تصرف تأتي به الزوجة العاقلة هو ظل عمل الزوج معها ومع البيت، وهذا لا يعني عدم وجود نساء سفيهات، كما في الرجال، لكن الزوج عادة هو الأصل.", "page": 311, "id": "unit-26__lesson-10__b06", "inline": [{"t": "emphasis", "s": "قوامة الرجل شرعًا يعني", "role": "emphasis"}, {"t": "text", "s": " أنه هو البيت، وكل تصرف تأتي به الزوجة العاقلة هو ظل عمل الزوج معها ومع البيت، وهذا لا يعني عدم وجود نساء سفيهات، كما في الرجال، لكن الزوج عادة هو الأصل."}]}, {"type": "paragraph", "md": "القوامة لا تعني فقط أن ينفق الزوج على البيت، ولا تعني فقط أن قرار الطلاق بيده، ولا تعني أنه صاحب القرار فيه؛ بل يعني أن خُلَقه هو الذي يسري في البيت، وسلوكه هو الذي يحكم حالة البيت، وأن الله ركب الزوجة بفطرتها على أن تلاحظ الزوج في كل شيء.. المرأة حين يحترمها أبناؤها لاحترام أبيهم لها، والمرأة عزيزة النفس لإعزاز زوجها لها، والمرأة تحترم من الناس لاحترام زوجها ومن يتبعه من الأولاد لها، وكل منقصة تقع على الزوجة لتخلف أخلاق الزوج في تحصيل هذه المنقصة.", "page": 311, "id": "unit-26__lesson-10__b07", "inline": [{"t": "emphasis", "s": "القوامة لا تعني فقط أن ينفق الزوج على البيت", "role": "emphasis"}, {"t": "text", "s": "، ولا تعني فقط أن قرار الطلاق بيده، ولا تعني أنه صاحب القرار فيه؛ بل يعني أن خُلَقه هو الذي يسري في البيت، وسلوكه هو الذي يحكم حالة البيت، وأن الله ركب الزوجة بفطرتها على أن تلاحظ الزوج في كل شيء.. المرأة حين يحترمها أبناؤها لاحترام أبيهم لها، والمرأة عزيزة النفس لإعزاز زوجها لها، والمرأة تحترم من الناس لاحترام زوجها ومن يتبعه من الأولاد لها، وكل منقصة تقع على الزوجة لتخلف أخلاق الزوج في تحصيل هذه المنقصة."}]}, {"type": "paragraph", "md": "ولقد خبرت حياة الزواج من نفسي ومن الناس، وراقبت باحثًا عن أعظم ما يحقق احترام الروج لزوجته فوجدته يعود لخلق عظيم، هو أساس العلم وأساس العقل وأساس الفهم، بل هو باعث الشكر لله، وباعث تقدير النعمة واعتبارها، وباعث الرضا عن الله تعالى وغير ذلك الكثير من آثار هذا الخلق، وهو عندي خلق العظماء، هذا الخلق هو: رؤية النعمة وهي بين يديك.", "page": 311, "id": "unit-26__lesson-10__b08", "inline": [{"t": "emphasis", "s": "ولقد خبرت حياة الزواج من نفسي ومن الناس، وراقبت باحثًا عن أعظم ما يحقق احترام الروج لزوجته فوجدته يعود لخلق عظيم، هو أساس العلم وأساس العقل وأساس الفهم، بل هو باعث الشكر لله، وباعث تقدير النعمة واعتبارها، وباعث الرضا عن الله تعالى وغير ذلك الكثير من آثار هذا الخلق، وهو عندي خلق العظماء، هذا الخلق هو:", "role": "emphasis"}, {"t": "text", "s": " رؤية النعمة وهي بين يديك."}]}, {"type": "paragraph", "md": "الأطفال في أعمارهم وعقولهم يشتهون كل شيء ما دام بيد الآخرين، ويتمنونه، ويسعون جهدهم في تحصيله، ويحسدون الناس عليه، حتى إذا ملكوه صار صغيرًا حقيرًا ولا قيمة له، وهذا أس سفاهة البشر.", "page": 311, "id": "unit-26__lesson-10__b09"}, {"type": "paragraph", "md": "الرجل العظيم هو من يرى عظمة الشيء وهو بين يديه، ومبذول له، ويعيش معه كل لحظة، وهذا هو سر الشكر والرضا، ومن فاته هذا الخلق مات قهرًا وحسدًا وأفسد حياته كلها.", "page": 311, "id": "unit-26__lesson-10__b10"}, {"type": "paragraph", "md": "تأمل حال الشاب وهو ذاهب للزواج من البنت، كيف يراها، وكيف يزين لها نفسه، ثم إذا حصلت عنده ذهبت عينه لغيرها، فيبدأ الفساد في البيت، فهو لا يقيم أهمية لما تصنع له، وما تكفيه من أمور حياتية وإنسانية، ولو كان ما تفعله له يعمله غريب عنه لشكره واحترمه، لكنه مع أهله كثير الصراخ، إن غضب نسي كل مكرمة من هذه التي سماها الحبيب المصطفى صلى الله عليه وسلم : (إنما هن عوان عندكم).", "page": 312, "id": "unit-26__lesson-10__b11", "inline": [{"t": "text", "s": "تأمل حال الشاب وهو ذاهب للزواج من البنت، كيف يراها، وكيف يزين لها نفسه، ثم إذا حصلت عنده ذهبت عينه لغيرها، فيبدأ الفساد في البيت، فهو لا يقيم أهمية لما تصنع له، وما تكفيه من أمور حياتية وإنسانية، ولو كان ما تفعله له يعمله غريب عنه لشكره واحترمه، لكنه مع أهله كثير الصراخ، إن غضب نسي كل مكرمة من هذه التي سماها الحبيب المصطفى "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إنما هن عوان عندكم)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "هذه العين التي تقدر ما في خارج الملك، وهي تحتقر ما هو تحت القدرة وتحت الملك هي أساس فساد العالم، وأساس ذهاب الشكر والاحترام.", "page": 312, "id": "unit-26__lesson-10__b12"}, {"type": "paragraph", "md": "ويتبع هذا الخلق تأمل الجمال في العالم، وتأمل الأخلاق، وتأمل النعمة، وتأمل الإحسان، ووالله من لا يراقب هذه القضايا مع حضورها وأهميتها وظهورها لهو أعجز من أن يكتشف حكمة قدر، أو رحمة موقف، أو إحسان محسن، والأخلاق هي أساس لا يتجزأ في الوجود: (من لم يشكر الناس لا يشكر الله).", "page": 312, "id": "unit-26__lesson-10__b13", "inline": [{"t": "text", "s": "ويتبع هذا الخلق تأمل الجمال في العالم، وتأمل الأخلاق، وتأمل النعمة، وتأمل الإحسان، ووالله من لا يراقب هذه القضايا مع حضورها وأهميتها وظهورها لهو أعجز من أن يكتشف حكمة قدر، أو رحمة موقف، أو إحسان محسن، والأخلاق هي أساس لا يتجزأ في الوجود: "}, {"t": "emphasis", "s": "(من لم يشكر الناس لا يشكر الله)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وهذا الحديث على معنيين، يشملهما في حال:", "page": 312, "id": "unit-26__lesson-10__b14"}, {"type": "paragraph", "md": "الأول: ما هو ظاهر، أن تارك شكر الناس على أخلاقهم وإنعامهم هو تارك لشكر الله تعالى، فالشكر حالة وملكة نفس، لا تتجزأ، وتحضر مع كل نعيم وإحسان، وهذا شرحته في سلسلة الأخلاق المصورة، وهي في الأرشيف، أطلب بالرجاء من الأخوة نشرها، ففيها إن شاء الله بعض منفعة بالدعوة لحسن الخلق، والذي خسرناه كثيرًا في مجتمعاتنا الخاصة والعامة.", "page": 312, "id": "unit-26__lesson-10__b15"}, {"type": "paragraph", "md": "والمعنى الثاني: أن من لم يشكر الناس فهو تارك لأمر رباني، إذ هو يأمر تعالى بشكرهم، فتارك شكر المحسنين عاص لله تعالى، وهو بهذا تارك لشكر الله.", "page": 312, "id": "unit-26__lesson-10__b16", "inline": [{"t": "emphasis", "s": "والمعنى الثاني", "role": "emphasis"}, {"t": "text", "s": ": أن من لم يشكر الناس فهو تارك لأمر رباني، إذ هو يأمر تعالى بشكرهم، فتارك شكر المحسنين عاص لله تعالى، وهو بهذا تارك لشكر الله."}]}, {"type": "paragraph", "md": "ومنبع هذا الخلق في جحد الإحسان والإنعام غشاوة على القلب في عدم مراقبة يد العطاء في الوجود، وأعظم خصال الشر في النفس البشرية، وهي مانعة من شكر المنعم هو ظن الجهل بوجود حق لك على الناس وعلى المنعمين، فهم يؤدونه، فلماذا أشكرهم!. ونسي هذا الجاهل -حتى في مسايرتنا لظنه- أن أحب الأعمال عند الله الفرائض، وهذا دليل أن أداء الواجبات التي على الناس أحق بالشكر، لأنها من ضروريات الحياة، فهي أولى بالاعتبار، ولذلك فشكرك لأمك أعظم أجرًا لهذا المعنى.", "page": 312, "id": "unit-26__lesson-10__b17"}, {"type": "paragraph", "md": "سؤال تقويمي: يُعتبر البنيان الأكبر الذي يقومُ عليه البيت: إدراك النعمة التي بين أيدينا.. وضحي!", "page": 312, "id": "unit-26__lesson-10__b18"}, {"type": "paragraph", "md": "منارات الهدى", "page": 313, "id": "unit-26__lesson-10__b19"}]' WHERE id='unit-26__lesson-10';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-11','unit-26',11,'أصول معركة الحجاب المعاصرة','الأسرة والمرأة',NULL,0,5,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "ملخصٌ من كتاب: سور العفاف", "page": 313, "id": "unit-26__lesson-11__b01", "role": "section"}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 313, "id": "unit-26__lesson-11__b02", "role": "objectives"}, {"type": "paragraph", "md": "- بيان أصول معركة الحجاب المعاصرة، وما أسموه بـ«تحرير المرأة» وإبطال أفكارهم.", "page": 313, "id": "unit-26__lesson-11__b03", "inline": [{"t": "text", "s": "- بيان أصول معركة الحجاب المعاصرة، وما أسموه بـ"}, {"t": "quote", "s": "تحرير المرأة"}, {"t": "text", "s": " وإبطال أفكارهم."}], "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "أصول معركة الإسلام مع العلمانية في تحرير المرأة:", "page": 313, "id": "unit-26__lesson-11__b04", "role": "section"}, {"type": "paragraph", "md": "بدأت حملات استعمار البلدان الإسلامية بهدف للسيطرة على كل مقدراتها، ولكنهم عرفوا أن ذلك لن يكون إلا بخلع هوية المجتمعات المسلمة، ونشر الأفكار الإباحية المخالفة للدين والفطرة، ويكون ذلك بالقهر العسكري لإجبار الناس على أن يتنازلوا عن دينهم.. وكلا الأمرين قد حصل: دعاة إلى الأفكار الهدامة، واستعمار عسكري متسلط متجبر على المسلمين يقهرهم على تغيير مبادئهم وقيمهم الإسلامية.", "page": 313, "id": "unit-26__lesson-11__b05"}, {"type": "paragraph", "md": "واستمرت دعوتهم الباطلة؛ حتى أقنعوا بعض ضعفاء النفوس بأن «التطور والحداثة» يكون بتعرية المرأة وإخراجها من بيتها ليتعدى عليها الجميع؛ فصاروا دعاة على أبواب جهنم وتأثر بهم حتى من كان من أهل الصلاح بسبب حالة الضعف الشديدة التي مرت بها الأمة الإسلامية، فطبيعة الضعيف أن يتأثر بالقوي.", "page": 313, "id": "unit-26__lesson-11__b06", "inline": [{"t": "text", "s": "واستمرت دعوتهم الباطلة؛ حتى أقنعوا بعض ضعفاء النفوس بأن "}, {"t": "quote", "s": "التطور والحداثة"}, {"t": "text", "s": " يكون بتعرية المرأة وإخراجها من بيتها ليتعدى عليها الجميع؛ فصاروا دعاة على أبواب جهنم وتأثر بهم حتى من كان من أهل الصلاح بسبب حالة الضعف الشديدة التي مرت بها الأمة الإسلامية، فطبيعة الضعيف أن يتأثر بالقوي."}]}, {"type": "paragraph", "md": "وقد بدأت هجمات الغرب وأذنابه العلمانيية بمحاربة الحجاب ومقته وتصويره بأقبح صورة؛ فيصفونه بأنه رجعية وتخلف وأن المرأة المحجبة تجلس في تابوت أسود كالجنازة المتحركة، وغيرها من الأوصاف لإضعاف المسلمين بعقيدة الحجاب، وبدؤوا بالمعركة تدريجيًا فبحثوا عن أقوال ضعيفة تجيز الخروج بالوجه والكفين للمرأة وهم يهدفون لأبعد من ذلك، لكن لا يحصل لهم هذا إلا إذا وضعوا السم بالعسل وجعلوا شربه على جرعات، ثم بعد ذلك أحدثوا في نفوس المسلمين أن التقدم الحضاري الذي يعيشه الغرب سببه تحرير المرأة وهذا لا شك أنه كذب بل هم تمسكوا بزمام السنن الكونية وعملوا بها وبالمنهج التجريبي وتقدموا دنيويًا وليس لتحرير المرأة علاقة بهذا الأمر، والناظر في تاريخ الغرب حتى مع تحضرهم لفترة قريبة دنيويًا -كما يدعون- يجدهم يعاملون المرأة على أنها مخلوق دون الإنسان، ولكن للأسف تأثر كثير من المسلمين بل والمصلحين بهذه الدعوة الكاذبة، ولا شكَّ أن دعوة الغرب هذه كانت لتدمير قيم المسلمين ونشر الرذيلة بينهم وإخراجهم من دائرة الأديان إلى دائرة الكفر والانحطاط لأجل السيطرة على مقدراتهم وبلدانهم، لا لأجل أن يتحضر المسلمون؛ فنحن أمة متحضرة بفضل الله عزوجل، والخلل الذي يحصل للمسلمين الآن ما حصل إلا من قريب من مئة وخمسين سنة تقريبًا، وإلا فقبل ذلك كنا نحكم العالم شرقًا وغربًا وكان الغرب متأثرًا بنا، لكن وقعت الأمة ببلاء الضعف والانهيار بسبب تركها أوامر الله.", "page": 314, "id": "unit-26__lesson-11__b07"}, {"type": "paragraph", "md": "والحضارة والتطور تكون بما يأمر به الإسلام فقط؛ فعندما أمر الإسلام المرأة بالحجاب فإنه يريد أن يحقق من خلال ذلك نظامًا اجتماعيا عظيمًا يصون الأعراض ويكبح جماح الشهوات ويقيدها بضوابط أخلاقية يكون في استعمالها خير الإنسان وطهارته بدل إهمالها أو تضيعها في الفوضى والهمجية.", "page": 314, "id": "unit-26__lesson-11__b08"}, {"type": "paragraph", "md": "ولا بد أن نعلم أن الغرب عندما ينشر هذه الفوضى والهمجية والسفور والفساد في أوساط المسلمين إنما يريد إشراك المرأة والرجل في تدبير شؤون الحياة وتحمل تبعات ذلك من شر مستطير واستعمال الشهوات في فنون ووسائل تُحولُ متاعب الحياة إلى لذات ومسرات؛ فلا وجه للمقارنة بين ما يدعو إليه الإسلام وما يدعو إليه الغرب قال تعالى: ﴿أُوْلَٰٓئِكَ يَدۡعُونَ إِلَى ٱلنَّارِۖ﴾، ﴿وَٱللَّهُ يَدۡعُوٓاْ إِلَىٰ دَارِ ٱلسَّلَٰمِ وَيَهۡدِي مَن يَشَآءُ إِلَىٰ صِرَٰطٖ مُّسۡتَقِيمٖ ۝٢٥﴾", "page": 314, "id": "unit-26__lesson-11__b09", "inline": [{"t": "text", "s": "ولا بد أن نعلم أن الغرب عندما ينشر هذه الفوضى والهمجية والسفور والفساد في أوساط المسلمين إنما يريد إشراك المرأة والرجل في تدبير شؤون الحياة وتحمل تبعات ذلك من شر مستطير واستعمال الشهوات في فنون ووسائل تُحولُ متاعب الحياة إلى لذات ومسرات؛ فلا وجه للمقارنة بين ما يدعو إليه الإسلام وما يدعو إليه الغرب قال تعالى: "}, {"t": "ayah", "s": "أُوْلَٰٓئِكَ يَدۡعُونَ إِلَى ٱلنَّارِۖ", "ayah": [], "verses": [{"n": 221, "text": "أُوْلَٰٓئِكَ يَدۡعُونَ إِلَى ٱلنَّارِۖ", "surah": 2, "surah_name": "البقرة", "ref": "2:221", "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:221"}], "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:221", "surah_name": "البقرة", "ayah_canonical": 221, "match": "contained", "ref": "2:221"}, {"t": "text", "s": "، "}, {"t": "ayah", "s": "وَٱللَّهُ يَدۡعُوٓاْ إِلَىٰ دَارِ ٱلسَّلَٰمِ وَيَهۡدِي مَن يَشَآءُ إِلَىٰ صِرَٰطٖ مُّسۡتَقِيمٖ ۝٢٥", "ayah": [25], "verses": [{"n": 25, "text": "وَٱللَّهُ يَدۡعُوٓاْ إِلَىٰ دَارِ ٱلسَّلَٰمِ وَيَهۡدِي مَن يَشَآءُ إِلَىٰ صِرَٰطٖ مُّسۡتَقِيمٖ", "surah": 10, "ref_api": "https://api.quran.com/api/v4/verses/by_key/10:25", "surah_name": "يونس", "ayah_canonical": 25, "match": "exact", "ref": "10:25"}], "surah": null, "ref_api": null}]}, {"type": "heading", "level": 3, "text": "أصول دعوة تحرير المرأة في العالم الإسلامي وبالأخص في مصر والشام:", "page": 314, "id": "unit-26__lesson-11__b10", "role": "section"}, {"type": "paragraph", "md": "بدأت بذور الدعوة إلى تحرير المرأة وإخراجها سافرة على أعين الناس في مصر من عهد محمد علي باشا الذي طعن الدولة العثمانية وغدر بها واتصل بالإنجليز والفرنسيين وانشق عن الخلافة العثمانية وتولى مصر وصار يرسل بعثات من مصر إلى بلاد الغرب وبالأخص فرنسا؛ لِتعلم وتلقي الخبرات والمهارات الغربية، فرجعوا بعلم دنيوي وأفكار غربية مسمومة ومبادئ وقيم داخلية تنافي المبادئ والقيم الإسلامية، كل ذلك متأثرين بالحضارة المادية ونسوا العلم السماوي -الوحي- الذي فيه النجاة في الدنيا والآخرة قال الله تعالى: ﴿يَعۡلَمُونَ ظَٰهِرٗا مِّنَ ٱلۡحَيَوٰةِ ٱلدُّنۡيَا وَهُمۡ عَنِ ٱلۡأٓخِرَةِ هُمۡ غَٰفِلُونَ ۝٧﴾؛ فانتشرت هذه الأفكار المسمومة من هذه البذور ثم بعد ذلك تأثر بهم من لم يذهب إلى الغرب.", "page": 314, "id": "unit-26__lesson-11__b11", "inline": [{"t": "text", "s": "بدأت بذور الدعوة إلى تحرير المرأة وإخراجها سافرة على أعين الناس في مصر من عهد محمد علي باشا الذي طعن الدولة العثمانية وغدر بها واتصل بالإنجليز والفرنسيين وانشق عن الخلافة العثمانية وتولى مصر وصار يرسل بعثات من مصر إلى بلاد الغرب وبالأخص فرنسا؛ لِتعلم وتلقي الخبرات والمهارات الغربية، فرجعوا بعلم دنيوي وأفكار غربية مسمومة ومبادئ وقيم داخلية تنافي المبادئ والقيم الإسلامية، كل ذلك متأثرين بالحضارة المادية ونسوا العلم السماوي -الوحي- الذي فيه النجاة في الدنيا والآخرة قال الله تعالى: "}, {"t": "ayah", "s": "يَعۡلَمُونَ ظَٰهِرٗا مِّنَ ٱلۡحَيَوٰةِ ٱلدُّنۡيَا وَهُمۡ عَنِ ٱلۡأٓخِرَةِ هُمۡ غَٰفِلُونَ ۝٧", "ayah": [7], "verses": [{"n": 7, "text": "يَعۡلَمُونَ ظَٰهِرٗا مِّنَ ٱلۡحَيَوٰةِ ٱلدُّنۡيَا وَهُمۡ عَنِ ٱلۡأٓخِرَةِ هُمۡ غَٰفِلُونَ", "surah": 30, "ref_api": "https://api.quran.com/api/v4/verses/by_key/30:7", "surah_name": "الروم", "ayah_canonical": 7, "match": "exact", "ref": "30:7"}], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ فانتشرت هذه الأفكار المسمومة من هذه البذور ثم بعد ذلك تأثر بهم من لم يذهب إلى الغرب."}]}, {"type": "paragraph", "md": "وكان على رأس الذاهبين والمتأثرين شيخ مصري يدعى رفاعة الطهطاوي، تأثر بالحضارة الغربية وابتعد عن الشريعة وروحها متأثرًا بالخلل الغربي والفساد الديني فصار من أوائل الداعين إلى الأفكار الغربية الفرنسية وله فتاوى مخالفة للدين في باب المرأة فكان أول من أثار قضية تحرير المرأة في القرن التاسع الهجري فكان صاحب هذه السنة السيئة ولاقى تأييدًا من السلطة الحاكمة لأنها تتبنى الفكر الغربي.", "page": 314, "id": "unit-26__lesson-11__b12"}, {"type": "paragraph", "md": "ثم جاء بعده محامي اسمه مرقص فهمي وألف كتابا اسمه «المرأة والشرق»؛ دعا فيه صراحة وللمرة الأولى في تاريخ المرأة المسلمة إلى تحقيق أهداف خمسة محدده وهي كالتالي:", "page": 315, "id": "unit-26__lesson-11__b13", "inline": [{"t": "text", "s": "ثم جاء بعده محامي اسمه مرقص فهمي وألف كتابا اسمه "}, {"t": "quote", "s": "المرأة والشرق"}, {"t": "text", "s": "؛ "}, {"t": "emphasis", "s": "دعا فيه صراحة وللمرة الأولى في تاريخ المرأة المسلمة إلى تحقيق أهداف خمسة محدده وهي كالتالي:", "role": "emphasis"}]}, {"type": "paragraph", "md": "الهدف الأول: القضاء على الحجاب الإسلامي .", "page": 315, "id": "unit-26__lesson-11__b14"}, {"type": "paragraph", "md": "الهدف الثاني: إباحة اختلاط المرأة المسلمة بالأجانب عنها", "page": 315, "id": "unit-26__lesson-11__b15"}, {"type": "paragraph", "md": "الهدف الثالث: تقييد الطلاق وإيجاب وقوعه أمام القاضي", "page": 315, "id": "unit-26__lesson-11__b16"}, {"type": "paragraph", "md": "الهدف الرابع: منع الزواج بأكثر من واحدة", "page": 315, "id": "unit-26__lesson-11__b17"}, {"type": "paragraph", "md": "الهدف الخامس: إباحة الزواج بين المسلمات والأقباط (المسيحيين النصارى).", "page": 315, "id": "unit-26__lesson-11__b18", "inline": [{"t": "text", "s": "الهدف الخامس: إباحة الزواج بين المسلمات والأقباط "}, {"t": "emphasis", "s": "(المسيحيين النصارى)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ثم بعد هذا الكتاب، صدر كتاب للدوق داركير باسم «المصريون» تعدى فيه على الإسلام ونال من الحجاب وقضايا المرأة، كل هذا الذي ذكرناه للفت النظر إلى أن القضية ليست قضية حضارية كما يدعون بل لها جذور مع الكفار ومع المستعمر وممن ساهم في هذه الدعوات جمال الدين الأفغاني والشيخ محمد عبده على الفرق الكبير بين الأفغاني وعبده؛ فمحمد عبده له جوانب إصلاحية مثمرة في المجتمع الإسلامي إلا أنه ممن تأثر بهذه الدعوات بالرغم أنه لم يكن يقصد هذا وإنما أراد الخير بالمسلمين فكان لمحمد عبده تلاميذ كانوا أشرس منه في هذه المعركة ومتأثرين بالغرب أكثر منه، منهم قاسم أمين وهو ممن درس في فرنسا أيضًا وانبهر بالحياة الأوربية بالرغم أن توجهه كان في البداية توجهًا إسلاميًا لكنه انحرف بعد ذلك فألف كتابًا يسمى «تحرير المرأة» هاجم الحجاب ودعا إلى السفور.", "page": 315, "id": "unit-26__lesson-11__b19", "inline": [{"t": "text", "s": "ثم بعد هذا الكتاب، صدر كتاب للدوق داركير باسم "}, {"t": "quote", "s": "المصريون"}, {"t": "text", "s": " تعدى فيه على الإسلام ونال من الحجاب وقضايا المرأة، كل هذا الذي ذكرناه للفت النظر إلى أن القضية ليست قضية حضارية كما يدعون بل لها جذور مع الكفار ومع المستعمر وممن ساهم في هذه الدعوات جمال الدين الأفغاني والشيخ محمد عبده على الفرق الكبير بين الأفغاني وعبده؛ فمحمد عبده له جوانب إصلاحية مثمرة في المجتمع الإسلامي إلا أنه ممن تأثر بهذه الدعوات بالرغم أنه لم يكن يقصد هذا وإنما أراد الخير بالمسلمين فكان لمحمد عبده تلاميذ كانوا أشرس منه في هذه المعركة ومتأثرين بالغرب أكثر منه، منهم قاسم أمين وهو ممن درس في فرنسا أيضًا وانبهر بالحياة الأوربية بالرغم أن توجهه كان في البداية توجهًا إسلاميًا لكنه انحرف بعد ذلك فألف كتابًا يسمى "}, {"t": "quote", "s": "تحرير المرأة"}, {"t": "text", "s": " هاجم الحجاب ودعا إلى السفور."}]}, {"type": "paragraph", "md": "ومن نماذج ضلالاته في تفسيره لآية الحجاب قوله تعالى: ﴿وَقُل لِّلۡمُؤۡمِنَٰتِ يَغۡضُضۡنَ مِنۡ أَبۡصَٰرِهِنَّ﴾ أنه قال: «إن الآية قد أباحت أن تَظْهَرَ بعض أعضاءٍ من جسم المرأة أمام الأجنبي عنها، غير أنها لم تسم تلك المواضع، وقد قال العلماء إنها وُكِلَ فهمها وتعينها إلى ما كان معروفًا في العادة ووقت الخطاب، واتفق الأئمة على أن الوجه والكفين مما شمله الاستثناء في الآية ووقع الخلاف بينهم في أعضاء أخرى كالذراعين والقدمين!!». انتهى، ولم يسم اسم عالم واحد ممن قال إنهم اتفقوا أو اختلفوا.", "page": 315, "id": "unit-26__lesson-11__b20", "inline": [{"t": "text", "s": "ومن نماذج ضلالاته في تفسيره لآية الحجاب قوله تعالى: "}, {"t": "ayah", "s": "وَقُل لِّلۡمُؤۡمِنَٰتِ يَغۡضُضۡنَ مِنۡ أَبۡصَٰرِهِنَّ", "ayah": [], "verses": [{"n": 31, "text": "وَقُل لِّلۡمُؤۡمِنَٰتِ يَغۡضُضۡنَ مِنۡ أَبۡصَٰرِهِنَّ", "surah": 24, "surah_name": "النور", "ref": "24:31", "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31"}], "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31", "surah_name": "النور", "ayah_canonical": 31, "match": "contained", "ref": "24:31"}, {"t": "text", "s": " أنه قال: "}, {"t": "quote", "s": "إن الآية قد أباحت أن تَظْهَرَ بعض أعضاءٍ من جسم المرأة أمام الأجنبي عنها، غير أنها لم تسم تلك المواضع، وقد قال العلماء إنها وُكِلَ فهمها وتعينها إلى ما كان معروفًا في العادة ووقت الخطاب، واتفق الأئمة على أن الوجه والكفين مما شمله الاستثناء في الآية ووقع الخلاف بينهم في أعضاء أخرى كالذراعين والقدمين!!"}, {"t": "text", "s": ". انتهى، ولم يسم اسم عالم واحد ممن قال إنهم اتفقوا أو اختلفوا."}]}, {"type": "paragraph", "md": "ثم بعد ذلك وصل الكتاب إلى الشام والعراق وواجه معارضة عنيفة وثار علماء الشام ثورة عنيفة ضد قاسم أمين وأعلنوا أن دعاة السفور هم دعاة فساد؛ لأنه يخالف أمر الله به، والسفور يهدم القيم والمجتمعات وتنحل به كل الروابط الاجتماعية بل حتى الشعراء والأدباء وقفوا بوجه هذه الدعوة «تحرير المرأة» كأحمد محرم والبناء العراقي ودواد الشبيبي والأزدي، ولكن هبت رياح العدوى إلى الشام وسارعت بعض الشخصيات لتبني هذه الأفكار الهدامة، كبطرس البستاني وميانا مراش الحلبية وماري العجمي وعادلة الجزائري وحنان نجمة ونازك العابد وثريا الحافظ وهدى شعراوي ونوال السعداوي وغيرهم من الأسماء العفنة في الشام ومصر والخليج.. كلهم سار لنشر فساد ما يسمى تحرير المرأة والواقع تدمير المرأة وليس تحريرها؛ لأن الإسلام لا شك حرر المرأة من براثن الجاهلية وأن هذه الحركات أوقعت المرأة والمجتمع في مستنقع الوحل والشهوات وتراجعت المجتمعات الإسلامية للوراء أكثر من أن تتقدم لذلك كان لهم نشاط قوي في نشر هذه الأفكار المسمومة وإقامة الصالونات التي يجتمع بها الناس وَيُفْتَحُ نقاش طويل في هذه المواضيع للتأثير على الناس، وَفَتْحُ جمعيات ومؤسسات داعية لخلع الحجاب وإخراج المرأة للشارع وإنشاء المجلات التي تبث هذه الأفكار الغير إسلامية التي جلبوها من الغرب تأثرًا بحياتهم المرفهة، ظنًا منهم أن هذا هو المطلوب منهم في الدنيا وليس امتثال أوامر الله واجتناب نواهيه وعبادته سبحانه حق العبادة، فَبُذِلَ الكثيرُ وأُنْفِقَتِ الأموال الضخمة لنشر هذه الأفكار التي تسمى تحريرية، والحقيقة أنها تُخْرِجُ الناس والمرأة على وجه الخصوص من جنة العبودية لله إلى جحيم قيود الشيطان، وصدق من قال: «فإن لم تكن عبدا لله ستكون عبدًا لغيره».", "page": 316, "id": "unit-26__lesson-11__b21", "inline": [{"t": "text", "s": "ثم بعد ذلك وصل الكتاب إلى الشام والعراق وواجه معارضة عنيفة وثار علماء الشام ثورة عنيفة ضد قاسم أمين وأعلنوا أن دعاة السفور هم دعاة فساد؛ لأنه يخالف أمر الله به، والسفور يهدم القيم والمجتمعات وتنحل به كل الروابط الاجتماعية بل حتى الشعراء والأدباء وقفوا بوجه هذه الدعوة "}, {"t": "quote", "s": "تحرير المرأة"}, {"t": "text", "s": " كأحمد محرم والبناء العراقي ودواد الشبيبي والأزدي، ولكن هبت رياح العدوى إلى الشام وسارعت بعض الشخصيات لتبني هذه الأفكار الهدامة، كبطرس البستاني وميانا مراش الحلبية وماري العجمي وعادلة الجزائري وحنان نجمة ونازك العابد وثريا الحافظ وهدى شعراوي ونوال السعداوي وغيرهم من الأسماء العفنة في الشام ومصر والخليج.. كلهم سار لنشر فساد ما يسمى تحرير المرأة والواقع تدمير المرأة وليس تحريرها؛ لأن الإسلام لا شك حرر المرأة من براثن الجاهلية وأن هذه الحركات أوقعت المرأة والمجتمع في مستنقع الوحل والشهوات وتراجعت المجتمعات الإسلامية للوراء أكثر من أن تتقدم لذلك كان لهم نشاط قوي في نشر هذه الأفكار المسمومة وإقامة الصالونات التي يجتمع بها الناس وَيُفْتَحُ نقاش طويل في هذه المواضيع للتأثير على الناس، وَفَتْحُ جمعيات ومؤسسات داعية لخلع الحجاب وإخراج المرأة للشارع وإنشاء المجلات التي تبث هذه الأفكار الغير إسلامية التي جلبوها من الغرب تأثرًا بحياتهم المرفهة، ظنًا منهم أن هذا هو المطلوب منهم في الدنيا وليس امتثال أوامر الله واجتناب نواهيه وعبادته سبحانه حق العبادة، فَبُذِلَ الكثيرُ وأُنْفِقَتِ الأموال الضخمة لنشر هذه الأفكار التي تسمى تحريرية، والحقيقة أنها تُخْرِجُ الناس والمرأة على وجه الخصوص من جنة العبودية لله إلى جحيم قيود الشيطان، وصدق من قال: "}, {"t": "quote", "s": "فإن لم تكن عبدا لله ستكون عبدًا لغيره"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "فهذه مقدمة مختصرة عن أصول معركة الحجاب وكيفية نشأة الحركة التحررية النسوية في العالم الإسلامي وبالأخص في الشام، وهذا يدفع أهل الخير أن يبذل أكثر؛ لأن معه الحجة والدليل والبرهان وتأييد الله..", "page": 316, "id": "unit-26__lesson-11__b22", "inline": [{"t": "emphasis", "s": "فهذه مقدمة مختصرة عن أصول معركة الحجاب وكيفية نشأة الحركة التحررية النسوية في العالم الإسلامي وبالأخص في الشام", "role": "emphasis"}, {"t": "text", "s": "، وهذا يدفع أهل الخير أن يبذل أكثر؛ لأن معه الحجة والدليل والبرهان وتأييد الله.."}]}, {"type": "paragraph", "md": "والميدان الآن مفتوح؛ فلا بد من الحرب المضادة وتقويم المسار والدخول إلى معركة العفة بكل ما نملك من أسلحة؛ لأن الذي يحاربنا هم من تأثروا بهذا الزيف والزور الذي تغذيه القوى المعادية من الصليبية واليهودية والماسونية وتدعمه بجميع أنواع الأسلحة وتعطيه المنابر في كل مكان وتفتح له المجال وتغلق على غيره ولكن: ﴿يُرِيدُونَ أَن يُطۡفِـُٔواْ نُورَ ٱللَّهِ بِأَفۡوَٰهِهِمۡ وَيَأۡبَى ٱللَّهُ إِلَّآ أَن يُتِمَّ نُورَهُۥ وَلَوۡ كَرِهَ ٱلۡكَٰفِرُونَ ۝٣٢﴾.", "page": 316, "id": "unit-26__lesson-11__b23", "inline": [{"t": "text", "s": "والميدان الآن مفتوح؛ فلا بد من الحرب المضادة وتقويم المسار والدخول إلى معركة العفة بكل ما نملك من أسلحة؛ لأن الذي يحاربنا هم من تأثروا بهذا الزيف والزور الذي تغذيه القوى المعادية من الصليبية واليهودية والماسونية وتدعمه بجميع أنواع الأسلحة وتعطيه المنابر في كل مكان وتفتح له المجال وتغلق على غيره ولكن: "}, {"t": "ayah", "s": "يُرِيدُونَ أَن يُطۡفِـُٔواْ نُورَ ٱللَّهِ بِأَفۡوَٰهِهِمۡ وَيَأۡبَى ٱللَّهُ إِلَّآ أَن يُتِمَّ نُورَهُۥ وَلَوۡ كَرِهَ ٱلۡكَٰفِرُونَ ۝٣٢", "ayah": [32], "verses": [{"n": 32, "text": "يُرِيدُونَ أَن يُطۡفِـُٔواْ نُورَ ٱللَّهِ بِأَفۡوَٰهِهِمۡ وَيَأۡبَى ٱللَّهُ إِلَّآ أَن يُتِمَّ نُورَهُۥ وَلَوۡ كَرِهَ ٱلۡكَٰفِرُونَ", "surah": 9, "ref_api": "https://api.quran.com/api/v4/verses/by_key/9:32", "surah_name": "التوبة", "ayah_canonical": 32, "match": "exact", "ref": "9:32"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 316, "id": "unit-26__lesson-11__b24", "role": "assessment"}, {"type": "paragraph", "md": "1- لخصي أصول معركة الحجاب المعاصرة في كلمة قدرها خمس دقائق.", "page": 316, "id": "unit-26__lesson-11__b25", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ما واجبنا اليوم في نشرِ الدعوة إلى الحجاب كما تعملناه في الدرس؟", "page": 316, "id": "unit-26__lesson-11__b26", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط حواري بحثي", "page": 316, "id": "unit-26__lesson-11__b27", "role": "activity"}, {"type": "paragraph", "md": "نرجع إلى كتاب «عودة الحجاب» للشيخ المقدم، ونتوسع أكثر في فهم معركة الحجاب المعاصرة.. ولان الكتاب كبير فيمكن تقسيم الكتاب على كل طالبة قسم منه لتفيدنا بأهم فوائده ومسائله.", "page": 316, "id": "unit-26__lesson-11__b28", "inline": [{"t": "text", "s": "نرجع إلى كتاب "}, {"t": "quote", "s": "عودة الحجاب"}, {"t": "text", "s": " للشيخ المقدم، ونتوسع أكثر في فهم معركة الحجاب المعاصرة.. ولان الكتاب كبير فيمكن تقسيم الكتاب على كل طالبة قسم منه لتفيدنا بأهم فوائده ومسائله."}], "item_role": "activity_step"}, {"type": "paragraph", "md": "منارات الهدى", "page": 317, "id": "unit-26__lesson-11__b29", "item_role": "activity_step"}]' WHERE id='unit-26__lesson-11';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-12','unit-26',12,'تكريم المرأة بين الإسلام والجاهلية','الأسرة والمرأة',NULL,0,4,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "ملخصٌ من كتاب: سور العفاف", "page": 317, "id": "unit-26__lesson-12__b01", "role": "section"}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 317, "id": "unit-26__lesson-12__b02", "role": "objectives"}, {"type": "paragraph", "md": "- بيان تكريم المرأة بإنزالها منزلتها اللائقة بها، بينما أهانتها الجاهلية المعاصرة بدعوى تحريرها.", "page": 317, "id": "unit-26__lesson-12__b03", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "أولا: صور إهانة الجاهلية المعاصرة للمرأة:", "page": 317, "id": "unit-26__lesson-12__b04", "role": "section"}, {"type": "paragraph", "md": "نذكر هنا بعض الصور الجاهلية المعاصرة التي تهين المرأة؛ هذه الجاهلية التي يدعون إليها ويريدونها في أوساط المسلمين المتمسكين بدينهم وعقيدتهم وإيمانهم.. ونذكر بعض الأمثلة والواقع أكثر من ذلك:", "page": 317, "id": "unit-26__lesson-12__b05"}, {"type": "paragraph", "md": "1- تمزيق الروابط الأسرية: فالأم ليس لها دور في توجيه الأولاد وتربيتهم بسبب الجهل وادعاء الحضارة ففسدت وفسد بها أجيال، ويرجع ذلك بصورة أساسية لسعيهم المحموم لإخراج المرأة للعمل؛ فعليها أن تعمل كالرجل، فأهملت تربية أولادها، وحين تكبر وتعجز عن العمل ترمى في دور العجزة والمسنين ولا يهتم بها حتى أقرب الناس لها، وباعتراف النساء العجزة في الغرب يقولون: «إن المرأة في بلادكم ملكة».", "page": 317, "id": "unit-26__lesson-12__b06", "inline": [{"t": "emphasis", "s": "1- تمزيق الروابط الأسرية", "role": "emphasis"}, {"t": "text", "s": ": فالأم ليس لها دور في توجيه الأولاد وتربيتهم بسبب الجهل وادعاء الحضارة ففسدت وفسد بها أجيال، ويرجع ذلك بصورة أساسية لسعيهم المحموم لإخراج المرأة للعمل؛ فعليها أن تعمل كالرجل، فأهملت تربية أولادها، وحين تكبر وتعجز عن العمل ترمى في دور العجزة والمسنين ولا يهتم بها حتى أقرب الناس لها، وباعتراف النساء العجزة في الغرب يقولون: "}, {"t": "quote", "s": "إن المرأة في بلادكم ملكة"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "ومن أمثلة هذا أن الصحف الغربية نشرت قصة الشاب الغربي الذي يعتبر بارًا بأمه وأعطاها حقها، وذلك أنه قَبِل أن تعيش معه ومع زوجته وأولاده بشرط أن تخدمهم وتخدم زوجته وأولاده وتنظف لهم البيت وهذا كان كرمًا من الشاب، فهذه حضارة الحرية وتحرير المرأة يا أولي الألباب!!", "page": 317, "id": "unit-26__lesson-12__b07"}, {"type": "paragraph", "md": "2- اعتبار المرأة سلعة للشهوة؛ تبيت مع أي رجل شاءت دون زواج رسمي وحقيقي يحفظ لها حقوقها ويصون لها كرامتها: وإن تزوجها رجل وقَبِلَ بذلك؛ فإنها تقوم بخيانة زوجها وتزني مع العشرات باسم «تحرير المرأة» و«الحرية»، وإن علم الزوج بخيانة زوجته فقد لا يتأثر وتستمر حياتهم كالعادة!، هذه صورة الحضارة الغربية التي يتكلم عنها دعاة الباطل، ويدعون الناس لخلع القيم الإسلامية والتمثل بكل عادات الغرب، ما علاقتها بالتقدم؟ ولكن الحقيقة أن هذه الدعوة دعوة إباحية وفساد وليست حضارة وتقدم.", "page": 317, "id": "unit-26__lesson-12__b08", "inline": [{"t": "text", "s": "2- اعتبار المرأة سلعة للشهوة؛ تبيت مع أي رجل شاءت دون زواج رسمي وحقيقي يحفظ لها حقوقها ويصون لها كرامتها: وإن تزوجها رجل وقَبِلَ بذلك؛ فإنها تقوم بخيانة زوجها وتزني مع العشرات باسم "}, {"t": "quote", "s": "تحرير المرأة"}, {"t": "text", "s": " و"}, {"t": "quote", "s": "الحرية"}, {"t": "text", "s": "، وإن علم الزوج بخيانة زوجته فقد لا يتأثر وتستمر حياتهم كالعادة!، هذه صورة الحضارة الغربية التي يتكلم عنها دعاة الباطل، ويدعون الناس لخلع القيم الإسلامية والتمثل بكل عادات الغرب، ما علاقتها بالتقدم؟ ولكن الحقيقة أن هذه الدعوة دعوة إباحية وفساد وليست حضارة وتقدم."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "والسؤال المطروح: كم عدد الأولاد الذين تنجبهم النساء الغربيات بالحرام والزنا ولا يعرف آباءهم.. في أمريكا فقط يُولد كل سنة تقريبًا مليون طفل من الزنا ويضيعون في حمأة الجاهلية.. فأي حضارة هذه؟!", "page": 317, "id": "unit-26__lesson-12__b09"}, {"type": "paragraph", "md": "3- نكاح المحارم والبهائم؛ فكثير من الدول التي تدعي التحضر تدرس قانون إباحة العلاقات الجنسية بين الأخ وأخته، ومن الدول التي تدعوا لهذا ألمانيا والسويد رائدات التحضر الغربي، أي حضارة هذه هل هذه حضارة أم حيوانية بهيمية.. وهذه الممارسات أصبحت واقعًا موجودًا في الغرب الكافر، ولكن النقاش الآن يدور حول إقراره كقانون وإلا فإن عائلة من أصل عشر عائلات تمارس هذا الأمر في الغرب.", "page": 318, "id": "unit-26__lesson-12__b10", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "وكل هذه الصور المؤلمة سببها إخراج المرأة من البيت وسفورها واختلاطها بالرجال.", "page": 318, "id": "unit-26__lesson-12__b11"}, {"type": "paragraph", "md": "4- ازدياد معدلات تعرض المرأة للقلق والاكتئاب والأمراض النفسية: بسبب ما تواجهه من ضغوط العمل والاختلاط بشكل كبير في المجتمع الغربي، ونحن بفضل الله ديار المسلمين تجد الاستقرار النفسي والسعادة لمن التزم بالشريعة الإسلامية؛ بالرغم من الفقر والحاجة ولكن تسعد الأسرة المسلمة بإمكانيتها القليلة فهي مستقرة نفسيًا بسبب الإيمان والالتزام بأوامر الله عز وجل ، وقرار المرأة في بيتها كالملكة.", "page": 318, "id": "unit-26__lesson-12__b12", "inline": [{"t": "text", "s": "4- ازدياد معدلات تعرض المرأة للقلق والاكتئاب والأمراض النفسية: بسبب ما تواجهه من ضغوط العمل والاختلاط بشكل كبير في المجتمع الغربي، ونحن بفضل الله ديار المسلمين تجد الاستقرار النفسي والسعادة لمن التزم بالشريعة الإسلامية؛ بالرغم من الفقر والحاجة ولكن تسعد الأسرة المسلمة بإمكانيتها القليلة فهي مستقرة نفسيًا بسبب الإيمان والالتزام بأوامر الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ، وقرار المرأة في بيتها كالملكة."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- تعرية المرأة ونزع الأنوثة عنها؛ حتى باتت سلعة للإعلانات التلفزيونية والمنتجات الغذائية بأرخص الأثمان بإظهار شيء من جسمها؛ حتى الإعلان عن كرة القدم والمصارعة باتت النساء مادة دسمة فيه!!", "page": 318, "id": "unit-26__lesson-12__b13", "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "7- التفنن في إظهار عورات المراة أمام الذئاب البشرية من خلال نشر اللباس الفاضح.. لإفسادها وإثارة الفتنة بين الشباب وإشاعة الرذيلة بين الناس، وصدق الله تعالى: ﴿إِنَّ ٱلَّذِينَ يُحِبُّونَ أَن تَشِيعَ ٱلۡفَٰحِشَةُ فِي ٱلَّذِينَ ءَامَنُواْ لَهُمۡ عَذَابٌ أَلِيمٞ فِي ٱلدُّنۡيَا وَٱلۡأٓخِرَةِۚ وَٱللَّهُ يَعۡلَمُ وَأَنتُمۡ لَا تَعۡلَمُونَ ۝١٩﴾؛ فشاعت الرذيلة بغياب الشريعة وعمت الفوضى والبلاء المجتمعات حتى المسلمة، وأصبح الفساد الأخلاقي ظاهرةً في بلاد المسلمين..", "page": 318, "id": "unit-26__lesson-12__b14", "inline": [{"t": "text", "s": "7- التفنن في إظهار عورات المراة أمام الذئاب البشرية من خلال نشر اللباس الفاضح.. لإفسادها وإثارة الفتنة بين الشباب وإشاعة الرذيلة بين الناس، وصدق الله تعالى: "}, {"t": "ayah", "s": "إِنَّ ٱلَّذِينَ يُحِبُّونَ أَن تَشِيعَ ٱلۡفَٰحِشَةُ فِي ٱلَّذِينَ ءَامَنُواْ لَهُمۡ عَذَابٌ أَلِيمٞ فِي ٱلدُّنۡيَا وَٱلۡأٓخِرَةِۚ وَٱللَّهُ يَعۡلَمُ وَأَنتُمۡ لَا تَعۡلَمُونَ ۝١٩", "ayah": [19], "verses": [{"n": 19, "text": "إِنَّ ٱلَّذِينَ يُحِبُّونَ أَن تَشِيعَ ٱلۡفَٰحِشَةُ فِي ٱلَّذِينَ ءَامَنُواْ لَهُمۡ عَذَابٌ أَلِيمٞ فِي ٱلدُّنۡيَا وَٱلۡأٓخِرَةِۚ وَٱللَّهُ يَعۡلَمُ وَأَنتُمۡ لَا تَعۡلَمُونَ", "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:19", "surah_name": "النور", "ayah_canonical": 19, "match": "exact", "ref": "24:19"}], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ فشاعت الرذيلة بغياب الشريعة وعمت الفوضى والبلاء المجتمعات حتى المسلمة، وأصبح الفساد الأخلاقي ظاهرةً في بلاد المسلمين.."}], "list": {"type": "ordered", "marker": "7"}}, {"type": "paragraph", "md": "خاتمة: الجاهلية المعاصرة أكثر فسادًا من الجاهلية قبل الإسلام وخاصة في ديار الغرب التي تدعي الحضارة وهي تعيش في أعلى صور البهيمية؛ لذلك لا بد من أن نعرف وأن يستقر في أذهاننا أن المرأة يكرمها الإسلام ولن يكرمها أحد مثله؛ فالإسلام أنزلها مكانة عظيمة لائقة بها كمرأة في جميع المجالات، وجعل لها دورًا في العمل الذي يناسبها، وجعل لها مكانًا في الدعوة إلى الله وتعليم القرآن ونشر الخير.", "page": 318, "id": "unit-26__lesson-12__b15", "inline": [{"t": "emphasis", "s": "خاتمة:", "role": "emphasis"}, {"t": "text", "s": " الجاهلية المعاصرة أكثر فسادًا من الجاهلية قبل الإسلام وخاصة في ديار الغرب التي تدعي الحضارة وهي تعيش في أعلى صور البهيمية؛ لذلك لا بد من أن نعرف وأن يستقر في أذهاننا أن المرأة يكرمها الإسلام ولن يكرمها أحد مثله؛ فالإسلام أنزلها مكانة عظيمة لائقة بها كمرأة في جميع المجالات، وجعل لها دورًا في العمل الذي يناسبها، وجعل لها مكانًا في الدعوة إلى الله وتعليم القرآن ونشر الخير."}]}, {"type": "paragraph", "md": "وما حصلت هذه الانتكاسة إلا في القرن الأخير، ولم يزل الإسلام زال يحافظ على المرأة قبل ذلك قرونًا..", "page": 318, "id": "unit-26__lesson-12__b16"}, {"type": "heading", "level": 3, "text": "صور من تكريم الإسلام للمرأة:", "page": 318, "id": "unit-26__lesson-12__b17", "role": "section"}, {"type": "paragraph", "md": "بعد أن ذكرنا بعض الصور الجاهلية المعاصرة التي طبقت على المرأة وأوصلتها إلى تلك الصورة البائسة أنتقل للحديث عن بعض الصور في تكريم الإسلام للمرأة... حيثُ جعل لها منهجًا قرآنيًا في تربيتها.", "page": 318, "id": "unit-26__lesson-12__b18"}, {"type": "paragraph", "md": "ونذكر هنا بعض الأمثلة لا على سبيل الحصر؛ لأنها كثيرة جدًا، فمن صور تكريم المرأة:", "page": 318, "id": "unit-26__lesson-12__b19", "inline": [{"t": "emphasis", "s": "ونذكر هنا بعض الأمثلة لا على سبيل الحصر؛ لأنها كثيرة جدًا، فمن صور تكريم المرأة:", "role": "emphasis"}]}, {"type": "paragraph", "md": "1- أن الإسلام أمر المرأة بالحجاب حتى يصونها ويحفظ كرامتها ويحميها من الألسنة البذيئة والأعين الغادرة والأيدي الباطشة؛ فأمرها بالحجاب سترًا لها وحفاظًا عليها وأمرها بالبعد عن السفور والتبرج والاختلاط بالرجال الأجانب وعما يؤدي إلى فتنتها.", "page": 319, "id": "unit-26__lesson-12__b20", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- أنه أمر وليها الأب أو الأخ أو الزوج أن ينفق عليها وأن يقضي حاجاتها؛ حتى لا تخرج للعمل بأعمال شاقة؛ فإن طبيعة المرأة لا تقدر على الأعمال المتعبة والشاقة التي يقوم بها الرجال.", "page": 319, "id": "unit-26__lesson-12__b21", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- أن الله أمر بمعاشرتهن بالمعروف والإحسان قولًا وفعلا وحذر من الإساءة إليها: (رفقًا بالقوارير).", "page": 319, "id": "unit-26__lesson-12__b22", "inline": [{"t": "text", "s": "3- أن الله أمر بمعاشرتهن بالمعروف والإحسان قولًا وفعلا وحذر من الإساءة إليها: "}, {"t": "emphasis", "s": "(رفقًا بالقوارير)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- جعل لها حقًا في الميراث وحدد لها فرضًا معينًا على حسب موقعها إن كانت زوجة أو أمًا أو أختًا أو بنتًا، قال تعالى ﴿وَلِلنِّسَآءِ نَصِيبٞ مِّمَّا تَرَكَ ٱلۡوَٰلِدَانِ وَٱلۡأَقۡرَبُونَ مِمَّا قَلَّ مِنۡهُ أَوۡ كَثُرَۚ نَصِيبٗا مَّفۡرُوضٗا ۝٧﴾.", "page": 319, "id": "unit-26__lesson-12__b23", "inline": [{"t": "text", "s": "4- جعل لها حقًا في الميراث وحدد لها فرضًا معينًا على حسب موقعها إن كانت زوجة أو أمًا أو أختًا أو بنتًا، قال تعالى "}, {"t": "ayah", "s": "وَلِلنِّسَآءِ نَصِيبٞ مِّمَّا تَرَكَ ٱلۡوَٰلِدَانِ وَٱلۡأَقۡرَبُونَ مِمَّا قَلَّ مِنۡهُ أَوۡ كَثُرَۚ نَصِيبٗا مَّفۡرُوضٗا ۝٧", "ayah": [7], "verses": [{"n": 7, "text": "وَلِلنِّسَآءِ نَصِيبٞ مِّمَّا تَرَكَ ٱلۡوَٰلِدَانِ وَٱلۡأَقۡرَبُونَ مِمَّا قَلَّ مِنۡهُ أَوۡ كَثُرَۚ نَصِيبٗا مَّفۡرُوضٗا", "surah": 4, "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:7", "surah_name": "النساء", "ayah_canonical": 7, "match": "contained", "ref": "4:7"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- أنه نهى الزوج أن يضرب زوجته بلا مسوغ، وأمره بالمعاشرة الحسنة لزوجته أمرًا واجبًا عليه وليس تفضلًا منه على المرأة، قال صلى الله عليه وسلم : (لا يجلد أحدكم امرأته جلد العبد ثم يضاجعها).", "page": 319, "id": "unit-26__lesson-12__b24", "inline": [{"t": "text", "s": "5- أنه نهى الزوج أن يضرب زوجته بلا مسوغ، وأمره بالمعاشرة الحسنة لزوجته أمرًا واجبًا عليه وليس تفضلًا منه على المرأة، قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لا يجلد أحدكم امرأته جلد العبد ثم يضاجعها)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6- أنه جعل لها حق التملك والإجارة والبيع والشراء وسائر العقود وجعل لها حق التعلم والتعليم.", "page": 319, "id": "unit-26__lesson-12__b25", "list": {"type": "ordered", "marker": "6"}}, {"type": "paragraph", "md": "7- أنه خصص سورة كاملة باسمها وهي سورة النساء وهناك سورة أخرى تتحدث عن قضايا المرأة كالبقرة والنور والأحزاب وغيرها من السور التي استفاضة بالحديث عن الأحكام الشرعية المتعلقة بالمرأة.. وكل هذا يدل على مكانة المرأة العظيمة في الإسلام، وكذلك في السنة حيثُ قال صلى الله عليه وسلم : (اتقوا الله في النساء، فإنهن عوان عندكم، أخذتموهن بأمانة الله واستحللتم فروجهن بكلمة الله).", "page": 319, "id": "unit-26__lesson-12__b26", "inline": [{"t": "text", "s": "7- أنه خصص سورة كاملة باسمها وهي سورة النساء وهناك سورة أخرى تتحدث عن قضايا المرأة كالبقرة والنور والأحزاب وغيرها من السور التي استفاضة بالحديث عن الأحكام الشرعية المتعلقة بالمرأة.. وكل هذا يدل على مكانة المرأة العظيمة في الإسلام، وكذلك في السنة حيثُ قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(اتقوا الله في النساء، فإنهن عوان عندكم، أخذتموهن بأمانة الله واستحللتم فروجهن بكلمة الله)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "7"}}, {"type": "paragraph", "md": "8- أنه ساوى بين المرأة والرجل من حيث العمل الصالح والثواب والأجر فقال الله عز وجل : ﴿مَنۡ عَمِلَ صَٰلِحٗا مِّن ذَكَرٍ أَوۡ أُنثَىٰ وَهُوَ مُؤۡمِنٞ فَلَنُحۡيِيَنَّهُۥ حَيَوٰةٗ طَيِّبَةٗۖ وَلَنَجۡزِيَنَّهُمۡ أَجۡرَهُم بِأَحۡسَنِ مَا كَانُواْ يَعۡمَلُونَ ۝٩٧﴾، وقال: ﴿يَٰٓأَيُّهَا ٱلنَّاسُ إِنَّا خَلَقۡنَٰكُم مِّن ذَكَرٖ وَأُنثَىٰ وَجَعَلۡنَٰكُمۡ شُعُوبٗا وَقَبَآئِلَ لِتَعَارَفُوٓاْۚ إِنَّ أَكۡرَمَكُمۡ عِندَ ٱللَّهِ أَتۡقَىٰكُمۡۚ﴾.", "page": 319, "id": "unit-26__lesson-12__b27", "inline": [{"t": "text", "s": "8- أنه ساوى بين المرأة والرجل من حيث العمل الصالح والثواب والأجر فقال الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " : "}, {"t": "ayah", "s": "مَنۡ عَمِلَ صَٰلِحٗا مِّن ذَكَرٍ أَوۡ أُنثَىٰ وَهُوَ مُؤۡمِنٞ فَلَنُحۡيِيَنَّهُۥ حَيَوٰةٗ طَيِّبَةٗۖ وَلَنَجۡزِيَنَّهُمۡ أَجۡرَهُم بِأَحۡسَنِ مَا كَانُواْ يَعۡمَلُونَ ۝٩٧", "ayah": [97], "verses": [{"n": 97, "text": "مَنۡ عَمِلَ صَٰلِحٗا مِّن ذَكَرٍ أَوۡ أُنثَىٰ وَهُوَ مُؤۡمِنٞ فَلَنُحۡيِيَنَّهُۥ حَيَوٰةٗ طَيِّبَةٗۖ وَلَنَجۡزِيَنَّهُمۡ أَجۡرَهُم بِأَحۡسَنِ مَا كَانُواْ يَعۡمَلُونَ", "surah": 16, "ref_api": "https://api.quran.com/api/v4/verses/by_key/16:97", "surah_name": "النحل", "ayah_canonical": 97, "match": "exact", "ref": "16:97"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، وقال: "}, {"t": "ayah", "s": "يَٰٓأَيُّهَا ٱلنَّاسُ إِنَّا خَلَقۡنَٰكُم مِّن ذَكَرٖ وَأُنثَىٰ وَجَعَلۡنَٰكُمۡ شُعُوبٗا وَقَبَآئِلَ لِتَعَارَفُوٓاْۚ إِنَّ أَكۡرَمَكُمۡ عِندَ ٱللَّهِ أَتۡقَىٰكُمۡۚ", "ayah": [], "verses": [{"n": 13, "text": "يَٰٓأَيُّهَا ٱلنَّاسُ إِنَّا خَلَقۡنَٰكُم مِّن ذَكَرٖ وَأُنثَىٰ وَجَعَلۡنَٰكُمۡ شُعُوبٗا وَقَبَآئِلَ لِتَعَارَفُوٓاْۚ إِنَّ أَكۡرَمَكُمۡ عِندَ ٱللَّهِ أَتۡقَىٰكُمۡۚ", "surah": 49, "surah_name": "الحجرات", "ref": "49:13", "ref_api": "https://api.quran.com/api/v4/verses/by_key/49:13"}], "surah": 49, "ref_api": "https://api.quran.com/api/v4/verses/by_key/49:13", "surah_name": "الحجرات", "ayah_canonical": 13, "match": "contained", "ref": "49:13"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "8"}}, {"type": "paragraph", "md": "ورضي الله عن عمر بن الخطاب القائل: «كنا في الجاهلية لا نعد النساء شيئًا فلما جاء الإسلام وذكرهن الله رأينا لهن بذلك علينا حقًا»، وجاهلية اليوم شر؛ لأنها تُظهر للمرأة أن لها حقوقا وهي تقتلها بدل أن تحييها.", "page": 319, "id": "unit-26__lesson-12__b28", "inline": [{"t": "text", "s": "ورضي الله عن عمر بن الخطاب القائل: "}, {"t": "quote", "s": "كنا في الجاهلية لا نعد النساء شيئًا فلما جاء الإسلام وذكرهن الله رأينا لهن بذلك علينا حقًا"}, {"t": "text", "s": "، وجاهلية اليوم شر؛ لأنها تُظهر للمرأة أن لها حقوقا وهي تقتلها بدل أن تحييها."}]}, {"type": "paragraph", "md": "فأي تحرير للمرأة يتكلم عنه الضالون المضلون أم أنهم يقصدون تحريرها من المكانة العالية التي أكرمها بها الإسلام والانحطاط بها إلى مستنقعات الغدر والكذب والزور والبهتان والفساد والزنا والخنا؟!", "page": 319, "id": "unit-26__lesson-12__b29"}, {"type": "paragraph", "md": "السؤال التقويمي: قارني بين تكريم الإسلام للمرأة، وإهانة الجاهلية لها.", "page": 319, "id": "unit-26__lesson-12__b30"}, {"type": "paragraph", "md": "نشاط: نرجع إلى كتاب «تكريم المرأة في الإسلام» للشيخ زينو، ونلخصه وننشر أهم ما فيه..", "page": 319, "id": "unit-26__lesson-12__b31", "inline": [{"t": "text", "s": "نشاط: نرجع إلى كتاب "}, {"t": "quote", "s": "تكريم المرأة في الإسلام"}, {"t": "text", "s": " للشيخ زينو، ونلخصه وننشر أهم ما فيه.."}]}, {"type": "paragraph", "md": "منارات الهدى", "page": 320, "id": "unit-26__lesson-12__b32"}]' WHERE id='unit-26__lesson-12';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-13','unit-26',13,'مزايا الحجاب ومثالب السفور','الأسرة والمرأة',NULL,2,13,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "ملخصٌ من كتاب: سور العفاف", "page": 320, "id": "unit-26__lesson-13__b01", "role": "section"}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 320, "id": "unit-26__lesson-13__b02", "role": "objectives"}, {"type": "paragraph", "md": "- بيان فضائل الحجاب، ومثالب السفور.. بالأدلة الشرعية والواقعية والاجتماعية.", "page": 320, "id": "unit-26__lesson-13__b03", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "أولا: مزايا الحجاب الشرعي وفضائله للمرأة المسلمة:", "page": 320, "id": "unit-26__lesson-13__b04", "role": "section"}, {"type": "paragraph", "md": "لا بد أن نعلم أن الالتزام بالحجاب الشرعي طاعة لله عز وجل ، وفيه الخير كله، وأنَّ السفور وترك الحجاب الشرعي له مخاطر عظيمة على المرأة والمجتمع والأمة، وقد أوجب الله طاعته وطاعة رسوله صلى الله عليه وسلم ؛ فمِن طاعة الله: اتباع أوامره واجتناب نواهيه، والله عز وجل أمر النساء أن يحتجبن ويستترن ولا يتبرجن، ولا ينبغي للمسلم والمسلمة إذا عرفوا أمر الله ورسوله صلى الله عليه وسلم إلا أن يمتثلوا له قال الله تعالى: ﴿وَمَا كَانَ لِمُؤْمِنٍ وَلَا مُؤْمِنَةٍ إِذَا قَضَى اللَّهُ وَرَسُولُهُ أَمْرًا أَنْ يَكُونَ لَهُمُ الْخِيَرَةُ مِنْ أَمْرِهِمْ وَمَنْ يَعْصِ اللَّهَ وَرَسُولَهُ فَقَدْ ضَلَّ ضَلَالًا مُبِينًا 36﴾، وقال الله تعالى: ﴿فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ ثُمَّ لَا يَجِدُوا فِي أَنْفُسِهِمْ حَرَجًا مِمَّا قَضَيْتَ وَيُسَلِّمُوا تَسْلِيمًا 65﴾.", "page": 320, "id": "unit-26__lesson-13__b05", "inline": [{"t": "text", "s": "لا بد أن نعلم أن الالتزام بالحجاب الشرعي طاعة لله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ، وفيه الخير كله، وأنَّ السفور وترك الحجاب الشرعي له مخاطر عظيمة على المرأة والمجتمع والأمة، وقد أوجب الله طاعته وطاعة رسوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ؛ فمِن طاعة الله: اتباع أوامره واجتناب نواهيه، والله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " أمر النساء أن يحتجبن ويستترن ولا يتبرجن، ولا ينبغي للمسلم والمسلمة إذا عرفوا أمر الله ورسوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " إلا أن يمتثلوا له قال الله تعالى: "}, {"t": "ayah", "s": "وَمَا كَانَ لِمُؤْمِنٍ وَلَا مُؤْمِنَةٍ إِذَا قَضَى اللَّهُ وَرَسُولُهُ أَمْرًا أَنْ يَكُونَ لَهُمُ الْخِيَرَةُ مِنْ أَمْرِهِمْ وَمَنْ يَعْصِ اللَّهَ وَرَسُولَهُ فَقَدْ ضَلَّ ضَلَالًا مُبِينًا 36", "ayah": [], "verses": [{"n": 36, "text": "وَمَا كَانَ لِمُؤْمِنٍ وَلَا مُؤْمِنَةٍ إِذَا قَضَى اللَّهُ وَرَسُولُهُ أَمْرًا أَنْ يَكُونَ لَهُمُ الْخِيَرَةُ مِنْ أَمْرِهِمْ وَمَنْ يَعْصِ اللَّهَ وَرَسُولَهُ فَقَدْ ضَلَّ ضَلَالًا مُبِينًا 36", "surah": 33, "surah_name": "الأحزاب", "ref": "33:36", "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:36"}], "surah": 33, "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:36", "surah_name": "الأحزاب", "ayah_canonical": 36, "match": "exact", "ref": "33:36"}, {"t": "text", "s": "، وقال الله تعالى: "}, {"t": "ayah", "s": "فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ ثُمَّ لَا يَجِدُوا فِي أَنْفُسِهِمْ حَرَجًا مِمَّا قَضَيْتَ وَيُسَلِّمُوا تَسْلِيمًا 65", "ayah": [], "verses": [{"n": 65, "text": "فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ ثُمَّ لَا يَجِدُوا فِي أَنْفُسِهِمْ حَرَجًا مِمَّا قَضَيْتَ وَيُسَلِّمُوا تَسْلِيمًا 65", "surah": 4, "surah_name": "النساء", "ref": "4:65", "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:65"}], "surah": 4, "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:65", "surah_name": "النساء", "ayah_canonical": 65, "match": "exact", "ref": "4:65"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وقد قال تعالى: ﴿وَقُلْ لِلْمُؤْمِنَاتِ يَغْضُضْنَ مِنْ أَبْصَارِهِنَّ وَيَحْفَظْنَ فُرُوجَهُنَّ وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَى جُيُوبِهِنَّ﴾؛ فخاطب الله عز وجل المؤمنات ولم يخاطب غيرهن في هذه الآيات، لأن الذي يمتثل أمر الله ويجتنب نهيه هو المؤمن بالله؛ فرأس فضائل الحجاب أن المرأة الممتثلة له تكون مؤمنة بشهادة القرآن، وهذه بعض فضائل الحجاب الشرعي ليترسخ في قلبكِ حبه والعمل به:", "page": 320, "id": "unit-26__lesson-13__b06", "inline": [{"t": "text", "s": "وقد قال تعالى: "}, {"t": "ayah", "s": "وَقُلْ لِلْمُؤْمِنَاتِ يَغْضُضْنَ مِنْ أَبْصَارِهِنَّ وَيَحْفَظْنَ فُرُوجَهُنَّ وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَى جُيُوبِهِنَّ", "ayah": [], "verses": [{"n": 31, "text": "وَقُلْ لِلْمُؤْمِنَاتِ يَغْضُضْنَ مِنْ أَبْصَارِهِنَّ وَيَحْفَظْنَ فُرُوجَهُنَّ وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَى جُيُوبِهِنَّ", "surah": 24, "surah_name": "النور", "ref": "24:31", "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31"}], "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31", "surah_name": "النور", "ayah_canonical": 31, "match": "contained", "ref": "24:31"}, {"t": "text", "s": "؛ فخاطب الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " المؤمنات ولم يخاطب غيرهن في هذه الآيات، لأن الذي يمتثل أمر الله ويجتنب نهيه هو المؤمن بالله؛ فرأس فضائل الحجاب أن المرأة الممتثلة له تكون مؤمنة بشهادة القرآن، "}, {"t": "emphasis", "s": "وهذه بعض فضائل الحجاب الشرعي ليترسخ في قلبكِ حبه والعمل به:", "role": "emphasis"}]}, {"type": "paragraph", "md": "1- أنه طهارة للرجال والنساء؛ قال تعالى ﴿فَاسْأَلُوهُنَّ مِنْ وَرَاءِ حِجَابٍ ذَلِكُمْ أَطْهَرُ لِقُلُوبِكُمْ وَقُلُوبِهِنَّ﴾.", "page": 320, "id": "unit-26__lesson-13__b07", "inline": [{"t": "text", "s": "1- أنه "}, {"t": "emphasis", "s": "طهارة", "role": "emphasis"}, {"t": "text", "s": " للرجال والنساء؛ قال تعالى "}, {"t": "ayah", "s": "فَاسْأَلُوهُنَّ مِنْ وَرَاءِ حِجَابٍ ذَلِكُمْ أَطْهَرُ لِقُلُوبِكُمْ وَقُلُوبِهِنَّ", "ayah": [], "verses": [{"n": 53, "text": "فَاسْأَلُوهُنَّ مِنْ وَرَاءِ حِجَابٍ ذَلِكُمْ أَطْهَرُ لِقُلُوبِكُمْ وَقُلُوبِهِنَّ", "surah": 33, "surah_name": "الأحزاب", "ref": "33:53", "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:53"}], "surah": 33, "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:53", "surah_name": "الأحزاب", "ayah_canonical": 53, "match": "contained", "ref": "33:53"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- أنه عفة؛ فقد علل الله الأمر بالحجاب بأن: ﴿ذَلِكَ أَدْنَى أَنْ يُعْرَفْنَ فَلَا يُؤْذَيْنَ﴾؛ لأنهن إن لم يحتجبن ظُنَّ أنهن غير عفيفات فيتعرضنَ للأذى لظهور محاسنها لكل الناس، وتأمل أنَّ الله أجاز للقواعد من النساء أن يخلعن غطاء الوجه، ثم ذكر أن الأفضل والأعف بقاءه حتى لهن؛ فقال: ﴿وَأَنْ يَسْتَعْفِفْنَ خَيْرٌ لَهُنَّ﴾.", "page": 320, "id": "unit-26__lesson-13__b08", "inline": [{"t": "text", "s": "2- أنه "}, {"t": "emphasis", "s": "عفة", "role": "emphasis"}, {"t": "text", "s": "؛ فقد علل الله الأمر بالحجاب بأن: "}, {"t": "ayah", "s": "ذَلِكَ أَدْنَى أَنْ يُعْرَفْنَ فَلَا يُؤْذَيْنَ", "ayah": [], "verses": [{"n": 59, "text": "ذَلِكَ أَدْنَى أَنْ يُعْرَفْنَ فَلَا يُؤْذَيْنَ", "surah": 33, "surah_name": "الأحزاب", "ref": "33:59", "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:59"}], "surah": 33, "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:59", "surah_name": "الأحزاب", "ayah_canonical": 59, "match": "contained", "ref": "33:59"}, {"t": "text", "s": "؛ لأنهن إن لم يحتجبن ظُنَّ أنهن غير عفيفات فيتعرضنَ للأذى لظهور محاسنها لكل الناس، وتأمل أنَّ الله أجاز للقواعد من النساء أن يخلعن غطاء الوجه، ثم ذكر أن الأفضل والأعف بقاءه حتى لهن؛ فقال: "}, {"t": "ayah", "s": "وَأَنْ يَسْتَعْفِفْنَ خَيْرٌ لَهُنَّ", "ayah": [], "verses": [{"n": 60, "text": "وَأَنْ يَسْتَعْفِفْنَ خَيْرٌ لَهُنَّ", "surah": 24, "surah_name": "النور", "ref": "24:60", "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:60"}], "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:60", "surah_name": "النور", "ayah_canonical": 60, "match": "contained", "ref": "24:60"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- أنه ستر، والله يحب الستر، قال صلى الله عليه وسلم : (إن الله تعالى حَيِّيٌ ستير يحب الستر) والستر وحبه من أخلاق الأنبياء؛ فكان صلى الله عليه وسلم يدعو: (اللهم استر عوراتي وآمن روعاتي) فيستحب ستر العورة حتى في الخلوة وقيل: يجب تأدبًا مع الله؛ فقد قال صلى الله عليه وسلم : (فالله أحق أن يستحيا منه من الناس)، وتأملوا حال حرص الصحابيات رضي الله عنهن على الستر في قصة عائشة رضي الله عنها في حادثة الإفك عندما لقيها صفوان بن المعطل رضي الله عنه ، وقد ذهب الجيش وتركها ووجدها نائمة على الأرض بلباسها الشرعي؛ فعرفها لأنها كان يراها قبل الحجاب، فقال: ظعينة رسول الله وأخذ يسترجع إنا لله وإنا إليه راجعون، قالت عائشة: (فاستيقظت على ترجيعه فخمرت وجهي)، والشاهد هنا واضح: سارعت في تخير وجهها عند استيقاظها من النوم سترًا لما أمر الله.", "page": 321, "id": "unit-26__lesson-13__b09", "inline": [{"t": "text", "s": "3- أنه "}, {"t": "emphasis", "s": "ستر", "role": "emphasis"}, {"t": "text", "s": "، والله يحب ال"}, {"t": "emphasis", "s": "ستر", "role": "emphasis"}, {"t": "text", "s": "، قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إن الله تعالى حَيِّيٌ ستير يحب الستر)", "role": "emphasis"}, {"t": "text", "s": " وال"}, {"t": "emphasis", "s": "ستر", "role": "emphasis"}, {"t": "text", "s": " وحبه من أخلاق الأنبياء؛ فكان "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يدعو: "}, {"t": "emphasis", "s": "(اللهم استر عوراتي وآمن روعاتي)", "role": "emphasis"}, {"t": "text", "s": " فيستحب "}, {"t": "emphasis", "s": "ستر", "role": "emphasis"}, {"t": "text", "s": " العورة حتى في الخلوة وقيل: يجب تأدبًا مع الله؛ فقد قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(فالله أحق أن يستحيا منه من الناس)", "role": "emphasis"}, {"t": "text", "s": "، وتأملوا حال حرص الصحابيات "}, {"t": "honorific", "s": "رضي الله عنهن"}, {"t": "text", "s": " على ال"}, {"t": "emphasis", "s": "ستر", "role": "emphasis"}, {"t": "text", "s": " في قصة عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " في حادثة الإفك عندما لقيها صفوان بن المعطل "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ، وقد ذهب الجيش وتركها ووجدها نائمة على الأرض بلباسها الشرعي؛ فعرفها لأنها كان يراها قبل الحجاب، فقال: ظعينة رسول الله وأخذ ي"}, {"t": "emphasis", "s": "ستر", "role": "emphasis"}, {"t": "text", "s": "جع إنا لله وإنا إليه راجعون، قالت عائشة: "}, {"t": "emphasis", "s": "(فاستيقظت على ترجيعه فخمرت وجهي)", "role": "emphasis"}, {"t": "text", "s": "، والشاهد هنا واضح: سارعت في تخير وجهها عند استيقاظها من النوم "}, {"t": "emphasis", "s": "ستر", "role": "emphasis"}, {"t": "text", "s": "ًا لما أمر الله."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "وقال ابن عباس: ألا أريك امرأة من أهل الجنة؟! هذه المرأة السوداء، أتت النبي صلى الله عليه وسلم فقالت: «إني أصرع وإني أتكشف، فادع الله لي، قال: (إن شئت صبرت ولك الجنة، وإن شئت دعوت الله أن يعافيك. قالت: أصبر، قالت: فإني أتكشف فادع الله ألا أتكشف فدعا لها»؛ فحرصت على الستر رغم مرضها.", "page": 321, "id": "unit-26__lesson-13__b10", "inline": [{"t": "text", "s": "وقال ابن عباس: ألا أريك امرأة من أهل الجنة؟! هذه المرأة السوداء، أتت النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " فقالت: "}, {"t": "hadith", "s": "إني أصرع وإني أتكشف، فادع الله لي، قال: (إن شئت صبرت ولك الجنة، وإن شئت دعوت الله أن يعافيك. قالت: أصبر، قالت: فإني أتكشف فادع الله ألا أتكشف فدعا لها", "narrator": null, "source": null, "confidence": "high", "ref_api": null}, {"t": "text", "s": "؛ فحرصت على الستر رغم مرضها."}]}, {"type": "paragraph", "md": "وقصة عائشة رضي الله عنها عندما دفن النبي صلى الله عليهم وسلم وأبوها في حجرتها ثم دفن عمر رضي الله عنها فقالت: «كنت أدخل بيتي الذي فيه رسول الله صلى الله عليه وسلم وإني واضع ثوبي وأقول إنما زوجي وأبي؛ فلما دفن عمر رضي الله عنه معهم فوالله ما دخلته إلا وأنا مشدودة عليَّ ثيابي حياء من عمر».", "page": 321, "id": "unit-26__lesson-13__b11", "inline": [{"t": "emphasis", "s": "وقصة عائشة", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "عندما دفن النبي صلى الله عليهم وسلم وأبوها في حجرتها ثم دفن عمر", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " فقالت: "}, {"t": "hadith", "s": "كنت أدخل بيتي الذي فيه رسول الله صلى الله عليه وسلم وإني واضع ثوبي وأقول إنما زوجي وأبي؛ فلما دفن عمر رضي الله عنه معهم فوالله ما دخلته إلا وأنا مشدودة عليَّ ثيابي حياء من عمر", "narrator": null, "source": null, "confidence": "medium", "ref_api": null}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "4- أنه حياء، قال صلى الله عليه وسلم : (الحياء لا يأتي إلا بخير)؛ لذلك ينبغي على المسلمين أن يعودوا أنفسهم وأولادهم على هذا الخلق العظيم وخاصة النساء؛ فهو خلق ممدوح في الشريعة جدا، وفي القرآن قصة بنت الرجل الصالح التي جاءت لموسى عليه السلام تدعوه إلى أبيها، وكلها عفة وطهارة وحياء؛ فقد قال الله تعالى عنها: ﴿فَجَاءَتْهُ إِحْدَاهُمَا تَمْشِي عَلَى اسْتِحْيَاءٍ﴾، قال عمر رضي الله عنه عند هذه الآية: «جاءت مستترة، وقد وضعت كم درعها على وجهها استحياءً».", "page": 321, "id": "unit-26__lesson-13__b12", "inline": [{"t": "emphasis", "s": "4- أنه حياء، قال", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": ": (الحياء لا يأتي إلا بخير)", "role": "emphasis"}, {"t": "text", "s": "؛ لذلك ينبغي على المسلمين أن يعودوا أنفسهم وأولادهم على هذا الخلق العظيم وخاصة النساء؛ فهو خلق ممدوح في الشريعة جدا، وفي القرآن قصة بنت الرجل الصالح التي جاءت لموسى "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " تدعوه إلى أبيها، وكلها عفة وطهارة وحياء؛ فقد قال الله تعالى عنها: "}, {"t": "ayah", "s": "فَجَاءَتْهُ إِحْدَاهُمَا تَمْشِي عَلَى اسْتِحْيَاءٍ", "ayah": [], "verses": [{"n": 25, "text": "فَجَاءَتْهُ إِحْدَاهُمَا تَمْشِي عَلَى اسْتِحْيَاءٍ", "surah": 28, "surah_name": "القصص", "ref": "28:25", "ref_api": "https://api.quran.com/api/v4/verses/by_key/28:25"}], "surah": 28, "ref_api": "https://api.quran.com/api/v4/verses/by_key/28:25", "surah_name": "القصص", "ayah_canonical": 25, "match": "contained", "ref": "28:25"}, {"t": "text", "s": "، قال عمر "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " عند هذه الآية: "}, {"t": "quote", "s": "جاءت مستترة، وقد وضعت كم درعها على وجهها استحياءً"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- أنه يناسب الغيرة التي جبل الله عليها الإنسان السوي: والغيرة تبعث على الاحتجاب، والشهوة تبعث على السفور؛ وضد الغَيور: الديوث الذي يقر الخبث في أهله ولا غيرة له على أهل بيته، قال صلى الله عليه وسلم : (ثلاث لا يدخلون الجنة ولا ينظر الله إليهم يوم القيامة: العاق والديه، والمرأة المترجلة المتشبهة بالرجال، والديوث).", "page": 321, "id": "unit-26__lesson-13__b13", "inline": [{"t": "text", "s": "5- "}, {"t": "emphasis", "s": "أنه يناسب الغيرة التي جبل الله عليها الإنسان السوي:", "role": "emphasis"}, {"t": "text", "s": " والغيرة تبعث على الاحتجاب، والشهوة تبعث على السفور؛ وضد الغَيور: الديوث الذي يقر الخبث في أهله ولا غيرة له على أهل بيته، قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(ثلاث لا يدخلون الجنة ولا ينظر الله إليهم يوم القيامة: العاق والديه، والمرأة المترجلة المتشبهة بالرجال، والديوث)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6- أن فيه حماية المرأة وصونها، وفي ذلك حماية للمجتمع كله وصون لأدبه وأخلاقه وقيمه؛ فهو زي لشرف للمرأة وعلامة على استقلالها وحريتها، وهو الذي يقطع الأطماع والخواطر الشيطانية عنها.", "page": 321, "id": "unit-26__lesson-13__b14", "list": {"type": "ordered", "marker": "6"}}, {"type": "paragraph", "md": "7- فيه وقاية اجتماعية من الأذى، فالرجل مفطور على التعليق بالمرأة وحب محاسنها، فإن تكشفت ظهرت أمراض القلوب في الرجال والنساء؛ فيأتي الحجاب لقطع الأطماع الفاجرة، وكف الأعين الخائنة، ودفع أذى الرجل في عرضه، وأذى المرأة في عرضها ومحارمها، وقطع حبال الشيطان عن الزنا والحرام.", "page": 322, "id": "unit-26__lesson-13__b15", "list": {"type": "ordered", "marker": "7"}}, {"type": "heading", "level": 3, "text": "أخطار ومثالب السفور؛ كثيرة كذلك، ولكن نذكر منها على سبيل المثال:", "page": 322, "id": "unit-26__lesson-13__b16", "role": "section"}, {"type": "paragraph", "md": "1- التبرج معصية لله ورسوله سبحانه وتعالى ، قال عز وجل : ﴿وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْأُولَى﴾، وقال صلى الله عليه وسلم : (كل أمتي يدخلون الجنة إلا من أبى. فقالوا: يا رسول الله من يأبى؟ قال: من أطاعني دخل الجنة ومن عصاني فقد أبى)، وقد خطب معاوية رضي الله عنه في حمص بالمسلمين وذكر أن رسول الله صلى الله عليه وسلم حرَّم سبعة أشياء ذكر منها: التبرج، وعن ابن مسعود رضي الله عنه أن النبي صلى الله عليه وسلم كان يكره عشر خصال وذكر منها: التبرج بالزينة لغير محلها.", "page": 322, "id": "unit-26__lesson-13__b17", "inline": [{"t": "text", "s": "1- التبرج معصية لله ورسوله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، قال "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " : "}, {"t": "ayah", "s": "وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْأُولَى", "ayah": [], "verses": [{"n": 33, "text": "وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْأُولَى", "surah": 33, "surah_name": "الأحزاب", "ref": "33:33", "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:33"}], "surah": 33, "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:33", "surah_name": "الأحزاب", "ayah_canonical": 33, "match": "contained", "ref": "33:33"}, {"t": "text", "s": "، وقال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(كل أمتي يدخلون الجنة إلا من أبى. فقالوا: يا رسول الله من يأبى؟ قال: من أطاعني دخل الجنة ومن عصاني فقد أبى)", "role": "emphasis"}, {"t": "text", "s": "، وقد خطب معاوية "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " في حمص بالمسلمين وذكر أن رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " حرَّم سبعة أشياء ذكر منها: التبرج، وعن ابن مسعود "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " أن النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " كان يكره عشر خصال وذكر منها: التبرج بالزينة لغير محلها."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- التبرج كبيرة موبقة؛ لأن النبي صلى الله عليه وسلم عندما بايع أميمة قال: (أبايعك على أن لا تشركي بالله ولا تسرقي ولا تزني ولا تقتلي ولدك ولا تأتي ببهتان تفتريه بين يديك ورجليك ولا تنوحي ولا تتبرجي تبرج الجاهلية)، فقرن النبي صلى الله عليه وسلم التبرج بأكبر الكبائر؛ كالشرك بالله فدل على أنه من الكبائر الموبقة.", "page": 322, "id": "unit-26__lesson-13__b18", "inline": [{"t": "text", "s": "2- التبرج كبيرة موبقة؛ لأن النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " عندما بايع أميمة قال: "}, {"t": "emphasis", "s": "(أبايعك على أن لا تشركي بالله ولا تسرقي ولا تزني ولا تقتلي ولدك ولا تأتي ببهتان تفتريه بين يديك ورجليك ولا تنوحي ولا تتبرجي تبرج الجاهلية)", "role": "emphasis"}, {"t": "text", "s": "، فقرن النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " التبرج بأكبر الكبائر؛ كالشرك بالله فدل على أنه من الكبائر الموبقة."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- التبرج يجلب اللعنة والطرد من رحمة الله؛ قال صلى الله عليه وسلم : (سيكون في آخر أمتي رجال يركبون على سروج كأشباه الرجال ينزلون على أبواب المساجد، نساؤهم كاسيات عاريات على رؤوسهن كأسنمة البخت العجاف، العنوهن فإنهن ملعونات).", "page": 322, "id": "unit-26__lesson-13__b19", "inline": [{"t": "text", "s": "3- التبرج يجلب اللعنة والطرد من رحمة الله؛ قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(سيكون في آخر أمتي رجال يركبون على سروج كأشباه الرجال ينزلون على أبواب المساجد، نساؤهم كاسيات عاريات على رؤوسهن كأسنمة البخت العجاف، العنوهن فإنهن ملعونات)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- التبرج من صفات أهل النار؛ فقد قال رسول الله صلى الله عليه وسلم : (صنفان من أهل النار لم أرهما، قوم معهم سياط كأذناب البقر، يضربون بها الناس، ونساء كاسيات عاريات، مميلات مائلات، رؤوسهن كأسنمة البخت المائلة، لا يدخلن الجنة، ولا يجدن ريحها، وإن ريحها ليوجد من مسيرة كذا وكذا).", "page": 322, "id": "unit-26__lesson-13__b20", "inline": [{"t": "text", "s": "4- التبرج من صفات أهل النار؛ فقد قال رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(صنفان من أهل النار لم أرهما، قوم معهم سياط كأذناب البقر، يضربون بها الناس، ونساء كاسيات عاريات، مميلات مائلات، رؤوسهن كأسنمة البخت المائلة، لا يدخلن الجنة، ولا يجدن ريحها، وإن ريحها ليوجد من مسيرة كذا وكذا)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- التبرج سواد وظلمة يوم القيامة، فقد قال صلى الله عليه وسلم : (مثل الرافلة في الزينة في غير أهلها كمثل ظلمة يوم القيامة لا نور لها) و(الرافلةِ) التي ترفلُ في ثوبها أيْ تتبخترُ في ثوبها بإرخائه، وقوله (في الزينةِ) أيْ في ثيابِ الزينةِ (في غيرِ أهلها) أيْ بينَ منْ يحرمُ نظرهُ إليها (كمثلِ ظلمةٍ يومَ القيامةِ) أيْ تكونُ يومَ القيامةِ كأنها ظلمةٌ (لا نورَ لها) الضميرُ للمرأةِ؛ يريدُ بذلك بيان إثم المتبرجةَ بالزينةِ لغيرِ زوجها.", "page": 322, "id": "unit-26__lesson-13__b21", "inline": [{"t": "text", "s": "5- التبرج سواد وظلمة يوم القيامة، فقد قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(مثل الرافلة في الزينة في غير أهلها كمثل ظلمة يوم القيامة لا نور لها)", "role": "emphasis"}, {"t": "text", "s": " و"}, {"t": "emphasis", "s": "(الرافلةِ)", "role": "emphasis"}, {"t": "text", "s": " التي ترفلُ في ثوبها أيْ تتبخترُ في ثوبها بإرخائه، وقوله "}, {"t": "emphasis", "s": "(في الزينةِ)", "role": "emphasis"}, {"t": "text", "s": " أيْ في ثيابِ الزينةِ "}, {"t": "emphasis", "s": "(في غيرِ أهلها)", "role": "emphasis"}, {"t": "text", "s": " أيْ بينَ منْ يحرمُ نظرهُ إليها "}, {"t": "emphasis", "s": "(كمثلِ ظلمةٍ يومَ القيامةِ)", "role": "emphasis"}, {"t": "text", "s": " أيْ تكونُ يومَ القيامةِ كأنها ظلمةٌ "}, {"t": "emphasis", "s": "(لا نورَ لها)", "role": "emphasis"}, {"t": "text", "s": " الضميرُ للمرأةِ؛ يريدُ بذلك بيان إثم المتبرجةَ بالزينةِ لغيرِ زوجها."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6-التبرج فاحشة والشيطان هو يأمر بهذه الفاحشة، قال الله عز وحل: ﴿الشَّيْطَانُ يَعِدُكُمُ الْفَقْرَ وَيَأْمُرُكُمْ بِالْفَحْشَاءِ وَاللَّهُ يَعِدُكُمْ مَغْفِرَةً مِنْهُ وَفَضْلًا وَاللَّهُ وَاسِعٌ عَلِيمٌ 268﴾، والتبرج من الفحش المذموم.", "page": 322, "id": "unit-26__lesson-13__b22", "inline": [{"t": "text", "s": "6-التبرج فاحشة والشيطان هو يأمر بهذه الفاحشة، قال الله عز وحل: "}, {"t": "ayah", "s": "الشَّيْطَانُ يَعِدُكُمُ الْفَقْرَ وَيَأْمُرُكُمْ بِالْفَحْشَاءِ وَاللَّهُ يَعِدُكُمْ مَغْفِرَةً مِنْهُ وَفَضْلًا وَاللَّهُ وَاسِعٌ عَلِيمٌ 268", "ayah": [], "verses": [{"n": 268, "text": "الشَّيْطَانُ يَعِدُكُمُ الْفَقْرَ وَيَأْمُرُكُمْ بِالْفَحْشَاءِ وَاللَّهُ يَعِدُكُمْ مَغْفِرَةً مِنْهُ وَفَضْلًا وَاللَّهُ وَاسِعٌ عَلِيمٌ 268", "surah": 2, "surah_name": "البقرة", "ref": "2:268", "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:268"}], "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:268", "surah_name": "البقرة", "ayah_canonical": 268, "match": "exact", "ref": "2:268"}, {"t": "text", "s": "، والتبرج من الفحش المذموم."}]}, {"type": "paragraph", "md": "7-التبرج تهتك وفضيحة، عن عائشة رضي الله عنها قالت: «أيما امرأة وضعت ثيابها في غير بيت زوجها فقد هتكت ستر ما بينها وبين الله)، ونزع الثياب عبارة عن تكشفها للأجنبي لينال منها ما حرم الله نظرًا أو جِماعًا؛ بخلاف ما لو نزعت ثيابها بين نساء مع المحافظة على ستر العورة، إذ لا وجه لدخولها في هذا الوعيد.", "page": 323, "id": "unit-26__lesson-13__b23", "inline": [{"t": "text", "s": "7-التبرج تهتك وفضيحة، عن عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " قالت: «أيما امرأة وضعت ثيابها في غير بيت زوجها فقد هتكت ستر ما بينها وبين الله)، ونزع الثياب عبارة عن تكشفها للأجنبي لينال منها ما حرم الله نظرًا أو جِماعًا؛ بخلاف ما لو نزعت ثيابها بين نساء مع المحافظة على ستر العورة، إذ لا وجه لدخولها في هذا الوعيد."}]}, {"type": "paragraph", "md": "8-التبرج سنة إبليسية، وهذا يدخل في المعركة مع الشيطان؛ لأن الشيطان يريد إغواء بني آدم قال الله عز وجل عنه: ﴿قَالَ فَبِمَا أَغْوَيْتَنِي لَأَقْعُدَنَّ لَهُمْ صِرَاطَكَ الْمُسْتَقِيمَ 16 ثُمَّ لَآتِيَنَّهُمْ مِنْ بَيْنِ أَيْدِيهِمْ وَمِنْ خَلْفِهِمْ﴾، ولا عاصم لبني آدم من الشيطان إلا اتباع سنن الله وليس سنن الشيطان، وبذلك نفهم أن إبليس هو رائد الدعوة إلى كشف العورات وهو مؤسس الدعوة إلى التبرج بدرجاته المتفاوتة.", "page": 323, "id": "unit-26__lesson-13__b24", "inline": [{"t": "text", "s": "8-التبرج سنة إبليسية، وهذا يدخل في المعركة مع الشيطان؛ لأن الشيطان يريد إغواء بني آدم قال الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " عنه: "}, {"t": "ayah", "s": "قَالَ فَبِمَا أَغْوَيْتَنِي لَأَقْعُدَنَّ لَهُمْ صِرَاطَكَ الْمُسْتَقِيمَ 16 ثُمَّ لَآتِيَنَّهُمْ مِنْ بَيْنِ أَيْدِيهِمْ وَمِنْ خَلْفِهِمْ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "، ولا عاصم لبني آدم من الشيطان إلا اتباع سنن الله وليس سنن الشيطان، وبذلك نفهم أن إبليس هو رائد الدعوة إلى كشف العورات وهو مؤسس الدعوة إلى التبرج بدرجاته المتفاوتة."}]}, {"type": "paragraph", "md": "9- التبرج من سنن اليهود والنصارى، قال الله عز وجل عنهم: ﴿وَيَسْعَوْنَ فِي الْأَرْضِ فَسَادًا وَاللَّهُ لَا يُحِبُّ الْمُفْسِدِينَ﴾، وفي الحديث: (يا أيها الناس انهوا نساءكم عن لبس الزينة، والتبختر في المسجد، فإن بني إسرائيل لم يلعنوا حتى لبسن الزينة، وتبخترن في المساجد) وهو حديث ضعيف سنده، صحيح معناه.", "page": 323, "id": "unit-26__lesson-13__b25", "inline": [{"t": "text", "s": "9- التبرج من سنن اليهود والنصارى، قال الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " عنهم: "}, {"t": "ayah", "s": "وَيَسْعَوْنَ فِي الْأَرْضِ فَسَادًا وَاللَّهُ لَا يُحِبُّ الْمُفْسِدِينَ", "ayah": [], "verses": [{"n": 64, "text": "وَيَسْعَوْنَ فِي الْأَرْضِ فَسَادًا وَاللَّهُ لَا يُحِبُّ الْمُفْسِدِينَ", "surah": 5, "surah_name": "المائدة", "ref": "5:64", "ref_api": "https://api.quran.com/api/v4/verses/by_key/5:64"}], "surah": 5, "ref_api": "https://api.quran.com/api/v4/verses/by_key/5:64", "surah_name": "المائدة", "ayah_canonical": 64, "match": "contained", "ref": "5:64"}, {"t": "text", "s": "، وفي الحديث: "}, {"t": "emphasis", "s": "(يا أيها الناس انهوا نساءكم عن لبس الزينة، والتبختر في المسجد، فإن بني إسرائيل لم يلعنوا حتى لبسن الزينة، وتبخترن في المساجد)", "role": "emphasis"}, {"t": "text", "s": " وهو حديث ضعيف سنده، صحيح معناه."}], "list": {"type": "ordered", "marker": "9"}}, {"type": "paragraph", "md": "10- التبرج جاهلية منتنة، قال تعالى: ﴿وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْأُولَى﴾، وقد وصف النبي صلى الله عليه وسلم الجاهلية بأنها منتنة أي خبيثة وأمرنا بنبذها ومحاربتها ومنعها في المجتمعات المسلمة.", "page": 323, "id": "unit-26__lesson-13__b26", "inline": [{"t": "text", "s": "10- التبرج جاهلية منتنة، قال تعالى: "}, {"t": "ayah", "s": "وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْأُولَى", "ayah": [], "verses": [{"n": 33, "text": "وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْأُولَى", "surah": 33, "surah_name": "الأحزاب", "ref": "33:33", "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:33"}], "surah": 33, "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:33", "surah_name": "الأحزاب", "ayah_canonical": 33, "match": "contained", "ref": "33:33"}, {"t": "text", "s": "، وقد وصف النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " الجاهلية بأنها منتنة أي خبيثة وأمرنا بنبذها ومحاربتها ومنعها في المجتمعات المسلمة."}], "list": {"type": "ordered", "marker": "10"}}, {"type": "paragraph", "md": "11- التبرج انتكاس وتخلف وانحطاط؛ لأن العري فطرة حيوانية، لا يميل إليها الإنسان إلا إذا نزل من مرتبة أقل من مرتبة الإنسان وهذا نوع من الانحطاط والتخلف عن المكانة التي كرم الله عز وجل بها الإنسان.", "page": 323, "id": "unit-26__lesson-13__b27", "inline": [{"t": "text", "s": "11- التبرج انتكاس وتخلف وانحطاط؛ لأن العري فطرة حيوانية، لا يميل إليها الإنسان إلا إذا نزل من مرتبة أقل من مرتبة الإنسان وهذا نوع من الانحطاط والتخلف عن المكانة التي كرم الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " بها الإنسان."}], "list": {"type": "ordered", "marker": "11"}}, {"type": "paragraph", "md": "وهو كذلك باب شر مستطير؛ فيجعل المتبرجات يتسابقن بلفت أنظار الناس إليهم مما يجعلها كالسلعة المهينة المعروضة لكل من شاء أن ينظر لها ويفتح باب الجرائم وفساد الأخلاق وتحطيم روابط الأسرة وتسهيل الزنا بالعين، ويجعل المجتمع يستحث العقوبات العامة التي هي من أخطر العواقب، قال عز وجل : ﴿وَإِذَا أَرَدْنَا أَنْ نُهْلِكَ قَرْيَةً أَمَرْنَا مُتْرَفِيهَا فَفَسَقُوا فِيهَا فَحَقَّ عَلَيْهَا الْقَوْلُ فَدَمَّرْنَاهَا تَدْمِيرًا 16﴾.", "page": 323, "id": "unit-26__lesson-13__b28", "inline": [{"t": "text", "s": "وهو كذلك باب شر مستطير؛ فيجعل المتبرجات يتسابقن بلفت أنظار الناس إليهم مما يجعلها كالسلعة المهينة المعروضة لكل من شاء أن ينظر لها ويفتح باب الجرائم وفساد الأخلاق وتحطيم روابط الأسرة وتسهيل الزنا بالعين، ويجعل المجتمع يستحث العقوبات العامة التي هي من أخطر العواقب، قال "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " : "}, {"t": "ayah", "s": "وَإِذَا أَرَدْنَا أَنْ نُهْلِكَ قَرْيَةً أَمَرْنَا مُتْرَفِيهَا فَفَسَقُوا فِيهَا فَحَقَّ عَلَيْهَا الْقَوْلُ فَدَمَّرْنَاهَا تَدْمِيرًا 16", "ayah": [], "verses": [{"n": 16, "text": "وَإِذَا أَرَدْنَا أَنْ نُهْلِكَ قَرْيَةً أَمَرْنَا مُتْرَفِيهَا فَفَسَقُوا فِيهَا فَحَقَّ عَلَيْهَا الْقَوْلُ فَدَمَّرْنَاهَا تَدْمِيرًا 16", "surah": 17, "surah_name": "الإسراء", "ref": "17:16", "ref_api": "https://api.quran.com/api/v4/verses/by_key/17:16"}], "surah": 17, "ref_api": "https://api.quran.com/api/v4/verses/by_key/17:16", "surah_name": "الإسراء", "ayah_canonical": 16, "match": "exact", "ref": "17:16"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "12-التبرج فتنة للنساء اللاتي يرتدين حجابًا؛ بأن يقع في أنفسهن حب التبرج أيضًا تأثرًا بالمتبرجة.", "page": 323, "id": "unit-26__lesson-13__b29"}, {"type": "paragraph", "md": "13- التبرج باب لشيوع الفاحشة في المجتمع والوقوع بالمعاصي والشهوات مما يصرف المجتمع عن الحلال إلى الحرام فيؤدي إلى الإعراض عن الزواج، ومن ثَم تكثر العوانس في المجتمعات المتفلتة.", "page": 323, "id": "unit-26__lesson-13__b30", "list": {"' WHERE id='unit-26__lesson-13';
UPDATE manhaj_lessons SET blocks = blocks || 'type": "ordered", "marker": "13"}}, {"type": "paragraph", "md": "14- في التبرج انعدام لقيم الفطرة والقيم الإسلامية؛ بسبب انتشار السفور، مما يقضي على الغيرة في المجتمع والحياء، وهذه من الأمو التي فُطِرَ الإنسان عليها ودعا إليها الشرع.", "page": 323, "id": "unit-26__lesson-13__b31", "list": {"type": "ordered", "marker": "14"}}, {"type": "paragraph", "md": "15- يؤدي التبرج إلى كثرة الجرائم والاعتداء على الأعراض؛ بسبب السفور، وأول من يتعرض لذلك المرأة السافرة ثم يصل هذا الأمر إلى المحجبة بسبب انتشاره، ولذلك ينتشر في الغرب الاغتصاب بصورة فظيعة حتى أثبتت بعض الدراسات الغربية أن أربعة من كل عشر نسوة تعرضن للاغتصاب!!", "page": 324, "id": "unit-26__lesson-13__b32", "list": {"type": "ordered", "marker": "15"}}, {"type": "paragraph", "md": "16- في التبرج فساد أخلاق الرجال والشباب والمراهقين، ودفعهم إلى الفواحش المحرمة بأنواعها.", "page": 324, "id": "unit-26__lesson-13__b33", "list": {"type": "ordered", "marker": "16"}}, {"type": "paragraph", "md": "17- من أخطار التبرج تحطيم الروابط الأسرية، وانعدام الثقة بين أفرادها، وتفشي الطلاق وتفكك البيوت المسلمة مما يؤدي إلى نقص كبير في التربية عند الناشئة؛ حيثُ تضيع الأسرة كلها بسبب ذلك.", "page": 324, "id": "unit-26__lesson-13__b34", "list": {"type": "ordered", "marker": "17"}}, {"type": "paragraph", "md": "18- من أخطار التبرج أنه يؤدي إلى المتاجرة بالمرأة كوسيلة دعاية، أو ترفيه في مجالات التجارة وغيرها، واستخدامها في الشهوات والملذات وعدم اعتبار قيمة لها وجعلها سلعة مهينة.", "page": 324, "id": "unit-26__lesson-13__b35", "list": {"type": "ordered", "marker": "18"}}, {"type": "paragraph", "md": "19- من أخطار التبرج تسهيل معصية الزنا بالعين، قال صلى الله عليه وسلم : (العينان زناهما النظر)، وأيضًا فيه تعسير طاعة غض البصر التي أُمرنا بها إرضاءً لله سبحانه.", "page": 324, "id": "unit-26__lesson-13__b36", "inline": [{"t": "text", "s": "19- من أخطار التبرج تسهيل معصية الزنا بالعين، قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(العينان زناهما النظر)", "role": "emphasis"}, {"t": "text", "s": "، وأيضًا فيه تعسير طاعة غض البصر التي أُمرنا بها إرضاءً لله سبحانه."}], "list": {"type": "ordered", "marker": "19"}}, {"type": "paragraph", "md": "20- يؤدي التبرج لانتشار الأمراض الجديدة؛ فقد قال صلى الله عليه وسلم : (ما ظهرت الفاحشة في قوم قط حتى يعلنوا بها، إلا فشا فيهم الطاعون والأوجاع التي لم تكن مضت في أسلافهم الذين مضوا قبلهم).", "page": 324, "id": "unit-26__lesson-13__b37", "inline": [{"t": "text", "s": "20- يؤدي التبرج لانتشار الأمراض الجديدة؛ فقد قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(ما ظهرت الفاحشة في قوم قط حتى يعلنوا بها، إلا فشا فيهم الطاعون والأوجاع التي لم تكن مضت في أسلافهم الذين مضوا قبلهم)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "20"}}, {"type": "paragraph", "md": "21- يؤدي التبرج إلى استحقاق نزول العقوبات العامة التي هي قطعًا أخطر عاقبة فينزل الله عقابه بكيفية لا يعلمها إلا هو كالآيات الكونية من زلازل وبراكين وأعاصير أو تسليط الأعداء أو انتشار الأوبئة.", "page": 324, "id": "unit-26__lesson-13__b38", "list": {"type": "ordered", "marker": "21"}}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 324, "id": "unit-26__lesson-13__b39", "role": "assessment"}, {"type": "paragraph", "md": "1- نعقد مقارنة بين فضائل الحجاب ومثالب السفور.", "page": 324, "id": "unit-26__lesson-13__b40", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ما الدليل على ما يأتي:", "page": 324, "id": "unit-26__lesson-13__b41", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "أ- التبرج سواد وظلمة. ب- الحجاب عفة. ج- الحجاب فطرة سليمة.", "page": 324, "id": "unit-26__lesson-13__b42", "item_role": "question"}, {"type": "paragraph", "md": "د- التبرج باب لكثرة الجرائم. هـ- التبرج سبب للأمراض الجديدة التي لم تكن من قبلُ.", "page": 324, "id": "unit-26__lesson-13__b43", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط دعوي واجتماعي", "page": 324, "id": "unit-26__lesson-13__b44", "role": "activity"}, {"type": "paragraph", "md": "1- نحصي أسماء خمس إخوات ملتزمات باللباس الشرعي ونزورهن ونثني عليهن بالخير.", "page": 324, "id": "unit-26__lesson-13__b45", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- نحصي أسماء خمس إخوات غير ملتزمات باللباس الشرعي ونزورهن ونذكرهن بفضل الحجاب", "page": 324, "id": "unit-26__lesson-13__b46", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- ننشر في وسائل التواصل الاجتماعي خمسًا من فضائل الحجاب، وخمسًا من مثالب التبرج.. من باب الدعوة إلى هذا الخير، والنهي عن المنكر الشائع بالتبرج والسفور؛ أمرًا بالمعروف ونهيا عن المنكر.", "page": 324, "id": "unit-26__lesson-13__b47", "item_role": "activity_step", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "منارات الهدى", "page": 325, "id": "unit-26__lesson-13__b48", "item_role": "activity_step"}]' WHERE id='unit-26__lesson-13';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-14','unit-26',14,'أدلة وجوب تغطية الوجه والكفين','الفقه',NULL,0,13,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "ملخصٌ من كتاب: سور العفاف", "page": 325, "id": "unit-26__lesson-14__b01", "role": "section"}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 325, "id": "unit-26__lesson-14__b02", "role": "objectives"}, {"type": "paragraph", "md": "1- ذكر بعض التعاريف المهمة في باب الحجاب الشرعي لتتضح الأحكام المتعلقة بها.", "page": 325, "id": "unit-26__lesson-14__b03", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- بيان حكم الحجاب الشرعي الكامل وحكم تغطية الوجه والكفين للمرأة المسلمة.", "page": 325, "id": "unit-26__lesson-14__b04", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "أولا: بعض المصطلحات الشرعية الواردة في باب الحجاب وأحكامه:", "page": 325, "id": "unit-26__lesson-14__b05", "role": "rulings"}, {"type": "paragraph", "md": "1- الحجاب: لغة: الحَجْبُ هو المنع من الوصول، حَجَبَهُ: منعه، ومنه قيل للساتر الذي يحول بين شيئين الحجاب؛ لأنه يمنع الرؤية بينهما، وسمي حجاب المرأة حجابًا لأنه يمنع المشاهدة.", "page": 325, "id": "unit-26__lesson-14__b06", "inline": [{"t": "emphasis", "s": "1- الحجاب: لغة", "role": "emphasis"}, {"t": "text", "s": ": الحَجْبُ هو المنع من الوصول، حَجَبَهُ: منعه، ومنه قيل للساتر الذي يحول بين شيئين الحجاب؛ لأنه يمنع الرؤية بينهما، وسمي حجاب المرأة حجابًا لأنه يمنع المشاهدة."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "وشرعًا: اللباس الساتر لجميع بدن المرأة وزينتها؛ بما يمنع الأجانب عنها من رؤية شيء من بدنها أو زينتها", "page": 325, "id": "unit-26__lesson-14__b07", "inline": [{"t": "emphasis", "s": "وشرعًا", "role": "emphasis"}, {"t": "text", "s": ": اللباس الساتر لجميع بدن المرأة وزينتها؛ بما يمنع الأجانب عنها من رؤية شيء من بدنها أو زينتها"}]}, {"type": "paragraph", "md": "2- الخمار: لغة الستر، فكُلُّ ما سَتَرَ شَيْئًا فَهْو خِمَارُه، ومنه خِمَارُ المَرْأَةِ تُغَطِّي به رَأْسَها ووجهها.", "page": 325, "id": "unit-26__lesson-14__b08", "inline": [{"t": "text", "s": "2- "}, {"t": "emphasis", "s": "الخمار:", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "لغة", "role": "emphasis"}, {"t": "text", "s": " الستر، فكُلُّ ما سَتَرَ شَيْئًا فَهْو خِمَارُه، ومنه خِمَارُ المَرْأَةِ تُغَطِّي به رَأْسَها ووجهها."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "ويُسمَّى الخمار بالنصيف؛ لأَنه نصَفٌ لها من الناس، فحَجز أَبصارهم عنها، فكل مغطى مخمَّر.", "page": 325, "id": "unit-26__lesson-14__b09"}, {"type": "paragraph", "md": "وشرعًا: ثوب تتجلل به المرأة فوق ثيابها كلِّها، وسمي خمارًا؛ لأنه يستر وجهها من فوق.", "page": 325, "id": "unit-26__lesson-14__b10", "inline": [{"t": "emphasis", "s": "وشرعًا", "role": "emphasis"}, {"t": "text", "s": ": ثوب تتجلل به المرأة فوق ثيابها كلِّها، وسمي خمارًا؛ لأنه يستر وجهها من فوق."}]}, {"type": "paragraph", "md": "3- النقاب: غطاء تستر به المرأة وجهها وتفتح لعينيها بقدر ما تنظر منه.", "page": 325, "id": "unit-26__lesson-14__b11", "inline": [{"t": "text", "s": "3- "}, {"t": "emphasis", "s": "النقاب:", "role": "emphasis"}, {"t": "text", "s": " غطاء تستر به المرأة وجهها وتفتح لعينيها بقدر ما تنظر منه."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "يسمى نقابًا لوجود نقبين في مواجهة العينين لمعرفة الطريق وإبصار ما أمامها.", "page": 325, "id": "unit-26__lesson-14__b12"}, {"type": "paragraph", "md": "4- الجلباب: لغةً: هو ما غطى جميع الجسم لا بعضه. ومعنى إدناء الجلباب: إرخاؤه حتى يغطي الوجه كله ويستره حتى لا يبين منه شيء، وهذا فهم الصحابيات للآية حيث تغطين بالكامل عند نزولها.", "page": 325, "id": "unit-26__lesson-14__b13", "inline": [{"t": "text", "s": "4- "}, {"t": "emphasis", "s": "الجلباب", "role": "emphasis"}, {"t": "text", "s": ": لغةً: هو ما غطى جميع الجسم لا بعضه. ومعنى إدناء "}, {"t": "emphasis", "s": "الجلباب", "role": "emphasis"}, {"t": "text", "s": ": إرخاؤه حتى يغطي الوجه كله ويستره حتى لا يبين منه شيء، وهذا فهم الصحابيات للآية حيث تغطين بالكامل عند نزولها."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- السفور: هو الظهور والكشف، السفر سفرًا لأنه يسفر عن حقائق المسافرين وأخلاقهم ويُبدي خفيَّها.", "page": 325, "id": "unit-26__lesson-14__b14", "inline": [{"t": "text", "s": "5- "}, {"t": "emphasis", "s": "السفور", "role": "emphasis"}, {"t": "text", "s": ": هو الظهور والكشف، السفر سفرًا لأنه يسفر عن حقائق المسافرين وأخلاقهم ويُبدي خفيَّها."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "وشرعًا: كشف الغطاء عن الوجه؛ فيقال امرأة سافر وسافرة، وأما كشف المرأة وإظهارها شيئا من بدنها أو زينتها المكتسبة أمام الرجال الأجانب عنها فهو التبرج؛ فالسفور أخص من التبرج، والتبرج أعم منه.", "page": 325, "id": "unit-26__lesson-14__b15", "inline": [{"t": "emphasis", "s": "وشرعًا", "role": "emphasis"}, {"t": "text", "s": ": كشف الغطاء عن الوجه؛ فيقال امرأة سافر وسافرة، وأما كشف المرأة وإظهارها شيئا من بدنها أو زينتها المكتسبة أمام الرجال الأجانب عنها فهو التبرج؛ فالسفور أخص من التبرج، والتبرج أعم منه."}]}, {"type": "paragraph", "md": "6- التبرج: لغة: ابداء المرأة زينتها وإظهار وجهها ومحاسن جيدها للرجال وكل ما تستدعي به شهوتهم حتى التكسر والتبختر في مشيتها مالم يكن ذلك للزوج.. فكل هذا يُمسى تبرجًا في اللغة.", "page": 325, "id": "unit-26__lesson-14__b16", "inline": [{"t": "text", "s": "6- "}, {"t": "emphasis", "s": "التبرج", "role": "emphasis"}, {"t": "text", "s": ": لغة: ابداء المرأة زينتها وإظهار وجهها ومحاسن جيدها للرجال وكل ما تستدعي به شهوتهم حتى التكسر والتبختر في مشيتها مالم يكن ذلك للزوج.. فكل هذا يُمسى تبرجًا في اللغة."}], "list": {"type": "ordered", "marker": "6"}}, {"type": "paragraph", "md": "وشرعًا: هو إظهار المراة زينتها وإبراز محاسنها، وقيل: هو التبختر والتكسر في المشية، وقيل: هو كل زينة أو تجمل تقصد المرأة بإظهاره أن تحلو في أعين الأجانب؛ حتى القناع الذي تتستر به المرأة إن انتخب من الألوان البارقة والشكل الجذاب لكي تلذ به أعين الناظرين فهو من مظاهر تبرج الجاهلية أيضًا.", "page": 326, "id": "unit-26__lesson-14__b17", "inline": [{"t": "emphasis", "s": "وشرعًا", "role": "emphasis"}, {"t": "text", "s": ": هو إظهار المراة زينتها وإبراز محاسنها، وقيل: هو التبختر والتكسر في المشية، وقيل: هو كل زينة أو تجمل تقصد المرأة بإظهاره أن تحلو في أعين الأجانب؛ حتى القناع الذي تتستر به المرأة إن انتخب من الألوان البارقة والشكل الجذاب لكي تلذ به أعين الناظرين فهو من مظاهر تبرج الجاهلية أيضًا."}]}, {"type": "paragraph", "md": "7- العورة: العورة عورتان، عورة في الصلاة وعورة في النظر؛ فأما في الصلاة: فالحرة لها أن تصلي مكشوفة الوجه والكفين في المسجد أو في بيتها أمام محارمها ويعتبر الوجه والكفان ليسا عورة في الصلاة.", "page": 326, "id": "unit-26__lesson-14__b18", "inline": [{"t": "text", "s": "7- "}, {"t": "emphasis", "s": "العورة", "role": "emphasis"}, {"t": "text", "s": ": "}, {"t": "emphasis", "s": "العورة", "role": "emphasis"}, {"t": "text", "s": " عورتان، عورة في الصلاة وعورة في النظر؛ فأما في الصلاة: فالحرة لها أن تصلي مكشوفة الوجه والكفين في المسجد أو في بيتها أمام محارمها ويعتبر الوجه والكفان ليسا عورة في الصلاة."}], "list": {"type": "ordered", "marker": "7"}}, {"type": "paragraph", "md": "وأما في النظر؛ فليس للمرأة الحرة أن تخرج في الأسواق ومجامع الناس؛ فيعتبر الوجه والكفان عورة نظر يحرم عليها كشفهما وإبداءهما للناس، وكذلك لا يحل لأحد أن ينظر إليها إن عصت وكشفتهما.", "page": 326, "id": "unit-26__lesson-14__b19"}, {"type": "heading", "level": 3, "text": "أدلة الحجاب ووجوب تغطية الوجه والكفين من القرآن العظيم:", "page": 326, "id": "unit-26__lesson-14__b20", "role": "evidence"}, {"type": "paragraph", "md": "قبل الحديث عن أدلة وجوب ستر الوجه والكفين لا بُدَّ أن نعلم أن الوجه مجمع المحاسن، وهو أكثر الأعضاء فتنة وإغراء وجذبًا، وظهور وجه المرأة باعث على الفتنة والتلذذ والاستمتاع؛ لذلك مدحَ الشعراء والعامة جمال الوجه أكثر من غيره، ومما يدل على أن الوجه مجمع المحاسن: قصة الفضل بن العباس وهو رديف النبي صلى الله عليه وسلم عندما كان ينظر إلى وجه المرأة الخثعمية، وكان وجهها جميلًا؛ فلما رآه النبي صلى الله عليه وسلم ينظر إليها أدار وجهه إلى الناحية الأخرى حتى لا ينظر إليها.. فهذا الفضل رضي الله عنه في عبادة وهي الحج وفي يوم حرام بشهر حرام في بلد حرام وهو رديف النبي صلى الله عليه وسلم وهو محرَّمٌ عليه النظر العمد، ومع هذا جذبه الحسن في ذلك الوجه الجميل؛ فكيف بغيره من الرجال في أماكن وأزمان فتنة؟ لذلك فإنَّ فتنة الوجه غلَّابة قاهرة، وقد علق الحافظ ابن حجر على هذه القصة فقال: «في الحديث فوائد منها: بيان ما رُكِّبَ في الآدمي من الشهوة وجُبِلَت طبائعه عليه من النظر إلى الصور الحسنة، وفيه منع النظر إلى الأجنبيات وغض البصر».", "page": 326, "id": "unit-26__lesson-14__b21", "inline": [{"t": "text", "s": "قبل الحديث عن أدلة وجوب ستر الوجه والكفين لا بُدَّ أن نعلم أن الوجه مجمع المحاسن، وهو أكثر الأعضاء فتنة وإغراء وجذبًا، وظهور وجه المرأة باعث على الفتنة والتلذذ والاستمتاع؛ لذلك مدحَ الشعراء والعامة جمال الوجه أكثر من غيره، ومما يدل على أن الوجه مجمع المحاسن: قصة الفضل بن العباس وهو رديف النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " عندما كان ينظر إلى وجه المرأة الخثعمية، وكان وجهها جميلًا؛ فلما رآه النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ينظر إليها أدار وجهه إلى الناحية الأخرى حتى لا ينظر إليها.. فهذا الفضل "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " في عبادة وهي الحج وفي يوم حرام بشهر حرام في بلد حرام وهو رديف النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وهو محرَّمٌ عليه النظر العمد، ومع هذا جذبه الحسن في ذلك الوجه الجميل؛ فكيف بغيره من الرجال في أماكن وأزمان فتنة؟ لذلك فإنَّ فتنة الوجه غلَّابة قاهرة، وقد علق الحافظ ابن حجر على هذه القصة فقال: "}, {"t": "quote", "s": "في الحديث فوائد منها: بيان ما رُكِّبَ في الآدمي من الشهوة وجُبِلَت طبائعه عليه من النظر إلى الصور الحسنة، وفيه منع النظر إلى الأجنبيات وغض البصر"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ولا بد من التنبيه على أنه لا يختلف الذين يقولون بوجوب تغطية الوجه والكفين مع الذين لا يرون وجوب تغطيتهما؛ أن الأفضل والأكمل والأتقى والأرضى لله هو ستر كل البدن بما فيه الوجه والكفين.", "page": 326, "id": "unit-26__lesson-14__b22"}, {"type": "paragraph", "md": "وجاءت الأدلة من القرآن العظيم على وجوب حجاب الوجه لا إظهاره وكشفه، ومن هذه الأدلة:", "page": 326, "id": "unit-26__lesson-14__b23", "inline": [{"t": "emphasis", "s": "وجاءت الأدلة من القرآن العظيم على وجوب حجاب الوجه لا إظهاره وكشفه، ومن هذه الأدلة:", "role": "emphasis"}]}, {"type": "paragraph", "md": "1- قوله تعالى: ﴿يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ وَبَنَاتِكَ وَنِسَاءِ الْمُؤْمِنِينَ يُدْنِينَ عَلَيْهِنَّ مِنْ جَلَابِيبِهِنَّ ذَلِكَ أَدْنَى أَنْ يُعْرَفْنَ فَلَا يُؤْذَيْنَ﴾، ومجمل كلام المفسرين أن الله عز وجل أمر النبي صلى الله عليه وسلم أن يأمر زوجاته وبناته ونساء المؤمنين كافة أن يدنين على أنفسهن من الجلابيب؛ أي يغطين أجسامهن ووجوههن، وليس المقصود فقط الجسم دون الوجه والكفين؛ بل يُرْخِينَ عليهنَّ من الجلابيب التي يلبسنها؛ حتى لا تنكشف منهن عورة أمام الأجانب من الرجال؛ فهذا أقرب أن يُعرف أنّهنّ حرائر عفيفات فلا يَتعرض لهنّ أحد بالإيذاء كما يتعرض به للإماء والله غفورٌ لذنوب من تاب من عباده، رحيمٌ به.", "page": 327, "id": "unit-26__lesson-14__b24", "inline": [{"t": "emphasis", "s": "1- قوله تعالى:", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "ayah", "s": "يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ وَبَنَاتِكَ وَنِسَاءِ الْمُؤْمِنِينَ يُدْنِينَ عَلَيْهِنَّ مِنْ جَلَابِيبِهِنَّ ذَلِكَ أَدْنَى أَنْ يُعْرَفْنَ فَلَا يُؤْذَيْنَ", "ayah": [], "verses": [{"n": 59, "text": "يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ وَبَنَاتِكَ وَنِسَاءِ الْمُؤْمِنِينَ يُدْنِينَ عَلَيْهِنَّ مِنْ جَلَابِيبِهِنَّ ذَلِكَ أَدْنَى أَنْ يُعْرَفْنَ فَلَا يُؤْذَيْنَ", "surah": 33, "surah_name": "الأحزاب", "ref": "33:59", "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:59"}], "surah": 33, "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:59", "surah_name": "الأحزاب", "ayah_canonical": 59, "match": "contained", "ref": "33:59"}, {"t": "text", "s": "، ومجمل كلام المفسرين أن الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " أمر النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أن يأمر زوجاته وبناته ونساء المؤمنين كافة أن يدنين على أنفسهن من الجلابيب؛ أي يغطين أجسامهن ووجوههن، وليس المقصود فقط الجسم دون الوجه والكفين؛ بل يُرْخِينَ عليهنَّ من الجلابيب التي يلبسنها؛ حتى لا تنكشف منهن عورة أمام الأجانب من الرجال؛ فهذا أقرب أن يُعرف أنّهنّ حرائر عفيفات فلا يَتعرض لهنّ أحد بالإيذاء كما يتعرض به للإماء والله غفورٌ لذنوب من تاب من عباده، رحيمٌ به."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "جاء في تفسير الطبري: «أي: قل لأزواجك وبناتك ونساء المؤمنين، لا يتشبهن بالإماء في لباسهن إذا هن خرجن من بيوتهن لحاجتهن، فكشفن شعورهن ووجوههن، ولكن ليدنين عليهن من جلابيبهن، لئلا يعرض لهن فاسق، إذا علم أنهن حرائر بأذى من قول.. عن ابن عباس قال: «أمر الله نساء المؤمنين إذا خرجن من بيوتهن في حاجة أن يغطين وجوههن من فوق رؤوسهن بالجلابيب، ويبدين عينا واحدة»» اهـ.", "page": 327, "id": "unit-26__lesson-14__b25", "inline": [{"t": "text", "s": "جاء في تفسير الطبري: "}, {"t": "quote", "s": "أي: قل لأزواجك وبناتك ونساء المؤمنين، لا يتشبهن بالإماء في لباسهن إذا هن خرجن من بيوتهن لحاجتهن، فكشفن شعورهن ووجوههن، ولكن ليدنين عليهن من جلابيبهن، لئلا يعرض لهن فاسق، إذا علم أنهن حرائر بأذى من قول.. عن ابن عباس قال: «أمر الله نساء المؤمنين إذا خرجن من بيوتهن في حاجة أن يغطين وجوههن من فوق رؤوسهن بالجلابيب، ويبدين عينا واحدة"}, {"t": "text", "s": "» اهـ."}]}, {"type": "paragraph", "md": "ولو لم يكن القصد من الحجاب ستر الوجه لما كان هناك ضرورة للنص على كشف المُحرمة بالحج أو العمرة وجهها، وما ضرورة النص على جواز رؤية الخاطب وجه خطيبته إذا كان يرى وجهها في الشارع؟ وإذا كان باب الوجه مفتوحًا فما ضرورة النص على إباحة فتح باب مفتوح؟", "page": 327, "id": "unit-26__lesson-14__b26", "inline": [{"t": "emphasis", "s": "ولو لم يكن القصد من الحجاب ستر الوجه", "role": "emphasis"}, {"t": "text", "s": " لما كان هناك ضرورة للنص على كشف المُحرمة بالحج أو العمرة وجهها، وما ضرورة النص على جواز رؤية الخاطب وجه خطيبته إذا كان يرى وجهها في الشارع؟ وإذا كان باب الوجه مفتوحًا فما ضرورة النص على إباحة فتح باب مفتوح؟"}]}, {"type": "paragraph", "md": "2- آية الحجاب، وهي قوله تعالى: ﴿وَإِذَا سَأَلْتُمُوهُنَّ مَتَاعًا فَاسْأَلُوهُنَّ مِنْ وَرَاءِ حِجَابٍ ذَلِكُمْ أَطْهَرُ لِقُلُوبِكُمْ وَقُلُوبِهِنَّ﴾؛ فهنا أمر الله المؤمنين إذا أرادوا أن يسألوا أمهات المؤمنين أي شيء من متاع الدنيا فعليهم أن يسألوهن من وراء حجاب أي من وراء شيء يسترهن فلا ينظر إليهن أحد، والستر هكذا أطهر لقلوب الجميع من عوارض العين التي تعرض في صدور الرجال من أمر النساء، وفي صدور النساء من أمر الرجال، وأحرى من أن لا يكون للشيطان عليهم وعليهن سبيلًا؛ فهذه الآية دالة على الحجاب لأنها تأمر بستر المرأة كاملة عن أعين الرجال، وفيها دلالة على عدم كشف الوجه والكفين أيضًا، وإلا لماذا أمر المؤمنين أن يسألوهم من وراء ستر يسترهنَّ كاملًا؟ وأيضًا فهذه الآية عامة في جميع النساء وليست خاصة بنساء النبي صلى الله عليه وسلم لأن جميع النساء يشتركن في نفس العلة مع أمهات المؤمنين بأن ذلك أطهر لهن.", "page": 327, "id": "unit-26__lesson-14__b27", "inline": [{"t": "emphasis", "s": "2- آية الحجاب، وهي قوله تعالى:", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "ayah", "s": "وَإِذَا سَأَلْتُمُوهُنَّ مَتَاعًا فَاسْأَلُوهُنَّ مِنْ وَرَاءِ حِجَابٍ ذَلِكُمْ أَطْهَرُ لِقُلُوبِكُمْ وَقُلُوبِهِنَّ", "ayah": [], "verses": [{"n": 53, "text": "وَإِذَا سَأَلْتُمُوهُنَّ مَتَاعًا فَاسْأَلُوهُنَّ مِنْ وَرَاءِ حِجَابٍ ذَلِكُمْ أَطْهَرُ لِقُلُوبِكُمْ وَقُلُوبِهِنَّ", "surah": 33, "surah_name": "الأحزاب", "ref": "33:53", "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:53"}], "surah": 33, "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:53", "surah_name": "الأحزاب", "ayah_canonical": 53, "match": "contained", "ref": "33:53"}, {"t": "text", "s": "؛ فهنا أمر الله المؤمنين إذا أرادوا أن يسألوا أمهات المؤمنين أي شيء من متاع الدنيا فعليهم أن يسألوهن من وراء حجاب أي من وراء شيء يسترهن فلا ينظر إليهن أحد، والستر هكذا أطهر لقلوب الجميع من عوارض العين التي تعرض في صدور الرجال من أمر النساء، وفي صدور النساء من أمر الرجال، وأحرى من أن لا يكون للشيطان عليهم وعليهن سبيلًا؛ فهذه الآية دالة على الحجاب لأنها تأمر بستر المرأة كاملة عن أعين الرجال، وفيها دلالة على عدم كشف الوجه والكفين أيضًا، وإلا لماذا أمر المؤمنين أن يسألوهم من وراء ستر يسترهنَّ كاملًا؟ وأيضًا فهذه الآية عامة في جميع النساء وليست خاصة بنساء النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " لأن جميع النساء يشتركن في نفس العلة مع أمهات المؤمنين بأن ذلك أطهر لهن."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "وجه الاستدلال بهذه الآية: أن خطاب الواحد يشمل خطاب الجماعة قال صلى الله عليه وسلم : (إنما قولي لامرأة واحدة كقولي لمئة امرأة)؛ فالأمر لنساء النبي صلى الله عليه وسلم ولكل نساء المؤمنين، والخطاب شامل للجميع للاشتراك في نفس العلة؛ فعلة السؤال من وراء حجاب: طهارة القلوب، ونساء المؤمنين كنساء النبي صلى الله عليه وسلم في الاحتياج إلى ذلك، ويؤيده قوله صلى الله عليه وسلم : (إياكم والدخول على النساء)، وأيضًا قوله تعالى: ﴿يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ وَبَنَاتِكَ وَنِسَاءِ الْمُؤْمِنِينَ﴾.", "page": 327, "id": "unit-26__lesson-14__b28", "inline": [{"t": "text", "s": "وجه الاستدلال بهذه الآية: أن خطاب الواحد يشمل خطاب الجماعة قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إنما قولي لامرأة واحدة كقولي لمئة امرأة)", "role": "emphasis"}, {"t": "text", "s": "؛ فالأمر لنساء النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ولكل نساء المؤمنين، والخطاب شامل للجميع للاشتراك في نفس العلة؛ فعلة السؤال من وراء حجاب: طهارة القلوب، ونساء المؤمنين كنساء النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " في الاحتياج إلى ذلك، ويؤيده قوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إياكم والدخول على النساء)", "role": "emphasis"}, {"t": "text", "s": "، وأيضًا قوله تعالى: "}, {"t": "ayah", "s": "يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ وَبَنَاتِكَ وَنِسَاءِ الْمُؤْمِنِينَ", "ayah": [], "verses": [{"n": 59, "text": "يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ وَبَنَاتِكَ وَنِسَاءِ الْمُؤْمِنِينَ", "surah": 33, "surah_name": "الأحزاب", "ref": "33:59", "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:59"}], "surah": 33, "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:59", "surah_name": "الأحزاب", "ayah_canonical": 59, "match": "contained", "ref": "33:59"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وقد نزلت هذه الآية في السنة الهجرية الخامسة وهي تعم بإطلاقها حجاب جميع الأعضاء؛ بما فيها الوجه والكفان، لا تستثني عضوًا من عضو، وهذا المعنى هو الذي يشهد له فعل أمهات المؤمنين، ولم يختلف العلماء في تعيين هذا المعنى حتى نطيل الكلام في تحقيقه، وإنما يقول من يظن أن الوجه والكفين خارجان عن الحجاب: «إن هذه الآية مختصة بأمهات المؤمنين!!» وهذه الناحية يردها أن نساء المؤمنين يشتركن في العلة مع أمهات المؤمنين، والحكم يدور مع العلة وجودًا وعدمًا.", "page": 328, "id": "unit-26__lesson-14__b29", "inline": [{"t": "text", "s": "وقد نزلت هذه الآية في السنة الهجرية الخامسة وهي تعم بإطلاقها حجاب جميع الأعضاء؛ بما فيها الوجه والكفان، لا تستثني عضوًا من عضو، وهذا المعنى هو الذي يشهد له فعل أمهات المؤمنين، ولم يختلف العلماء في تعيين هذا المعنى حتى نطيل الكلام في تحقيقه، وإنما يقول من يظن أن الوجه والكفين خارجان عن الحجاب: "}, {"t": "quote", "s": "إن هذه الآية مختصة بأمهات المؤمنين!!"}, {"t": "text", "s": " وهذه الناحية يردها أن نساء المؤمنين يشتركن في العلة مع أمهات المؤمنين، والحكم يدور مع العلة وجودًا وعدمًا."}]}, {"type": "paragraph", "md": "3- قوله تعالى: ﴿يَا نِسَاءَ النَّبِيِّ لَسْتُنَّ كَأَحَدٍ مِنَ النِّسَاءِ إِنِ اتَّقَيْتُنَّ فَلَا تَخْضَعْنَ بِالْقَوْلِ فَيَطْمَعَ الَّذِي فِي قَلْبِهِ مَرَضٌ وَقُلْنَ قَوْلًا مَعْرُوفًا 32 وَقَرْنَ فِي بُيُوتِكُنَّ وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْأُولَى وَأَقِمْنَ الصَّلَاةَ وَآتِينَ الزَّكَاةَ وَأَطِعْنَ اللَّهَ وَرَسُولَهُ إِنَّمَا يُرِيدُ اللَّهُ لِيُذْهِبَ عَنْكُمُ الرِّجْسَ أَهْلَ الْبَيْتِ وَيُطَهِّرَكُمْ تَطْهِيرًا 33﴾.", "page": 328, "id": "unit-26__lesson-14__b30", "inline": [{"t": "emphasis", "s": "3- قوله تعالى:", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "ayah", "s": "يَا نِسَاءَ النَّبِيِّ لَسْتُنَّ كَأَحَدٍ مِنَ النِّسَاءِ إِنِ اتَّقَيْتُنَّ فَلَا تَخْضَعْنَ بِالْقَوْلِ فَيَطْمَعَ الَّذِي فِي قَلْبِهِ مَرَضٌ وَقُلْنَ قَوْلًا مَعْرُوفًا 32 وَقَرْنَ فِي بُيُوتِكُنَّ وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْأُولَى وَأَقِمْنَ الصَّلَاةَ وَآتِينَ الزَّكَاةَ وَأَطِعْنَ اللَّهَ وَرَسُولَهُ إِنَّمَا يُرِيدُ اللَّهُ لِيُذْهِبَ عَنْكُمُ الرِّجْسَ أَهْلَ الْبَيْتِ وَيُطَهِّرَكُمْ تَطْهِيرًا 33", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "فهنا يُخاطب الله سبحانه وتعالى نساء النبي صلى الله عليه وسلم ويبين لهن أنهن لسن في الفضل والشرف كسائر النساء؛ بل إنهن في الفضل والشرف بالمنزلة التي لا يصل إليها غيرهنَّ إن امتثلنَ أوامر الله، ولهذا فعليهن ألا يرَقِّقْن الصوت إذا تكلمنَ مع الأجانب من الرجال؛ فيطمع بسبب ذلك من في قلبه مرض النفاق وشهوة الحرام، وعليهن أن يقلن قولا بعيدًا من الريبة بأن يكون جِدًّا لا هزلًا بقدر الحاجة.", "page": 328, "id": "unit-26__lesson-14__b31", "inline": [{"t": "text", "s": "فهنا يُخاطب الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " نساء النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ويبين لهن أنهن لسن في الفضل والشرف كسائر النساء؛ بل إنهن في الفضل والشرف بالمنزلة التي لا يصل إليها غيرهنَّ إن امتثلنَ أوامر الله، ولهذا فعليهن ألا يرَقِّقْن الصوت إذا تكلمنَ مع الأجانب من الرجال؛ فيطمع بسبب ذلك من في قلبه مرض النفاق وشهوة الحرام، وعليهن أن يقلن قولا بعيدًا من الريبة بأن يكون جِدًّا لا هزلًا بقدر الحاجة."}]}, {"type": "paragraph", "md": "وكلك عليهن أن يثبتن في بيوتهنّ؛ فلا يخرجن منها لغير حاجة، ولا يُظْهِرن محاسنهنَّ كما كانت تصنع النساء قبل الإسلام؛ حيثُ يبدين ذلك استمالة للرجال؛ يريد الله سبحانه أن يذهب عنكم الأذى والشر، يا أزواج رسول الله ويا أهل بيته، وأن يطهّر نفوسكم؛ بتحليتها بفضائل الأخلاق، ويرزقكم الطهر الكامل.", "page": 328, "id": "unit-26__lesson-14__b32"}, {"type": "paragraph", "md": "ووجه الشاهد: أنَّ الأمر لنساء النبي صلى الله عليه وسلم أمر لكل نساء الأمة؛ فكلهم سواء في طلب الطهر والعفة.", "page": 328, "id": "unit-26__lesson-14__b33", "inline": [{"t": "text", "s": "ووجه الشاهد: أنَّ الأمر لنساء النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أمر لكل نساء الأمة؛ فكلهم سواء في طلب الطهر والعفة."}]}, {"type": "paragraph", "md": "4- قوله تعالى: ﴿وَقُلْ لِلْمُؤْمِنَاتِ يَغْضُضْنَ مِنْ أَبْصَارِهِنَّ وَيَحْفَظْنَ فُرُوجَهُنَّ وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَى جُيُوبِهِنَّ﴾، وتعني هذه الآية: أن الله عز وجل أمر النبي صلى الله عليه وسلم بأن يأمر المؤمنات بأن يكففن أبصارَهن عن النظر إلى ما لا يحلُّ لهن النظر إليه من العورات، ويحفظن فروجهن بالبعد عن الفاحشة وبالستر، ولا يُظْهِرن زينتهن للأجانب إلا ما ظهر منها مما لا يمكن إخفاؤه كالثياب، وليضربن بأغطيتهنَّ على فتحات أعلى ثيابهن ليسترن شعورهن ووجوههن وأعناقهن، ولا يُظْهِرن زينتهنَّ الخفية إلا لأزواجهنّ، أو آبائهن.. الخ، ولا يضرب النساء بأرجلهن قصد أن يُعْلَم ما يسترن من زينتهنّ مثل الخلخال وما شابهه.", "page": 328, "id": "unit-26__lesson-14__b34", "inline": [{"t": "emphasis", "s": "4- قوله تعالى:", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "ayah", "s": "وَقُلْ لِلْمُؤْمِنَاتِ يَغْضُضْنَ مِنْ أَبْصَارِهِنَّ وَيَحْفَظْنَ فُرُوجَهُنَّ وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَى جُيُوبِهِنَّ", "ayah": [], "verses": [{"n": 31, "text": "وَقُلْ لِلْمُؤْمِنَاتِ يَغْضُضْنَ مِنْ أَبْصَارِهِنَّ وَيَحْفَظْنَ فُرُوجَهُنَّ وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَى جُيُوبِهِنَّ", "surah": 24, "surah_name": "النور", "ref": "24:31", "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31"}], "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31", "surah_name": "النور", "ayah_canonical": 31, "match": "contained", "ref": "24:31"}, {"t": "text", "s": "، وتعني هذه الآية: أن الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " أمر النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بأن يأمر المؤمنات بأن يكففن أبصارَهن عن النظر إلى ما لا يحلُّ لهن النظر إليه من العورات، ويحفظن فروجهن بالبعد عن الفاحشة وبالستر، ولا يُظْهِرن زينتهن للأجانب إلا ما ظهر منها مما لا يمكن إخفاؤه كالثياب، وليضربن بأغطيتهنَّ على فتحات أعلى ثيابهن ليسترن شعورهن ووجوههن وأعناقهن، ولا يُظْهِرن زينتهنَّ الخفية إلا لأزواجهنّ، أو آبائهن.. الخ، ولا يضرب النساء بأرجلهن قصد أن يُعْلَم ما يسترن من زينتهنّ مثل الخلخال وما شابهه."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "قال السعدي: «﴿وَلَا يُبْدِينَ زِينَتَهُنَّ﴾ كالثياب الجميلة والحلي، وجميع البدن كله من الزينة، ولما كانت الثياب الظاهرة، لا بد لها منها، قال: ﴿إِلَّا مَا ظَهَرَ مِنْهَا﴾ أي: الثياب الظاهرة، التي جرت العادة بلبسها إذا لم يكن في ذلك ما يدعو إلى الفتنة بها، ﴿وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَى جُيُوبِهِنَّ﴾ وهذا لكمال الاستتار، ويدل ذلك على أن الزينة التي يحرم إبداؤها، يدخل فيها جميع البدن، كما ذكرنا؛ ثم كرر النهي عن إبداء زينتهن، ليستثني منه قوله: ﴿إِلَّا لِبُعُولَتِهِنَّ﴾ أي: أزواجهن.. الخ، ﴿وَلَا يَضْرِبْنَ بِأَرْجُلِهِنَّ لِيُعْلَمَ مَا يُخْفِينَ مِنْ زِينَتِهِنَّ﴾ أي: لا يضربن الأرض بأرجلهن، ليصوت ما عليهن من حلي، كخلاخل وغيرها، فتعلم زينتها بسببه، فيكون وسيلة إلى الفتنة. ويؤخذ من هذا ونحوه، قاعدة سد الذرائع، وأن الأمر إذا كان مباحا، ولكنه يفضي إلى محرم، أو يخاف من وقوعه، فإنه يمنع منه، فالضرب بالرجل في الأرض، الأصل أنه مباح، ولكن لما كان وسيلة لعلم الزينة، منع منه» اهـ.", "page": 329, "id": "unit-26__lesson-14__b35", "inline": [{"t": "text", "s": "قال السعدي: "}, {"t": "quote", "s": "﴿وَلَا يُبْدِينَ زِينَتَهُنَّ﴾ كالثياب الجميلة والحلي، وجميع البدن كله من الزينة، ولما كانت الثياب الظاهرة، لا بد لها منها، قال: ﴿إِلَّا مَا ظَهَرَ مِنْهَا﴾ أي: الثياب الظاهرة، التي جرت العادة بلبسها إذا لم يكن في ذلك ما يدعو إلى الفتنة بها، ﴿وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَى جُيُوبِهِنَّ﴾ وهذا لكمال الاستتار، ويدل ذلك على أن الزينة التي يحرم إبداؤها، يدخل فيها جميع البدن، كما ذكرنا؛ ثم كرر النهي عن إبداء زينتهن، ليستثني منه قوله: ﴿إِلَّا لِبُعُولَتِهِنَّ﴾ أي: أزواجهن.. الخ، ﴿وَلَا يَضْرِبْنَ بِأَرْجُلِهِنَّ لِيُعْلَمَ مَا يُخْفِينَ مِنْ زِينَتِهِنَّ﴾ أي: لا يضربن الأرض بأرجلهن، ليصوت ما عليهن من حلي، كخلاخل وغيرها، فتعلم زينتها بسببه، فيكون وسيلة إلى الفتنة. ويؤخذ من هذا ونحوه، قاعدة سد الذرائع، وأن الأمر إذا كان مباحا، ولكنه يفضي إلى محرم، أو يخاف من وقوعه، فإنه يمنع منه، فالضرب بالرجل في الأرض، الأصل أنه مباح، ولكن لما كان وسيلة لعلم الزينة، منع منه", "speaker": "السعدي"}, {"t": "text", "s": " اهـ."}]}, {"type": "paragraph", "md": "ومن المواضع التي استدل بها على وجوب الحجاب في هذه الآية الكريمة:", "page": 329, "id": "unit-26__lesson-14__b36", "inline": [{"t": "emphasis", "s": "ومن المواضع التي استدل بها على وجوب الحجاب في هذه الآية الكريمة:", "role": "emphasis"}]}, {"type": "paragraph", "md": "أ- الموضع الأول: قوله تعالى: ﴿وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا﴾؛ فهذه الزينة التي لا خطر على إبدائها هي الزينة الظاهرة التي لا يمكن إخفاؤها لأنها هي نفسها الحجاب الذي يخفي وراءه زينتها التي أمرت بإخفائها، وهذه الزينة المسموح بإبدائها والتي لا سلطان لها عليها حتى تخفيها هي الثوب العام الذي تستتر به المرأة فإذا ظهر ذلك الثوب كالملاءة أو العباءة التي تغطي جسم المرأة كله من قمة الرأس إلى القدم فلا شيء عليها لأن ذلك مما لا قدرة لها على إخفائه وهذه هي الزينة التي عفي عن إبدائها.", "page": 329, "id": "unit-26__lesson-14__b37", "inline": [{"t": "emphasis", "s": "أ- الموضع الأول", "role": "emphasis"}, {"t": "text", "s": ": قوله تعالى: "}, {"t": "ayah", "s": "وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا", "ayah": [], "verses": [{"n": 31, "text": "وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا", "surah": 24, "surah_name": "النور", "ref": "24:31", "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31"}], "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31", "surah_name": "النور", "ayah_canonical": 31, "match": "contained", "ref": "24:31"}, {"t": "text", "s": "؛ فهذه الزينة التي لا خطر على إبدائها هي الزينة الظاهرة التي لا يمكن إخفاؤها لأنها هي نفسها الحجاب الذي يخفي وراءه زينتها التي أمرت بإخفائها، وهذه الزينة المسموح بإبدائها والتي لا سلطان لها عليها حتى تخفيها هي الثوب العام الذي تستتر به المرأة فإذا ظهر ذلك الثوب كالملاءة أو العباءة التي تغطي جسم المرأة كله من قمة الرأس إلى القدم فلا شيء عليها لأن ذلك مما لا قدرة لها على إخفائه وهذه هي الزينة التي عفي عن إبدائها."}]}, {"type": "paragraph", "md": "فقد صح عن ابن مسعود وغيره تفسير الزينة بالثياب الظاهرة من المرأة.", "page": 329, "id": "unit-26__lesson-14__b38"}, {"type": "paragraph", "md": "وأما من قال إن ﴿مَا ظَهَرَ مِنْهَا﴾ الوجه والكفان فقد بنى مذهبه على عدة أمور منها:", "page": 329, "id": "unit-26__lesson-14__b39", "inline": [{"t": "text", "s": "وأما من قال إن "}, {"t": "ayah", "s": "مَا ظَهَرَ مِنْهَا", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": " الوجه والكفان فقد بنى مذهبه على عدة أمور منها:"}]}, {"type": "paragraph", "md": "إما على آثار ضعيفة السند منسوبة إلى ابن عباس، وإما على أساس الترجيح الفقهي بناءً على أن عورة المرأة في الصلاة البدن كله ما عدا الوجه والكفان وأن إحرامها في الوجه والكفين؛ فيلزم إباحة إظهارهما.", "page": 329, "id": "unit-26__lesson-14__b40"}, {"type": "paragraph", "md": "ولا شك أن هناك فرق بين داخل الصلاة وخارجها كما ذكرنا قبلُ أن العورة عورتان: عورة الصلاة وعورة النظر، وأن الأمر بالحجاب يشمل ما هو عورة وما هو فتنة.", "page": 329, "id": "unit-26__lesson-14__b41"}, {"type": "paragraph", "md": "وقد رخص بعضهم جواز كشف الوجه والكفين؛ لأن الحاجة قد تمس إلى إظهارهما كالخطبة والشهادة والتطبيب.. إلخ والجواب أنه يرخص لها ذلك في حدود حاجتها؛ فلا يُتجاوز فيه إلى غيره، والله أعلم.", "page": 329, "id": "unit-26__lesson-14__b42"}, {"type": "paragraph", "md": "وأما الآثار المنسوبة إلى ابن عباس في تفسير ﴿إِلَّا مَا ظَهَرَ مِنْهَا﴾؛ فقد ضعف أسانيدها الشيخ محمد إسماعيل المقدم وناقش الأسنايد باستفاضة فيتراجع في كتابه «عودة الحجاب»؛ ثم لو افترضنا صحة ما نقل عن ابن عباس فبيانه بما قاله شيخ الإسلام ابن تيمية: «والسلف تنازعوا في الزينة الظاهرة على قولين فقال ابن مسعود: هي الثياب، وقال ابن عباس ومن وافقه: هي ما في الوجه واليدين مثل الكحل والخاتم. قال شيخ الإسلام: وحقيقة الأمر أن الله جعل الزينة زينتين؛ زينة ظاهرة وزينة غير ظاهرة، وجوز لها إبداء زينتها الظاهرة لغير الزوج والمحارم، وأما الباطنة فلا تبديها إلا للزوج وذوي المحارم. وقبل أن تنزل آية الحجاب كان النساء يخرجن بلا جلباب يرى الرجال وجهها ويديها وكان إذ ذاك يجوز لها أن تظهر الوجه والكفين، وكان حينئذ يجوز ا' WHERE id='unit-26__lesson-14';
UPDATE manhaj_lessons SET blocks = blocks || 'لنظر إليها لأنه يجوز لها إظهاره ثم أنزل الله عز وجل آية الحجاب بقوله: ﴿يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ وَبَنَاتِكَ وَنِسَاءِ الْمُؤْمِنِينَ يُدْنِينَ عَلَيْهِنَّ مِنْ جَلَابِيبِهِنَّ﴾؛ حجب النساء عن الرجال، وكذلك لما تزوج النبي صلى الله عليه وسلم زينب بنت جحش رضي الله عنها فأرخى النبي صلى الله عليه وسلم الستر ومنع أنسًا أن ينظر. ولما اصطفى صفية بنت حيي بعد عام خيبر قالوا: «إن حجبها فهي من أمهات المؤمنين، وإلا فهي مما ملكت يمينه»، فحجبها.", "page": 330, "id": "unit-26__lesson-14__b43", "inline": [{"t": "text", "s": "وأما الآثار المنسوبة إلى ابن عباس في تفسير "}, {"t": "ayah", "s": "إِلَّا مَا ظَهَرَ مِنْهَا", "ayah": [], "verses": [{"n": 31, "text": "إِلَّا مَا ظَهَرَ مِنْهَا", "surah": 24, "surah_name": "النور", "ref": "24:31", "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31"}], "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31", "surah_name": "النور", "ayah_canonical": 31, "match": "contained", "ref": "24:31"}, {"t": "text", "s": "؛ فقد ضعف أسانيدها الشيخ محمد إسماعيل المقدم وناقش الأسنايد باستفاضة فيتراجع في كتابه "}, {"t": "quote", "s": "عودة الحجاب"}, {"t": "text", "s": "؛ ثم لو افترضنا صحة ما نقل عن ابن عباس فبيانه بما قاله شيخ الإسلام ابن تيمية: "}, {"t": "quote", "s": "والسلف تنازعوا في الزينة الظاهرة على قولين فقال ابن مسعود: هي الثياب، وقال ابن عباس ومن وافقه: هي ما في الوجه واليدين مثل الكحل والخاتم. قال شيخ الإسلام: وحقيقة الأمر أن الله جعل الزينة زينتين؛ زينة ظاهرة وزينة غير ظاهرة، وجوز لها إبداء زينتها الظاهرة لغير الزوج والمحارم، وأما الباطنة فلا تبديها إلا للزوج وذوي المحارم. وقبل أن تنزل آية الحجاب كان النساء يخرجن بلا جلباب يرى الرجال وجهها ويديها وكان إذ ذاك يجوز لها أن تظهر الوجه والكفين، وكان حينئذ يجوز النظر إليها لأنه يجوز لها إظهاره ثم أنزل الله عز وجل آية الحجاب بقوله: ﴿يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ وَبَنَاتِكَ وَنِسَاءِ الْمُؤْمِنِينَ يُدْنِينَ عَلَيْهِنَّ مِنْ جَلَابِيبِهِنَّ﴾؛ حجب النساء عن الرجال، وكذلك لما تزوج النبي صلى الله عليه وسلم زينب بنت جحش رضي الله عنها فأرخى النبي صلى الله عليه وسلم الستر ومنع أنسًا أن ينظر. ولما اصطفى صفية بنت حيي بعد عام خيبر قالوا: «إن حجبها فهي من أمهات المؤمنين، وإلا فهي مما ملكت يمينه", "speaker": "شيخ الإسلام ابن تيمية"}, {"t": "text", "s": "، فحجبها."}]}, {"type": "paragraph", "md": "فلما أمر الله أن لا يسألن إلا من وراء حجاب، وأمر أزواجه وبناته ونساء المؤمنين أن يدنين على أنفسهن من جلابيبهن، والجلباب هو الملاءة، وهو الذي يسميه ابن مسعود وغيره: الرداء وتسميته العامة: الإزار وهو الإزار الكبير الذي يغطي رأسها وبدنها، وقد حكى عَبيدة السلماني وغيره أنها تدنيه من فوق رأسها فلا تُظهر إلا عينها، ومن جنسه: النقاب؛ فكان النساء ينتقبن وفي الصحيح: (إن المحرمة لا تنتقب ولا تلبس القفازين) فإذا أمرن بالجلباب وهو ستر الوجه، أو ستر الوجه بالنقاب؛ كان حينئذ الوجه واليدان من الزينة فعن ابن مسعود رضي الله عنه ذكر آخر الأمرين، وابن عباس رضي الله عنه ذكر أول الأمرين» انتهى كلام ابن تيمية.", "page": 330, "id": "unit-26__lesson-14__b44", "inline": [{"t": "text", "s": "فلما أمر الله أن لا يسألن إلا من وراء حجاب، وأمر أزواجه وبناته ونساء المؤمنين أن يدنين على أنفسهن من جلابيبهن، والجلباب هو الملاءة، وهو الذي يسميه ابن مسعود وغيره: الرداء وتسميته العامة: الإزار وهو الإزار الكبير الذي يغطي رأسها وبدنها، وقد حكى عَبيدة السلماني وغيره أنها تدنيه من فوق رأسها فلا تُظهر إلا عينها، ومن جنسه: النقاب؛ فكان النساء ينتقبن وفي الصحيح: "}, {"t": "emphasis", "s": "(إن المحرمة لا تنتقب ولا تلبس القفازين)", "role": "emphasis"}, {"t": "text", "s": " فإذا أمرن بالجلباب وهو ستر الوجه، أو ستر الوجه بالنقاب؛ كان حينئذ الوجه واليدان من الزينة فعن ابن مسعود "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ذكر آخر الأمرين، وابن عباس "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ذكر أول الأمرين» انتهى كلام ابن تيمية."}]}, {"type": "paragraph", "md": "ب- الموضع الثاني: قوله تعالى: ﴿وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَى جُيُوبِهِنَّ﴾، ووجه الدلالة في الآية على وجوب تغطية الوجه والكفين، أن هذا يتضمن أمر النساء بتغطية وجوههن ورقابهن، وبيان ذلك أن المرأة إذا كانت مأمورة بسدل الخمار من رأسها على جيبها لتستر صدرها؛ فهي مأمورة ضمنًا بستر ما بين الرأس والصدر وهما الوجه والرقبة، وإنما لم يذكر هنا للعلم بأن سدل الخمار إلى أن يضرب على الجيب وهو الصدر لا بد من أن يغطي الوجه قطعًا؛ فأراد جل ذكره أن يعلمها كيف تحيط مواضع الزينة بلف الخمار الذي تضعه على رأسها فقال: ﴿وَلْيَضْرِبْنَ بِخُمُرِهِنَّ﴾ يعني من الرأس وأعالي الوجه ﴿عَلَى جُيُوبِهِنَّ﴾ يعني الصدور حتى تكون بذلك قد حفظت الرأس وما حوى والصدر من تحته وما بين ذلك من الرقبة وما حولها لتضمن المرأة بذلك ستر الزينة الأصلية والفرعية؛ فمن استثنى شيئًا من تلك المنطقة المحرمة بنص القرآن العزيز فعليه الدليل الذي يخصص هذا ويحدد المستثنى، وهذا غير ممكن قطعًا لأنه يحتاج إلى نص صريح من القرآن العزيز أو من السنة المطهرة، وأنى لأولئك الذين قد استثنوا الوجه من تلك المنطقة بالأمور الظنية أن يأتوا بالدليل القطعي.", "page": 331, "id": "unit-26__lesson-14__b45", "inline": [{"t": "text", "s": "ب- الموضع الثاني: قوله تعالى: "}, {"t": "ayah", "s": "وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَى جُيُوبِهِنَّ", "ayah": [], "verses": [{"n": 31, "text": "وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَى جُيُوبِهِنَّ", "surah": 24, "surah_name": "النور", "ref": "24:31", "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31"}], "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31", "surah_name": "النور", "ayah_canonical": 31, "match": "contained", "ref": "24:31"}, {"t": "text", "s": "، ووجه الدلالة في الآية على وجوب تغطية الوجه والكفين، أن هذا يتضمن أمر النساء بتغطية وجوههن ورقابهن، وبيان ذلك أن المرأة إذا كانت مأمورة بسدل الخمار من رأسها على جيبها لتستر صدرها؛ فهي مأمورة ضمنًا بستر ما بين الرأس والصدر وهما الوجه والرقبة، وإنما لم يذكر هنا للعلم بأن سدل الخمار إلى أن يضرب على الجيب وهو الصدر لا بد من أن يغطي الوجه قطعًا؛ فأراد جل ذكره أن يعلمها كيف تحيط مواضع الزينة بلف الخمار الذي تضعه على رأسها فقال: "}, {"t": "ayah", "s": "وَلْيَضْرِبْنَ بِخُمُرِهِنَّ", "ayah": [], "verses": [{"n": 31, "text": "وَلْيَضْرِبْنَ بِخُمُرِهِنَّ", "surah": 24, "surah_name": "النور", "ref": "24:31", "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31"}], "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31", "surah_name": "النور", "ayah_canonical": 31, "match": "contained", "ref": "24:31"}, {"t": "text", "s": " يعني من الرأس وأعالي الوجه "}, {"t": "ayah", "s": "عَلَى جُيُوبِهِنَّ", "ayah": [], "verses": [{"n": 31, "text": "عَلَى جُيُوبِهِنَّ", "surah": 24, "surah_name": "النور", "ref": "24:31", "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31"}], "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31", "surah_name": "النور", "ayah_canonical": 31, "match": "contained", "ref": "24:31"}, {"t": "text", "s": " يعني الصدور حتى تكون بذلك قد حفظت الرأس وما حوى والصدر من تحته وما بين ذلك من الرقبة وما حولها لتضمن المرأة بذلك ستر الزينة الأصلية والفرعية؛ فمن استثنى شيئًا من تلك المنطقة المحرمة بنص القرآن العزيز فعليه الدليل الذي يخصص هذا ويحدد المستثنى، وهذا غير ممكن قطعًا لأنه يحتاج إلى نص صريح من القرآن العزيز أو من السنة المطهرة، وأنى لأولئك الذين قد استثنوا الوجه من تلك المنطقة بالأمور الظنية أن يأتوا بالدليل القطعي."}]}, {"type": "paragraph", "md": "ج- الموضع الثالث: قوله: ﴿وَلَا يَضْرِبْنَ بِأَرْجُلِهِنَّ لِيُعْلَمَ مَا يُخْفِينَ مِنْ زِينَتِهِنَّ﴾؛ فدلالة هذه الآية على الحجاب الكامل أظهر وأقوى مما سبقها؛ لأن إثارة الفتنة بسماع صوت الخلخال في الرِّجل أقل بكثير من فتنة النظر إلى وجهها؛ فإذا حرم الله تعالى بهذه الآية على المرأة أن تضرب الأرض برجلها خشية أن يسمع صوت حليها فيفتن به سامعه؛ كان تحريم النظر إلى وجهها وهو محط محاسنها أولى وأشد حرمة.", "page": 331, "id": "unit-26__lesson-14__b46", "inline": [{"t": "text", "s": "ج- الموضع الثالث: قوله: "}, {"t": "ayah", "s": "وَلَا يَضْرِبْنَ بِأَرْجُلِهِنَّ لِيُعْلَمَ مَا يُخْفِينَ مِنْ زِينَتِهِنَّ", "ayah": [], "verses": [{"n": 31, "text": "وَلَا يَضْرِبْنَ بِأَرْجُلِهِنَّ لِيُعْلَمَ مَا يُخْفِينَ مِنْ زِينَتِهِنَّ", "surah": 24, "surah_name": "النور", "ref": "24:31", "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31"}], "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31", "surah_name": "النور", "ayah_canonical": 31, "match": "contained", "ref": "24:31"}, {"t": "text", "s": "؛ فدلالة هذه الآية على الحجاب الكامل أظهر وأقوى مما سبقها؛ لأن إثارة الفتنة بسماع صوت الخلخال في الرِّجل أقل بكثير من فتنة النظر إلى وجهها؛ فإذا حرم الله تعالى بهذه الآية على المرأة أن تضرب الأرض برجلها خشية أن يسمع صوت حليها فيفتن به سامعه؛ كان تحريم النظر إلى وجهها وهو محط محاسنها أولى وأشد حرمة."}]}, {"type": "paragraph", "md": "5- قوله تعالى: ﴿وَالْقَوَاعِدُ مِنَ النِّسَاءِ اللَّاتِي لَا يَرْجُونَ نِكَاحًا فَلَيْسَ عَلَيْهِنَّ جُنَاحٌ أَنْ يَضَعْنَ ثِيَابَهُنَّ غَيْرَ مُتَبَرِّجَاتٍ بِزِينَةٍ وَأَنْ يَسْتَعْفِفْنَ خَيْرٌ لَهُنَّ وَاللَّهُ سَمِيعٌ عَلِيمٌ 60﴾، والقواعد هن العجائز اللاتي فقدن الصبوة بحكم الشيخوخة، وهؤلاء مأذون لهن أن يسفرن سفورًا محتشمًا بعيدًا عن الزينة والتبرج؛ بأن يضعن بعض ثيابهنّ كالرداء والقناع، غير مظهرات للزينة الخفية التي أُمِرْن بسترها، فإذا اتخذن الزينة أثمن، لأن سفور الوجه مقيد بالتجرد من الزينة؛ لأن ذلك لا يتفق مع كرامة الشيخوخة، وخير لها أن لا تسفر مع جوازه إمعانًا في الستر والتعفف لها فأن تبقى محجبة بالكامل أفضل؛ فالحجاب شعار المسلمة.", "page": 331, "id": "unit-26__lesson-14__b47", "inline": [{"t": "emphasis", "s": "5- قوله تعالى", "role": "emphasis"}, {"t": "text", "s": ": "}, {"t": "ayah", "s": "وَالْقَوَاعِدُ مِنَ النِّسَاءِ اللَّاتِي لَا يَرْجُونَ نِكَاحًا فَلَيْسَ عَلَيْهِنَّ جُنَاحٌ أَنْ يَضَعْنَ ثِيَابَهُنَّ غَيْرَ مُتَبَرِّجَاتٍ بِزِينَةٍ وَأَنْ يَسْتَعْفِفْنَ خَيْرٌ لَهُنَّ وَاللَّهُ سَمِيعٌ عَلِيمٌ 60", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "، والقواعد هن العجائز اللاتي فقدن الصبوة بحكم الشيخوخة، وهؤلاء مأذون لهن أن يسفرن سفورًا محتشمًا بعيدًا عن الزينة والتبرج؛ بأن يضعن بعض ثيابهنّ كالرداء والقناع، غير مظهرات للزينة الخفية التي أُمِرْن بسترها، فإذا اتخذن الزينة أثمن، لأن سفور الوجه مقيد بالتجرد من الزينة؛ لأن ذلك لا يتفق مع كرامة الشيخوخة، وخير لها أن لا تسفر مع جوازه إمعانًا في الستر والتعفف لها فأن تبقى محجبة بالكامل أفضل؛ فالحجاب شعار المسلمة."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "فإذا كان الله قد أباح للقواعد من النساء أن تضع خمارها؛ فلا معنى لتخصيصهن بالحكم إذا كان للشابة أن تضعه، فللعجوز اختصاص بجواز كشف الوجه مع كونها مغطاة الرأس، لأنها لا تشتهى، والاستعفاف بأن لا تضع ثيابها بين يدي الرجال خير لها، أما الشابة فيحرم عليها ذلك لأن الشرع لم يستثنها في الحكم.", "page": 331, "id": "unit-26__lesson-14__b48", "inline": [{"t": "emphasis", "s": "فإذا كان الله قد", "role": "emphasis"}, {"t": "text", "s": " أباح للقواعد من النساء أن تضع خمارها؛ فلا معنى لتخصيصهن بالحكم إذا كان للشابة أن تضعه، فللعجوز اختصاص بجواز كشف الوجه مع كونها مغطاة الرأس، لأنها لا تشتهى، والاستعفاف بأن لا تضع ثيابها بين يدي الرجال خير لها، أما الشابة فيحرم عليها ذلك لأن الشرع لم يستثنها في الحكم."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 331, "id": "unit-26__lesson-14__b49", "role": "assessment"}, {"type": "paragraph", "md": "1- اذكري ثلاثة أدلة على وجوب تغطية الوجه والكفين من القرآن.", "page": 331, "id": "unit-26__lesson-14__b50", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- عرفي المصطلحات الآتية: العورة، الخمار، النقاب، الجلباب.", "page": 331, "id": "unit-26__lesson-14__b51", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط دعوي واجتماعي", "page": 331, "id": "unit-26__lesson-14__b52", "role": "activity"}, {"type": "paragraph", "md": "1- نشرحُ هذا الدرس لخمسة من معارفنا حتى ولو كن يلبسن الخمار.. نشرًا للعلم بالشريعة.", "page": 331, "id": "unit-26__lesson-14__b53", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- نحاول البحث عن أدلة أخرى في القرآن الكريم يُستفاد منها وجوب تغطية الوجه ونذكرها.", "page": 331, "id": "unit-26__lesson-14__b54", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "منارات الهدى", "page": 332, "id": "unit-26__lesson-14__b55", "item_role": "activity_step"}]' WHERE id='unit-26__lesson-14';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-15','unit-26',15,'الأدلة من السنة النبوية على وجوب
تغطية الوجه والكفين','الأسرة والمرأة',NULL,1,2,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 332, "id": "unit-26__lesson-15__b01", "role": "objectives"}, {"type": "paragraph", "md": "- ذكر بعض الأدلة الصحيحة من السنة النبوية على وجوب تغطية الوجه والكفين، واحتجاب المرأة.", "page": 332, "id": "unit-26__lesson-15__b02", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "بعض الأدلة من السنة النبوية على وجوب الحجاب وتغطية الوجه:", "page": 332, "id": "unit-26__lesson-15__b03", "role": "evidence"}, {"type": "paragraph", "md": "الصحيح أن على المرأة أن تستر جميع بدنها حتى الوجه والكفين؛ بل إن الإمام أحمد يرى أن ظفر المرأة عورة وهو قول مالك رحمهما الله ؛ خلافا لمن قال بعدم وجوب ذلك وهو قول غير قوي.", "page": 332, "id": "unit-26__lesson-15__b04", "inline": [{"t": "text", "s": "الصحيح أن على المرأة أن تستر جميع بدنها حتى الوجه والكفين؛ بل إن الإمام أحمد يرى أن ظفر المرأة عورة وهو قول مالك "}, {"t": "honorific", "s": "رحمهما الله"}, {"t": "text", "s": " ؛ خلافا لمن قال بعدم وجوب ذلك وهو قول غير قوي."}]}, {"type": "paragraph", "md": "ولو تتبعنا أقوال القائلين بعدم وجوب تغطية الوجه؛ فهي كما قال الشيخ بكر أبو زيد في كتابه «حراسة الفضيلة» لا تخلو من ثلاث حالات: «1- دليل صحيح صريح ، لكنه منسوخ بآيات فرض الحجاب.. 2- دليل صحيح لكنه غير صريح؛ لا تثبت دلالته أمام الأدلة القطعية الدلالة من الكتاب والسنة على حجب الوجه والكفين.. 3- دليل صريح، ولكنه غير صحيح»، ودونك بعض أدلة وجوب تغطية الوجه والكفين، وعدم طاعة الزوج والأب في كشفهما لأنه معصية، وحرمة نظر الرجال لوجه الأجنبية:", "page": 332, "id": "unit-26__lesson-15__b05", "inline": [{"t": "text", "s": "ولو تتبعنا أقوال القائلين بعدم وجوب تغطية الوجه؛ فهي كما قال الشيخ بكر أبو زيد في كتابه "}, {"t": "quote", "s": "حراسة الفضيلة", "speaker": "الشيخ بكر أبو زيد في كتابه"}, {"t": "text", "s": " لا تخلو من ثلاث حالات: "}, {"t": "quote", "s": "1- دليل صحيح صريح ، لكنه منسوخ بآيات فرض الحجاب.. 2- دليل صحيح لكنه غير صريح؛ لا تثبت دلالته أمام الأدلة القطعية الدلالة من الكتاب والسنة على حجب الوجه والكفين.. 3- دليل صريح، ولكنه غير صحيح"}, {"t": "text", "s": "، "}, {"t": "emphasis", "s": "ودونك بعض أدلة وجوب تغطية الوجه والكفين، وعدم طاعة الزوج والأب في كشفهما لأنه معصية، وحرمة نظر الرجال لوجه الأجنبية:", "role": "emphasis"}]}, {"type": "paragraph", "md": "1- قال النبي صلى الله عليه وسلم : (المرأة عورة)، وهذا الحديث دالٌ على أن جميع أجزاء المرأة عورة في حق الرجال الأجانب سواء في ذلك وجهها أو غيره من أعضائها، قال الإمام أحمد: «ظفر المرأة عورة فإذا خرجت من بيتها فلا تُبِنْ منها شيئًا ولا خُفَّها، فإن الخف يصف القدم وأحب إليَّ أن لا تجعل لكُمِّهَا زرًا عند يدها حتى لا يبين منها شيء»، وقال به ابن تيمية وقال هو قول مالك وبه قال الشنقيطي.", "page": 332, "id": "unit-26__lesson-15__b06", "inline": [{"t": "text", "s": "1- قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(المرأة عورة)", "role": "emphasis"}, {"t": "text", "s": "، وهذا الحديث دالٌ على أن جميع أجزاء المرأة عورة في حق الرجال الأجانب سواء في ذلك وجهها أو غيره من أعضائها، قال الإمام أحمد: "}, {"t": "quote", "s": "ظفر المرأة عورة فإذا خرجت من بيتها فلا تُبِنْ منها شيئًا ولا خُفَّها، فإن الخف يصف القدم وأحب إليَّ أن لا تجعل لكُمِّهَا زرًا عند يدها حتى لا يبين منها شيء", "speaker": "الإمام أحمد"}, {"t": "text", "s": "، وقال به ابن تيمية وقال هو قول مالك وبه قال الشنقيطي."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- وقال صلى الله عليه وسلم : (لا تنتقب المرأة المحرمة ولا تلبس القفازين)؛ هذا الحديث يدل على أن لبس النقاب والقفازين كانا معروفين في النساء اللاتي لم يحرمن وذلك يقتضي تغطية وجهها وكفيها خارج الإحرام بالنقاب والقفازين، وأما في الإحرام فليس المراد أن لا تلبس النقاب والقفازين أي أن تظهرهما؛ بل لا بد من تغطيتهما بشيء من لباسها الذي تلبس أو ترخي شيئًا من خمارها على وجهها غير لاصق به، وتعرض عن الرجال ويعرضون عنها، فلا يغطى الوجه بما صنع على قدره كالنقاب بل يغطى من الأثواب التي تلبسها المرأة، فالنهي هنا عن النقاب خاصة لا عن تغطية الوجه؛ قال ابن حجر: «لها أن تغطي رأسها وتستر شعرها إلا وجهها فتسدل عليه الثوب سدلًا خفيفًا تستر به عن الرجال الأجانب ولا تخمره».", "page": 333, "id": "unit-26__lesson-15__b07", "inline": [{"t": "text", "s": "2- وقال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لا تنتقب المرأة المحرمة ولا تلبس القفازين)", "role": "emphasis"}, {"t": "text", "s": "؛ هذا الحديث يدل على أن لبس النقاب والقفازين كانا معروفين في النساء اللاتي لم يحرمن وذلك يقتضي تغطية وجهها وكفيها خارج الإحرام بالنقاب والقفازين، وأما في الإحرام فليس المراد أن لا تلبس النقاب والقفازين أي أن تظهرهما؛ بل لا بد من تغطيتهما بشيء من لباسها الذي تلبس أو ترخي شيئًا من خمارها على وجهها غير لاصق به، وتعرض عن الرجال ويعرضون عنها، فلا يغطى الوجه بما صنع على قدره كالنقاب بل يغطى من الأثواب التي تلبسها المرأة، فالنهي هنا عن النقاب خاصة لا عن تغطية الوجه؛ قال ابن حجر: "}, {"t": "quote", "s": "لها أن تغطي رأسها وتستر شعرها إلا وجهها فتسدل عليه الثوب سدلًا خفيفًا تستر به عن الرجال الأجانب ولا تخمره", "speaker": "ابن حجر"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- قال رسول الله صلى الله عليه وسلم : (من جر ثوبه خيلاء لم ينظر الله إليه يوم القيامة، فقالت أم سلمة: فكيف تصنع النساء بذيولهن يا رسول الله؟ قال: يرخين شبرا. قالت: إذا تنكشف أقدامهن!، قال: فيرخينه ذراعا لا يزدن عليه)؛ فالحديث دليل على وجوب ستر القدمين، إذا كان الأمر بحق القدمين هكذا فكيف بما هو فوقهما من سائر أجزاء البدن، ولا سيما الوجه الذي هو مجمع محاسن المرأة وأعظم ما يفتتن به الرجال ويتنافسون في تحصيله إن كان حسنًا؛ فوجهها أولى بالستر من قدميها وأسفل رجليها.", "page": 333, "id": "unit-26__lesson-15__b08", "inline": [{"t": "text", "s": "3- قال رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(من جر ثوبه خيلاء لم ينظر الله إليه يوم القيامة، فقالت أم سلمة: فكيف تصنع النساء بذيولهن يا رسول الله؟ قال: يرخين شبرا. قالت: إذا تنكشف أقدامهن!، قال: فيرخينه ذراعا لا يزدن عليه)", "role": "emphasis"}, {"t": "text", "s": "؛ فالحديث دليل على وجوب ستر القدمين، إذا كان الأمر بحق القدمين هكذا فكيف بما هو فوقهما من سائر أجزاء البدن، ولا سيما الوجه الذي هو مجمع محاسن المرأة وأعظم ما يفتتن به الرجال ويتنافسون في تحصيله إن كان حسنًا؛ فوجهها أولى بالستر من قدميها وأسفل رجليها."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- قال صلى الله عليه وسلم : (إياكم والدخولَ على النساء، فقال رجل من الأنصار: يا رسول الله، أرأيتَ الحَمُو؟ قال: الحَمُو الموتُ). والحمو: أخو الزوج وما أشبهه من أقارب الزوج، ابن عم ونحوه.", "page": 333, "id": "unit-26__lesson-15__b09", "inline": [{"t": "text", "s": "4- قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إياكم والدخولَ على النساء، فقال رجل من الأنصار: يا رسول الله، أرأيتَ الحَمُو؟ قال: الحَمُو الموتُ)", "role": "emphasis"}, {"t": "text", "s": ". والحمو: أخو الزوج وما أشبهه من أقارب الزوج، ابن عم ونحوه."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "فسمى النبي صلى الله عليه وسلم دخول قريب الرجل على امرأته وهو غير محرم عليها باسم الموت، ولا شك أن تلك العبارة أبلغ عبارات التحذير؛ لأن الموت أفظع حادث يأتي على الإنسان في الدنيا وفي ذلك دليل على أن قوله تعالى: ﴿فَاسْأَلُوهُنَّ مِنْ وَرَاءِ حِجَابٍ﴾ عام في جميع النساء وليس فقط أزواج النبي صلى الله عليه وسلم وظاهر الحديث التشديد على أن لا يرى الرجل المرأة ولو كان من الأقارب ولو كان أخو الزوج؛ فهذا يدل على حرمة خروج المرأة منكشفة الوجه والكفين أمام الأقارب والأباعد.", "page": 333, "id": "unit-26__lesson-15__b10", "inline": [{"t": "text", "s": "فسمى النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " دخول قريب الرجل على امرأته وهو غير محرم عليها باسم الموت، ولا شك أن تلك العبارة أبلغ عبارات التحذير؛ لأن الموت أفظع حادث يأتي على الإنسان في الدنيا وفي ذلك دليل على أن قوله تعالى: "}, {"t": "ayah", "s": "فَاسْأَلُوهُنَّ مِنْ وَرَاءِ حِجَابٍ", "ayah": [], "verses": [{"n": 53, "text": "فَاسْأَلُوهُنَّ مِنْ وَرَاءِ حِجَابٍ", "surah": 33, "surah_name": "الأحزاب", "ref": "33:53", "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:53"}], "surah": 33, "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:53", "surah_name": "الأحزاب", "ayah_canonical": 53, "match": "contained", "ref": "33:53"}, {"t": "text", "s": " عام في جميع النساء وليس فقط أزواج النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وظاهر الحديث التشديد على أن لا يرى الرجل المرأة ولو كان من الأقارب ولو كان أخو الزوج؛ فهذا يدل على حرمة خروج المرأة منكشفة الوجه والكفين أمام الأقارب والأباعد."}]}, {"type": "paragraph", "md": "5- عن عائشة رضي الله عنها : أنَّ أفلحَ أخَا أبي القُعَيْسِ استأذنَ عليْها بعدَ ما أُنْزِلَ الحجابُ، قالتْ عائشةُ: فقُلْتُ: واللهِ لا آذَنُ لهُ حتى أستأذنَ رسولَ اللهِ صلى الله عليه وسلم ؛ فإنَّ أبا القُعَيْسِ ليس هو أرضعَني، ولكنْ أَرْضَعَتْنِي امرأتُهُ، قالتْ: فلمَّا دخلَ صلى الله عليه وسلم ، ذكرْتُ ذلكَ لهُ، فقال: (ائْذَنِي لهُ، فإنَّهُ عَمُّكِ تَرِبَتْ يَمِينُكِ)، وكان أبُو القُعَيْسِ زَوْجَ المرأةِ التي أَرْضَعَتْ عائشةَ. ذكر ابن حجر من فوائد الحديث: «احتجاب المرأة من الرجال الأجانب وهذا تعميم على جميع النساء لأنه لم يثبت لعائشة رضي الله عنها أنه عمها من الرضاعة فظنته أجنبيًّا عنها».", "page": 333, "id": "unit-26__lesson-15__b11", "inline": [{"t": "text", "s": "5- عن عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " : أنَّ أفلحَ أخَا أبي القُعَيْسِ استأذنَ عليْها بعدَ ما أُنْزِلَ الحجابُ، قالتْ عائشةُ: فقُلْتُ: واللهِ لا آذَنُ لهُ حتى أستأذنَ رسولَ اللهِ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ؛ فإنَّ أبا القُعَيْسِ ليس هو أرضعَني، ولكنْ أَرْضَعَتْنِي امرأتُهُ، قالتْ: فلمَّا دخلَ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، ذكرْتُ ذلكَ لهُ، فقال: "}, {"t": "emphasis", "s": "(ائْذَنِي لهُ، فإنَّهُ عَمُّكِ تَرِبَتْ يَمِينُكِ)", "role": "emphasis"}, {"t": "text", "s": "، وكان أبُو القُعَيْسِ زَوْجَ المرأةِ التي أَرْضَعَتْ عائشةَ. ذكر ابن حجر من فوائد الحديث: "}, {"t": "quote", "s": "احتجاب المرأة من الرجال الأجانب وهذا تعميم على جميع النساء لأنه لم يثبت لعائشة رضي الله عنها أنه عمها من الرضاعة فظنته أجنبيًّا عنها"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6- عن عائشة رضي الله عنها في حادثة الإفك الطويل أنها قالت: «فبينا أنا جالسة في منزلي غلبتني عيني فنمت، وكان صفوان بن المعطل السلمي ثم الذكواني من وراء الجيش، فأدلج فأصبح عند منزلي، فرأى سواد إنسان نائم، فأتاني فعرفني حين رآني، وكان رآني قبل الحجاب، فاستيقظت باسترجاعه حين عرفني فخمرت وجهي بجلبابي، ووالله ما كلمني كلمة ولا سمعت منه كلمة غير استرجاعه، حتى أناخ راحلته فوطئ على يديها فركبتها، فانطلق يقود بي الراحلة، حتى أتينا الجيش بعدما نزلوا موغرين في نحر الظهيرة..)، ووجه الدلالة قول عائشة رضي الله عنها : «فخمرت وجهي بجلبابي» وهو ظاهر في وجوب تغطية الوجه.", "page": 334, "id": "unit-26__lesson-15__b12", "inline": [{"t": "text", "s": "6- عن عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " في حادثة الإفك الطويل أنها قالت: "}, {"t": "quote", "s": "فبينا أنا جالسة في منزلي غلبتني عيني فنمت، وكان صفوان بن المعطل السلمي ثم الذكواني من وراء الجيش، فأدلج فأصبح عند منزلي، فرأى سواد إنسان نائم، فأتاني فعرفني حين رآني، وكان رآني قبل الحجاب، فاستيقظت باسترجاعه حين عرفني فخمرت وجهي بجلبابي، ووالله ما كلمني كلمة ولا سمعت منه كلمة غير استرجاعه، حتى أناخ راحلته فوطئ على يديها فركبتها، فانطلق يقود بي الراحلة، حتى أتينا الجيش بعدما نزلوا موغرين في نحر الظهيرة..)، ووجه الدلالة قول عائشة رضي الله عنها : «فخمرت وجهي بجلبابي"}, {"t": "text", "s": " وهو ظاهر في وجوب تغطية الوجه."}], "list": {"type": "ordered", "marker": "6"}}, {"type": "paragraph", "md": "7- وعن أبي سلمة بن عبد الرحمن قال: قلت لعائشة رضي الله عنها : إنما فاقنا عروة بدخوله عليك كلما أراد! قالت: «وأنت إذا أردت فاجلس من وراء حجاب فسلني عما أحببت، فإنا لم نجد أحدًا بعد النبي صلى الله عليه وسلم أولى لنا من أبيك»، والشاهد قولها: «فاجلس من وراء حجاب» امتثالًا لقوله تعالى: ﴿فَاسْأَلُوهُنَّ مِنْ وَرَاءِ حِجَابٍ﴾؛ ففيه دليل على وجوب الحجاب والستر الكامل حتى الوجه والكفان.", "page": 334, "id": "unit-26__lesson-15__b13", "inline": [{"t": "text", "s": "7- وعن أبي سلمة بن عبد الرحمن قال: قلت لعائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " : إنما فاقنا عروة بدخوله عليك كلما أراد! قالت: "}, {"t": "quote", "s": "وأنت إذا أردت فاجلس من وراء حجاب فسلني عما أحببت، فإنا لم نجد أحدًا بعد النبي صلى الله عليه وسلم أولى لنا من أبيك"}, {"t": "text", "s": "، والشاهد قولها: "}, {"t": "hadith", "s": "فاجلس من وراء حجاب", "narrator": "أبي سلمة بن عبد الرحمن", "source": null, "confidence": "high", "ref_api": null}, {"t": "text", "s": " امتثالًا لقوله تعالى: "}, {"t": "ayah", "s": "فَاسْأَلُوهُنَّ مِنْ وَرَاءِ حِجَابٍ", "ayah": [], "verses": [{"n": 53, "text": "فَاسْأَلُوهُنَّ مِنْ وَرَاءِ حِجَابٍ", "surah": 33, "surah_name": "الأحزاب", "ref": "33:53", "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:53"}], "surah": 33, "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:53", "surah_name": "الأحزاب", "ayah_canonical": 53, "match": "contained", "ref": "33:53"}, {"t": "text", "s": "؛ ففيه دليل على وجوب الحجاب والستر الكامل حتى الوجه والكفان."}], "list": {"type": "ordered", "marker": "7"}}, {"type": "paragraph", "md": "8- عن عائشَةَ رضي الله عنها أنها قالَت: «يَرحَمُ اللَّهُ نساءَ المُهاجراتِ الأُوَلَ، لمَّا أنزلَ اللَّهُ: ﴿وَلۡيَضۡرِبۡنَ بِخُمُرِهِنَّ عَلَىٰ جُيُوبِهِنَّۖ﴾ شقَّقنَ أكنف مروطَهُنَّ فاختمرنَ بِها) قال ابن حجر: «(فاختمرن) أي غطين وجوههن»، وهو وجه الدلالة على أن نساء المؤمنين كن يخمرن وجوههن، وليس الجسم فقط دون الوجه والكفين.", "page": 334, "id": "unit-26__lesson-15__b14", "inline": [{"t": "text", "s": "8- عن عائشَةَ "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " أنها قالَت: "}, {"t": "quote", "s": "يَرحَمُ اللَّهُ نساءَ المُهاجراتِ الأُوَلَ، لمَّا أنزلَ اللَّهُ: ﴿وَلۡيَضۡرِبۡنَ بِخُمُرِهِنَّ عَلَىٰ جُيُوبِهِنَّۖ﴾ شقَّقنَ أكنف مروطَهُنَّ فاختمرنَ بِها) قال ابن حجر: «(فاختمرن) أي غطين وجوههن"}, {"t": "text", "s": "، وهو وجه الدلالة على أن نساء المؤمنين كن يخمرن وجوههن، وليس الجسم فقط دون الوجه والكفين."}], "list": {"type": "ordered", "marker": "8"}}, {"type": "paragraph", "md": "9- عن أم المؤمنين عائشة رضي الله عنها قالت: «كان الركبان يمرون بنا ونحن مع رسول الله صلى الله عليه وسلم محرمات؛ فإذا حاذَوا بنا سَدَلَت إحدانا جلبابها من رأسها على وجهها، فإذا جاوزونا كشفناه».", "page": 334, "id": "unit-26__lesson-15__b15", "inline": [{"t": "text", "s": "9- عن أم المؤمنين عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " قالت: "}, {"t": "quote", "s": "كان الركبان يمرون بنا ونحن مع رسول الله صلى الله عليه وسلم محرمات؛ فإذا حاذَوا بنا سَدَلَت إحدانا جلبابها من رأسها على وجهها، فإذا جاوزونا كشفناه"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "9"}}, {"type": "paragraph", "md": "وهذان الحديثان صريحان في شمول الحجاب للوجه؛ بل يفيدان بأن تغطية الوجه هو المقصود بأمر الحجاب، والحديث الأخير حكمه عام لجميع نساء المؤمنين؛ فإن المراد بضمائر جمع المتكلم ليست أمهات المؤمنين فحسب كما يزعمه الزاعمون، والدليل على ذلك أن عائشة رضي الله عنها هي التي روت هذا الحديث وهي التي كانت تفتي بأن المرأة المحرمة تسدل حجابها من فوق رأسها على وجهها.", "page": 334, "id": "unit-26__lesson-15__b16", "inline": [{"t": "text", "s": "وهذان الحديثان صريحان في شمول الحجاب للوجه؛ بل يفيدان بأن تغطية الوجه هو المقصود بأمر الحجاب، والحديث الأخير حكمه عام لجميع نساء المؤمنين؛ فإن المراد بضمائر جمع المتكلم ليست أمهات المؤمنين فحسب كما يزعمه الزاعمون، والدليل على ذلك أن عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " هي التي روت هذا الحديث وهي التي كانت تفتي بأن المرأة المحرمة تسدل حجابها من فوق رأسها على وجهها."}]}, {"type": "paragraph", "md": "10- ومن الآثار عن الضحابيات في ذلك: عن فاطمة بنت المنذر قالت: «كنا نُخَمِّرُ وجوهنا، ونحن محرمات مع أسماء بنت أبي بكر»، وعن أسماء بنت أبي بكر رضي الله عنها قالت: (كنا نغطي وجوهنا من الرجال، وكنا نمتشط قبل ذلك في الإحرام)؛ فففي هذه الآثار دليل على أن عمل النساء في زمن الصحابة رضي الله عنهن كان على تغطية الوجوه من الرجال الأجانب. وأما حديث فاطمة بنت المنذر فيفيد أن تغطية الوجه في الإحرام كان عامًا في النساء لا في زمن الصحابة فقط؛ بل فيما بعده أيضًا.", "page": 334, "id": "unit-26__lesson-15__b17", "inline": [{"t": "text", "s": "10- ومن الآثار عن الضحابيات في ذلك: عن فاطمة بنت المنذر قالت: "}, {"t": "quote", "s": "كنا نُخَمِّرُ وجوهنا، ونحن محرمات مع أسماء بنت أبي بكر"}, {"t": "text", "s": "، وعن أسماء بنت أبي بكر "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " قالت: "}, {"t": "emphasis", "s": "(كنا نغطي وجوهنا من الرجال، وكنا نمتشط قبل ذلك في الإحرام)", "role": "emphasis"}, {"t": "text", "s": "؛ فففي هذه الآثار دليل على أن عمل النساء في زمن الصحابة "}, {"t": "honorific", "s": "رضي الله عنهن"}, {"t": "text", "s": " كان على تغطية الوجوه من الرجال الأجانب. وأما حديث فاطمة بنت المنذر فيفيد أن تغطية الوجه في الإحرام كان عامًا في النساء لا في زمن الصحابة فقط؛ بل فيما بعده أيضًا."}], "list": {"type": "ordered", "marker": "10"}}, {"type": "paragraph", "md": "11- ومن أفعال الصحابة في ذلك: حديث جابر رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم : (إذا خطب أحدكم المرأة، فإن استطاع أن ينظر إلى ما يدعوه إلى نكاحها فليفعل)، قال جابر: فخطبت جارية فكنت أتخبأ لها، حتى رأيت منها ما دعاني إلى نكاحها، وتزوجتها.", "page": 334, "id": "unit-26__lesson-15__b18", "inline": [{"t": "text", "s": "11- ومن أفعال الصحابة في ذلك: حديث جابر "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قال: قال رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إذا خطب أحدكم المرأة، فإن استطاع أن ينظر إلى ما يدعوه إلى نكاحها فليفعل)", "role": "emphasis"}, {"t": "text", "s": "، قال جابر: فخطبت جارية فكنت أتخبأ لها، حتى رأيت منها ما دعاني إلى نكاحها، وتزوجتها."}], "list": {"type": "ordered", "marker": "11"}}, {"type": "paragraph", "md": "وعن محمد بن مسلمة رضي الله عنه قال: «خطَبتُ امرَأةً فجعَلتُ أتَخبَّأُ لَها حتَّى نظَرتُ إليها في نخلٍ لَها فقيلَ لَهُ أتَفعلُ هذا وأنتَ صاحبُ رسولِ اللَّهِ صلى الله عليه وسلم فقالَ: سَمِعْتُ رسولَ اللَّهِ صلى الله عليه وسلم يقولُ: (إذا ألقَى اللَّهُ في قلبِ امرئٍ خِطبةَ امرأةٍ فلا بأسَ أن ينظرَ إليها).", "page": 335, "id": "unit-26__lesson-15__b19", "inline": [{"t": "text", "s": "وعن محمد بن مسلمة "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قال: «خطَبتُ امرَأةً فجعَلتُ أتَخبَّأُ لَها حتَّى نظَرتُ إليها في نخلٍ لَها فقيلَ لَهُ أتَفعلُ هذا وأنتَ صاحبُ رسولِ اللَّهِ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " فقالَ: سَمِعْتُ رسولَ اللَّهِ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يقولُ: "}, {"t": "emphasis", "s": "(إذا ألقَى اللَّهُ في قلبِ امرئٍ خِطبةَ امرأةٍ فلا بأسَ أن ينظرَ إليها)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وعن المغيرة بن شعبة أنه خطب امرأة، فقال له النبي صلى الله عليه وسلم : (انظر إليها فإنه أحرى أن يؤدم بينكما) فأتيتها وعندها أبوها وهي في خدرها، قال فقلت: إن رسول الله صلى الله عليه وسلم أمرني أن أنظر إليها، قال: فسكتا، قال: فرفعت الجارية جانب الخدر، فقالت: أحرج عليك إن كان رسول الله صلى الله عليه وسلم أمرك أن تنظر لما نظرت، وإن كان رسول الله صلى الله عليه وسلم لم يأمرك أن تنظر فلا تنظر، قال: فنظرت إليها ثم تزوجتها فما وقعت عندي امرأة بمنزلتها ولقد تزوجت سبعين أو بضعا وسبعين امرأة.", "page": 335, "id": "unit-26__lesson-15__b20", "inline": [{"t": "text", "s": "وعن المغيرة بن شعبة أنه خطب امرأة، فقال له النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(انظر إليها فإنه أحرى أن يؤدم بينكما)", "role": "emphasis"}, {"t": "text", "s": " فأتيتها وعندها أبوها وهي في خدرها، قال فقلت: إن رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أمرني أن أنظر إليها، قال: فسكتا، قال: فرفعت الجارية جانب الخدر، فقالت: أحرج عليك إن كان رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أمرك أن تنظر لما نظرت، وإن كان رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " لم يأمرك أن تنظر فلا تنظر، قال: فنظرت إليها ثم تزوجتها فما وقعت عندي امرأة بمنزلتها ولقد تزوجت سبعين أو بضعا وسبعين امرأة."}]}, {"type": "paragraph", "md": "وفي هذه الأحاديث الثلاثة دليل على مشروعية احتجاب النساء من الرجال الأجانب، ولهذا أنكروا على محمد بن مسلمة لما أخبرهم أنه تخبأ لمخطوبته حتى نظر إليها وهي لا تشعر؛ فأخبرهم أن النبي صلى الله عليه وسلم قد رخص في ذلك للخاطب. وكذلك المغيرة رضي الله عنه لما طلب النظر إلى المخطوبة كره ذلك والداها، وأعظمت ذلك المرأة، ثم مكنته من النظر إليها طاعة لأمر رسول الله صلى الله عليه وسلم . وفي هذه الأحاديث أيضًا بيان ما كان عليه نساء الصحابة رضي الله عنهن من المبالغة في التستر من الأجانب، ولهذا لم يتمكن جابر وابن مسلمة رضي الله عنهما من النظر إلى المخطوبة إلا من طريق الاختباء والاغتفال؛ فكل هذا يدل على حالة التستر في المجتمع المسلم؛ بحيث لم يكن أحد يستطيع أن يرى النساء إلا بالحيلة ولغرض الخطبة، ولو كن يخرجن سافرات الوجوه كاشفات الخدين لم يكن الرجال يحتاجون إلى تجشم تلك المشقةِ في رؤيتهن.", "page": 335, "id": "unit-26__lesson-15__b21", "inline": [{"t": "text", "s": "وفي هذه الأحاديث الثلاثة دليل على مشروعية احتجاب النساء من الرجال الأجانب، ولهذا أنكروا على محمد بن مسلمة لما أخبرهم أنه تخبأ لمخطوبته حتى نظر إليها وهي لا تشعر؛ فأخبرهم أن النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قد رخص في ذلك للخاطب. وكذلك المغيرة "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " لما طلب النظر إلى المخطوبة كره ذلك والداها، وأعظمت ذلك المرأة، ثم مكنته من النظر إليها طاعة لأمر رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " . وفي هذه الأحاديث أيضًا بيان ما كان عليه نساء الصحابة "}, {"t": "honorific", "s": "رضي الله عنهن"}, {"t": "text", "s": " من المبالغة في التستر من الأجانب، ولهذا لم يتمكن جابر وابن مسلمة "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " من النظر إلى المخطوبة إلا من طريق الاختباء والاغتفال؛ فكل هذا يدل على حالة التستر في المجتمع المسلم؛ بحيث لم يكن أحد يستطيع أن يرى النساء إلا بالحيلة ولغرض الخطبة، ولو كن يخرجن سافرات الوجوه كاشفات الخدين لم يكن الرجال يحتاجون إلى تجشم تلك المشقةِ في رؤيتهن."}]}, {"type": "paragraph", "md": "12- وقال النبي صلى الله عليه وسلم : (لا تباشر المرأة فتنعتها لزوجها كأنه ينظر إليها)؛ ففيه دليل على مشروعية احتجاب النساء عن الرجال وأنه لم يبق للرجال سبيل إلى معرفة الأجنبيات من النساء إلا من طريق الوصف أو الاغتفال ونحو ذلك، ولهذا قال: (كأنه ينظر إليها) فدل على أن نظر الرجال إلى الأجنبيات ممتنع شرعًا من أجل احتجابهن عن الرجال، ولو كان السفور جائزًا لما كان الرجال يحتاجون إلى أن تُنعت لهم النساء بل كانوا يستغنون بنظرهم إليهن؛ كما هو معروف في البلدان التي قد فشا فيها التبرج والسفور.", "page": 335, "id": "unit-26__lesson-15__b22", "inline": [{"t": "text", "s": "12- وقال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لا تباشر المرأة فتنعتها لزوجها كأنه ينظر إليها)", "role": "emphasis"}, {"t": "text", "s": "؛ ففيه دليل على مشروعية احتجاب النساء عن الرجال وأنه لم يبق للرجال سبيل إلى معرفة الأجنبيات من النساء إلا من طريق الوصف أو الاغتفال ونحو ذلك، ولهذا قال: "}, {"t": "emphasis", "s": "(كأنه ينظر إليها)", "role": "emphasis"}, {"t": "text", "s": " فدل على أن نظر الرجال إلى الأجنبيات ممتنع شرعًا من أجل احتجابهن عن الرجال، ولو كان السفور جائزًا لما كان الرجال يحتاجون إلى أن تُنعت لهم النساء بل كانوا يستغنون بنظرهم إليهن؛ كما هو معروف في البلدان التي قد فشا فيها التبرج والسفور."}], "list": {"type": "ordered", "marker": "12"}}, {"type": "paragraph", "md": "13-عن جرير بن عبد الله رضي الله عنه قال: (سألت رسول الله صلى الله عليه وسلم عن نظر الفُجاءة فأمرني أن أصرف بصري)، ويستفاد من الحديث: أن النساء في زمن رسول الله صلى الله عليه وسلم كن يستترن عن الرجال الأجانب ويغطين وجوههن عنهم، وإنما كان يقع عليهن فجأة في بعض الأحيان، وأيضًا لو كنَّ يكشفن وجوههن عند الرجال الأجانب لكان في صرف البصر عنهن مشقة عظيمة.", "page": 336, "id": "unit-26__lesson-15__b23", "inline": [{"t": "text", "s": "13-عن جرير بن عبد الله "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قال: "}, {"t": "emphasis", "s": "(سألت رسول الله", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "عن نظر الفُجاءة فأمرني أن أصرف بصري)", "role": "emphasis"}, {"t": "text", "s": "، ويستفاد من الحديث: أن النساء في زمن رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " كن يستترن عن الرجال الأجانب ويغطين وجوههن عنهم، وإنما كان يقع عليهن فجأة في بعض الأحيان، وأيضًا لو كنَّ يكشفن وجوههن عند الرجال الأجانب لكان في صرف البصر عنهن مشقة عظيمة."}]}, {"type": "paragraph", "md": "14-عن فاطمة بنت قيس: أن أبا عمرو بن حفص طلقها البتة وهو غائب، فأرسل إليها وكيله بشعير، فسخطته، فقال: والله ما لك علينا من شيء، فجاءت رسول الله صلى الله عليه وسلم فذكرت ذلك له: فقال: (ليس لك نفقة)، فأمرها أن تعتد في بيت أم شريك، ثم قال: (تلك امرأة يغشاها أصحابي، وهي كثيرة الضيفان؛ فإني أكره أن يسقط عنك خمارك أو ينكشف الثوب عن ساقيك، فيرى القوم منك ‌بعض ‌ما ‌تكرهين، ولكن انتقلي إلى ابن عمك عبد الله بن عمرو ابن أم مكتوم فاعتدي عنده، فإنه رجل أعمى، تضعين ثيابك، فإذا حللت فآذنيني)، قالت: فلما حللت، ذكرت له أن معاوية بن أبي سفيان وأبا جهم خطباني، فقال رسول الله صلى الله عليه وسلم : (أما أبو جهم، فلا يضع عصاه عن عاتقه، وأما معاوية فصعلوك لا مال له، ولكن انكحي أسامة بن زيد)، فكرهته، ثم قال: (انكحي أسامة بن زيد) فنكحته، فجعل الله عز وجل فيه خيرا، واغتبطت به).", "page": 336, "id": "unit-26__lesson-15__b24", "inline": [{"t": "text", "s": "14-عن فاطمة بنت قيس: أن أبا عمرو بن حفص طلقها البتة وهو غائب، فأرسل إليها وكيله بشعير، فسخطته، فقال: والله ما لك علينا من شيء، فجاءت رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " فذكرت ذلك له: فقال: "}, {"t": "emphasis", "s": "(ليس لك نفقة)", "role": "emphasis"}, {"t": "text", "s": "، فأمرها أن تعتد في بيت أم شريك، ثم قال: "}, {"t": "emphasis", "s": "(تلك امرأة يغشاها أصحابي، وهي كثيرة الضيفان؛ فإني أكره أن يسقط عنك خمارك أو ينكشف الثوب عن ساقيك، فيرى القوم منك ‌بعض ‌ما ‌تكرهين، ولكن انتقلي إلى ابن عمك عبد الله بن عمرو ابن أم مكتوم فاعتدي عنده، فإنه رجل أعمى، تضعين ثيابك، فإذا حللت فآذنيني)", "role": "emphasis"}, {"t": "text", "s": "، قالت: فلما حللت، ذكرت له أن معاوية بن أبي سفيان وأبا جهم خطباني، فقال رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(أما أبو جهم، فلا يضع عصاه عن عاتقه، وأما معاوية فصعلوك لا مال له، ولكن انكحي أسامة بن زيد)", "role": "emphasis"}, {"t": "text", "s": "، فكرهته، ثم قال: "}, {"t": "emphasis", "s": "(انكحي أسامة بن زيد)", "role": "emphasis"}, {"t": "text", "s": " فنكحته، فجعل الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " فيه خيرا، واغتبطت به)."}]}, {"type": "paragraph", "md": "ووجه الدلالة قوله صلى الله عليه وسلم : (فإني أكره أن يسقط منك خمارك فيرى القوم منك بعض ما تكرهين)، دليل على أنه لا يجوز للمرأة أن تكشف وجهها فضلًا عن غيره عند البصير من الرجال.", "page": 336, "id": "unit-26__lesson-15__b25", "inline": [{"t": "text", "s": "ووجه الدلالة قوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(فإني أكره أن يسقط منك خمارك فيرى القوم منك بعض ما تكرهين)", "role": "emphasis"}, {"t": "text", "s": "، دليل على أنه لا يجوز للمرأة أن تكشف وجهها فضلًا عن غيره عند البصير من الرجال."}]}, {"type": "paragraph", "md": "15- عن عائشة رضي الله عنها قالت: «خرجت سودة بعدما ضرب الحجاب لحاجتها، وكانت امرأة جسيمة لا تخفى على من يعرفها، فرآها عمر بن الخطاب فقال: يا سودة، أما والله ما تخفين علينا، فانظري كيف تخرجين، قالت: فانكفأت راجعة، ورسول الله صلى الله عليه وسلم في بيتي، وإنه ليتعشى وفي يده عرق، فدخلت فقالت: يا رسول الله، إني خرجت لبعض حاجتي، فقال لي عمر كذا وكذا، قالت: فأوحى الله إليه ثم رفع عنه، وإن العرق في يده ما وضعه، فقال: إنه قد أذن لكن أن تخرجن لحاجتكن).", "page": 336, "id": "unit-26__lesson-15__b26", "inline": [{"t": "text", "s": "15- عن عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " قالت: «خرجت سودة بعدما ضرب الحجاب لحاجتها، وكانت امرأة جسيمة لا تخفى على من يعرفها، فرآها عمر بن الخطاب فقال: يا سودة، أما والله ما تخفين علينا، فانظري كيف تخرجين، قالت: فانكفأت راجعة، ورسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " في بيتي، وإنه ليتعشى وفي يده عرق، فدخلت فقالت: يا رسول الله، إني خرجت لبعض حاجتي، فقال لي عمر كذا وكذا، قالت: فأوحى الله إليه ثم رفع عنه، وإن العرق في يده ما وضعه، فقال: "}, {"t": "emphasis", "s": "إنه قد أذن لكن أن تخرجن لحاجتكن", "role": "emphasis"}, {"t": "text", "s": ")."}], "list": {"type": "ordered", "marker": "15"}}, {"type": "paragraph", "md": "ووجه الدلالة أن عمر عرف سودة لطول قدمها وهيئتها وليس من وجهها؛ فلو عرفها من وجهها، فما حاجة قول عائشة رضي الله عنها أن عمر فرفها من هيئتها؛ مما يدل على أنهن كن يختمرن.", "page": 336, "id": "unit-26__lesson-15__b27", "inline": [{"t": "text", "s": "ووجه الدلالة أن عمر عرف سودة لطول قدمها وهيئتها وليس من وجهها؛ فلو عرفها من وجهها، فما حاجة قول عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " أن عمر فرفها من هيئتها؛ مما يدل على أنهن كن يختمرن."}]}, {"type": "paragraph", "md": "التقويم والأسئلة: 1- اذكري ثلاثة أدلة على وجوب تغطية الوجه والكفين من السنة.", "page": 336, "id": "unit-26__lesson-15__b28"}, {"type": "paragraph", "md": "2- هل حديث (المرأة عورة) يُؤخذ منه وجوب تغطية المراة لوجهها وكفيها.. بيني ذلك.", "page": 336, "id": "unit-26__lesson-15__b29", "inline": [{"t": "text", "s": "2- هل حديث "}, {"t": "emphasis", "s": "(المرأة عورة)", "role": "emphasis"}, {"t": "text", "s": " يُؤخذ منه وجوب تغطية المراة لوجهها وكفيها.. بيني ذلك."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط دعوي واجتماعي", "page": 336, "id": "unit-26__lesson-15__b30", "role": "activity"}, {"type": "paragraph", "md": "1- نشرحُ هذا الدرس لخمسة من معارفنا حتى ولو كن يلبسن الخمار.. نشرًا للعلم بالشريعة.", "page": 336, "id": "unit-26__lesson-15__b31", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- نحاول البحث عن أدلة أخرى في السنة يُستفاد منها وجوب تغطية الوجه ونذكرها.", "page": 336, "id": "unit-26__lesson-15__b32", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- نرجع إلى كتاب « الحجاب... في الشرع والفطرة» للشيخ عبد العزيز الطريفي، ونلخصه.", "page": 336, "id": "unit-26__lesson-15__b33", "inline": [{"t": "text", "s": "3- نرجع إلى كتاب "}, {"t": "quote", "s": "الحجاب... في الشرع ' WHERE id='unit-26__lesson-15';
UPDATE manhaj_lessons SET blocks = blocks || 'والفطرة"}, {"t": "text", "s": " للشيخ عبد العزيز الطريفي، ونلخصه."}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "منارات الهدى", "page": 337, "id": "unit-26__lesson-15__b34", "item_role": "activity_step"}]' WHERE id='unit-26__lesson-15';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-16','unit-26',16,'شروط الحجاب الشرعي
وصفات حجاب التبرج','الأسرة والمرأة',NULL,1,4,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 337, "id": "unit-26__lesson-16__b01", "role": "objectives"}, {"type": "paragraph", "md": "- ذكر شروط الحجاب الشرعي، وبيان صفات حجاب التبرج والسفور.", "page": 337, "id": "unit-26__lesson-16__b02", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "أولا: شروط الحجاب الشرعي للمرأة المسلمة:", "page": 337, "id": "unit-26__lesson-16__b03", "role": "section"}, {"type": "paragraph", "md": "لا بد أن نعلم أن الأصل في المرأة أن تقر في بيتها إلا للحاجة، وإلا فلا تخرج، وقد دلت الأدلة الشرعية على أن جلوس المرأة في بيتها أفضل لها، قال الله تعالى مخاطبًا نساء النبي صلى الله عليه وسم: ﴿وَقَرْنَ فِي بُيُوتِكُنَّ وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْأُولَى﴾ وهذا أمر من الله عز وجل لأشرف نساء الدنيا؛ فكيف بمن دونهن؟!، وقد قال صلى الله عليه وسلم : (والمرأة في بيت زوجها راعية، وهي مسئولة عن رعيتها)، فأصل عمل المرأة القيام على بيتها ورعاية أولادها وزوجها؛ هذه هي المهمة التي أوكلها لها الإسلام: التربية والتعليم لأولادها ورعايتهم، وتخريج أجيال تحب الله ورسوله.. هذا محور عملها وما أعظمه.", "page": 337, "id": "unit-26__lesson-16__b04", "inline": [{"t": "text", "s": "لا بد أن نعلم أن الأصل في المرأة أن تقر في بيتها إلا للحاجة، وإلا فلا تخرج، وقد دلت الأدلة الشرعية على أن جلوس المرأة في بيتها أفضل لها، قال الله تعالى مخاطبًا نساء النبي صلى الله عليه وسم: "}, {"t": "ayah", "s": "وَقَرْنَ فِي بُيُوتِكُنَّ وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْأُولَى", "ayah": [], "verses": [{"n": 33, "text": "وَقَرْنَ فِي بُيُوتِكُنَّ وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْأُولَى", "surah": 33, "surah_name": "الأحزاب", "ref": "33:33", "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:33"}], "surah": 33, "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:33", "surah_name": "الأحزاب", "ayah_canonical": 33, "match": "contained", "ref": "33:33"}, {"t": "text", "s": " وهذا أمر من الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " لأشرف نساء الدنيا؛ فكيف بمن دونهن؟!، وقد قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(والمرأة في بيت زوجها راعية، وهي مسئولة عن رعيتها)", "role": "emphasis"}, {"t": "text", "s": "، فأصل عمل المرأة القيام على بيتها ورعاية أولادها وزوجها؛ هذه هي المهمة التي أوكلها لها الإسلام: التربية والتعليم لأولادها ورعايتهم، وتخريج أجيال تحب الله ورسوله.. هذا محور عملها وما أعظمه."}]}, {"type": "paragraph", "md": "ومع هذا؛ فقد جوز الإسلام لها أن تخرج للحاجة، ولكن بضوابط شرعية؛ على رأسها بعد استئذان زوجها: أن تلبس الحجاب الشرعي صيانة لها، وصيانة للمجتمع من الافتتان بها، وحرم عليها التبرج، وإظهار الزينة والتجمل للفت نظر الناس، وحرَّم عليها الخضوع بالقول؛ فقد يكون صوتها رقيقًا جميلًا يحرك النفوس المريضة فيجرها إلى المعصية، فأمرت أن تتحرى الصوت الجاد العاري عن أسباب الفتنة، وقد بيَّن القرآن العظيم أن أول من أُمِرَ بذلك هن أمهات المؤمنين، ومن دونهن فهو أولى.", "page": 337, "id": "unit-26__lesson-16__b05"}, {"type": "paragraph", "md": "ويُفهم من هذه الضوابط الشرعية للمرأة؛ أنها إجراءات وقائية واحترازية فرضها الشارع الحكيم للحفاظ على المرأة من الشر، وأن لا تقع المرأة والمجتمع في الفساد؛ فـ(أول فتنة بني إسرائيل كانت في النساء).", "page": 337, "id": "unit-26__lesson-16__b06", "inline": [{"t": "text", "s": "ويُفهم من هذه الضوابط الشرعية للمرأة؛ أنها إجراءات وقائية واحترازية فرضها الشارع الحكيم للحفاظ على المرأة من الشر، وأن لا تقع المرأة والمجتمع في الفساد؛ فـ"}, {"t": "emphasis", "s": "(أول فتنة بني إسرائيل كانت في النساء)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ويجب على المرأة ألا تخرج من بيتها حتى تُحَقِقَ شروط الحجاب الشرعي، وهي ثمانية شروط:", "page": 337, "id": "unit-26__lesson-16__b07", "inline": [{"t": "emphasis", "s": "ويجب على المرأة ألا تخرج من بيتها حتى تُحَقِقَ شروط الحجاب الشرعي، وهي ثمانية شروط:", "role": "emphasis"}]}, {"type": "paragraph", "md": "1- استيعاب جميع البدن: وذلك بأن تغطي المرأة وجهها ورأسها وجميع بدنها من الأعلى للأسفل.", "page": 337, "id": "unit-26__lesson-16__b08", "inline": [{"t": "emphasis", "s": "1- استيعاب جميع البدن:", "role": "emphasis"}, {"t": "text", "s": " وذلك بأن تغطي المرأة وجهها ورأسها وجميع بدنها من الأعلى للأسفل."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ألا يكون زينة في نفسه: وذلك أن لا تكون الثياب الظاهرة مزينة تلفت النظر، قال تعالى: ﴿وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا﴾، وقال تعالى: ﴿وَقَرْنَ فِي بُيُوتِكُنَّ وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْأُولَى﴾؛ فالمقصود من الأمر بالجلباب إنما هو ستر زينة المرأة فلا يعقل حينئذ أن يكون الجلباب زينة وهذا أمرٌ بين لا يخفى، ولذلك قال الذهبي في كتاب الكبائر: «ومن الأفعال التي تلعن عليها المرأة بإظهار الزينة والذهب واللؤلؤ تحت النقاب... ولباسها الصماغات والأزر الحريرية والأقبية القصار... وكل ذلك من التبرج الذي يمقت الله عليه فاعله في الدنيا والآخرة».", "page": 338, "id": "unit-26__lesson-16__b09", "inline": [{"t": "emphasis", "s": "2- ألا يكون زينة في نفسه:", "role": "emphasis"}, {"t": "text", "s": " وذلك أن لا تكون الثياب الظاهرة مزينة تلفت النظر، قال تعالى: "}, {"t": "ayah", "s": "وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا", "ayah": [], "verses": [{"n": 31, "text": "وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا", "surah": 24, "surah_name": "النور", "ref": "24:31", "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31"}], "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:31", "surah_name": "النور", "ayah_canonical": 31, "match": "contained", "ref": "24:31"}, {"t": "text", "s": "، وقال تعالى: "}, {"t": "ayah", "s": "وَقَرْنَ فِي بُيُوتِكُنَّ وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْأُولَى", "ayah": [], "verses": [{"n": 33, "text": "وَقَرْنَ فِي بُيُوتِكُنَّ وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْأُولَى", "surah": 33, "surah_name": "الأحزاب", "ref": "33:33", "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:33"}], "surah": 33, "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:33", "surah_name": "الأحزاب", "ayah_canonical": 33, "match": "contained", "ref": "33:33"}, {"t": "text", "s": "؛ فالمقصود من الأمر بالجلباب إنما هو ستر زينة المرأة فلا يعقل حينئذ أن يكون الجلباب زينة وهذا أمرٌ بين لا يخفى، ولذلك قال الذهبي في كتاب الكبائر: "}, {"t": "quote", "s": "ومن الأفعال التي تلعن عليها المرأة بإظهار الزينة والذهب واللؤلؤ تحت النقاب... ولباسها الصماغات والأزر الحريرية والأقبية القصار... وكل ذلك من التبرج الذي يمقت الله عليه فاعله في الدنيا والآخرة", "speaker": "الذهبي في كتاب الكبائر"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- أن يكون صفيقًا لا يشفُّ: والصفيق: كثيف النسج؛ فلا يكون لباسها رقيقًا يلتصق على الجسم من رقته، وألا يشف فيُرى ما تحته، وقد علق ابن عبد البر رحمه الله عند حديث النبي صلى الله عليه وسلم : (سيكون في آخر أمتي نساء كاسيات عاريات على رؤوسهن كأسنمة البخت العنوهن فإنهن ملعونات)، فقال: «هن النساء اللواتي يلبسن من الثياب: الخفيف الذي يصف ولا يستر فهن كاسيات بالاسم عاريات في الحقيقة».", "page": 338, "id": "unit-26__lesson-16__b10", "inline": [{"t": "emphasis", "s": "3- أن يكون صفيقًا لا يشفُّ:", "role": "emphasis"}, {"t": "text", "s": " والصفيق: كثيف النسج؛ فلا يكون لباسها رقيقًا يلتصق على الجسم من رقته، وألا يشف فيُرى ما تحته، وقد علق ابن عبد البر "}, {"t": "honorific", "s": "رحمه الله"}, {"t": "text", "s": " عند حديث النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(سيكون في آخر أمتي نساء كاسيات عاريات على رؤوسهن كأسنمة البخت العنوهن فإنهن ملعونات)", "role": "emphasis"}, {"t": "text", "s": "، فقال: "}, {"t": "hadith", "s": "هن النساء اللواتي يلبسن من الثياب: الخفيف الذي يصف ولا يستر فهن كاسيات بالاسم عاريات في الحقيقة", "narrator": null, "source": null, "confidence": "high", "ref_api": null}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- أن يكون فضفاضًا غير ضيق فيصف جسمها: وذلك يعني أن يكون واسعًا وليس ضيقًا ملتصقًا بها فيصف جسمها بضيقه، ويصبح فتنة أكثر، فهذا اللباس الضيق فيه فساد؛ فيجب أن يكون واسعًا.", "page": 338, "id": "unit-26__lesson-16__b11", "inline": [{"t": "emphasis", "s": "4- أن يكون فضفاضًا غير ضيق فيصف جسمها:", "role": "emphasis"}, {"t": "text", "s": " وذلك يعني أن يكون واسعًا وليس ضيقًا ملتصقًا بها فيصف جسمها بضيقه، ويصبح فتنة أكثر، فهذا اللباس الضيق فيه فساد؛ فيجب أن يكون واسعًا."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "عن أسامة بن زيد قال: كساني رسول الله صلى الله عليه وسلم قُبطية كثيفة مما أهداها له دحية الكلبي فكسوتها امرأتي فقال: (مرها فلتجعل تحتها غلالة فإني أخاف أن تصف حجم عظامها) أي أن تجعل تحت القبطية الثخينة غلالة وهي شعار يلبس تحت الثوب يمنع بها وصف بدنها، والأمر يفيد الوجوب.", "page": 338, "id": "unit-26__lesson-16__b12", "inline": [{"t": "text", "s": "عن أسامة بن زيد قال: كساني رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قُبطية كثيفة مما أهداها له دحية الكلبي فكسوتها امرأتي فقال: "}, {"t": "emphasis", "s": "(مرها فلتجعل تحتها غلالة فإني أخاف أن تصف حجم عظامها)", "role": "emphasis"}, {"t": "text", "s": " أي أن تجعل تحت القبطية الثخينة غلالة وهي شعار يلبس تحت الثوب يمنع بها وصف بدنها، والأمر يفيد الوجوب."}]}, {"type": "paragraph", "md": "5- ألا يكون مبخرًا ولا مطيبًا: وذلك يعني أن لا تضع العطر على ثيابها وتُطيبْها عند الخروج من البيت، قال صلى الله عليه وسلم : (أيما امرأة استعطرت فمرت على قوم ليجدوا من ريحها فهي زانية) وقال صلى الله عليه وسلم : (إذا خرجت إحداكن إلى المسجد فلا تقربن طيبًا)، وسبب المنع أن الطيب يُحرك الشهوة عند الرجال؛ فإذا كان ذلك محرمًا على مريدة المسجد فماذا يكون حكم مريدة السوق والشوارع؟ لا شك أنه أشد حرمة وأكبر إثمًا، قال ابن حجر الهيتمي: (خروج المرأة من بيتها متعطرة متزينة من الكبائر ولو أذن لها زوجها).", "page": 338, "id": "unit-26__lesson-16__b13", "inline": [{"t": "text", "s": "5- ألا يكون مبخرًا ولا مطيبًا: وذلك يعني أن لا تضع العطر على ثيابها وتُطيبْها عند الخروج من البيت، قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(أيما امرأة استعطرت فمرت على قوم ليجدوا من ريحها فهي زانية)", "role": "emphasis"}, {"t": "text", "s": " وقال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إذا خرجت إحداكن إلى المسجد فلا تقربن طيبًا)", "role": "emphasis"}, {"t": "text", "s": "، وسبب المنع أن الطيب يُحرك الشهوة عند الرجال؛ فإذا كان ذلك محرمًا على مريدة المسجد فماذا يكون حكم مريدة السوق والشوارع؟ لا شك أنه أشد حرمة وأكبر إثمًا، قال ابن حجر الهيتمي: "}, {"t": "emphasis", "s": "(خروج المرأة من بيتها متعطرة متزينة من الكبائر ولو أذن لها زوجها)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6- ألا يشبه لباس الرجل: فقد توعد الشرع المرأة التي تتشبه بالرجال باللعن والطرد من رحمة الله؛ فقد قال صلى الله عليه وسلم : (ليس منا من تشبه بالرجال من النساء ولا من تشبه بالنساء من الرجال).", "page": 338, "id": "unit-26__lesson-16__b14", "inline": [{"t": "text", "s": "6- ألا يشبه لباس الرجل: فقد توعد الشرع المرأة التي تتشبه بالرجال باللعن والطرد من رحمة الله؛ فقد قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(ليس منا من تشبه بالرجال من النساء ولا من تشبه بالنساء من الرجال)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "6"}}, {"type": "paragraph", "md": "وعن أبي هريرة رضي الله عنه قال: (لعن رسول الله صلى الله عليه وسلم الرجل يلبس لِبْسَةَ المرأة، والمرأة لبسة الرجل)، وفي الأحاديث دلالة واضحة على تحريم تشبه النساء بالرجال وعلى العكس.", "page": 338, "id": "unit-26__lesson-16__b15", "inline": [{"t": "text", "s": "وعن أبي هريرة "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قال: "}, {"t": "emphasis", "s": "(لعن رسول الله", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "الرجل يلبس لِبْسَةَ المرأة، والمرأة لبسة الرجل)", "role": "emphasis"}, {"t": "text", "s": "، وفي الأحاديث دلالة واضحة على تحريم تشبه النساء بالرجال وعلى العكس."}]}, {"type": "paragraph", "md": "7- ألا يشبه لباس الكافرات: وذلك لأن الشرع الحنيف أمرنا أن لا نتشبه بالكفار، وهذا من مقاصد الدين العليا وأخلاقه السامية؛ لأن ذلك يمس عقيدة المسلم وسلوكه والإسلام حدد لنا أشياء في ديننا ودنيانا نستغني بها عن غير ما شرعه الإسلام، قال الله تعالى: ﴿ثُمَّ جَعَلْنَاكَ عَلَى شَرِيعَةٍ مِنَ الْأَمْرِ فَاتَّبِعْهَا وَلَا تَتَّبِعْ أَهْوَاءَ الَّذِينَ لَا يَعْلَمُونَ 18﴾، ووجه الدلالة في الآية أن نتبع ما شرع الله وننتهي عن اتباع أهواء الذين لا يعلمون وهم كل من خالف الشريعة، لذلك كان ترك التشبه بالكفار في أعمالهم وأقوالهم وأهوائهم من المقاصد والغايات التي جاء بها القرآن والتي بينها لنا النبي صلى الله عليه وسلم بأقواله وأفعاله وهذا في جميع الأبواب ومنها اللباس والآداب والعادات والعبادات والمعاملات، وقد قال صلى الله عليه وسلم : (... ومن تشبه بقوم فهو منهم).", "page": 339, "id": "unit-26__lesson-16__b16", "inline": [{"t": "text", "s": "7- ألا يشبه لباس الكافرات: وذلك لأن الشرع الحنيف أمرنا أن لا نتشبه بالكفار، وهذا من مقاصد الدين العليا وأخلاقه السامية؛ لأن ذلك يمس عقيدة المسلم وسلوكه والإسلام حدد لنا أشياء في ديننا ودنيانا نستغني بها عن غير ما شرعه الإسلام، قال الله تعالى: "}, {"t": "ayah", "s": "ثُمَّ جَعَلْنَاكَ عَلَى شَرِيعَةٍ مِنَ الْأَمْرِ فَاتَّبِعْهَا وَلَا تَتَّبِعْ أَهْوَاءَ الَّذِينَ لَا يَعْلَمُونَ 18", "ayah": [], "verses": [{"n": 18, "text": "ثُمَّ جَعَلْنَاكَ عَلَى شَرِيعَةٍ مِنَ الْأَمْرِ فَاتَّبِعْهَا وَلَا تَتَّبِعْ أَهْوَاءَ الَّذِينَ لَا يَعْلَمُونَ 18", "surah": 45, "surah_name": "الجاثية", "ref": "45:18", "ref_api": "https://api.quran.com/api/v4/verses/by_key/45:18"}], "surah": 45, "ref_api": "https://api.quran.com/api/v4/verses/by_key/45:18", "surah_name": "الجاثية", "ayah_canonical": 18, "match": "exact", "ref": "45:18"}, {"t": "text", "s": "، ووجه الدلالة في الآية أن نتبع ما شرع الله وننتهي عن اتباع أهواء الذين لا يعلمون وهم كل من خالف الشريعة، لذلك كان ترك التشبه بالكفار في أعمالهم وأقوالهم وأهوائهم من المقاصد والغايات التي جاء بها القرآن والتي بينها لنا النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بأقواله وأفعاله وهذا في جميع الأبواب ومنها اللباس والآداب والعادات والعبادات والمعاملات، وقد قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(... ومن تشبه بقوم فهو منهم)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "7"}}, {"type": "paragraph", "md": "8- ألا يكون لباس شهرة: وذلك يكون باتخاذ لباس يقصد بين الناس سواء كان ثوبًا غاليًا أو رخيصًا وهو يقصد به لفت نظر الناس إليه، قال صلى الله عليه وسلم : (من لبس ثوب شهرة في الدنيا ألبسه الله ثوب مذلة يوم القيامة ثم ألهب فيه نارًا)، لأنه لبس هذا اللباس ليعز في الدنيا فيذله الله في الآخرة، والعقوبة من جنس العمل، لذلك يقصد بلبس الحجاب التعبد لله والطاعة والستر والعفاف وليس التميز على الناس فإنما الأعمال بالنيات.", "page": 339, "id": "unit-26__lesson-16__b17", "inline": [{"t": "emphasis", "s": "8- ألا يكون لباس شهرة:", "role": "emphasis"}, {"t": "text", "s": " وذلك يكون باتخاذ لباس يقصد بين الناس سواء كان ثوبًا غاليًا أو رخيصًا وهو يقصد به لفت نظر الناس إليه، قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(من لبس ثوب شهرة في الدنيا ألبسه الله ثوب مذلة يوم القيامة ثم ألهب فيه نارًا)", "role": "emphasis"}, {"t": "text", "s": "، لأنه لبس هذا اللباس ليعز في الدنيا فيذله الله في الآخرة، والعقوبة من جنس العمل، لذلك يقصد بلبس الحجاب التعبد لله والطاعة والستر والعفاف وليس التميز على الناس فإنما الأعمال بالنيات."}], "list": {"type": "ordered", "marker": "8"}}, {"type": "heading", "level": 3, "text": "ثانيًا: صفات حجاب التبرج المذموم -وبضدها تتمايز الأشياء-:", "page": 339, "id": "unit-26__lesson-16__b18", "role": "section"}, {"type": "paragraph", "md": "1- أنه يكشف عورات مجمع على تحريم كشفها: كالحجاب الذي يستر الجسم ويظهر الوجه بأبهى صورة من المكياج والحمرة والكحل، أو لبس لباس لكن مع ظهور الساقين أو اليدين أو شيء من الرقبة، أو الخمار الملون بالأحمر والأصفر أو وضع أشرطة ذهبية على الخمار أو أو مزركشة فهذا ليس شرعيا.", "page": 339, "id": "unit-26__lesson-16__b19", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- زينة في نفسه من حيث ألوانه الفاقعة وما فيه من الزخارف؛ فالحجاب لستر الزينة لا ليكون هو زينة.", "page": 339, "id": "unit-26__lesson-16__b20", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- شفاف: يظهر ما يجب ستره من العورات فلا يحجب رؤية العورة؛ كأن يظهر لون شعرها من تحته.", "page": 339, "id": "unit-26__lesson-16__b21", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- أن يكون ضيقًا يصف العورات فيكون ملتصقًا بجسد المراة؛ فهذا كله من الحرام كذلك.", "page": 339, "id": "unit-26__lesson-16__b22", "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- أن يكون معطرًا، فتحرك الشهوة في قلوب الرجال؛ رغم أنها مختمرة، فهنا خالفت المشروع.", "page": 339, "id": "unit-26__lesson-16__b23", "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6- أن يشبه لباس الرجال كـ«البنطال» و«المناطو» وفوقه حجاب يستر الرأس فقط؛ فهذا تبرج المحجبة.", "page": 339, "id": "unit-26__lesson-16__b24", "inline": [{"t": "text", "s": "6- أن يشبه لباس الرجال كـ"}, {"t": "quote", "s": "البنطال"}, {"t": "text", "s": " و"}, {"t": "quote", "s": "المناطو"}, {"t": "text", "s": " وفوقه حجاب يستر الرأس فقط؛ فهذا تبرج المحجبة."}], "list": {"type": "ordered", "marker": "6"}}, {"type": "paragraph", "md": "7- أن يكون لباس شهرة وتفاخر؛ فهذا كله وإن سمي حجابًا فهو ليس بحجاب لأنه خالف الشرع.", "page": 339, "id": "unit-26__lesson-16__b25", "list": {"type": "ordered", "marker": "7"}}, {"type": "paragraph", "md": "التقويم والأسئلة: 1- اذكري صفات الحجاب الشرعي وصفات حجاب التبرج.", "page": 339, "id": "unit-26__lesson-16__b26"}, {"type": "paragraph", "md": "2- هل الأصل في المرأة أن تخرج من البيت في كل حين؟ ام تقر في البيت ولا تخرج إلا للحاجة؟", "page": 339, "id": "unit-26__lesson-16__b27", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط دعوي واجتماعي", "page": 339, "id": "unit-26__lesson-16__b28", "role": "activity"}, {"type": "paragraph", "md": "1- هل جاء في الشريعة اشتراط لون معين للباس الشرعي.. بيني ذلك بالدليل.", "page": 339, "id": "unit-26__lesson-16__b29", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- نتأمل في واقع النساء من حولنا، ونطبق هذه الشروط على اللباس المنتشر، ونسعى للتغيير..", "page": 339, "id": "unit-26__lesson-16__b30", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "منارات الهدى", "page": 340, "id": "unit-26__lesson-16__b31", "item_role": "activity_step"}]' WHERE id='unit-26__lesson-16';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-17','unit-26',17,'واجبات المرأة المسلمة الخاصة','الأسرة والمرأة',NULL,1,5,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 340, "id": "unit-26__lesson-17__b01", "role": "objectives"}, {"type": "paragraph", "md": "- ذكر ما اختصت به المرأة المسلمة من الواجبات الشرعية عليها، على كافة الصعد والمستويات.", "page": 340, "id": "unit-26__lesson-17__b02", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "أولا: مسؤوليتها نحو ربها سبحانه وتعالى :", "page": 340, "id": "unit-26__lesson-17__b03", "role": "section"}, {"type": "paragraph", "md": "تؤمن المسلمة بأن الله هو الرب الخالق المدبر المعبود الذي يرجع الأمر كله إليه، وتؤمن بآثار ذلك؛ كما آمنت هاجر عليها السلام عندما وضعها زوجها إبراهيم عليه السلام وابنها بمكة، فسألت: آللهُ أمرك بهذا؟ قال: نعم، قال: إذًا لا يضيعنا. فتوجهت إليه واتكلت عليه سبحانه وتعالى ، وتراقبه في السر والعلانية، وتكون رقابتها لربها تعالى لا لزوجها وأولادها؛ فإيمانها بربها يغرس فيها الرقابة الإيمانية الذاتية.", "page": 340, "id": "unit-26__lesson-17__b04", "inline": [{"t": "text", "s": "تؤمن المسلمة بأن الله هو الرب الخالق المدبر المعبود الذي يرجع الأمر كله إليه، وتؤمن بآثار ذلك؛ كما آمنت هاجر "}, {"t": "honorific", "s": "عليها السلام"}, {"t": "text", "s": " عندما وضعها زوجها إبراهيم "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " وابنها بمكة، فسألت: آللهُ أمرك بهذا؟ قال: نعم، قال: إذًا لا يضيعنا. فتوجهت إليه واتكلت عليه "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، وتراقبه في السر والعلانية، وتكون رقابتها لربها تعالى لا لزوجها وأولادها؛ فإيمانها بربها يغرس فيها الرقابة الإيمانية الذاتية."}]}, {"type": "paragraph", "md": "وفي عبادتها: تتحرى الطهارة في بدنها وثيابها ومكان صلاتها، وتدع الصلاة والصيام أيام حيضها، وتعرف وقت إقبال دورتها الشهرية وإدبارها، وتعرف أحكام الجنابة والغسل من الحيض والنفاس، وتقيم الصلاة في وقتها؛ مع حرصها على أدائها كاملة مستوفاة الأركان والسنن، ولا تقصر في صلاة وصدقة التطوع، كل ذلك مع حفظ حق زوجها وأولادها وبيتها، وتحرص على أداء زكاة مالها راضية بذلك مسلمة لأمر الله.", "page": 340, "id": "unit-26__lesson-17__b05", "inline": [{"t": "emphasis", "s": "وفي عبادتها", "role": "emphasis"}, {"t": "text", "s": ": تتحرى الطهارة في بدنها وثيابها ومكان صلاتها، وتدع الصلاة والصيام أيام حيضها، وتعرف وقت إقبال دورتها الشهرية وإدبارها، وتعرف أحكام الجنابة والغسل من الحيض والنفاس، وتقيم الصلاة في وقتها؛ مع حرصها على أدائها كاملة مستوفاة الأركان والسنن، ولا تقصر في صلاة وصدقة التطوع، كل ذلك مع حفظ حق زوجها وأولادها وبيتها، وتحرص على أداء زكاة مالها راضية بذلك مسلمة لأمر الله."}]}, {"type": "paragraph", "md": "وإن قدم شهر رمضان فرحت به واستبشرت بقدومه؛ فتصوم نهاره وتقوم ليله، وتتحرى ليلة القدر في بيتها أو في المسجد، وتحرص على صيام ما تقدر عليه من النوافل كالاثنين والخميس وعرفات وعاشوراء، ولا تصوم نفلا وزوجها حاضرٌ إلا بإذنه. وكذلك تحج وتعتمر فهذا جهادها، وإن جاء الجهاد وقامت المعارك حثت زوجها ةإخوتها وأولادها على الجهاد وشاركت بما تقدر عليه في تجهيز الطعام وتطبيب الجرحى وسقيا الماء وتربية أولاد المجاهدين وحفظ البلاد خلفَهم ومنع الفساد وراءَهم.", "page": 340, "id": "unit-26__lesson-17__b06"}, {"type": "paragraph", "md": "و(النساء شقائق الرجال) فلهن من التكاليف ما على لرجال، ويستحققن الأجر الكامل: ﴿فَٱسۡتَجَابَ لَهُمۡ رَبُّهُمۡ أَنِّي لَآ أُضِيعُ عَمَلَ عَٰمِلٖ مِّنكُم مِّن ذَكَرٍ أَوۡ أُنثَىٰۖ بَعۡضُكُم مِّنۢ بَعۡضٖۖ﴾، وقال تعالى: ﴿مَنۡ عَمِلَ صَٰلِحٗا مِّن ذَكَرٍ أَوۡ أُنثَىٰ وَهُوَ مُؤۡمِنٞ فَلَنُحۡيِيَنَّهُۥ حَيَوٰةٗ طَيِّبَةٗۖ وَلَنَجۡزِيَنَّهُمۡ أَجۡرَهُم بِأَحۡسَنِ مَا كَانُواْ يَعۡمَلُونَ﴾.", "page": 340, "id": "unit-26__lesson-17__b07", "inline": [{"t": "text", "s": "و"}, {"t": "emphasis", "s": "(النساء شقائق الرجال)", "role": "emphasis"}, {"t": "text", "s": " فلهن من التكاليف ما على لرجال، ويستحققن الأجر الكامل: "}, {"t": "ayah", "s": "فَٱسۡتَجَابَ لَهُمۡ رَبُّهُمۡ أَنِّي لَآ أُضِيعُ عَمَلَ عَٰمِلٖ مِّنكُم مِّن ذَكَرٍ أَوۡ أُنثَىٰۖ بَعۡضُكُم مِّنۢ بَعۡضٖۖ", "ayah": [], "verses": [{"n": 195, "text": "فَٱسۡتَجَابَ لَهُمۡ رَبُّهُمۡ أَنِّي لَآ أُضِيعُ عَمَلَ عَٰمِلٖ مِّنكُم مِّن ذَكَرٍ أَوۡ أُنثَىٰۖ بَعۡضُكُم مِّنۢ بَعۡضٖۖ", "surah": 3, "surah_name": "آل عمران", "ref": "3:195", "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:195"}], "surah": 3, "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:195", "surah_name": "آل عمران", "ayah_canonical": 195, "match": "contained", "ref": "3:195"}, {"t": "text", "s": "، وقال تعالى: "}, {"t": "ayah", "s": "مَنۡ عَمِلَ صَٰلِحٗا مِّن ذَكَرٍ أَوۡ أُنثَىٰ وَهُوَ مُؤۡمِنٞ فَلَنُحۡيِيَنَّهُۥ حَيَوٰةٗ طَيِّبَةٗۖ وَلَنَجۡزِيَنَّهُمۡ أَجۡرَهُم بِأَحۡسَنِ مَا كَانُواْ يَعۡمَلُونَ", "ayah": [], "verses": [{"n": 97, "text": "مَنۡ عَمِلَ صَٰلِحٗا مِّن ذَكَرٍ أَوۡ أُنثَىٰ وَهُوَ مُؤۡمِنٞ فَلَنُحۡيِيَنَّهُۥ حَيَوٰةٗ طَيِّبَةٗۖ وَلَنَجۡزِيَنَّهُمۡ أَجۡرَهُم بِأَحۡسَنِ مَا كَانُواْ يَعۡمَلُونَ", "surah": 16, "surah_name": "النحل", "ref": "16:97", "ref_api": "https://api.quran.com/api/v4/verses/by_key/16:97"}], "surah": 16, "ref_api": "https://api.quran.com/api/v4/verses/by_key/16:97", "surah_name": "النحل", "ayah_canonical": 97, "match": "exact", "ref": "16:97"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "ثانيًا: مسؤوليتها نحو نبيها صلى الله عليه وسلم ودينه والدعوةِ إليه:", "page": 340, "id": "unit-26__lesson-17__b08", "role": "section"}, {"type": "paragraph", "md": "المرأة المسلمة مكلفة مسؤولة عن دينها دين الإسلام؛ فعليها أن تتعلم وتفقه في دين الله، وتدعو إليه، وتصبر على الأذى الذي يردُ عليها بهذا البلاغ والصبر على الدين، وقدوتها في ذلك أمهات المؤمنين رضي الله عنهن ؛ فهذه خديجة كانت أول من آزر النبي صلى الله عليه وسلم في دعوته فقالت له: «أبشر، والله ما يُخزيك الله أبدًا إنك لتصل الرحم وتحمل الكل وتكسب المعدوم..» وأخذته إلى ابن عمها ورقة؛ فكان جزاء ذلك أن الله سبحانه وتعالى أرسل جبريل عليه السلام ليُقرئ خديجة السلام وبشرها ببيت في الجنة من قصب لا صخب فيه ولا نصب. وهذه سُمَية أم عمار كانت أول شهيدة في الإسلام، وبعدها الخنساء الشاعرة دفعت أربعة من أبنائها شهداء في موقعة القادسية وصبرت على فراقهم. وتلك أمنا عائشة رضي الله عنها ضربت أروع الأمثلة في العلم والتفقه في الدين؛ فكانت من أفقه الصحابة رجالا ونساء، وروت مئات الأحاديث عن النبي صلى الله عليه وسلم وناظرت كبار الصحابة.", "page": 341, "id": "unit-26__lesson-17__b09", "inline": [{"t": "text", "s": "المرأة المسلمة مكلفة مسؤولة عن دينها دين الإسلام؛ فعليها أن تتعلم وتفقه في دين الله، وتدعو إليه، وتصبر على الأذى الذي يردُ عليها بهذا البلاغ والصبر على الدين، وقدوتها في ذلك أمهات المؤمنين "}, {"t": "honorific", "s": "رضي الله عنهن"}, {"t": "text", "s": " ؛ فهذه خديجة كانت أول من آزر النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " في دعوته فقالت له: "}, {"t": "hadith", "s": "أبشر، والله ما يُخزيك الله أبدًا إنك لتصل الرحم وتحمل الكل وتكسب المعدوم..", "narrator": "دينها دين الإسلام؛ فعليها", "source": "مسلم", "confidence": "high", "ref_api": null}, {"t": "text", "s": " وأخذته إلى ابن عمها ورقة؛ فكان جزاء ذلك أن الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " أرسل جبريل "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " ليُقرئ خديجة السلام وبشرها ببيت في الجنة من قصب لا صخب فيه ولا نصب. وهذه سُمَية أم عمار كانت أول شهيدة في الإسلام، وبعدها الخنساء الشاعرة دفعت أربعة من أبنائها شهداء في موقعة القادسية وصبرت على فراقهم. وتلك أمنا عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " ضربت أروع الأمثلة في العلم والتفقه في الدين؛ فكانت من أفقه الصحابة رجالا ونساء، وروت مئات الأحاديث عن النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وناظرت كبار الصحابة."}]}, {"type": "heading", "level": 3, "text": "ثالثًا: مسؤوليتها نحو نفسها:", "page": 341, "id": "unit-26__lesson-17__b10", "role": "section"}, {"type": "paragraph", "md": "تتكون المرأة المسلمة مما يكون منه الرجل: الجسم، والعقل، والروح.. ولا بد أن تعطي لكل منها حقه:", "page": 341, "id": "unit-26__lesson-17__b11"}, {"type": "paragraph", "md": "1- عنايتها بجسمها: بأن تكون ذات أثر في المنزل؛ أما كانت أو بنتا أو أختًا، فتتميز بين النساء بحضورها في خلقها وحسن مظهرها والتزين لبعلها، وتقتصد في أكلها وشربها ولا تسرف فيه، وتهتم بالرياضة البدنية التي تليق بمثلها؛ لتبقى محافظة على صحتها وأنوثتها، وتحرص على نظافة جسدها بالمداومة على الاستحمام وتعهد ملابسها وشعرها؛ على الأقل تغتسل في كل أسبوع مرة وهذا الغسل أقل النظافة.", "page": 341, "id": "unit-26__lesson-17__b12", "inline": [{"t": "emphasis", "s": "1- عنايتها بجسمها", "role": "emphasis"}, {"t": "text", "s": ": بأن تكون ذات أثر في المنزل؛ أما كانت أو بنتا أو أختًا، فتتميز بين النساء بحضورها في خلقها وحسن مظهرها والتزين لبعلها، وتقتصد في أكلها وشربها ولا تسرف فيه، وتهتم بالرياضة البدنية التي تليق بمثلها؛ لتبقى محافظة على صحتها وأنوثتها، وتحرص على نظافة جسدها بالمداومة على الاستحمام وتعهد ملابسها وشعرها؛ على الأقل تغتسل في كل أسبوع مرة وهذا الغسل أقل النظافة."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "وتحرص على تنظيف أسنانها؛ فقد كانت عائشة رضي الله عنه تستاك حتى يُسمع صوت السواك في أسنانها، وتعتني بنظافة شعرها وردائها؛ مبتعدة عن كشف عورتها ومشابهة الكافرات في زيها ولو داخل بيتها، ولا يجوز لها حلق شعر رأسها بالكلية لما فيه من مشابهة الرجال، ولا تفرط في الزينة حتى إنها تقدمها على واجباتها الأخرى من العناية ببيتها وزوجها ومن باب أولى تضييع صلاتها وفروضها.", "page": 341, "id": "unit-26__lesson-17__b13", "inline": [{"t": "text", "s": "وتحرص على تنظيف أسنانها؛ فقد كانت عائشة "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " تستاك حتى يُسمع صوت السواك في أسنانها، وتعتني بنظافة شعرها وردائها؛ مبتعدة عن كشف عورتها ومشابهة الكافرات في زيها ولو داخل بيتها، ولا يجوز لها حلق شعر رأسها بالكلية لما فيه من مشابهة الرجال، ولا تفرط في الزينة حتى إنها تقدمها على واجباتها الأخرى من العناية ببيتها وزوجها ومن باب أولى تضييع صلاتها وفروضها."}]}, {"type": "paragraph", "md": "2- عنايتها بعقلها: فالجهل داء فتاك، وعلاجه العلم، وأعظم العلوم: التفقه في الدين؛ ففي الصحيح: (طلب العلم فريضة)، وكانت تقول عائشة رضي الله عنها : «نعم النساء نساء الأنصار لم يكن يمنعهن الحياء أن يتفقهن في الدين»، وقد طلبن من النبي صلى الله عليه وسلم أن يجعل لهن يومًا يعظهن فيه ففعل ذلك وعلمهن. وتحرص على إتقان تلاوة القرآن الكريم وحفظ ما أمكن من السنة النبوية وأخبار الصحابيات؛ ولا بأس أن يكون لها اختصاص في علم دنيوي يناسب النساء كالطب والأدب واللغات؛ مع حرصها على دينها أولا.", "page": 341, "id": "unit-26__lesson-17__b14", "inline": [{"t": "emphasis", "s": "2- عنايتها بعقلها", "role": "emphasis"}, {"t": "text", "s": ": فالجهل داء فتاك، وعلاجه العلم، وأعظم العلوم: التفقه في الدين؛ ففي الصحيح: "}, {"t": "emphasis", "s": "(طلب العلم فريضة)", "role": "emphasis"}, {"t": "text", "s": "، وكانت تقول عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " : "}, {"t": "quote", "s": "نعم النساء نساء الأنصار لم يكن يمنعهن الحياء أن يتفقهن في الدين"}, {"t": "text", "s": "، وقد طلبن من النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أن يجعل لهن يومًا يعظهن فيه ففعل ذلك وعلمهن. وتحرص على إتقان تلاوة القرآن الكريم وحفظ ما أمكن من السنة النبوية وأخبار الصحابيات؛ ولا بأس أن يكون لها اختصاص في علم دنيوي يناسب النساء كالطب والأدب واللغات؛ مع حرصها على دينها أولا."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- عنايتها بروحها: قال الله تعالى: ﴿قَدۡ أَفۡلَحَ مَن زَكَّىٰهَا ۝٩ وَقَدۡ خَابَ مَن دَسَّىٰهَا ۝١٠﴾ فترتقي بروحها وتزكي نفسها بفعل الواجبات وترك المنهيات والإكثار من النوافل صلاة وصدقة وصيامًا، وتحرص على اختيار الرفقة الصالحة التي تسمو بها، وتترك الشرك والخرافات والتعلق بغير الله.", "page": 342, "id": "unit-26__lesson-17__b15", "inline": [{"t": "emphasis", "s": "3- عنايتها بروحها", "role": "emphasis"}, {"t": "text", "s": ": قال الله تعالى: "}, {"t": "ayah", "s": "قَدۡ أَفۡلَحَ مَن زَكَّىٰهَا ۝٩ وَقَدۡ خَابَ مَن دَسَّىٰهَا ۝١٠", "ayah": [9, 10], "verses": [{"n": 9, "text": "قَدۡ أَفۡلَحَ مَن زَكَّىٰهَا", "surah": 91, "ref_api": "https://api.quran.com/api/v4/verses/by_key/91:9", "surah_name": "الشمس", "ayah_canonical": 9, "match": "exact", "ref": "91:9"}, {"n": 10, "text": "وَقَدۡ خَابَ مَن دَسَّىٰهَا", "surah": 91, "ref_api": "https://api.quran.com/api/v4/verses/by_key/91:10", "surah_name": "الشمس", "ayah_canonical": 10, "match": "exact", "ref": "91:10"}], "surah": null, "ref_api": null}, {"t": "text", "s": " فترتقي بروحها وتزكي نفسها بفعل الواجبات وترك المنهيات والإكثار من النوافل صلاة وصدقة وصيامًا، وتحرص على اختيار الرفقة الصالحة التي تسمو بها، وتترك الشرك والخرافات والتعلق بغير الله."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "رابعًا: مسؤوليتها نحو أسرتها «والديها وزوجها وأولادها»:", "page": 342, "id": "unit-26__lesson-17__b16", "role": "section"}, {"type": "paragraph", "md": "1- أما الأبوين: فقد قرن الله حقهما بحقه سبحانه وتعالى في عدد من آيات القرآن الكريم، وجعلت الشريعة عقوقهما من الكبائر، والعاق تُعَجَّلُ له العقوبة في الدنيا قبل الآخرة؛ فعلى المسلمة أن تؤدي حق والديها ببرهما وطاعتهما في المعروف وتقديم ما تقدر عليه من المساعدة لهما في حياتهما، وتتصدق عنهما بعد وفاتهما، ومهما فعلت فلن تؤدي لهما شيئًا من حقوقهما؛ قال النبي صلى الله عليه وسلم : (‌لا ‌يجزي ‌ولدٌ والدَه إلا أن يجده ‌مملوكا فيشتريه فيعتقه)، والأم مقدمة في البر على الأب للوصية النبوية بذلك.", "page": 342, "id": "unit-26__lesson-17__b17", "inline": [{"t": "emphasis", "s": "1- أما الأبوين", "role": "emphasis"}, {"t": "text", "s": ": فقد قرن الله حقهما بحقه "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " في عدد من آيات القرآن الكريم، وجعلت الشريعة عقوقهما من الكبائر، والعاق تُعَجَّلُ له العقوبة في الدنيا قبل الآخرة؛ فعلى المسلمة أن تؤدي حق والديها ببرهما وطاعتهما في المعروف وتقديم ما تقدر عليه من المساعدة لهما في حياتهما، وتتصدق عنهما بعد وفاتهما، ومهما فعلت فلن تؤدي لهما شيئًا من حقوقهما؛ قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(‌لا ‌يجزي ‌ولدٌ والدَه إلا أن يجده ‌مملوكا فيشتريه فيعتقه)", "role": "emphasis"}, {"t": "text", "s": "، والأم مقدمة في البر على الأب للوصية النبوية بذلك."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- وأما الزوج: فقد كرمت الشريعة رباط الزوجية وجعلته آية من آيات الله بأن جعل بين الزوجين مودة ورحمة، فالأسرة في المجتمع المسلم هي النواة الأساسية لبنائه، والمرتكز القويم في صلاحه؛ فمتى كانت الأسرة صالحة صلح المجتمع، فالواجب حسن اختيار الزوج؛ قال النبي صلى الله عليه وسلم : (تخيروا لنطفكم، وأنكحوا الأكفاء، وأنكحوا إليهم)، والمرأة لها الحق في قَبول خاطبها أو رفضه؛ فلا تُجبر على نكاح رجل بعينه؛ لذلك عليها أن تختار صاحب الدين والخلق.", "page": 342, "id": "unit-26__lesson-17__b18", "inline": [{"t": "emphasis", "s": "2- وأما الزوج", "role": "emphasis"}, {"t": "text", "s": ": فقد كرمت الشريعة رباط الزوجية وجعلته آية من آيات الله بأن جعل بين الزوجين مودة ورحمة، فالأسرة في المجتمع المسلم هي النواة الأساسية لبنائه، والمرتكز القويم في صلاحه؛ فمتى كانت الأسرة صالحة صلح المجتمع، فالواجب حسن اختيار الزوج؛ قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(تخيروا لنطفكم، وأنكحوا الأكفاء، وأنكحوا إليهم)", "role": "emphasis"}, {"t": "text", "s": "، والمرأة لها الحق في قَبول خاطبها أو رفضه؛ فلا تُجبر على نكاح رجل بعينه؛ لذلك عليها أن تختار صاحب الدين والخلق."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "وعلى المرأة أن تُطيع زوجها في غير معصية الله؛ فقد قال صلى الله عليه وسلم : (لو كنت آمرا أحدا أن يسجد لأحد؛ لأمرت الزوجة أن تسجد لزوجها) لعظيم حقه عليها، ولكن السجود لا يجوز إلا لله؛ فلا يُطاع الزوج إن أراد من زوجته حرامًا كأن تكشف حجابها، أو يأتيها في الدبر، أو أن تستمع معه الأغاني والأفلام.", "page": 342, "id": "unit-26__lesson-17__b19", "inline": [{"t": "text", "s": "وعلى المرأة أن تُطيع زوجها في غير معصية الله؛ فقد قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لو كنت آمرا أحدا أن يسجد لأحد؛ لأمرت الزوجة أن تسجد لزوجها)", "role": "emphasis"}, {"t": "text", "s": " لعظيم حقه عليها، ولكن السجود لا يجوز إلا لله؛ فلا يُطاع الزوج إن أراد من زوجته حرامًا كأن تكشف حجابها، أو يأتيها في الدبر، أو أن تستمع معه الأغاني والأفلام."}]}, {"type": "paragraph", "md": "فلا تطيعه في الحرام، وإنما في رغباته المشروعة؛ لتكفيه حاجته، فتتزين له وتأتيه في الفراش متى شاء ولو كانت مشغولة بشيء آخر، وتطبخ له وتزور معه أقاربه وأهله؛ فبهذا تدوم السعادة في البيوت.", "page": 342, "id": "unit-26__lesson-17__b20"}, {"type": "paragraph", "md": "ومتى عصت المرأة زوجها ومنعته حقَّه في الفراش؛ استحقت لعنة الله وملائكته حتى تعود لطاعته.", "page": 342, "id": "unit-26__lesson-17__b21"}, {"type": "paragraph", "md": "ويجمع الخصال المطلوبة من المرأة هذه الوصية الذهبية: «عليك بالقناعة، والسمع والطاعة، والعناية بالنظافة في المظهر والمخبر، والتعهد لوقت الطعم، والهدوء عند المنام، وحفظ المال، وحسن تدبير العيال، ثم حفظ السر، وإكرام أهله ووالديه؛ مع احتساب طاعة الله في كل ذلك».", "page": 342, "id": "unit-26__lesson-17__b22", "inline": [{"t": "text", "s": "ويجمع الخصال المطلوبة من المرأة هذه الوصية الذهبية: "}, {"t": "quote", "s": "عليك بالقناعة، والسمع والطاعة، والعناية بالنظافة في المظهر والمخبر، والتعهد لوقت الطعم، والهدوء عند المنام، وحفظ المال، وحسن تدبير العيال، ثم حفظ السر، وإكرام أهله ووالديه؛ مع احتساب طاعة الله في كل ذلك"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "3- وأما الأولاد: فهم زينة الحياة، ولكن الحياة ليست كل شيء؛ فعلى المراة أن تحرص على نجاتهم في الآخرة كما تحرص على سعادتهم في الدنيا: ﴿يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ قُوٓاْ أَنفُسَكُمۡ وَأَهۡلِيكُمۡ نَارٗا﴾، فتربيهم على الخلق القويم، والدين المتين، وتغرس فيهم حب الله ودينه وأداء الصلاة في وقتها، ولا تحقر الأم دورها في ذلك؛ فوراء كل رجل عظيم امرأة عظيمة، فتغرس فيه أعظم الخصال وأحسنها.", "page": 343, "id": "unit-26__lesson-17__b23", "inline": [{"t": "emphasis", "s": "3- وأما الأولاد", "role": "emphasis"}, {"t": "text", "s": ": فهم زينة الحياة، ولكن الحياة ليست كل شيء؛ فعلى المراة أن تحرص على نجاتهم في الآخرة كما تحرص على سعادتهم في الدنيا: "}, {"t": "ayah", "s": "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ قُوٓاْ أَنفُسَكُمۡ وَأَهۡلِيكُمۡ نَارٗا", "ayah": [], "verses": [{"n": 6, "text": "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ قُوٓاْ أَنفُسَكُمۡ وَأَهۡلِيكُمۡ نَارٗا", "surah": 66, "surah_name": "التحريم", "ref": "66:6", "ref_api": "https://api.quran.com/api/v4/verses/by_key/66:6"}], "surah": 66, "ref_api": "https://api.quran.com/api/v4/verses/by_key/66:6", "surah_name": "التحريم", "ayah_canonical": 6, "match": "contained", "ref": "66:6"}, {"t": "text", "s": "، فتربيهم على الخلق القويم، والدين المتين، وتغرس فيهم حب الله ودينه وأداء الصلاة في وقتها، ولا تحقر الأم دورها في ذلك؛ فوراء كل رجل عظيم امرأة عظيمة، فتغرس فيه أعظم الخصال وأحسنها."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "خامسًا: مسؤوليتها نحو المجتمع المحيط «أقاربها وجاراتها وصديقاتها»:", "page": 343, "id": "unit-26__lesson-17__b24", "role": "section"}, {"type": "paragraph", "md": "أول واجب على المرأة في مجتمعها: صلة رحمها؛ ليصلها الله بفضله ورحمته، وتوثيق علاقتها بأقاربها، فتنتهز الفرص في المناسبات والأعياد لتشاركهم أفراحهم وأتراحهم.", "page": 343, "id": "unit-26__lesson-17__b25"}, {"type": "paragraph", "md": "وكذلك تحرص على زيارة جاراتها وقريباتها، وتحتك بهن في حدود ما يسمح به وقتها ولا يضيع واجباتها الأخرى، وتحرص على بناء رابطة علمية شرعية بينهنَّ؛ لئلا يكون الاجتماع معهن على الدنيا أو الغيبة والنميمة والبهتان، فمن لم يجتمع على الحق اجتمع على الباطل، وتتعاون معهن على البر والقتوى ككفالة يتيم قريب أو التشارك في الطعام أو حل الإشكالات الاجتماعية، ولتحذر أن تكون جارة سوء؛ فقد سُئل النبي صلى الله عليه وسلم عن امرأة تقوم الليل وتصوم النهار ولكنها تؤذي جيرانها بلسانها، فقال: (لا خير فيها؛ هي من أهل النار)، فتحسن خلقها معهم جميعًا؛ هذا واجبها.", "page": 343, "id": "unit-26__lesson-17__b26", "inline": [{"t": "text", "s": "وكذلك تحرص على زيارة جاراتها وقريباتها، وتحتك بهن في حدود ما يسمح به وقتها ولا يضيع واجباتها الأخرى، وتحرص على بناء رابطة علمية شرعية بينهنَّ؛ لئلا يكون الاجتماع معهن على الدنيا أو الغيبة والنميمة والبهتان، فمن لم يجتمع على الحق اجتمع على الباطل، وتتعاون معهن على البر والقتوى ككفالة يتيم قريب أو التشارك في الطعام أو حل الإشكالات الاجتماعية، ولتحذر أن تكون جارة سوء؛ فقد سُئل النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " عن امرأة تقوم الليل وتصوم النهار ولكنها تؤذي جيرانها بلسانها، فقال: "}, {"t": "emphasis", "s": "(لا خير فيها؛ هي من أهل النار)", "role": "emphasis"}, {"t": "text", "s": "، فتحسن خلقها معهم جميعًا؛ هذا واجبها."}]}, {"type": "paragraph", "md": "ومن أهم الصفات الواجبة على المسلمة: الصدق؛ فالله يحب الصادقين، وبذل النصيحة؛ فلا تغش معارفها وجاراتها بل تنصح لهم وتصحح أخطاءهم متحلية بآداب النصح، والحياء والحشمة؛ فإن الحياء من شعب الإيمان ومن صفات الأنبياء عليهم السلام ، والكرم؛ ببذل الصدقة، وعدم التدخل فيما لا يعنيها؛ فتكف عن الخوض في أعراض الناس وتتبع عوراتهم، والانشغال بالنافع كالقرآن والسنة والذكر والعلم فبذلك لا تنشغل بالباطل؛ لأن الفراغ أعظم ما يُفسد دين المرأة ودنياها.", "page": 343, "id": "unit-26__lesson-17__b27", "inline": [{"t": "emphasis", "s": "ومن أهم الصفات الواجبة على المسلمة", "role": "emphasis"}, {"t": "text", "s": ": "}, {"t": "emphasis", "s": "الصدق؛", "role": "emphasis"}, {"t": "text", "s": " فالله يحب الصادقين، "}, {"t": "emphasis", "s": "وبذل النصيحة؛", "role": "emphasis"}, {"t": "text", "s": " فلا تغش معارفها وجاراتها بل تنصح لهم وتصحح أخطاءهم متحلية بآداب النصح، "}, {"t": "emphasis", "s": "والحياء والحشمة؛", "role": "emphasis"}, {"t": "text", "s": " فإن الحياء من شعب الإيمان ومن صفات الأنبياء "}, {"t": "honorific", "s": "عليهم السلام"}, {"t": "text", "s": " ، "}, {"t": "emphasis", "s": "والكرم", "role": "emphasis"}, {"t": "text", "s": "؛ ببذل الصدقة، "}, {"t": "emphasis", "s": "وعدم التدخل فيما لا يعنيها؛", "role": "emphasis"}, {"t": "text", "s": " فتكف عن الخوض في أعراض الناس وتتبع عوراتهم، "}, {"t": "emphasis", "s": "والانشغال بالنافع كالقرآن والسنة والذكر والعلم", "role": "emphasis"}, {"t": "text", "s": " فبذلك لا تنشغل بالباطل؛ لأن الفراغ أعظم ما يُفسد دين المرأة ودنياها."}]}, {"type": "paragraph", "md": "سؤال تقويمي: اذكري واجب المرأة نحو: ربها، دينها، جاراتها، زوجها، والديها.", "page": 343, "id": "unit-26__lesson-17__b28"}, {"type": "heading", "level": 3, "text": "نشاط دعوي واجتماعي", "page": 343, "id": "unit-26__lesson-17__b29", "role": "activity"}, {"type": "paragraph", "md": "1- نشرح هذه الوجابات لعشرة نساء حولنا؛ بما فيهم بناتنا وأقاربنا، ولخمسة من الرجال محارمنا.", "page": 343, "id": "unit-26__lesson-17__b30", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- هل ثمة واجبات أخرى تعرفينها.. اذكريها لنا وبيني شيئا مما فاتنا ذكره من واجبات المرأة.", "page": 343, "id": "unit-26__lesson-17__b31", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "منارات الهدى", "page": 344, "id": "unit-26__lesson-17__b32", "item_role": "activity_step"}]' WHERE id='unit-26__lesson-17';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-18','unit-26',18,'حقوق المرأة المسلمة العامة','الأسرة والمرأة',NULL,0,2,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 344, "id": "unit-26__lesson-18__b01", "role": "objectives"}, {"type": "paragraph", "md": "1- ذكر حقوق المرأة المسلمة العامة في الشريعة الإسلامية؛ على كافة الصعد والمستويات.", "page": 344, "id": "unit-26__lesson-18__b02", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- بيان أن مصدر الحق هو الله تعالى؛ فما جعله الله حقا مشروعا فهو حق، وما جعله باطلا فهو باطل.", "page": 344, "id": "unit-26__lesson-18__b03", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "أولا: الحرية الشخصية وفق ضوابط الشريعة:", "page": 344, "id": "unit-26__lesson-18__b04", "role": "section"}, {"type": "paragraph", "md": "أي الحرية في الرواح والمجيء، وهو آمن على كرامته وسلامته من أي اعتداء، ومنع القبض عليه ومعاقبته بدون حق، وحق التنقل في داخل البلد وخارجه بالضوابط الشرعية.. وهذه الحرية ضرورية للإنسان، وهي من لوزام كرامته؛ فالله حرم الظلم وجعله محرمًا بين خلقه، وحتى تعدي الإنسان على ذاته بقتلها انتحارًا: حرام؛ لأن الحرية مقيدةً بعبودية الله وما أذن به في شرعه؛ فلا تُمنع النساء المساجد، وإن شاءت أن تسافر فلها الحق بذلك على ألا تسافر لوحدها بل يكون معها محرم حفظًا لها وحرصًا عليها.", "page": 344, "id": "unit-26__lesson-18__b05"}, {"type": "paragraph", "md": "وليس من الحرية الشخصية قول الكفر أو فعل الحرام؛ فالعبد مقيدة حريته بأحكامِ الله تعالى وحدوده.", "page": 344, "id": "unit-26__lesson-18__b06"}, {"type": "heading", "level": 3, "text": "ثانيًا: حق السكن والقرار:", "page": 344, "id": "unit-26__lesson-18__b07", "role": "section"}, {"type": "paragraph", "md": "فالإنسان رجلًا كان أو امرأة؛ من حقه أن يسكن في مكان يأويه ويستره، ويكون محل راحته وأسراره، وهذا حق قررته الشريعة وحمته، وأواجبت على من أراد دخول دار غيره أن يستأذن ويسلم على أهل الدار؛ فإن أذنوا له وإلا رجع: ﴿ وَإِن قِيلَ لَكُمُ ٱرۡجِعُواْ فَٱرۡجِعُواْۖ﴾، ولا يحمل في نفسه شيئًا؛ فهذا حق لأصحاب البيت.", "page": 344, "id": "unit-26__lesson-18__b08", "inline": [{"t": "text", "s": "فالإنسان رجلًا كان أو امرأة؛ من حقه أن يسكن في مكان يأويه ويستره، ويكون محل راحته وأسراره، وهذا حق قررته الشريعة وحمته، وأواجبت على من أراد دخول دار غيره أن يستأذن ويسلم على أهل الدار؛ فإن أذنوا له وإلا رجع: "}, {"t": "ayah", "s": "وَإِن قِيلَ لَكُمُ ٱرۡجِعُواْ فَٱرۡجِعُواْۖ", "ayah": [], "verses": [{"n": 28, "text": "وَإِن قِيلَ لَكُمُ ٱرۡجِعُواْ فَٱرۡجِعُواْۖ", "surah": 24, "surah_name": "النور", "ref": "24:28", "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:28"}], "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:28", "surah_name": "النور", "ayah_canonical": 28, "match": "contained", "ref": "24:28"}, {"t": "text", "s": "، ولا يحمل في نفسه شيئًا؛ فهذا حق لأصحاب البيت."}]}, {"type": "paragraph", "md": "وحرمت الشريعة التجسس والتلصص على منازل الغير، وأهدر النبي صلى الله عليه وسلم عين من تجسس على العورات.", "page": 344, "id": "unit-26__lesson-18__b09", "inline": [{"t": "text", "s": "وحرمت الشريعة التجسس والتلصص على منازل الغير، وأهدر النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " عين من تجسس على العورات."}]}, {"type": "heading", "level": 3, "text": "ثالثًا: حق التعلم:", "page": 344, "id": "unit-26__lesson-18__b10", "role": "section"}, {"type": "paragraph", "md": "فالعلم من الحوائج الأصلية للإنسان؛ فمن حقه معرفة ربه وأحكام عبادته، قال ابن حزم: «وفرض على كل امرأة النفقة في ‌كل ‌ما ‌يخصها كما ذلك فرض على الرجال؛ ففرض على ذات المال منهن معرفة أحكام الزكاة، وفرض عليهن كلهن معرفة أحكام الطهارة والصلاة والصوم، وما يحل وما يحرم من المآكل والمشارب والملابس وغير ذلك؛ كالرجال ولا فرق» وكثير من أحكام الدين نقلتها زوجات النبي صلى الله عليه وسلم وغيرهن من الصحابيات الكريمات رضي الله عنهن ، وواجب الدولة المسلمة ندب بعض النساء لتعلم الدين وتعليمه، وتعلم ما يلزم النساء في الطب والتمريض، وكذلك تتعلم المرأة الطبخ وتدبير شؤون المنزل، وتربية الأبناء؛ فهذه واجباتها، ولا يلزم أن تتعلم المرأة مهن الرجال كالهندسة والبناء فإن لكل شيئٌ يختص به؛ فالعدل إعطاء كل ذي حق حقه، والتسوية بين المفترقين ظلم لا عدل.", "page": 345, "id": "unit-26__lesson-18__b11", "inline": [{"t": "text", "s": "فالعلم من الحوائج الأصلية للإنسان؛ فمن حقه معرفة ربه وأحكام عبادته، قال ابن حزم: "}, {"t": "quote", "s": "وفرض على كل امرأة النفقة في ‌كل ‌ما ‌يخصها كما ذلك فرض على الرجال؛ ففرض على ذات المال منهن معرفة أحكام الزكاة، وفرض عليهن كلهن معرفة أحكام الطهارة والصلاة والصوم، وما يحل وما يحرم من المآكل والمشارب والملابس وغير ذلك؛ كالرجال ولا فرق", "speaker": "ابن حزم"}, {"t": "text", "s": " وكثير من أحكام الدين نقلتها زوجات النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وغيرهن من الصحابيات الكريمات "}, {"t": "honorific", "s": "رضي الله عنهن"}, {"t": "text", "s": " ، وواجب الدولة المسلمة ندب بعض النساء لتعلم الدين وتعليمه، وتعلم ما يلزم النساء في الطب والتمريض، وكذلك تتعلم المرأة الطبخ وتدبير شؤون المنزل، وتربية الأبناء؛ فهذه واجباتها، ولا يلزم أن تتعلم المرأة مهن الرجال كالهندسة والبناء فإن لكل شيئٌ يختص به؛ فالعدل إعطاء كل ذي حق حقه، والتسوية بين المفترقين ظلم لا عدل."}]}, {"type": "heading", "level": 3, "text": "رابعًا: حق التملك:", "page": 345, "id": "unit-26__lesson-18__b12", "role": "section"}, {"type": "paragraph", "md": "المرأة المسلمة في الشريعة لا تحتاج للنفقة على نفسها؛ فهي مكفولة النفقة من الأب أو الزوج أو الأخ، وإن لم يوجد فيكفيها بيت المال، ومع ذلك فلا تُمنع من العمل المناسب لها كالخياطة والطبابة والتعليم، ومن ثَم فلها حق التملك وعليها زكاةٌ في مالها، وتتصرف في مالها كيف شاءت وإن لم يأذن لها الزوج لأنه مالها لا ماله؛ فقد كانت النسوة يتصدقن في عهد النبي صلى الله عليه وسلم ولا يرجعن لأزواجهن.", "page": 345, "id": "unit-26__lesson-18__b13", "inline": [{"t": "text", "s": "المرأة المسلمة في الشريعة لا تحتاج للنفقة على نفسها؛ فهي مكفولة النفقة من الأب أو الزوج أو الأخ، وإن لم يوجد فيكفيها بيت المال، ومع ذلك فلا تُمنع من العمل المناسب لها كالخياطة والطبابة والتعليم، ومن ثَم فلها حق التملك وعليها زكاةٌ في مالها، وتتصرف في مالها كيف شاءت وإن لم يأذن لها الزوج لأنه مالها لا ماله؛ فقد كانت النسوة يتصدقن في عهد النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ولا يرجعن لأزواجهن."}]}, {"type": "heading", "level": 3, "text": "خامسًا: حق الزواج:", "page": 345, "id": "unit-26__lesson-18__b14", "role": "section"}, {"type": "paragraph", "md": "وبه يحصل بناء الأسرة، والاستمتاع المشروع، وقضاء الوطر، وحصول الولد، وتربيتهم؛ فالأم أصل التربية لأودلاها، وفي الزواج تكون المرحمة والسكينة بين الزوجين، وتُحفظ المرأة من الزنا ومقدماته، وقد جعلت لها الشريعة حقَّ قَبول خاطبها أو رفضه، وراعى حياءها فجعل قَبول البكر صمتها وعدم رفضها وأوصاها بان تختار صاحب الدين؛ فقال صلى الله عليه وسلم : (إذا جاءكم من ترضون دينه وخلقه فزوجوه؛ إلا تفعلوا تكن فتنة في الأرض وفساد كبير)، وفي القرآن الكريم: ﴿وَلَعَبۡدٞ مُّؤۡمِنٌ خَيۡرٞ مِّن مُّشۡرِكٖ وَلَوۡ أَعۡجَبَكُمۡۗ﴾؛ فقد تعجب المرأة بالشهادة والمظهر والمال، ثم تكون حياتها جحيمًا لا يُطاق.", "page": 345, "id": "unit-26__lesson-18__b15", "inline": [{"t": "text", "s": "وبه يحصل بناء الأسرة، والاستمتاع المشروع، وقضاء الوطر، وحصول الولد، وتربيتهم؛ فالأم أصل التربية لأودلاها، وفي الزواج تكون المرحمة والسكينة بين الزوجين، وتُحفظ المرأة من الزنا ومقدماته، وقد جعلت لها الشريعة حقَّ قَبول خاطبها أو رفضه، وراعى حياءها فجعل قَبول البكر صمتها وعدم رفضها وأوصاها بان تختار صاحب الدين؛ فقال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إذا جاءكم من ترضون دينه وخلقه فزوجوه؛ إلا تفعلوا تكن فتنة في الأرض وفساد كبير)، وفي القرآن الكريم:", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "ayah", "s": "وَلَعَبۡدٞ مُّؤۡمِنٌ خَيۡرٞ مِّن مُّشۡرِكٖ وَلَوۡ أَعۡجَبَكُمۡۗ", "ayah": [], "verses": [{"n": 221, "text": "وَلَعَبۡدٞ مُّؤۡمِنٌ خَيۡرٞ مِّن مُّشۡرِكٖ وَلَوۡ أَعۡجَبَكُمۡۗ", "surah": 2, "surah_name": "البقرة", "ref": "2:221", "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:221"}], "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:221", "surah_name": "البقرة", "ayah_canonical": 221, "match": "contained", "ref": "2:221"}, {"t": "text", "s": "؛ فقد تعجب المرأة بالشهادة والمظهر والمال، ثم تكون حياتها جحيمًا لا يُطاق."}]}, {"type": "paragraph", "md": "وينبغي اليوم تيسير أمر الزواج وتقليل المهور؛ لأن الزنا والحرام يسير فلا نعسر الزواج فنساهم بإفساد الشباب والنساء، فقد كان مهر أزواج النبي صلى الله عليه وسلم وبناته رضي الله عنهن لا يزيد عن (12.5) أوقية فضة؛ أي 500 درهم = (1487.5 جم فضة)، وهو مبلغ يسير أمام مهور اليوم، قال صلى الله عليه وسلم : (أكثر النساء بركة أيسرهن مؤنة).", "page": 345, "id": "unit-26__lesson-18__b16", "inline": [{"t": "text", "s": "وينبغي اليوم تيسير أمر الزواج وتقليل المهور؛ لأن الزنا والحرام يسير فلا نعسر الزواج فنساهم بإفساد الشباب والنساء، فقد كان مهر أزواج النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وبناته "}, {"t": "honorific", "s": "رضي الله عنهن"}, {"t": "text", "s": " لا يزيد عن (12.5) أوقية "}, {"t": "emphasis", "s": "فضة", "role": "emphasis"}, {"t": "text", "s": "؛ أي 500 درهم = "}, {"t": "emphasis", "s": "(1487.5 جم", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "فضة", "role": "emphasis"}, {"t": "text", "s": ")، وهو مبلغ يسير أمام مهور اليوم، قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(أكثر النساء بركة أيسرهن مؤنة)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "سؤال تقويمي:", "page": 345, "id": "unit-26__lesson-18__b17", "role": "assessment"}, {"type": "paragraph", "md": "هل للمرأة حقوق في الإسلام.. بيني لنا أربعة منها باختصار.", "page": 345, "id": "unit-26__lesson-18__b18", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط دعوي واجتماعي", "page": 345, "id": "unit-26__lesson-18__b19", "role": "activity"}, {"type": "paragraph", "md": "1- نرجع إلى كتاب الشيخ محمد رشيد رضا «حقوق النساء في الإسلام» ونلخص أهم ما فيه.", "page": 345, "id": "unit-26__lesson-18__b20", "inline": [{"t": "text", "s": "1- نرجع إلى كتاب الشيخ محمد رشيد رضا "}, {"t": "quote", "s": "حقوق النساء في الإسلام"}, {"t": "text", "s": " ونلخص أهم ما فيه."}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- اذكري حقوقًا أخرى عامة وأنزليها على واقع المرأة المسلمة غير تلك التي ذكرناها في الدرس.", "page": 345, "id": "unit-26__lesson-18__b21", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- ننشرُ بين جماعة من النساء المحيطاتِ بنا والقريبات منا هذه الحقوق، ونعرفهم بعظمة الإسلام.", "page": 345, "id": "unit-26__lesson-18__b22", "item_role": "activity_step", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "منارات الهدى", "page": 346, "id": "unit-26__lesson-18__b23", "item_role": "activity_step"}]' WHERE id='unit-26__lesson-18';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-19','unit-26',19,'حقوق المرأة المسلمة الخاصة','الأسرة والمرأة',NULL,0,1,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 346, "id": "unit-26__lesson-19__b01", "role": "objectives"}, {"type": "paragraph", "md": "- ذكر حقوق المرأة المسلمة الخاصة في الشريعة الإسلامية؛ على كافة الصعد والمستويات.", "page": 346, "id": "unit-26__lesson-19__b02", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "أولا: حق المرأة على والديها الكريمَين:", "page": 346, "id": "unit-26__lesson-19__b03", "role": "section"}, {"type": "paragraph", "md": "قال صلى الله عليه وسلم : (من ابتُلي من هذه البنات بشيء كن له سترًا من النار)، وقال: (كلكم راعٍ وكلكم مسؤول عن رعيته)، ومن هنا فللوالدين مسؤولية في تربية أبنائهم أن ينشئوهم على قيم الإسلام وآدابه، ويبدأ ذلك من اختيار الأم، وذكر الله عند الجماع لئلا يضر الشيطانُ الولدَ، وإن رزقه الله ولدًا فيحنكه ويؤذن في أذنيه.", "page": 346, "id": "unit-26__lesson-19__b04", "inline": [{"t": "text", "s": "قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(من ابتُلي من هذه البنات بشيء كن له سترًا من النار)", "role": "emphasis"}, {"t": "text", "s": "، وقال: "}, {"t": "emphasis", "s": "(كلكم راعٍ وكلكم مسؤول عن رعيته)", "role": "emphasis"}, {"t": "text", "s": "، ومن هنا فللوالدين مسؤولية في تربية أبنائهم أن ينشئوهم على قيم الإسلام وآدابه، ويبدأ ذلك من اختيار الأم، وذكر الله عند الجماع لئلا يضر الشيطانُ الولدَ، وإن رزقه الله ولدًا فيحنكه ويؤذن في أذنيه."}]}, {"type": "paragraph", "md": "ويبدأ في غرس تعظيم الله في قلبه من صغره، ودعوته لاتباع هدي النبي صلى الله عليه وسلم متدرجًا في خطابهم بما يفقهون ويعلمهم أركان الإسلام وأحكام الدين علميا وعمليا، ويحكي لهم قصص الأنبياء والصحابة.", "page": 346, "id": "unit-26__lesson-19__b05", "inline": [{"t": "text", "s": "ويبدأ في غرس تعظيم الله في قلبه من صغره، ودعوته لاتباع هدي النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " متدرجًا في خطابهم بما يفقهون ويعلمهم أركان الإسلام وأحكام الدين علميا وعمليا، ويحكي لهم قصص الأنبياء والصحابة."}]}, {"type": "paragraph", "md": "ومن حق البنتِ: ألا يحضرَ لها والدها ما يُفسد دينها من الأفلام والكتب المنحرفة خلقيا أو عقديا، وأن تكون أمها قدوةً لها في الصلاح، وأن تعلمها أصول النظافة والطبخ وحسن المظهر، وتهيئها للحياة الزوجية، حتى إذا تزوجت أعانتها في بناء أسرتها ولا تتدخل في حياتها الزوجية إلا بالإصلاح والتوجيه.", "page": 346, "id": "unit-26__lesson-19__b06"}, {"type": "heading", "level": 3, "text": "ثانيًا: حق المراة على زوجها:", "page": 346, "id": "unit-26__lesson-19__b07", "role": "section"}, {"type": "paragraph", "md": "فقد قال صلى الله عليه وسلم : (اتقوا الله في النساء؛ فإنكم أخذتموهن بأمان الله، واستحللتم ‌فروجهن ‌بكلمة ‌الله، ولكم عليهن أن لا يوطئن فرشكم أحدا تكرهونه، فإن فعلن ذلك، فاضربوهن ضربا غير مبرح، ولهن عليكم رزقهن، وكسوتهن بالمعروف)، وقال صلى الله عليه وسلم : (خيركم خيركم لأهله، وأنا خيركم لأهلي)، وقال كذلك: (استوصوا ‌بالنساء؛ فإن المرأة خلقت من ضلع، وإن أعوج شيء في الضلع أعلاه؛ فإن ذهبت تقيمه كسرته، وإن تركته لم يزل أعوج؛ فاستوصوا بالنساء)، ويمكن تلخيص حقوق المرأة على زوجها بالآتي:", "page": 346, "id": "unit-26__lesson-19__b08", "inline": [{"t": "text", "s": "فقد قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(اتقوا الله في النساء؛ فإنكم أخذتموهن بأمان الله، واستحللتم ‌فروجهن ‌بكلمة ‌الله، ولكم عليهن أن لا يوطئن فرشكم أحدا تكرهونه، فإن فعلن ذلك، فاضربوهن ضربا غير مبرح، ولهن عليكم رزقهن، وكسوتهن بالمعروف)", "role": "emphasis"}, {"t": "text", "s": "، وقال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(خيركم خيركم لأهله، وأنا خيركم لأهلي)", "role": "emphasis"}, {"t": "text", "s": "، وقال كذلك: "}, {"t": "emphasis", "s": "(استوصوا ‌بالنساء؛ فإن المرأة خلقت من ضلع، وإن أعوج شيء في الضلع أعلاه؛ فإن ذهبت تقيمه كسرته، وإن تركته لم يزل أعوج؛ فاستوصوا بالنساء)", "role": "emphasis"}, {"t": "text", "s": "، "}, {"t": "emphasis", "s": "ويمكن تلخيص حقوق المرأة على زوجها بالآتي", "role": "emphasis"}, {"t": "text", "s": ":"}]}, {"type": "paragraph", "md": "1- المهر: وهو المال الذي يجب على الرجل للمرأة بسبب عقد الزواج، وتستحقه كاملا إذا دخل بها؛ قل أو كثر، ولا حد لأكثره على الصحيح، والسنة أن يكون يسيرًا، والمهر ملك المرأة فلا يطمع فيه أبواها بل يعيناها في استعماله في مصالحها لا في تبذيره فيما لا يُفيد ولا ينفع.", "page": 346, "id": "unit-26__lesson-19__b09", "inline": [{"t": "emphasis", "s": "1- المهر", "role": "emphasis"}, {"t": "text", "s": ": وهو المال الذي يجب على الرجل للمرأة بسبب عقد الزواج، وتستحقه كاملا إذا دخل بها؛ قل أو كثر، ولا حد لأكثره على الصحيح، والسنة أن يكون يسيرًا، والمهر ملك المرأة فلا يطمع فيه أبواها بل يعيناها في استعماله في مصالحها لا في تبذيره فيما لا يُفيد ولا ينفع."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- الإنفاق على الزوجة: قال تعالى: ﴿لِيُنفِقۡ ذُو سَعَةٖ مِّن سَعَتِهِۦۖ﴾، وقد أجمع العلماء على وجوب نفقة الزوجة على الزوج لانها محبوسة لحقه، والقاعدة أن من خُبس لحق غيره فنفقته واجبةٌ عليه، ويُنفق الزوج بقدر طاقته غِنى أو فقرًا؛ فحتى الفقير يجب عليه أن يُنفق عليها ولو كانت غنية، ومن حق المرأة إن أعسر زوجها بالنفقة مُطلقًا ولم تستطع الصبر عليه أبدًا أن تطلب الطلاق، ولا تُلزم بالنفقة عليه وعلى أولادها فإن فعلت فهو فضل وإحسان منها تُشكر عليه، وهذا يدلنا على وجوبِ عمل الرجل لينفق على أهله، فإن عجز بالمرة وأنفقت المرأة فضلا منها فلا يجوز لها المن عليه بذلك فهو من باب المواساة وحسن الخُلق.", "page": 347, "id": "unit-26__lesson-19__b10", "inline": [{"t": "emphasis", "s": "2- الإنفاق على الزوجة", "role": "emphasis"}, {"t": "text", "s": ": قال تعالى: "}, {"t": "ayah", "s": "لِيُنفِقۡ ذُو سَعَةٖ مِّن سَعَتِهِۦۖ", "ayah": [], "verses": [{"n": 7, "text": "لِيُنفِقۡ ذُو سَعَةٖ مِّن سَعَتِهِۦۖ", "surah": 65, "surah_name": "الطلاق", "ref": "65:7", "ref_api": "https://api.quran.com/api/v4/verses/by_key/65:7"}], "surah": 65, "ref_api": "https://api.quran.com/api/v4/verses/by_key/65:7", "surah_name": "الطلاق", "ayah_canonical": 7, "match": "contained", "ref": "65:7"}, {"t": "text", "s": "، وقد أجمع العلماء على وجوب نفقة الزوجة على الزوج لانها محبوسة لحقه، والقاعدة أن من خُبس لحق غيره فنفقته واجبةٌ عليه، ويُنفق الزوج بقدر طاقته غِنى أو فقرًا؛ فحتى الفقير يجب عليه أن يُنفق عليها ولو كانت غنية، ومن حق المرأة إن أعسر زوجها بالنفقة مُطلقًا ولم تستطع الصبر عليه أبدًا أن تطلب الطلاق، ولا تُلزم بالنفقة عليه وعلى أولادها فإن فعلت فهو فضل وإحسان منها تُشكر عليه، وهذا يدلنا على وجوبِ عمل الرجل لينفق على أهله، فإن عجز بالمرة وأنفقت المرأة فضلا منها فلا يجوز لها المن عليه بذلك فهو من باب المواساة وحسن الخُلق."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- حق المبيت: فمن حقها أن يبيت عندها ليلة من أربع؛ لأن الله تعالى أباح للرجل نكاح أربع نسوة؛ فيكون المبيت حقا واجبًا لكل ليلة من أربع على الأقل، وهذا معنى قوله صلى الله عليه وسلم : (وإن لزوجك عليك حقا) قاله لعبد الله بن مرو رضي الله عنه لما كان يقوم كل ليلة؛ فنهاه عن ذلك لأجل حق زوجِه؛ إلا لو كان له عذر فلا بأس به، والمبيت حق حتى لمن عجز عن الوطء؛ فلا ارتباط بينهما.", "page": 347, "id": "unit-26__lesson-19__b11", "inline": [{"t": "emphasis", "s": "3- حق المبيت", "role": "emphasis"}, {"t": "text", "s": ": فمن حقها أن يبيت عندها ليلة من أربع؛ لأن الله تعالى أباح للرجل نكاح أربع نسوة؛ فيكون المبيت حقا واجبًا لكل ليلة من أربع على الأقل، وهذا معنى قوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(وإن لزوجك عليك حقا)", "role": "emphasis"}, {"t": "text", "s": " قاله لعبد الله بن مرو "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " لما كان يقوم كل ليلة؛ فنهاه عن ذلك لأجل حق زوجِه؛ إلا لو كان له عذر فلا بأس به، والمبيت حق حتى لمن عجز عن الوطء؛ فلا ارتباط بينهما."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "ومعنى المبيت: وقت راحته؛ فمن كان عمله في النهار مكث عندها ليلا، ومن كان عمله ليلا فمبيته النهار.", "page": 347, "id": "unit-26__lesson-19__b12"}, {"type": "paragraph", "md": "4- حق الوطء: وهو من أعظم مقاصد النكاح؛ ففيه الاستمتاع الحلال الذي غرسه الله في النفوس، ويحرم على الزوج تركه إضرارًا لزوجته، ومن حلف ألا يطأ زوجته مطلقًا أو أكثر من أربعة أشهر فهذا الإيلاء المحرم فيُمهل أربعة أشهر فإن وطئها وإلا فيُلزم بتطليقها، ويحتسب الرجل بالوطء الأجر عند الله؛ ففي الحديث: (في بضع أهلك صدقة) لأنه بذلك يمنعهم من الحرام فيُؤجر به، ولأنه وسيلة إلى الولد وغض البصر وسكون النفس.", "page": 347, "id": "unit-26__lesson-19__b13", "inline": [{"t": "emphasis", "s": "4- حق الوطء", "role": "emphasis"}, {"t": "text", "s": ": وهو من أعظم مقاصد النكاح؛ ففيه الاستمتاع الحلال الذي غرسه الله في النفوس، ويحرم على الزوج تركه إضرارًا لزوجته، ومن حلف ألا يطأ زوجته مطلقًا أو أكثر من أربعة أشهر فهذا الإيلاء المحرم فيُمهل أربعة أشهر فإن وطئها وإلا فيُلزم بتطليقها، ويحتسب الرجل بالوطء الأجر عند الله؛ ففي الحديث: "}, {"t": "emphasis", "s": "(في بضع أهلك صدقة)", "role": "emphasis"}, {"t": "text", "s": " لأنه بذلك يمنعهم من الحرام فيُؤجر به، ولأنه وسيلة إلى الولد وغض البصر وسكون النفس."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- حق التوجيه والتقويم والتعليم: فإذا تزوج الرجل امرأة لا تعرف أحكام دينها وجب عليه تعليمها وتربيتها، ولو كان مشغولا دفعها لمن يُعلمها في المعاهد والمساجد والجامعات، ويؤمن لها الكتب والمحاضرات النافعة التي تستفيد منها في دينها ودنياها، ولا يجب أن يجعلها تُكمل جامعتها ونحو ذلك إذا كان هذا مؤثرًا على حقه أو مضرًا بالبيت وفيه كثرة مفارقة الأسرة والأهل؛ فإن اتفقا عليه فلا بأس حينها.", "page": 347, "id": "unit-26__lesson-19__b14", "inline": [{"t": "emphasis", "s": "5- حق التوجيه والتقويم والتعليم:", "role": "emphasis"}, {"t": "text", "s": " فإذا تزوج الرجل امرأة لا تعرف أحكام دينها وجب عليه تعليمها وتربيتها، ولو كان مشغولا دفعها لمن يُعلمها في المعاهد والمساجد والجامعات، ويؤمن لها الكتب والمحاضرات النافعة التي تستفيد منها في دينها ودنياها، ولا يجب أن يجعلها تُكمل جامعتها ونحو ذلك إذا كان هذا مؤثرًا على حقه أو مضرًا بالبيت وفيه كثرة مفارقة الأسرة والأهل؛ فإن اتفقا عليه فلا بأس حينها."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "سؤال تقويمي: اذكري حقوق المرأة على والديها، وحقوق المرأة على زوجها؟", "page": 347, "id": "unit-26__lesson-19__b15"}, {"type": "heading", "level": 3, "text": "نشاط دعوي واجتماعي", "page": 347, "id": "unit-26__lesson-19__b16", "role": "activity"}, {"type": "paragraph", "md": "1- اذكري حقوقًا أخرى للزوجة، وأنزليها على واقع المرأة؛ غير تلك التي ذكرناها في الدرس.", "page": 347, "id": "unit-26__lesson-19__b17", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ننشرُ بين جماعة من النساء المحيطاتِ بنا والقريبات منا هذه الحقوق، ونعرفهم بعظمة الإسلام.", "page": 347, "id": "unit-26__lesson-19__b18", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "منارات الهدى", "page": 348, "id": "unit-26__lesson-19__b19", "item_role": "activity_step"}]' WHERE id='unit-26__lesson-19';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-20','unit-26',20,'حقوق المرأة الاجتماعية','الأسرة والمرأة',NULL,0,3,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "تمهيد بين يدي هذه الحقوق:", "page": 348, "id": "unit-26__lesson-20__b01", "role": "intro"}, {"type": "paragraph", "md": "قرر الإسلام إنسانية المرأة كالرجل، وجعلها أهلا للحقوق والواجبات؛ بحسب ما لديها من خصائص.", "page": 348, "id": "unit-26__lesson-20__b02"}, {"type": "paragraph", "md": "ولكي يؤدي المجتمع حق المرأة فلا بد من الطهارة من الانحرافات؛ ثم الاستقامة على السلوك الصحيح، هذه الاستقامة التي يصلح معها القلب، وتعظم التقوى في الفؤاد؛ يكون المجتمع معها مهيأ لأداء الحقوق الواجبة عليه سواء للرجال أو النساء، ومن حقوق المرأة المجتعمية التي جعلتها الشريعة:", "page": 348, "id": "unit-26__lesson-20__b03", "inline": [{"t": "text", "s": "ولكي يؤدي المجتمع حق المرأة فلا بد من الطهارة من الانحرافات؛ ثم الاستقامة على السلوك الصحيح، هذه الاستقامة التي يصلح معها القلب، وتعظم التقوى في الفؤاد؛ يكون المجتمع معها مهيأ لأداء الحقوق الواجبة عليه سواء للرجال أو النساء، "}, {"t": "emphasis", "s": "ومن حقوق المرأة المجتعمية التي جعلتها الشريعة", "role": "emphasis"}, {"t": "text", "s": ":"}]}, {"type": "heading", "level": 3, "text": "أولا: معاونة المرأة على الحجاب والسِّتر:", "page": 348, "id": "unit-26__lesson-20__b04", "role": "section"}, {"type": "paragraph", "md": "فلو أن كل فرد في المجتمع قام بنشاط جيدٍ في هذا الباب لسهل ارتداء الحجاب؛ فخطيب المسجد على المنبر يُبين وجوب الحجاب وأهميته، والداعية في السوق يأمر المرأة بالاحتجاب ويأخذ على أيدي السفيهات المعاندات، والإعلامي يشيد بنماذج العفة ويُحذر من السفور، والشاب الذي يُريد الزواج يسأل عن حجاب المرأة وتسترها ويترك السافرة.. إذا احترم الناس المحجبة وأكرموها فسرعان ما ستُقدم النساء على الحجاب، بينما تُزدرى السافرة وتُحتقر فلا تُقدم في عمل، وتُهجر لهتكها سترَ الله.. فلو قام أفراد المجتمع المسلم بهذا الدور لكان له أكبر الأثر في تحجيب النساء ونشر العفة والفضيلة.", "page": 348, "id": "unit-26__lesson-20__b05"}, {"type": "heading", "level": 3, "text": "ثانيًا: الابتعاد عن الخلوة والاختلاط المحرمين:", "page": 348, "id": "unit-26__lesson-20__b06", "role": "section"}, {"type": "paragraph", "md": "يجب أن يعرف المجتمع مغبة الخلوة بالأجنبية، وخطر الاختلاط؛ فيبتعدوا عنهما، وبهذا تُصان المرأة.", "page": 348, "id": "unit-26__lesson-20__b07"}, {"type": "paragraph", "md": "فلو أن صاحب سيارة الأجرة لم يحمل المرأة التي ليس معها محرم ممن ظاهرها محل للربية، ولو أن التاجر جعل سوقًا خاصا بالنساء واختار له إدارة نسائية صالحة، ولو عزلت النساء عن الرجال في المشافي والمدارس والجامعات؛ فجعلت النساء في أماكن مخصصة لهن.. لقطع بهذا دابر الاختلاط في الأسواق.", "page": 348, "id": "unit-26__lesson-20__b08"}, {"type": "paragraph", "md": "وقد نهى الإسلام عن خلوة الرجل بالمرأة الأجنبية فقد قال صلى الله عليه وسلم : (من كان يؤمن بالله واليوم الآخر؛ فلا يخلون بامرأة ليس معها ذو محرم منها؛ فإن ثالثهما الشيطان)، وهو حرام إجماعًا؛ حتى لو كان من أقاربها أو أقارب الزوج، فكل من جازَ لهم الزواج بها في الأصل حرمت الخلوة به.", "page": 348, "id": "unit-26__lesson-20__b09", "inline": [{"t": "emphasis", "s": "وقد نهى الإسلام عن خلوة الرجل بالمرأة الأجنبية", "role": "emphasis"}, {"t": "text", "s": " فقد قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(من كان يؤمن بالله واليوم الآخر؛ فلا يخلون بامرأة ليس معها ذو محرم منها؛ فإن ثالثهما الشيطان)", "role": "emphasis"}, {"t": "text", "s": "، وهو حرام إجماعًا؛ حتى لو كان من أقاربها أو أقارب الزوج، فكل من جازَ لهم الزواج بها في الأصل حرمت الخلوة به."}]}, {"type": "heading", "level": 3, "text": "ثالثًا: حق المرأة في إعزازها وإكرامها ووضعها في المكانة اللائقة بها:", "page": 348, "id": "unit-26__lesson-20__b10", "role": "section"}, {"type": "paragraph", "md": "فقد احترم الإسلام المرأة وكفل لها حقها أمًّا وزوجة وبنتًا وعضوة فاعلة في المجتمع؛ فحرم دمها ومالها وعرضها إلا بحق الإسلام، وجعلها عليها مسؤولية عن أعمالها حسنة كانت أو سيئة: ﴿لِّلرِّجَالِ نَصِيبٞ مِّمَّا ٱكۡتَسَبُواْۖ وَلِلنِّسَآءِ نَصِيبٞ مِّمَّا ٱكۡتَسَبۡنَۚ﴾ وجعل لهـا كالرجل حق الأمر بالمعروف والنهي عن المنكر في المجتمع: ﴿وَٱلۡمُؤۡمِنُونَ وَٱلۡمُؤۡمِنَٰتُ بَعۡضُهُمۡ أَوۡلِيَآءُ بَعۡضٖۚ يَأۡمُرُونَ بِٱلۡمَعۡرُوفِ وَيَنۡهَوۡنَ عَنِ ٱلۡمُنكَرِ﴾ كما فتح أمامها المجالات كلها؛ في العمل والجهاد والتعليم والعبادة وشهود الجماعات وكل عمل مفيد وصالح.", "page": 349, "id": "unit-26__lesson-20__b11", "inline": [{"t": "text", "s": "فقد احترم الإسلام المرأة وكفل لها حقها أمًّا وزوجة وبنتًا وعضوة فاعلة في المجتمع؛ فحرم دمها ومالها وعرضها إلا بحق الإسلام، وجعلها عليها مسؤولية عن أعمالها حسنة كانت أو سيئة: "}, {"t": "ayah", "s": "لِّلرِّجَالِ نَصِيبٞ مِّمَّا ٱكۡتَسَبُواْۖ وَلِلنِّسَآءِ نَصِيبٞ مِّمَّا ٱكۡتَسَبۡنَۚ", "ayah": [], "verses": [{"n": 32, "text": "لِّلرِّجَالِ نَصِيبٞ مِّمَّا ٱكۡتَسَبُواْۖ وَلِلنِّسَآءِ نَصِيبٞ مِّمَّا ٱكۡتَسَبۡنَۚ", "surah": 4, "surah_name": "النساء", "ref": "4:32", "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:32"}], "surah": 4, "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:32", "surah_name": "النساء", "ayah_canonical": 32, "match": "contained", "ref": "4:32"}, {"t": "text", "s": " وجعل لهـا كالرجل حق الأمر بالمعروف والنهي عن المنكر في المجتمع: "}, {"t": "ayah", "s": "وَٱلۡمُؤۡمِنُونَ وَٱلۡمُؤۡمِنَٰتُ بَعۡضُهُمۡ أَوۡلِيَآءُ بَعۡضٖۚ يَأۡمُرُونَ بِٱلۡمَعۡرُوفِ وَيَنۡهَوۡنَ عَنِ ٱلۡمُنكَرِ", "ayah": [], "verses": [{"n": 71, "text": "وَٱلۡمُؤۡمِنُونَ وَٱلۡمُؤۡمِنَٰتُ بَعۡضُهُمۡ أَوۡلِيَآءُ بَعۡضٖۚ يَأۡمُرُونَ بِٱلۡمَعۡرُوفِ وَيَنۡهَوۡنَ عَنِ ٱلۡمُنكَرِ", "surah": 9, "surah_name": "التوبة", "ref": "9:71", "ref_api": "https://api.quran.com/api/v4/verses/by_key/9:71"}], "surah": 9, "ref_api": "https://api.quran.com/api/v4/verses/by_key/9:71", "surah_name": "التوبة", "ayah_canonical": 71, "match": "contained", "ref": "9:71"}, {"t": "text", "s": " كما فتح أمامها المجالات كلها؛ في العمل والجهاد والتعليم والعبادة وشهود الجماعات وكل عمل مفيد وصالح."}]}, {"type": "paragraph", "md": "وقد حرص الرسول صلى الله عليه وسلم وخلفاؤه الراشدون والمسلمون من بعدهم على تكريم المرأة؛ حتى جعل الإسلام منها: عالمة وراوية وحافظة ومحتسبة، وشاعرة، ومجاهدة، وشهيدة، وداعية.", "page": 349, "id": "unit-26__lesson-20__b12", "inline": [{"t": "text", "s": "وقد حرص الرسول "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وخلفاؤه الراشدون والمسلمون من بعدهم على تكريم المرأة؛ حتى جعل الإسلام منها: عالمة وراوية وحافظة ومحتسبة، وشاعرة، ومجاهدة، وشهيدة، وداعية."}]}, {"type": "paragraph", "md": "وفي ظل هذه التعاليم الإسلامية تربت المرأة وتعلمت وتفقهت، فأنتجت وأفادت ونبغت وبرزت، حيث نجد في تاريخنا الإسلامي كثيرًا من النابغات الشهيرات اللواتي سجل التاريخ أسماءهن بمداد الفخر.", "page": 349, "id": "unit-26__lesson-20__b13"}, {"type": "heading", "level": 3, "text": "رابعًا: استقرارها في بيتها وقيامها على رعاية أولادها وتربية أسرتها:", "page": 349, "id": "unit-26__lesson-20__b14", "role": "section"}, {"type": "paragraph", "md": "الأصل في المرأة أن تستقر في بيتها الذي تراه مملكة فسيحة لها، وليس عليها في هذا غضاضة؛ فالحياة شراكة بين الزوجين؛ فالرجل خارج البيت، والمرأة داخله: تربي الأولاد وتعد الطعام وتنظم المنزل، وهذه الوظيفة في البيت عظيمة شريفة؛ فالأم مصنع الرجال العظماء والنساء الكريمات؛ فالأمم قد تبني القصور العظيمة وناطحات السحاب والمصانع الفخمة؛ لكن لا يُحسن بناء الإنسان المسلم إلا أم تقوم عليه في البيت تربية وإعدادًا وبناءً وتسقي غرسها بالتوجيه والتربية؛ وفق الكتاب والسنة، فالأولاد بين يدي أمهم كالعجينة تشكلهم على يدها كما تشاء، ومن شب على شيءٍ شابَ عليه.. فلماذا تحتقر بعض النساء هذا الدور؟ وتعلو صراخت جاهلة بأن طاقتها معطلة! وهل أعظم من استغلال الطاقة في تربية الأسرة؟!", "page": 349, "id": "unit-26__lesson-20__b15"}, {"type": "heading", "level": 3, "text": "خامسًا: تعداد الزوجات حق من حقوق المرأة على المجتمع المسلم:", "page": 349, "id": "unit-26__lesson-20__b16", "role": "section"}, {"type": "paragraph", "md": "كان اليونانيون يبيعون النساء في الأسواق ويبحيون التعدد بغير حساب، وكذا الحال عند الأوربيين والرومان والجرمانيين، وأباحه بعض البابوات لملوك الإفراج، وعدد العرب في الجاهلية بغير حساب، حتى كان الرجل يجتمع تحته عشر نسوة، وثبت في الصحيح أن النبي سليمان عليه السلام كان تحته أكثر من ستين امرأة.. فإيهام الناس أن دين الإسلام هو الذي أنشأ تعدد الزوجات غير صحيح.", "page": 349, "id": "unit-26__lesson-20__b17", "inline": [{"t": "text", "s": "كان اليونانيون يبيعون النساء في الأسواق ويبحيون التعدد بغير حساب، وكذا الحال عند الأوربيين والرومان والجرمانيين، وأباحه بعض البابوات لملوك الإفراج، وعدد العرب في الجاهلية بغير حساب، حتى كان الرجل يجتمع تحته عشر نسوة، وثبت في الصحيح أن النبي سليمان "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " كان تحته أكثر من ستين امرأة.. فإيهام الناس أن دين الإسلام هو الذي أنشأ تعدد الزوجات غير صحيح."}]}, {"type": "paragraph", "md": "فتعدد الزوجات قضية فطرية متعارف عليها في جميع الأمم؛ على اختلاف بينهم في التطبيق، وحينما يحظر قانون البشر تعدد الزوجات؛ يتجه الناس إلى إقامة علاقات محرمة خارج البيوت.. فلذلك يأتي هذا التشريع الإلهي الحكيم، ولو جهلت المسلمة وجه الحكمة فيه؛ فعليه التسليم؛ فهذا ابتلاء من الله تعالى للمرأة أتؤمن وتسلم بأمر الله، أم تشكك في حُكمه وحِكمته؟", "page": 350, "id": "unit-26__lesson-20__b18"}, {"type": "paragraph", "md": "وقد أباح الشرع التعددَ بضوابط شرعية دقيقة؛ تُستنبط من الكتاب والسنة، وتبين عظمة هذا التشريع؛ منها:", "page": 350, "id": "unit-26__lesson-20__b19"}, {"type": "paragraph", "md": "1- أن الإسلام لم يوجب التعدد بل أباحه، وندب لتركه لمن خاف الظلم: ﴿فَإِنۡ خِفۡتُمۡ أَلَّا تَعۡدِلُواْ فَوَٰحِدَةً﴾.", "page": 350, "id": "unit-26__lesson-20__b20", "inline": [{"t": "text", "s": "1- أن الإسلام لم يوجب التعدد بل أباحه، وندب لتركه لمن خاف الظلم: "}, {"t": "ayah", "s": "فَإِنۡ خِفۡتُمۡ أَلَّا تَعۡدِلُواْ فَوَٰحِدَةً", "ayah": [], "verses": [{"n": 3, "text": "فَإِنۡ خِفۡتُمۡ أَلَّا تَعۡدِلُواْ فَوَٰحِدَةً", "surah": 4, "surah_name": "النساء", "ref": "4:3", "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:3"}], "surah": 4, "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:3", "surah_name": "النساء", "ayah_canonical": 3, "match": "contained", "ref": "4:3"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- حدده بأربع وهو القدر الذي تُطيقه المرأة، وقد كان قبل الإسلام دون تحديد، فضبطه.", "page": 350, "id": "unit-26__lesson-20__b21", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- أوجب العدل على الرجل، قال صلى الله عليه وسلم : (من كانت له امرأتان فمال إلى إحداهما؛ جاء يوم القيامة وشقه مائل) والعدل ليس الكفاية المادية فقط كما يظن البعض؛ بل يجب العدل في المبيت والنفقة والسكنى، وأما ميل القلب في حب أحد نسائه فلا ضير فيه: (اللهم هذا قسمي فيما أملك فلا تلمني فيما لا أملك).", "page": 350, "id": "unit-26__lesson-20__b22", "inline": [{"t": "text", "s": "3- أوجب العدل على الرجل، قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(من كانت له امرأتان فمال إلى إحداهما؛ جاء يوم القيامة وشقه مائل)", "role": "emphasis"}, {"t": "text", "s": " والعدل ليس الكفاية المادية فقط كما يظن البعض؛ بل يجب العدل في المبيت والنفقة والسكنى، وأما ميل القلب في حب أحد نسائه فلا ضير فيه: "}, {"t": "emphasis", "s": "(اللهم هذا قسمي فيما أملك فلا تلمني فيما لا أملك)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- التعدد في المجتمع الإسلامي حق للمرأة قبل الرجل، لأن فيه حلا لكثير من مشكلات النساء الأرامل والمطلقات والعوانس؛ فبه تُرفع المرأة إلى شرف الزوجية، وتبني أسرتها، وأما المرأة الأولى فقد تكون مريضة أو عقيمًا أو مشغولة عن أسرتها بشاغل ما؛ فلا يُطلقها الزوج بل يأتي بمن تنشغلُ بمصالحه وتكمل له نقصه في باب الزوجية، وبهذا يحفظ زوجته الأولى وياتي بأخرى يحفظها من فتنة بقائها بلا زوج.", "page": 350, "id": "unit-26__lesson-20__b23", "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "في التعدد تحقيق السعادة الاجتماعية عندما يتم الالتزام فيه بالشرع؛ فينتشر التراحم والتكامل الاجتماعي، فتعدد الزوجات هو الحل الـمثالي الأول للواقع البشري الاجتماعي، ومعالجة الأنانية في النفوس البشرية، ويحقق حق النساء في إيجاد البديل عن العبث بالنساء ضمن تجارة البغاء والعلاقات المؤقتة.", "page": 350, "id": "unit-26__lesson-20__b24"}, {"type": "paragraph", "md": "فلماذا يصر البعض على تدمير حقوق المرأة الواجبة على الرجل بمبدأ الخليلات (والجيرل فرند) الذي لا يعني إلا العبث بكرامة المرأة، وعدم تحمل مسؤولية الزواج، والقيام على الأسرة؟!", "page": 350, "id": "unit-26__lesson-20__b25", "inline": [{"t": "text", "s": "فلماذا يصر البعض على تدمير حقوق المرأة الواجبة على الرجل بمبدأ الخليلات "}, {"t": "emphasis", "s": "(والجيرل فرند)", "role": "emphasis"}, {"t": "text", "s": " الذي لا يعني إلا العبث بكرامة المرأة، وعدم تحمل مسؤولية الزواج، والقيام على الأسرة؟!"}]}, {"type": "paragraph", "md": "مع التذكير أن غيرة المرأة على الرجل أمر طبيعي جِبلِّي فقد كن نساء النبي صلى الله عليه وسلم يغرن عليه وهن أفضل النساء.", "page": 350, "id": "unit-26__lesson-20__b26", "inline": [{"t": "text", "s": "مع التذكير أن غيرة المرأة على الرجل أمر طبيعي جِبلِّي فقد كن نساء النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يغرن عليه وهن أفضل النساء."}]}, {"type": "paragraph", "md": "الأسئلة التقويمية: 1- اذكري ثلاثة حقوق للمرأة يؤديها لها المجتمع المسلم.", "page": 350, "id": "unit-26__lesson-20__b27"}, {"type": "paragraph", "md": "2- هل في التعدد مصلحة للمرأة.. بيني ذلك؛ وهل التعدد واجب أم مباح؟!", "page": 350, "id": "unit-26__lesson-20__b28", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- أجيبي عن قولهم: «لقد حبستم المرأة في البيوت..» هل هذا صحيح؟", "page": 350, "id": "unit-26__lesson-20__b29", "inline": [{"t": "text", "s": "3- أجيبي عن قولهم: "}, {"t": "quote", "s": "لقد حبستم المرأة في البيوت.."}, {"t": "text", "s": " هل هذا صحيح؟"}], "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "نشاط دعوي واجتماعي", "page": 350, "id": "unit-26__lesson-20__b30", "role": "activity"}, {"type": "paragraph", "md": "1- نسعى لنشرِ هذه الحقوق الاجتماعية في أسواط المجتمع المسلم.. نكلم أزواجنا وندعوهم لنشرها.", "page": 350, "id": "unit-26__lesson-20__b31", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- نزور امرأة عدد عليها زوجها ونكلمها عن ضرورة الرضا بقضاء الله وقدره والتسليم لحكمه.", "page": 350, "id": "unit-26__lesson-20__b32", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "منارات الهدى", "page": 351, "id": "unit-26__lesson-20__b33", "item_role": "activity_step"}]' WHERE id='unit-26__lesson-20';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-21','unit-26',21,'أحكام الحيض والنفاس','الفقه',NULL,0,0,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 351, "id": "unit-26__lesson-21__b01", "role": "objectives"}, {"type": "paragraph", "md": "1- معرفة أحكام الحيض والنفاس في الشريعة الإسلامية، وأحوال النساء فيها.", "page": 351, "id": "unit-26__lesson-21__b02", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ذكر الأدلة على أصول أحكام الاستحاضة المَرَضية وأحوال المستحاضة من النساء.", "page": 351, "id": "unit-26__lesson-21__b03", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "أولا: أحكام الحيض", "page": 351, "id": "unit-26__lesson-21__b04", "role": "rulings"}, {"type": "paragraph", "md": "الحيض لغة: السيلان. يقال حاض الوادي إذا سال. وشرعا: دم جِبِلَّة -أي خلقة وطبيعة- تقتضيه الطباع السليمة يخرج من أقصى رحم المرأة بعد بلوغها على سبيل الصحة، في أوقات معلومة.", "page": 351, "id": "unit-26__lesson-21__b05", "inline": [{"t": "text", "s": "الحيض لغة: السيلان. يقال حاض الوادي إذا سال. "}, {"t": "emphasis", "s": "وشرعا", "role": "emphasis"}, {"t": "text", "s": ": دم جِبِلَّة -أي خلقة وطبيعة- تقتضيه الطباع السليمة يخرج من أقصى رحم المرأة بعد بلوغها على سبيل الصحة، في أوقات معلومة."}]}, {"type": "paragraph", "md": "لا حيضَ قبل تسع سنين قمرية، ولا يوجد سن محدد لانقطاعه عن المرأة، والدليلُ: الاستقراءُ.", "page": 351, "id": "unit-26__lesson-21__b06"}, {"type": "paragraph", "md": "وأقلُّهُ في الزمان: يومٌ وليلةٌ وأكثَرُه: نصفُ شهر، وأوسَطُه: ستة أو سبعة أيام.", "page": 351, "id": "unit-26__lesson-21__b07"}, {"type": "paragraph", "md": "وأقل طهر بين الحيضتين خمسة عشر يومًا، ولا حد لأكثر الطهر؛ فقد لا تحيض المرأة سنة أو سنين.", "page": 351, "id": "unit-26__lesson-21__b08"}, {"type": "paragraph", "md": "فإذا رأت المرأة دمًا أقل من مدة الحيض يومًا وليلة أو رأت الدم بعد مدة أكثر الحيض؛ اعتبر دم استحاضة، لا حيض. ويتميز دم الحيض عن الاستحاضة بلونه وشدته.", "page": 351, "id": "unit-26__lesson-21__b09"}, {"type": "paragraph", "md": "والحامل لا تحيض، ودَمُها دم فساد، ودليله قول النبي صلى الله عليه وسلم : (لا تُوطَأُ حَامِلٌ حتى تَضَعَ، ولا غَيْرُ ذَاتِ حَمْلٍ حتى تَحِيضَ حَيْضَةً)، ومفوم المخالفة أن الحامل لا تحيض؛ فدم الحامل دم فساد.", "page": 351, "id": "unit-26__lesson-21__b10", "inline": [{"t": "emphasis", "s": "والحامل", "role": "emphasis"}, {"t": "text", "s": " لا تحيض، ودَمُها دم فساد، ودليله قول النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لا تُوطَأُ حَامِلٌ حتى تَضَعَ، ولا غَيْرُ ذَاتِ حَمْلٍ حتى تَحِيضَ حَيْضَةً)", "role": "emphasis"}, {"t": "text", "s": "، ومفوم المخالفة أن الحامل لا تحيض؛ فدم الحامل دم فساد."}]}, {"type": "paragraph", "md": "والصُّفرةُ والكُدْرَةُ في أيام الحيض حيضٌ، لقول عائشة رضي الله عنها : «لا تَعْجَلْنَ حتَّى ترَيْنَ القَصَّةَ البَيْضاءَ»، وأمّا حديثُ أُمِّ عطية رضي الله عنها : «كُنَّا لا نعُدُّ الكُدْرَةَ والصُّفْرةَ بَعْدَ الطُّهْرِ شَيئًا»؛ فمحمولٌ على الكدرة بعد الطُّهر.", "page": 351, "id": "unit-26__lesson-21__b11", "inline": [{"t": "text", "s": "والصُّفرةُ والكُدْرَةُ في أيام الحيض حيضٌ، لقول عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " : "}, {"t": "quote", "s": "لا تَعْجَلْنَ حتَّى ترَيْنَ القَصَّةَ البَيْضاءَ"}, {"t": "text", "s": "، وأمّا حديثُ أُمِّ عطية "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " : "}, {"t": "quote", "s": "كُنَّا لا نعُدُّ الكُدْرَةَ والصُّفْرةَ بَعْدَ الطُّهْرِ شَيئًا"}, {"t": "text", "s": "؛ فمحمولٌ على الكدرة بعد الطُّهر."}]}, {"type": "paragraph", "md": "وتترك المرأة الصلاة والصيام إذا حاضت، ولا يأتيها زوجها، ولا تمس المصحف إلا بحائل، وتقرأه بنية ذكر الله تعالى لا بنية القرآن خروجًا من الخلاف، ويجب عليها الغسل بعد انقطاع الدم؛ قال صلى الله عليه وسلم : (فإذا أقبلت ‌الحيضة فدعي الصلاة، وإذا أدبرت فاغسلي عنك الدم وصلي) وتقضي الصوم ولا تقضي الصلاة.", "page": 351, "id": "unit-26__lesson-21__b12", "inline": [{"t": "text", "s": "وتترك المرأة الصلاة والصيام إذا حاضت، ولا يأتيها زوجها، ولا تمس المصحف إلا بحائل، وتقرأه بنية ذكر الله تعالى لا بنية القرآن خروجًا من الخلاف، ويجب عليها الغسل بعد انقطاع الدم؛ قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(فإذا أقبلت ‌الحيضة فدعي الصلاة، وإذا أدبرت فاغسلي عنك الدم وصلي)", "role": "emphasis"}, {"t": "text", "s": " وتقضي الصوم ولا تقضي الصلاة."}]}, {"type": "heading", "level": 3, "text": "ثانيًا: أحكام الاستحاضة", "page": 351, "id": "unit-26__lesson-21__b13", "role": "rulings"}, {"type": "paragraph", "md": "هو دم علة ومرض يخرج من عرق من أدنى الرحم يقال له: العاذل، وهذا الدم ينقض الوضوء، ولا يوجب الغسل، ولا يوجب ترك الصلاة ولا الصوم ولا يحرم معه أن يأتيها زوجها؛ فالمستحاضة تغسل الدم، وتربط على موضعه، وتتوضأ لكل فرض، وتصلي، وأصولُ أحكام الاستحاضة في ثلاثة أحاديث:", "page": 351, "id": "unit-26__lesson-21__b14", "inline": [{"t": "text", "s": "هو دم علة ومرض يخرج من عرق من أدنى الرحم يقال له: العاذل، وهذا الدم ينقض الوضوء، ولا يوجب الغسل، ولا يوجب ترك الصلاة ولا الصوم ولا يحرم معه أن يأتيها زوجها؛ فالمستحاضة تغسل الدم، وتربط على موضعه، وتتوضأ لكل فرض، وتصلي، "}, {"t": "emphasis", "s": "وأصولُ أحكام الاستحاضة في ثلاثة أحاديث:", "role": "emphasis"}]}, {"type": "paragraph", "md": "أ- حديث فاطمة بنت أبي حبيش رضي الله عنها ، أنَّها كانت تُستَحاضُ، فقال لها النبيَّ صلى الله عليه وسلم : (إنَّ دَمَ الحَيْضِ دَمٌ أَسْوَدُ يُعْرَفُ فَإِذَا كَانَ ذَلِكَ فَأَمْسِكِي عنِ الصَّلاةِ فَإِذَا كَانَ الآخَرُ فَتَوَضَّئي وصلِّي).", "page": 352, "id": "unit-26__lesson-21__b15", "inline": [{"t": "text", "s": "أ- حديث فاطمة بنت أبي حبيش "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " ، أنَّها كانت تُستَحاضُ، فقال لها النبيَّ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إنَّ دَمَ الحَيْضِ دَمٌ أَسْوَدُ يُعْرَفُ فَإِذَا كَانَ ذَلِكَ فَأَمْسِكِي عنِ الصَّلاةِ فَإِذَا كَانَ الآخَرُ فَتَوَضَّئي وصلِّي)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ب- وحديث عائشة رضي الله عنها أنَّ النبي صلى الله عليه وسلم قال لأمِّ حبيبة بنت جحش وكانت تستحيض: (امْكُثِي قَدْرَ ما كَانَتْ تَحْبِسُكِ حَيْضَتُكِ ثُمَّ اغْتَسِلِي).", "page": 352, "id": "unit-26__lesson-21__b16", "inline": [{"t": "text", "s": "ب- وحديث عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " أنَّ النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قال لأمِّ حبيبة بنت جحش وكانت تستحيض: "}, {"t": "emphasis", "s": "(امْكُثِي قَدْرَ ما كَانَتْ تَحْبِسُكِ حَيْضَتُكِ ثُمَّ اغْتَسِلِي)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ج- وحديث حَمْنَة بنت جحش رضي الله عنها أن النبي صلى الله عليه وسلم قال لها وكانت مستحاضة: (إِنَّمَا هَذِهِ رَكْضَةٌ مِنْ رَكَضَات الشَّيْطَانِ فَتَحَيَّضِي سِتَّةَ أَيَّامٍ أَوْ سَبْعَةَ أَيَّامٍ في عِلْمِ الله، ثُمَّ اغْتَسِلِي)؛ فهذه حالات ثلاثة عليها مدار الباب:", "page": 352, "id": "unit-26__lesson-21__b17", "inline": [{"t": "text", "s": "ج- وحديث حَمْنَة بنت جحش "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " أن النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قال لها وكانت مستحاضة: "}, {"t": "emphasis", "s": "(إِنَّمَا هَذِهِ رَكْضَةٌ مِنْ رَكَضَات الشَّيْطَانِ فَتَحَيَّضِي سِتَّةَ أَيَّامٍ أَوْ سَبْعَةَ أَيَّامٍ في عِلْمِ الله، ثُمَّ اغْتَسِلِي)", "role": "emphasis"}, {"t": "text", "s": "؛ "}, {"t": "emphasis", "s": "فهذه حالات ثلاثة عليها مدار الباب:", "role": "emphasis"}]}, {"type": "paragraph", "md": "1- الحالة الأولى: مَن كانت دورتها الشهرية معتادةً ثم اضطربت دورتها، فهذه تعملُ بعادتها السابقة ومدة حيضها ولا يضرُّها التغيّر، والدم بهذا التغيُّر دمُ عِرقٍ واستحاضة، ودم الحيض هو عادتها فقط.", "page": 352, "id": "unit-26__lesson-21__b18", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2-الثانية: امرأةٌ غير معتادة، ولكنها تُمَيِّزُ دَمَ الحَيْض عن غَيْرِهِ بلونه أو بريحه؛ فهذه تعمَلُ بهذا التمييز.", "page": 352, "id": "unit-26__lesson-21__b19"}, {"type": "paragraph", "md": "3-الثالثة: امرأةٌ لا تُمَيِّزُ ولم يكُن لها عادةٌ سابقة؛ فهذه كالمرأة المبتدأة في الحيض؛ فتعمَلُ بحديث حَمْنَة، وهو تركُ الصلاة سبعةَ أيامٍ أو سِتةٍ، وذلك بحسب أقرب النساء لها، إذ فيه: (كَمَا تَحيضُ النِّساءُ).", "page": 352, "id": "unit-26__lesson-21__b20", "inline": [{"t": "text", "s": "3-الثالثة: امرأةٌ لا تُمَيِّزُ ولم يكُن لها عادةٌ سابقة؛ فهذه كالمرأة المبتدأة في الحيض؛ فتعمَلُ بحديث حَمْنَة، وهو تركُ الصلاة سبعةَ أيامٍ أو سِتةٍ، وذلك بحسب أقرب النساء لها، إذ فيه: "}, {"t": "emphasis", "s": "(كَمَا تَحيضُ النِّساءُ)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "فإن تنُوزِعَ بين العادة وبين التمييز عُمِلَ بالتمييز لأنه أقوى؛ فالمرأة المعتادة التي تُمَيِّزُ دَمَ الحَيْضِ عن غيره باللون والرائحة تعمل بالتمييز، فإن اشتبهَ عليها الدم فتعمل بالعادة.", "page": 352, "id": "unit-26__lesson-21__b21"}, {"type": "paragraph", "md": "ولا تلفيق في الأيام؛ بل السحب، أي: إذا طَهُرَت الحائض يومًا وأتاها الدم يومًا أثناء عادتها؛ فكله حَيْضٌ.", "page": 352, "id": "unit-26__lesson-21__b22"}, {"type": "heading", "level": 3, "text": "ثالثًا: أحكام النفاس والولادة", "page": 352, "id": "unit-26__lesson-21__b23", "role": "rulings"}, {"type": "paragraph", "md": "النفاس لغة: الولادة. وشرعًا: الدم الخارج عقب الولادة. وسمي نفاسًا لخروجه عقب خروج النفس.", "page": 352, "id": "unit-26__lesson-21__b24"}, {"type": "paragraph", "md": "والدم الذي يخرج أثناء الطلق، أو مع خروج الولد، لا يعتبر دم نفاس؛ لتقدمه على خروج الولد، بل يعتبر دم فساد، فتجب الصلاة أثناء الطلق ولو رأت الدم، وإذا لم تتمكن من الصلاة، وجب قضاؤها.", "page": 352, "id": "unit-26__lesson-21__b25"}, {"type": "paragraph", "md": "وأقل مدة النفاس لحظة، وقد يمتد أيامًا، وأكثره ستون، فما زاد عليا فهو استحاضة.", "page": 352, "id": "unit-26__lesson-21__b26"}, {"type": "paragraph", "md": "الأسئلة التقويمية: 1- فرقي بين الحيض والاستحاضة؟ وما حكم الدم الخارج قبل وضع الولد.", "page": 352, "id": "unit-26__lesson-21__b27"}, {"type": "paragraph", "md": "2- امرأة كانت تحيض خمسة أيام ثم حاضت عشرة؛ فكم مدة حيضها؟", "page": 352, "id": "unit-26__lesson-21__b28", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط دعوي واجتماعي", "page": 352, "id": "unit-26__lesson-21__b29", "role": "activity"}, {"type": "paragraph", "md": "نرجع إلى كتاب « الإفادة بأحكام الحيض والنفاس والاستحاضة» للشيخ الطيار، ونتوسع أكثر في الباب..", "page": 352, "id": "unit-26__lesson-21__b30", "inline": [{"t": "text", "s": "نرجع إلى كتاب "}, {"t": "quote", "s": "الإفادة بأحكام الحيض والنفاس والاستحاضة"}, {"t": "text", "s": " للشيخ الطيار، ونتوسع أكثر في الباب.."}], "item_role": "activity_step"}, {"type": "paragraph", "md": "منارات الهدى", "page": 352, "id": "unit-26__lesson-21__b31", "item_role": "activity_step"}]' WHERE id='unit-26__lesson-21';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-22','unit-26',22,'آداب المعاشرة الزوجية','الأسرة والمرأة',NULL,0,1,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 352, "id": "unit-26__lesson-22__b01", "role": "objectives"}, {"type": "paragraph", "md": "1- التعرف على أحكام المعاشرة بين الزوجين «الجماع ومقدماته»، وأنَّ هذا لا يمنع الحياء من تعلمه.", "page": 352, "id": "unit-26__lesson-22__b02", "inline": [{"t": "text", "s": "1- التعرف على أحكام المعاشرة بين الزوجين "}, {"t": "quote", "s": "الجماع ومقدماته"}, {"t": "text", "s": "، وأنَّ هذا لا يمنع الحياء من تعلمه."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- معرفة مقاصد الجماع ولماذا أباحته الشريعة وأذنت به ورتبت عليه الأجر.", "page": 352, "id": "unit-26__lesson-22__b03", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "أولا: مقاصد النكاح وأغراضه", "page": 352, "id": "unit-26__lesson-22__b04", "role": "section"}, {"type": "paragraph", "md": "قال الإمام ابن القيم رحمه الله : «وأمَّا الجماع والباه، فكان هديه فيه صلى الله عليه وسلم أكمل هديٍ ‌يحفظ ‌به ‌الصِّحَّة، وتتمُّ به اللَّذَّة وسرور النَّفس، ويحصل به مقاصده الَّتي وضع لأجلها.", "page": 352, "id": "unit-26__lesson-22__b05", "inline": [{"t": "text", "s": "قال الإمام ابن القيم "}, {"t": "honorific", "s": "رحمه الله"}, {"t": "text", "s": " : «وأمَّا الجماع والباه، فكان هديه فيه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أكمل هديٍ ‌يحفظ ‌به ‌الصِّحَّة، وتتمُّ به اللَّذَّة وسرور النَّفس، ويحصل به مقاصده الَّتي وضع لأجلها."}]}, {"type": "paragraph", "md": "فإنَّ الجماع في الأصل وضع لثلاثة أمورٍ هي مقاصده الأصليَّة:", "page": 352, "id": "unit-26__lesson-22__b06"}, {"type": "paragraph", "md": "1- أحدها: حفظ النَّسل ودوام النَّوع إلى أن تتكامل العِدَّة الَّتي قدَّر الله بروزها إلى هذا العالم.", "page": 352, "id": "unit-26__lesson-22__b07", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- الثَّاني: إخراج الماء الذي يضرُّ احتباسه واحتقانه بجملة البدن.", "page": 352, "id": "unit-26__lesson-22__b08", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- الثَّالث: قضاء الوطر ونيل اللَّذَّة والتَّمتُّع بالنِّعمة؛ وهذه وحدها هي الفائدة الَّتي في الجنَّة، إذ لا تناسل هناك ولا احتقان يستفرغه الإنزال. وفضلاء الأطبَّاء يرون أنَّ الجماع من أحد أسباب حفظ الصِّحَّة».", "page": 352, "id": "unit-26__lesson-22__b09", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "ومن منافعه: غضُّ البصر، وكفُّ النَّفس، والقدرة على العفَّة عن الحرام وتحصيل ذلك للمرأة؛ فهو ينفع نفسه في دنياه وأخراه، وينفع المرأة. ولذلك كان صلى الله عليه وسلم يتعاهده ويحبُّه، ويقول: (حبِّب إليَّ من دنياكم: النِّساء والطِّيب)، وقال: (يا معشر الشَّباب، من استطاع منكم الباءة فليتزوَّج، فإنَّه أغضُّ للبصر، وأحصَنُ للفرج. ومن لم يستطع فعليه بالصَّوم، فإنَّه له وِجاءٌ)، وقال (الدُّنيا متاعٌ، وخيرُ متاعها المرأة الصَّالحة)».", "page": 352, "id": "unit-26__lesson-22__b10", "inline": [{"t": "text", "s": "ومن منافعه: غضُّ البصر، وكفُّ النَّفس، والقدرة على العفَّة عن الحرام وتحصيل ذلك للمرأة؛ فهو ينفع نفسه في دنياه وأخراه، وينفع المرأة. ولذلك كان "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يتعاهده ويحبُّه، ويقول: "}, {"t": "emphasis", "s": "(حبِّب إليَّ من دنياكم: النِّساء والطِّيب)", "role": "emphasis"}, {"t": "text", "s": "، وقال: "}, {"t": "emphasis", "s": "(يا معشر الشَّباب، من استطاع منكم الباءة فليتزوَّج، فإنَّه أغضُّ للبصر، وأحصَنُ للفرج. ومن لم يستطع فعليه بالصَّوم، فإنَّه له وِجاءٌ)", "role": "emphasis"}, {"t": "text", "s": "، وقال "}, {"t": "emphasis", "s": "(الدُّنيا متاعٌ، وخيرُ متاعها المرأة الصَّالحة)", "role": "emphasis"}, {"t": "text", "s": "»."}]}, {"type": "paragraph", "md": "ثانيًا: آداب الجماع وأحكامه الشرعية؛ فإنَّ للجماع آدابًا حث عليها الإسلام، وصولًا به إلى العمل الكريم اللائق بالإنسان، وتحقيقًا للأهداف المرجوة من النكاح، ومن هذه الآداب:", "page": 352, "id": "unit-26__lesson-22__b11", "inline": [{"t": "text", "s": "ثانيًا: آداب الجماع وأحكامه الشرعية؛ فإنَّ للجماع آدابًا حث عليها الإسلام، وصولًا به إلى العمل الكريم اللائق بالإنسان، وتحقيقًا للأهداف المرجوة من النكاح، "}, {"t": "emphasis", "s": "ومن هذه الآداب:", "role": "emphasis"}]}, {"type": "paragraph", "md": "1- التطيب قبل الجماع: ففي الصحيحين من حديث عائشة رضي الله عنها قالت: «كنت أطيب رسول الله صلى الله عليه وسلم ، فيطوف على نسائه ثم يصبح محرمًا ينضخ طيبًا».", "page": 352, "id": "unit-26__lesson-22__b12", "inline": [{"t": "text", "s": "1- التطيب قبل الجماع: ففي الصحيحين من حديث عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " قالت: "}, {"t": "quote", "s": "كنت أطيب رسول الله صلى الله عليه وسلم ، فيطوف على نسائه ثم يصبح محرمًا ينضخ طيبًا"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ملاعبة الزوجة ومداعبتها قبل الجماع: لتنهض شهوتها فتنال من اللذة مثله؛ فلها من الحق كالرجل.", "page": 352, "id": "unit-26__lesson-22__b13", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- ويقولُ قبل أن يجامع أهله ما علمناه النبي صلى الله عليه وسلم : (لو أن أحدكم إذا أراد أن يأتي أهله قال: باسم الله، اللهم جنبنا الشيطان وجنب الشيطان ما رزقتنا، فإنه إن يقدر بينهما ولد في ذلك لم يضره شيطان أبدا).", "page": 353, "id": "unit-26__lesson-22__b14", "inline": [{"t": "text", "s": "3- ويقولُ قبل أن يجامع أهله ما علمناه النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لو أن أحدكم إذا أراد أن يأتي أهله قال: باسم الله، اللهم جنبنا الشيطان وجنب الشيطان ما رزقتنا، فإنه إن يقدر بينهما ولد في ذلك لم يضره شيطان أبدا)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- والجماع لا يجوز إلا في الفرج -القُبل- الذي هو موضع الولادة والحرث؛ سواء جامعها فيه من الأمام أو من الخلف، فعن جابر رضي الله عنه قال: كانت اليهود تقول: إذا أتى الرجل امرأته من دبرها في قبلها كان الولد أحول، فنزلت: ﴿نِسَآؤُكُمۡ حَرۡثٞ لَّكُمۡ فَأۡتُواْ حَرۡثَكُمۡ أَنَّىٰ شِئۡتُمۡۖ﴾» والحرث موضع الولد.", "page": 353, "id": "unit-26__lesson-22__b15", "inline": [{"t": "text", "s": "4- والجماع لا يجوز إلا في الفرج -القُبل- الذي هو موضع الولادة والحرث؛ سواء جامعها فيه من الأمام أو من الخلف، فعن جابر "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قال: كانت اليهود تقول: إذا أتى الرجل امرأته من دبرها في قبلها كان الولد أحول، فنزلت: "}, {"t": "ayah", "s": "نِسَآؤُكُمۡ حَرۡثٞ لَّكُمۡ فَأۡتُواْ حَرۡثَكُمۡ أَنَّىٰ شِئۡتُمۡۖ", "ayah": [], "verses": [{"n": 223, "text": "نِسَآؤُكُمۡ حَرۡثٞ لَّكُمۡ فَأۡتُواْ حَرۡثَكُمۡ أَنَّىٰ شِئۡتُمۡۖ", "surah": 2, "surah_name": "البقرة", "ref": "2:223", "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:223"}], "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:223", "surah_name": "البقرة", "ayah_canonical": 223, "match": "contained", "ref": "2:223"}, {"t": "text", "s": "» والحرث موضع الولد."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- إذا قضى الزوج أربه فلا ينزع حتى تقضي الزوجة أربها؛ فلها من الحقوق مثله، حتى يعفها ويكفيَها.", "page": 353, "id": "unit-26__lesson-22__b16", "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6- يحرم وطء الحائض؛ قال صلى الله عليه وسلم : (من أتى حائضًا أو امرأة في دبرها أو كاهنًا فقد كفر بما أنزل على محمد)، ويحرم الوطء في الدبر؛ لأنه موضع النجس والخبث، وقد قال النبي صلى الله عليه وسلم : (ملعون من أتى امرأته في دبرها)، والشريعة تحرم مقاربة الخَبث، والدبر للعذرة لا للنكاح.", "page": 353, "id": "unit-26__lesson-22__b17", "inline": [{"t": "text", "s": "6- يحرم وطء الحائض؛ قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(من أتى حائضًا أو امرأة في دبرها أو كاهنًا فقد كفر بما أنزل على محمد)", "role": "emphasis"}, {"t": "text", "s": "، ويحرم الوطء في الدبر؛ لأنه موضع النجس والخبث، وقد قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(ملعون من أتى امرأته في دبرها)،", "role": "emphasis"}, {"t": "text", "s": " والشريعة تحرم مقاربة الخَبث، والدبر للعذرة لا للنكاح."}], "list": {"type": "ordered", "marker": "6"}}, {"type": "paragraph", "md": "7- يحرم إفشاء ما بين الزوجين مما يتصل بالمعاشرة وأسرار الزوجية، فقد قال النبي صلى الله عليه وسلم : (إن من شر الناس عند الله منزلة يوم القيامة الرجل يفضي إلى امرأته وتفضي إليه ثم ينشر سرها).", "page": 353, "id": "unit-26__lesson-22__b18", "inline": [{"t": "text", "s": "7- يحرم إفشاء ما بين الزوجين مما يتصل بالمعاشرة وأسرار الزوجية، فقد قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إن من شر الناس عند الله منزلة يوم القيامة الرجل يفضي إلى امرأته وتفضي إليه ثم ينشر سرها)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "7"}}, {"type": "paragraph", "md": "8- يجب الغسل من الجماع ولو لم ينزل؛ لقوله صلى الله عليه وسلم : (إذا جلس بين شعبها الأربع ثم جهدها فقد وجب عليه الغسل وإن لم ينزل)، وفي رواية: (إذا جلس بين شعبها الأربع ومس الختان الختان، فقد وجب الغسل)، فالعبرة بالإدخال لا بالإنزال.. فمن أنزل أو أدخل وجب عليه الغسل.", "page": 353, "id": "unit-26__lesson-22__b19", "inline": [{"t": "text", "s": "8- يجب الغسل من الجماع ولو لم ينزل؛ لقوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إذا جلس بين شعبها الأربع ثم جهدها فقد وجب عليه الغسل وإن لم ينزل)", "role": "emphasis"}, {"t": "text", "s": "، وفي رواية: "}, {"t": "emphasis", "s": "(إذا جلس بين شعبها الأربع ومس الختان الختان، فقد وجب الغسل)", "role": "emphasis"}, {"t": "text", "s": "، فالعبرة بالإدخال لا بالإنزال.. فمن أنزل أو أدخل وجب عليه الغسل."}], "list": {"type": "ordered", "marker": "8"}}, {"type": "paragraph", "md": "ويجوز للزوجين أن يغتسلا معا ولو رأى كل منهما من الآخر كل شيء؛ فلا عورةَ بين الزوجين", "page": 353, "id": "unit-26__lesson-22__b20"}, {"type": "paragraph", "md": "فإذا التزم الإنسان هذه الآداب مع غض بصره عن الحرام، واستشعار نعمة الله عليه في الزواج، واستحضار نية إعفاف أهله ووقايتهم من الحرام؛ تحقق له مراده في الإشباع الجنسي له ولأهله، ويأخذ الأجر بنيته.", "page": 353, "id": "unit-26__lesson-22__b21"}, {"type": "paragraph", "md": "ولا مانع من الاستفادة من بعض الكتب النافعة التي عنيت بالحديث عن اللقاء بين الزوجين وعلاج مشاكل ذلك، ككتاب: «تحفة العروس»، وكتاب «اللقاء بين الزوجين»، وكتاب «متعة الحياة الزوجية».", "page": 353, "id": "unit-26__lesson-22__b22", "inline": [{"t": "text", "s": "ولا مانع من الاستفادة من بعض الكتب النافعة التي عنيت بالحديث عن اللقاء بين الزوجين وعلاج مشاكل ذلك، ككتاب: "}, {"t": "quote", "s": "تحفة العروس"}, {"t": "text", "s": "، وكتاب "}, {"t": "quote", "s": "اللقاء بين الزوجين"}, {"t": "text", "s": "، وكتاب "}, {"t": "quote", "s": "متعة الحياة الزوجية"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "الأسئلة التقويمية: 1- اذكري أربعة آداب للجماع؟ ثم عقبي بذكر مقصدين من مقاصد الجماع.", "page": 353, "id": "unit-26__lesson-22__b23"}, {"type": "paragraph", "md": "2- ما حكم نكاح المرأة في دبرها أو وهي حائض؟ وهل يجوز لها طاعة الزوج في ذلك؟", "page": 353, "id": "unit-26__lesson-22__b24", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط دعوي واجتماعي", "page": 353, "id": "unit-26__lesson-22__b25", "role": "activity"}, {"type": "paragraph", "md": "1- ننشر هذه الآداب بحياء وأدبٍ في وسط خمس نسوة نظن أنها لا تعرف هذه الأحكام..", "page": 353, "id": "unit-26__lesson-22__b26", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- نرجع إلى كتاب «تحفة العروس» لاستانبولي، ونقرأ فصل «في مخدع العرس والسعادة»", "page": 353, "id": "unit-26__lesson-22__b27", "inline": [{"t": "text", "s": "2- نرجع إلى كتاب "}, {"t": "quote", "s": "تحفة العروس"}, {"t": "text", "s": " لاستانبولي، ونقرأ فصل "}, {"t": "quote", "s": "في مخدع العرس والسعادة"}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "منارات الهدى", "page": 354, "id": "unit-26__lesson-22__b28", "item_role": "activity_step"}]' WHERE id='unit-26__lesson-22';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-23','unit-26',23,'أحكام زينة المرأة المسلمة','الفقه',NULL,1,4,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 354, "id": "unit-26__lesson-23__b01", "role": "objectives"}, {"type": "paragraph", "md": "- التعرف على أحكام الزينة للمرأة المسلمة، باستثناء أحكام الوجه وتغطية الوجه والكفين فقد تقدما.", "page": 354, "id": "unit-26__lesson-23__b02", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "أولا: أسباب التساهل في زينة المرأة المسلمة وحدوث الإشكالات الشرعية:", "page": 354, "id": "unit-26__lesson-23__b03", "role": "section"}, {"type": "paragraph", "md": "اللباس والزينة من أعظم الأسلحة التي حوربت بها المرأة -بل الأمة كلها- في عصرنا هذا، وكان من آثار ذلك أن تجاوزت كثير من النساء حدودَ الإسلام في اللباس والزينة، ولهذا التجاوز أسباب:", "page": 354, "id": "unit-26__lesson-23__b04"}, {"type": "paragraph", "md": "1- أن المرأة مفطورة على حب الحليِّ والزينة كما قال تعالى: ﴿أَوَمَن يُنَشَّؤُاْ فِي ٱلۡحِلۡيَةِ وَهُوَ فِي ٱلۡخِصَامِ غَيۡرُ مُبِينٖ﴾ والذي ينبغي ضبط هذه الفطرة بالضوابط الشرعية لئلا يحرفها الشيطان.", "page": 354, "id": "unit-26__lesson-23__b05", "inline": [{"t": "text", "s": "1- أن المرأة مفطورة على حب الحليِّ والزينة كما قال تعالى: "}, {"t": "ayah", "s": "أَوَمَن يُنَشَّؤُاْ فِي ٱلۡحِلۡيَةِ وَهُوَ فِي ٱلۡخِصَامِ غَيۡرُ مُبِينٖ", "ayah": [], "verses": [{"n": 18, "text": "أَوَمَن يُنَشَّؤُاْ فِي ٱلۡحِلۡيَةِ وَهُوَ فِي ٱلۡخِصَامِ غَيۡرُ مُبِينٖ", "surah": 43, "surah_name": "الزخرف", "ref": "43:18", "ref_api": "https://api.quran.com/api/v4/verses/by_key/43:18"}], "surah": 43, "ref_api": "https://api.quran.com/api/v4/verses/by_key/43:18", "surah_name": "الزخرف", "ayah_canonical": 18, "match": "exact", "ref": "43:18"}, {"t": "text", "s": " والذي ينبغي ضبط هذه الفطرة بالضوابط الشرعية لئلا يحرفها الشيطان."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- خفة التديُّن واتباع الهوى وعدم مراقبة الله تعالى لدى كثير من النساء؛ بسبب طول الأمل.", "page": 354, "id": "unit-26__lesson-23__b06", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- ارتياد أماكن التجمعات العامة لغير حاجة كالأسواق وبيوت الأزياء؛ فتتأثر المرأة بها سلبًا.", "page": 354, "id": "unit-26__lesson-23__b07", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- سلبية بعض الأولياء والأزواج؛ فلا تجد المرأة من أحدهم نصحًا أو اعتراضًا على ما ترتديه.", "page": 354, "id": "unit-26__lesson-23__b08", "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- سوء عشرة بعض الأزواج لزوجاتهم، وهجرانهم لهن، مع وجود صديقات سوء يأخذنها للشر!", "page": 354, "id": "unit-26__lesson-23__b09", "list": {"type": "ordered", "marker": "5"}}, {"type": "heading", "level": 3, "text": "ثانيًا: ضوابط التزين العامة في الشريعة الإسلامية:", "page": 354, "id": "unit-26__lesson-23__b10", "role": "section"}, {"type": "paragraph", "md": "الزِّينةُ: اسمٌ جامِعٌ لكُلِّ شَيءٍ يُتزيَّنُ به، ولزينة النساء في الشريعة الإسلامية ضوابط متعددة، أهمها:", "page": 354, "id": "unit-26__lesson-23__b11", "inline": [{"t": "emphasis", "s": "الزِّينةُ", "role": "emphasis"}, {"t": "text", "s": ": اسمٌ جامِعٌ لكُلِّ شَيءٍ يُتزيَّنُ به، "}, {"t": "emphasis", "s": "ولزينة النساء في الشريعة الإسلامية ضوابط متعددة، أهمها:", "role": "emphasis"}]}, {"type": "paragraph", "md": "1- الضابط الأول: ألَّا يكونَ فيه تشَبُّهٌ مِن النِّساءِ بالرِّجالِ ولا العكس؛ قال ابن عباس رضي الله عنهما : (لعنَ رَسولُ الله صلى الله عليه وسلم المتشَبِّهينَ مِن الرِّجالِ بالنِّساءِ، والمتشَبِّهاتِ مِن النِّساءِ بالرِّجالِ)", "page": 354, "id": "unit-26__lesson-23__b12", "inline": [{"t": "emphasis", "s": "1- الضابط الأول", "role": "emphasis"}, {"t": "text", "s": ": ألَّا يكونَ فيه تشَبُّهٌ مِن النِّساءِ بالرِّجالِ ولا العكس؛ قال ابن عباس "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لعنَ رَسولُ الله", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "المتشَبِّهينَ مِن الرِّجالِ بالنِّساءِ، والمتشَبِّهاتِ مِن النِّساءِ بالرِّجالِ)", "role": "emphasis"}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- الضابط الثاني: ألَّا يكونَ فيه تشَبُّهٌ بالكُفَّارِ ولا أهلِ البِدَعِ ولا الفُسَّاقِ والسَّفِلةِ مِن النَّاس، فقد قال النبي صلى الله عليه وسلم : (من تشَبَّه بقَومٍ فهو منهم)، وقال: (خالِفوا المُشرِكينَ، وَفِّرُوا اللِّحَى، وأحْفُوا الشَّوارِبَ).", "page": 354, "id": "unit-26__lesson-23__b13", "inline": [{"t": "emphasis", "s": "2- الضابط الثاني", "role": "emphasis"}, {"t": "text", "s": ": ألَّا يكونَ فيه تشَبُّهٌ بالكُفَّارِ ولا أهلِ البِدَعِ ولا الفُسَّاقِ والسَّفِلةِ مِن النَّاس، فقد قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(من تشَبَّه بقَومٍ فهو منهم)", "role": "emphasis"}, {"t": "text", "s": "، وقال: "}, {"t": "emphasis", "s": "(خالِفوا المُشرِكينَ، وَفِّرُوا اللِّحَى، وأحْفُوا الشَّوارِبَ)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- الضابط الثالث: ألَّا يترتَّبَ على التزَيُّنِ ضَرَرٌ، فقد قال الله تعالى: ﴿وَلَا تُلۡقُواْ بِأَيۡدِيكُمۡ إِلَى ٱلتَّهۡلُكَةِ﴾؛ فما كان سببًا للضَّررِ فإنَّه مَنهيٌّ عنه، كبعض الزينة التي تؤدي للسرطانات في الجلد أو الثدي ونحوه.", "page": 354, "id": "unit-26__lesson-23__b14", "inline": [{"t": "emphasis", "s": "3- الضابط الثالث", "role": "emphasis"}, {"t": "text", "s": ": ألَّا يترتَّبَ على التزَيُّنِ ضَرَرٌ، فقد قال الله تعالى: "}, {"t": "ayah", "s": "وَلَا تُلۡقُواْ بِأَيۡدِيكُمۡ إِلَى ٱلتَّهۡلُكَةِ", "ayah": [], "verses": [{"n": 195, "text": "وَلَا تُلۡقُواْ بِأَيۡدِيكُمۡ إِلَى ٱلتَّهۡلُكَةِ", "surah": 2, "surah_name": "البقرة", "ref": "2:195", "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:195"}], "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:195", "surah_name": "البقرة", "ayah_canonical": 195, "match": "contained", "ref": "2:195"}, {"t": "text", "s": "؛ فما كان سببًا للضَّررِ فإنَّه مَنهيٌّ عنه، كبعض الزينة التي تؤدي للسرطانات في الجلد أو الثدي ونحوه."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- الضابط الرابع: ألَّا يكونَ في التزَيُّنِ سَرَفٌ؛ قال تعالى: ﴿۞يَٰبَنِيٓ ءَادَمَ خُذُواْ زِينَتَكُمۡ عِندَ كُلِّ مَسۡجِدٖ وَكُلُواْ وَٱشۡرَبُواْ وَلَا تُسۡرِفُوٓاْۚ إِنَّهُۥ لَا يُحِبُّ ٱلۡمُسۡرِفِينَ ۝٣١﴾، وقال صلى الله عليه وسلم : (الْبَسوا في غيرِ إسرافٍ ولا مَخِيلةٍ).", "page": 354, "id": "unit-26__lesson-23__b15", "inline": [{"t": "emphasis", "s": "4- الضابط الرابع", "role": "emphasis"}, {"t": "text", "s": ": ألَّا يكونَ في التزَيُّنِ سَرَفٌ؛ قال تعالى: "}, {"t": "ayah", "s": "۞يَٰبَنِيٓ ءَادَمَ خُذُواْ زِينَتَكُمۡ عِندَ كُلِّ مَسۡجِدٖ وَكُلُواْ وَٱشۡرَبُواْ وَلَا تُسۡرِفُوٓاْۚ إِنَّهُۥ لَا يُحِبُّ ٱلۡمُسۡرِفِينَ ۝٣١", "ayah": [31], "verses": [{"n": 31, "text": "۞يَٰبَنِيٓ ءَادَمَ خُذُواْ زِينَتَكُمۡ عِندَ كُلِّ مَسۡجِدٖ وَكُلُواْ وَٱشۡرَبُواْ وَلَا تُسۡرِفُوٓاْۚ إِنَّهُۥ لَا يُحِبُّ ٱلۡمُسۡرِفِينَ", "surah": 7, "ref_api": "https://api.quran.com/api/v4/verses/by_key/7:31", "surah_name": "الأعراف", "ayah_canonical": 31, "match": "exact", "ref": "7:31"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، وقال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(الْبَسوا في غيرِ إسرافٍ ولا مَخِيلةٍ)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- الضابط الخامس: ألَّا يكونَ مُغَيِّرًا لخَلقِ اللهِ تغييرًا ثابتًا؛ فقد قال الله تعالى حكايةً عن إبليسَ لعنه اللهُ: ﴿وَلَأُضِلَّنَّهُمۡ وَلَأُمَنِّيَنَّهُمۡ وَلَأٓمُرَنَّهُمۡ فَلَيُبَتِّكُنَّ ءَاذَانَ ٱلۡأَنۡعَٰمِ وَلَأٓمُرَنَّهُمۡ فَلَيُغَيِّرُنَّ خَلۡقَ ٱللَّهِۚ﴾ وسيأتي تفصيله قريبا.", "page": 355, "id": "unit-26__lesson-23__b16", "inline": [{"t": "emphasis", "s": "5- الضابط الخامس", "role": "emphasis"}, {"t": "text", "s": ": ألَّا يكونَ مُغَيِّرًا لخَلقِ اللهِ تغييرًا ثابتًا؛ فقد قال الله تعالى حكايةً عن إبليسَ لعنه اللهُ: "}, {"t": "ayah", "s": "وَلَأُضِلَّنَّهُمۡ وَلَأُمَنِّيَنَّهُمۡ وَلَأٓمُرَنَّهُمۡ فَلَيُبَتِّكُنَّ ءَاذَانَ ٱلۡأَنۡعَٰمِ وَلَأٓمُرَنَّهُمۡ فَلَيُغَيِّرُنَّ خَلۡقَ ٱللَّهِۚ", "ayah": [], "verses": [{"n": 119, "text": "وَلَأُضِلَّنَّهُمۡ وَلَأُمَنِّيَنَّهُمۡ وَلَأٓمُرَنَّهُمۡ فَلَيُبَتِّكُنَّ ءَاذَانَ ٱلۡأَنۡعَٰمِ وَلَأٓمُرَنَّهُمۡ فَلَيُغَيِّرُنَّ خَلۡقَ ٱللَّهِۚ", "surah": 4, "surah_name": "النساء", "ref": "4:119", "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:119"}], "surah": 4, "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:119", "surah_name": "النساء", "ayah_canonical": 119, "match": "contained", "ref": "4:119"}, {"t": "text", "s": " وسيأتي تفصيله قريبا."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6- الضابط السَّادس: ألَّا يُكونَ فيه غِشٌّ أو تدليسٌ؛ قال صلى الله عليه وسلم : (من غَشَّنَا فليس مِنَّا)، وعن سعيدِ بنِ المسَيِّبِ قال: «قَدِمَ مُعاوِيةُ المدينةَ فخَطَبَنا، وأخرج كُبَّةً مِن شَعرٍ -أي وصلة شَعْر- فقال: ما كنتُ أُرى أنَّ أحدًا يفعَلُه إلَّا اليهودَ، إنَّ رَسولَ الله صلى الله عليه وسلم بلَغَه، فسَمَّاه الزُّورَ»، أي أن وِصالَ الشَّعرِ زور، والزور هو: الكَذِبُ والتَّزيينُ بالبَاطلِ، ولا شكَّ أَنَّ وصْلَ الشَّعْرِ منه، فنُهِيَ عَن ذلك؛ لِما فيه من الغِشِّ والخِداعِ.", "page": 355, "id": "unit-26__lesson-23__b17", "inline": [{"t": "emphasis", "s": "6- الضابط السَّادس", "role": "emphasis"}, {"t": "text", "s": ": ألَّا يُكونَ فيه غِشٌّ أو تدليسٌ؛ قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(من غَشَّنَا فليس مِنَّا)", "role": "emphasis"}, {"t": "text", "s": "، وعن سعيدِ بنِ المسَيِّبِ قال: "}, {"t": "hadith", "s": "قَدِمَ مُعاوِيةُ المدينةَ فخَطَبَنا، وأخرج كُبَّةً مِن شَعرٍ -أي وصلة شَعْر- فقال: ما كنتُ أُرى أنَّ أحدًا يفعَلُه إلَّا اليهودَ، إنَّ رَسولَ الله صلى الله عليه وسلم بلَغَه، فسَمَّاه الزُّورَ", "narrator": "سعيد بن المسيب", "source": null, "confidence": "high", "ref_api": null}, {"t": "text", "s": "، أي أن وِصالَ الشَّعرِ زور، والزور هو: الكَذِبُ والتَّزيينُ بالبَاطلِ، ولا شكَّ أَنَّ وصْلَ الشَّعْرِ منه، فنُهِيَ عَن ذلك؛ لِما فيه من الغِشِّ والخِداعِ."}], "list": {"type": "ordered", "marker": "6"}}, {"type": "paragraph", "md": "7- الضابط السابع: ألَّا يكونَ التزَيُّنُ بمُحَرَّمٍ؛ كتزَيُّنِ الرِّجالِ بالذَّهَبِ وغَيرِه.", "page": 355, "id": "unit-26__lesson-23__b18", "inline": [{"t": "emphasis", "s": "7- الضابط السابع", "role": "emphasis"}, {"t": "text", "s": ": ألَّا يكونَ التزَيُّنُ بمُحَرَّمٍ؛ كتزَيُّنِ الرِّجالِ بالذَّهَبِ وغَيرِه."}], "list": {"type": "ordered", "marker": "7"}}, {"type": "heading", "level": 3, "text": "ثالثًا: أحكام ومسائل في زينة المراة المسلمة:", "page": 355, "id": "unit-26__lesson-23__b19", "role": "benefits"}, {"type": "paragraph", "md": "- يجوزُ للمَرأةِ التزَيُّنُ باستخدامِ الكحل ومَساحيقِ التَجميلِ؛ لأنَّ الأصلَ في الزينةِ الحِلُّ إلَّا ما حُرِّم شرعًا.", "page": 355, "id": "unit-26__lesson-23__b20", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- يُباحُ استخدامُ العَدَساتِ اللَّاصِقةِ المُلَوَّنةِ، ويحرم وضع الرموش الصناعية؛ لأنها من الوصل المحرم.", "page": 355, "id": "unit-26__lesson-23__b21", "inline": [{"t": "text", "s": "- يُباحُ استخدامُ "}, {"t": "emphasis", "s": "العَدَساتِ اللَّاصِقةِ", "role": "emphasis"}, {"t": "text", "s": " المُلَوَّنةِ، ويحرم وضع "}, {"t": "emphasis", "s": "الرموش الصناعية", "role": "emphasis"}, {"t": "text", "s": "؛ لأنها من الوصل المحرم."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- يجوزُ وَضعُ الخالِ المُصطَنَع بالقَلَمِ (رسم الشامة صناعيا)؛ لأن الأصل في الزينة الحِل.", "page": 355, "id": "unit-26__lesson-23__b22", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- يجوزُ تَبييضُ الأسنانِ؛ لإزالةِ عَيبِ الاصْفِرارِ، وإزالة العيب جائزة، والشَّرع رغَّبَ في تنظيف الأسنان.", "page": 355, "id": "unit-26__lesson-23__b23", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- تُكرَهُ إطالةُ الأظْفارِ باتفاق المذاهب الأربعة، ويُباح وضع المناكير على الأظفار؛ لأنه زينة مشروعة.", "page": 355, "id": "unit-26__lesson-23__b24", "inline": [{"t": "text", "s": "- تُكرَهُ إطالةُ الأظْفارِ باتفاق المذاهب الأربعة، ويُباح وضع "}, {"t": "emphasis", "s": "المناكير", "role": "emphasis"}, {"t": "text", "s": " على الأظفار؛ لأنه زينة مشروعة."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- يُكرَهُ خِضابُ الشَّعرِ بالسَّوادِ -ولا يَحرم؛ حيثُ خضب صحابةٌ بالسواد-، ويستحب الخضاب بغيره، ويجوز صبغ الشعر بـ«الميش»؛ إلا إذا كان مُضرًّا حسب كلام الأطباء فيُمنع منه لوجود الضرر.", "page": 355, "id": "unit-26__lesson-23__b25", "inline": [{"t": "text", "s": "- يُكرَهُ خِضابُ الشَّعرِ بالسَّوادِ -ولا يَحرم؛ حيثُ خضب صحابةٌ بالسواد-، ويستحب الخضاب بغيره، ويجوز صبغ الشعر بـ"}, {"t": "quote", "s": "الميش"}, {"t": "text", "s": "؛ إلا إذا كان مُضرًّا حسب كلام الأطباء فيُمنع منه لوجود الضرر."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- يجوزُ للنِّساءِ خَضبُ أيديهنَّ وأرجُلِهنَّ؛ لأنَّ فيه زينةً وجمالًا لهنَّ، وهُنَّ في حاجةٍ لذلك، ويَحرُمُ على الرِّجالِ خِضابُ اليَدَينِ والرِّجلينِ للزِّينةِ؛ لأنه من خصائص زينة المرأة ولا يجوز للرجل التشبه بها.", "page": 355, "id": "unit-26__lesson-23__b26", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- يجوزُ لُبسُ السَّاعةِ والتزَيُّنُ بها للرِّجالِ والنِّساءِ؛ في معصم اليد اليُمنى أو اليسرى، لأنَّها من جنس التختم.", "page": 355, "id": "unit-26__lesson-23__b27", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- لا يجوزُ لُبسُ حُلِيٍّ على هيئةِ حَيوانٍ مجسَّم، أو فيه صُورة لذواتِ الأرواحِ؛ لأن التصاوير محرمة.", "page": 355, "id": "unit-26__lesson-23__b28", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- يُباحُ للمَرأةِ التزَيُّنُ بحُلِيِّ الذَّهَبِ والفِضَّةِ، ولكن يحرم لبسها النعال الذهبية؛ للسرف وليس زينةً معتادة.", "page": 355, "id": "unit-26__lesson-23__b29", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- يجوزُ للرَّجُلِ والمرأة التخَتُّمُ بخاتَمِ الفِضَّةِ، ويجوز اتخاذ خاتم من حديد كذلك، ويُباحُ للمَرأةِ التَّحَلِّي بالجواهِرِ والأحْجارِ الكَريمةِ كذلك، ويجوزُ نَقشُ الخاتَمِ بما بدا لصاحِبِه؛ كنَقشِ اسمِه واسمِ أبيه، أو بما فيه ذِكرٌ لله؛ على أنه لا يدخل مواضع الأذى كالخلاء وغيره بما فيهِ ذكرٌ لله تعظيمًا له.", "page": 355, "id": "unit-26__lesson-23__b30", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- يجوزُ إجراءُ العمَليَّاتِ الجِراحيَّة للعِلاجِ لا للتجميل، أو لإزالةِ العُيوبِ الخِلْقيَّة والمُكتَسَبةِ «الطَّارئة»، وإجراءَ العَمَليَّاتِ الجِراحيَّةِ لإزالةِ العُيوبِ يُعَدُّ حاجةً؛ ولذلك يجوزُ إعمالًا للقاعدةِ العامة: الحاجةُ تُنزَّلُ مَنزِلةَ الضَّرورةِ، عامةً كانت أو خاصَّةً؛ أن تُجرى هذه العمليات، ومن أمثلة مما يُشرع فعله على ذلك:", "page": 356, "id": "unit-26__lesson-23__b31", "inline": [{"t": "text", "s": "- يجوزُ إجراءُ العمَليَّاتِ الجِراحيَّة للعِلاجِ لا للتجميل، أو لإزالةِ العُيوبِ الخِلْقيَّة والمُكتَسَبةِ "}, {"t": "quote", "s": "الطَّارئة"}, {"t": "text", "s": "، وإجراءَ العَمَليَّاتِ الجِراحيَّةِ لإزالةِ العُيوبِ يُعَدُّ حاجةً؛ ولذلك يجوزُ إعمالًا للقاعدةِ العامة: الحاجةُ تُنزَّلُ مَنزِلةَ الضَّرورةِ، عامةً كانت أو خاصَّةً؛ أن تُجرى هذه العمليات، "}, {"t": "emphasis", "s": "ومن أمثلة مما يُشرع فعله على ذلك", "role": "emphasis"}, {"t": "text", "s": ":"}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "1- تقويمُ الأسنانِ لإزالةِ عَيبٍ فيها. 2- زراعةُ الأسنانِ وتَركيبُ الأسنانِ الصِّناعيَّة.", "page": 356, "id": "unit-26__lesson-23__b32", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "3- زراعةُ الشَّعرِ؛ لإزالةِ عَيبِ الصَّلَعِ. 4- إزالةُ عَيبِ الشَّامات والوَحماتِ.", "page": 356, "id": "unit-26__lesson-23__b33", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "5- قطعُ الأعضاءِ الزَّائدة. 6- إعادةُ العُضوِ المقطوعِ. 7- علاجُ السِّمنةِ المُفرِطة.", "page": 356, "id": "unit-26__lesson-23__b34", "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "- تجوز العَمَليَّاتُ الجِراحيَّةُ التَّجميليَّةُ التي ليس فيها تغييرٌ لخَلقِ اللهِ؛ كثقب أذن البنت أو الأنف للزينة.", "page": 356, "id": "unit-26__lesson-23__b35", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- لا يجوزُ القِيامُ بعَمَليَّاتٍ جِراحيَّةٍ تَجميليَّةٍ، إذا كان فيها تغييرٌ لخِلقةِ اللهِ؛ التِماسَ التحَسُّنِ به لزَوجٍ أو غيرِه؛ فقد قال صلى الله عليه وسلم: (لعَنَ اللهُ الواشِماتِ والمُستَوشِماتِ، والمتنَمِّصاتِ، والمتفَلِّجاتِ للحُسنِ، المغَيِّراتِ خَلقَ اللهِ)؛ فلا يجوز تغيير خلقِ الله إذا كان لطلبِ الحُسْن، ومن أمثلة التغيير المحرم:", "page": 356, "id": "unit-26__lesson-23__b36", "inline": [{"t": "text", "s": "- لا يجوزُ القِيامُ بعَمَليَّاتٍ جِراحيَّةٍ تَجميليَّةٍ، إذا كان فيها تغييرٌ لخِلقةِ اللهِ؛ التِماسَ التحَسُّنِ به لزَوجٍ أو غيرِه؛ فقد قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": ": "}, {"t": "emphasis", "s": "(لعَنَ اللهُ الواشِماتِ والمُستَوشِماتِ، والمتنَمِّصاتِ، والمتفَلِّجاتِ للحُسنِ، المغَيِّراتِ خَلقَ اللهِ)؛", "role": "emphasis"}, {"t": "text", "s": " فلا يجوز تغيير خلقِ الله إذا كان لطلبِ الحُسْن، "}, {"t": "emphasis", "s": "ومن أمثلة التغيير المحرم", "role": "emphasis"}, {"t": "text", "s": ":"}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "1- تجميلُ الأنفِ، بتَصغيرِه أو تَغييرِ شَكْلِه. 2- تجميلُ الذَّقَنِ. 3- تجميلُ الأذُنِ صغرًا أو كِبرًا.", "page": 356, "id": "unit-26__lesson-23__b37", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "4- تجميلُ الثَّديَينِ، بتَصغيرِهما، أو تَكبيرِهما، أو بإدخالِ النَّهدِ الصِّناعيِّ داخِلَ جَوفِ الثَّديِ.", "page": 356, "id": "unit-26__lesson-23__b38", "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- تَجميلُ البَطنِ. 6- تَجميلُ الوَجهِ بشَدِّ تجاعيدِه، أو بعمَليَّةِ القَشرِ الكِيماويِّ، أو الليزَر، أو الحَقنِ.", "page": 356, "id": "unit-26__lesson-23__b39", "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "7- تجميلُ الأردافِ، وشَدُّ جِلدتِها، وتهذيبُ حَجمِها بحَسَبِ الصُّورةِ المطلوبةِ.8- تجميلُ السَّاعِدِ.", "page": 356, "id": "unit-26__lesson-23__b40", "list": {"type": "ordered", "marker": "7"}}, {"type": "paragraph", "md": "9- تجميلُ اليَدَينِ بشَدِّ تجاعيدِهما، وخاصَّةً لكِبارِ السِّنِّ. 10- تجميلُ الحواجِبِ والجُفونِ ورَفعُها.", "page": 356, "id": "unit-26__lesson-23__b41", "list": {"type": "ordered", "marker": "9"}}, {"type": "paragraph", "md": "11- تجميلُ الأسنانِ بوَضعِ الكِريستالِ أو الألْماس، عن طريقِ الحَفرِ والتَّثبيتِ الدَّائِمِ.", "page": 356, "id": "unit-26__lesson-23__b42", "list": {"type": "ordered", "marker": "11"}}, {"type": "paragraph", "md": "12- تَبييضُ البَشَرةِ على وجهِ الدَّوامِ. 13- تطويلُ القامةِ. 14- نَفخُ الخُدودِ والشِّفاه.", "page": 356, "id": "unit-26__lesson-23__b43", "list": {"type": "ordered", "marker": "12"}}, {"type": "paragraph", "md": "- يحرُمُ تزيين البيوت بالصُّوَرِ المُجَسِّمةِ لذواتِ الأرواحِ، أو تعليق الصور المطبوعة؛ للزِّينةِ أو غَيرِها.", "page": 356, "id": "unit-26__lesson-23__b44", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- يُباحُ فَرشُ الأرضِ بما يَشتَمِلُ على صُوَرِ ذَواتِ الأرواحِ؛ لامتهانها، ولا بأس بتعليق ما قُطع رأسه.", "page": 356, "id": "unit-26__lesson-23__b45", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "الأسئلة التقويمية: 1- اذكري خمسة ضوابط للزينة في الشريعة؟ وما أسباب مخالفة النساء لها.", "page": 356, "id": "unit-26__lesson-23__b46"}, {"type": "paragraph", "md": "2- ما حكم الزينة التي فيها تغيير لخلق الله، واذكري خمسة أمثلة لذلك.", "page": 356, "id": "unit-26__lesson-23__b47", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط دعوي واجتماعي", "page": 356, "id": "unit-26__lesson-23__b48", "role": "activity"}, {"type": "paragraph", "md": "من المهم نشرُ هذه الأحكام؛ فلنعمل على نشر مضمون هذا الدرس بين عشر نساء حولنا", "page": 356, "id": "unit-26__lesson-23__b49", "item_role": "activity_step"}, {"type": "paragraph", "md": "منارات الهدى", "page": 357, "id": "unit-26__lesson-23__b50", "item_role": "activity_step"}]' WHERE id='unit-26__lesson-23';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-26__lesson-24','unit-26',24,'أحكام العدة والإحْداد','الفقه',NULL,0,0,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أولا: تعريف العدة، وذكر أحكام عدة المتوفى عنها زوجها:", "page": 357, "id": "unit-26__lesson-24__b01", "role": "definitions"}, {"type": "paragraph", "md": "- العِدَّة لغةً: مأخوذٌ مِنَ العَدِّ والحِسابِ، وسُمِّيَ زَمانُ الترَبُّصِ عِدَّةً؛ لأنَّها تَعُدُّه. وشَرعًا: اسمٌ لِمُدَّةٍ تترَبَّصُ فيها المرأةُ عن التَّزويجِ بعدَ وفاةِ زَوجِها أو فِراقِه لها؛ إمَّا بالوِلادةِ، أو بالأقراءِ، أو الأشهُرِ.", "page": 357, "id": "unit-26__lesson-24__b02", "inline": [{"t": "text", "s": "- العِدَّة لغةً: مأخوذٌ مِنَ العَدِّ والحِسابِ، وسُمِّيَ زَمانُ الترَبُّصِ عِدَّةً؛ لأنَّها تَعُدُّه. "}, {"t": "emphasis", "s": "وشَرعًا", "role": "lemma"}, {"t": "text", "s": ": اسمٌ لِمُدَّةٍ تترَبَّصُ فيها المرأةُ عن التَّزويجِ بعدَ وفاةِ زَوجِها أو فِراقِه لها؛ إمَّا بالوِلادةِ، أو بالأقراءِ، أو الأشهُرِ."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- وتجِبُ العِدَّةُ على المرأةِ المسلمة عندَ وُجودِ سَبَبهِا؛ فلا يحل للمرأةِ مخالفةُ ذلك وإلا أثمت.", "page": 357, "id": "unit-26__lesson-24__b03", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- عدة المتوفى عنها زوجها: تجِبُ العِدَّةُ على المتوفى عنها زَوجُها، سواءٌ دخل بها أم لم يدخُلْ؛ فإن كانت حائلا «غير حامل» فعدتها: أربعة أشهر وعشر أيام من تاريخ وفاة زوجها بالأشهر القمرية. وإن كانت حاملًا فعدتها تنتهي بوضع حملها، بشرط أن تضعَ حملًا يتبين فيه خلق إنسان ولو ميت.", "page": 357, "id": "unit-26__lesson-24__b04", "inline": [{"t": "emphasis", "s": "- عدة المتوفى عنها زوجها", "role": "lemma"}, {"t": "text", "s": ": تجِبُ العِدَّةُ على المتوفى عنها زَوجُها، سواءٌ دخل بها أم لم يدخُلْ؛ فإن كانت حائلا "}, {"t": "quote", "s": "غير حامل"}, {"t": "text", "s": " فعدتها: أربعة أشهر وعشر أيام من تاريخ وفاة زوجها بالأشهر القمرية. وإن كانت حاملًا فعدتها تنتهي بوضع حملها، بشرط أن تضعَ حملًا يتبين فيه خلق إنسان ولو ميت."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "-المُعتَدَّةُ مِن وفاةِ زَوجِها لا نَفَقةَ لها؛ فلها نصيبٌ في التركة والعِدة حقٌّ لله وليست حقُّ الزوج فقط.", "page": 357, "id": "unit-26__lesson-24__b05"}, {"type": "paragraph", "md": "-يجوزُ للمُعتَدَّةِ مِن الوفاةِ الخُروجُ مِن بَيتِها؛ للحاجةِ فقط، كالتكسب وشراء أغراض البيت.. الخ.", "page": 357, "id": "unit-26__lesson-24__b06"}, {"type": "paragraph", "md": "-لا يجوزُ للمُتوَفَّى عنها زَوجُها أن تَبيتَ في غيرِ بيتها الذي كانت تسْكُنه لحديث: (امكثي في بيتك)", "page": 357, "id": "unit-26__lesson-24__b07", "inline": [{"t": "text", "s": "-لا يجوزُ للمُتوَفَّى عنها زَوجُها أن تَبيتَ في غيرِ بيتها الذي كانت تسْكُنه لحديث: "}, {"t": "emphasis", "s": "(امكثي في بيتك)", "role": "lemma"}]}, {"type": "heading", "level": 3, "text": "ثانيًا: أحكام العدة للمرأة المطلقة:", "page": 357, "id": "unit-26__lesson-24__b08", "role": "rulings"}, {"type": "paragraph", "md": "- تجِبُ العِدَّةُ على المطلقةِ إذا حَصَلت خَلوةٌ صَحيحةٌ بينَ الزَّوجينِ ولو بدونِ وَطءٍ؛ فإن لم تحصل خلوة بينهما ولا وطء فلا عدة عليها بنص كتاب الله تعالى، وعدة المطلقة على أنواع:", "page": 357, "id": "unit-26__lesson-24__b09", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "1- ذوات الحيض: ثلاثة قروء؛ أي ثلاثة أطهار. وإذا ارتفَعَ حَيضُها لعلةٍ فبالأقراء أيضًا ولو طالت المدة.", "page": 357, "id": "unit-26__lesson-24__b10", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- الآيسة، والصغيرة التي لم تحض، المستحاضة المتحيرة التي لا تُميز دورتها: تعتد ثلاثة أشهر.", "page": 357, "id": "unit-26__lesson-24__b11", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "- لا تنقَطِعُ العِدَّةُ باكتشافِ براءةِ الرَّحِمِ مِن الحَملِ طبيًّا؛ وذلك لأنَّ العِدَّةَ يَغلِبُ عليها معنى التعبُّدِ مِن حيثُ الجُملةُ، ولها مقاصِدُ أُخرى غيرُ براءةِ الرَّحِمِ؛ ولهذا تجِبُ على الصَّغيرةِ والآيِسةِ وغيرهما مثلا.", "page": 357, "id": "unit-26__lesson-24__b12", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- تجِبُ نَفَقةُ المُطَلَّقةِ الرَّجعيَّةِ وسُكناها في العِدَّةِ على الزوجِ؛ لأنها لا تزال زوجة له، ولو ماتَ ورثته.", "page": 357, "id": "unit-26__lesson-24__b13", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- وتَجِبُ النَّفَقةُ والسُّكنى للمُطَلَّقةِ البائِنِ الحامِلِ في العِدَّةِ؛ لأنَّ الحمل ولده فيُنفق عليه ولا يُمكنه ذلك إلا بالإنفاق عليها؛ كما يُعطيها لاحقًا أجرة الرضاع، والمرأة محبوسة بسبب الحمل الذي بها من زوجها.", "page": 357, "id": "unit-26__lesson-24__b14", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- لا يَجِبُ للمُعتَدَّةِ البائِنِ الحائِلِ (غيرِ الحامِلِ) السُّكنى ولا النَّفَقةُ؛ لنص الحديث بذلك.", "page": 357, "id": "unit-26__lesson-24__b15", "inline": [{"t": "text", "s": "- لا يَجِبُ للمُعتَدَّةِ البائِنِ الحائِلِ "}, {"t": "emphasis", "s": "(غيرِ الحامِلِ)", "role": "emphasis"}, {"t": "text", "s": " السُّكنى ولا النَّفَقةُ؛ لنص الحديث بذلك."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- يجوزُ للمُعتَدَّةِ الرَّجعيَّةِ الخُروجُ مِن بَيتِها بإذنِ زَوجِها؛ لأن الوحية لم تنقطع عنها وإن كانت مطلقة.", "page": 358, "id": "unit-26__lesson-24__b16", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- يَجوزُ للمُعتَدَّةِ البائِنِ بَينونةً كُبرى الخروجُ مِن بَيتِها نهارًا؛ للحاجةِ، ولا يُشترط إذن الزوج السابق.", "page": 358, "id": "unit-26__lesson-24__b17", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- يجِبُ على المُعتَدَّةِ مِن طلاقٍ رَجعيٍّ أن تبيتَ في بيتِ الزَّوجيَّةِ؛ ولا يجوز للزوج إخراجها من بيتهما.", "page": 358, "id": "unit-26__lesson-24__b18", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- المُطَلَّقةُ البائِنُ بَينونةً كُبرى تعتَدُّ حيث شاءت، ولا يجِبُ عليها المبيت عند مُطَلِّقِها؛ فلا سُكنى لها عنده.", "page": 358, "id": "unit-26__lesson-24__b19", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "ثالثًا: أحكام الإحداد", "page": 358, "id": "unit-26__lesson-24__b20", "role": "rulings"}, {"type": "paragraph", "md": "- الإحداد شرعًا: هو الامتِناعُ مِنَ الزِّينةِ والطِّيبِ على المُتوَفَّى عنها زَوجُها، ومُلازمةُ البَيتِ إلَّا لحاجةٍ.", "page": 358, "id": "unit-26__lesson-24__b21", "inline": [{"t": "text", "s": "- الإحداد "}, {"t": "emphasis", "s": "شرعًا:", "role": "emphasis"}, {"t": "text", "s": " هو الامتِناعُ مِنَ الزِّينةِ والطِّيبِ على المُتوَفَّى عنها زَوجُها، ومُلازمةُ البَيتِ إلَّا لحاجةٍ."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- ويجِبُ الإحدادُ على المرأةِ التي تُوفِّيَ عنها زَوجُها؛ طول مدة العدة الشرعية، وشُرع الإحداد لما يأتي:", "page": 358, "id": "unit-26__lesson-24__b22", "inline": [{"t": "text", "s": "- ويجِبُ الإحدادُ على المرأةِ التي تُوفِّيَ عنها زَوجُها؛ طول مدة العدة الشرعية، "}, {"t": "emphasis", "s": "وشُرع الإحداد لما يأتي", "role": "emphasis"}, {"t": "text", "s": ":"}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "1- تَعظيمًا لعَقدِ النكاحِ، وإظهارِ خَطَرِه وشَرَفِه وأنَّه عندَ الله بمكانٍ؛ فالعِدَّةُ حريمٌ له، والإحدادُ مِن تمامِ هذا المقصودِ وتأكُّدِه؛ حتى جُعِلَت الزَّوجةُ أَولى بفِعلِه على زَوجِها مِن أبيها وابنِها وأخيها وسائِرِ أقارِبِها.", "page": 358, "id": "unit-26__lesson-24__b23", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- الإحدادُ على الزَّوجِ يدُلُّ على تأكُّدِ الفَرقِ بينَه وبينَ السِّفاحِ مِن جميعِ أحكامِه؛ ولهذا شُرِعَ في ابتداء النكاح: إعلانُه والإشهادُ عليه والضَّربُ بالدُّفِّ؛ وشُرِعَ في آخِرِه: العِدَّةِ والإحدادِ؛ ما لم يُشرَعْ في غَيرِه.", "page": 358, "id": "unit-26__lesson-24__b24", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- أنَّ إظهارَ الزِّينةِ والطِّيبِ والحُلِيِّ مِمَّا يدعو المرأةَ إلى الرِّجالِ، والعكس، فلا يُؤمَنُ أن تَكذِبَ في انقِضاءِ عِدَّتِها؛ استِعجالًا لذلك، فمُنِعَت مِن دواعي ذلك وسُدَّت إليه الذَّريعةُ.", "page": 358, "id": "unit-26__lesson-24__b25", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "- تجتنب المرأة في العِدة والإحداد الأمورَ الآتية: (1) أن تَلبَسَ المُعَصفَرَ والمُزَعفَرَ مِنَ الثِّيابِ؛ لأنه يفوح منه الطيب. (2) الطيب والزينة. (3) التحلي بالحلي؛ لأنه يدعو لنكاحها ويزيد حسنها. (4) الاكتحال للزينة؛ لمنافاته الحزن، ولأنه داعٍ لنكاحها. (5) الاختضاب بالحناء وما شابهه من التزين.", "page": 358, "id": "unit-26__lesson-24__b26", "inline": [{"t": "emphasis", "s": "- تجتنب المرأة في العِدة والإحداد الأمورَ الآتية", "role": "emphasis"}, {"t": "text", "s": ": (1) أن تَلبَسَ المُعَصفَرَ والمُزَعفَرَ مِنَ الثِّيابِ؛ لأنه يفوح منه الطيب. (2) الطيب والزينة. (3) التحلي بالحلي؛ لأنه يدعو لنكاحها ويزيد حسنها. (4) الاكتحال للزينة؛ لمنافاته الحزن، ولأنه داعٍ لنكاحها. (5) الاختضاب بالحناء وما شابهه من التزين."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- يُباح للمعتدة من وفاةٍ: استعمال الدهن والزيت غير المطيب، واستعمال المنظفات كالصابون ونحوه، ويجوز لها أن تخاطب الرجال وأن تخرج من البيت للحاجة؛ وفق الضوابط الشرعية لذلك.", "page": 358, "id": "unit-26__lesson-24__b27", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- الحداد للوفاة فقط؛ فلا حداد على المطلقة أيا كانت رجعية أو بائن؛ فتعتد للطلاق ولا إحداد عليها.", "page": 358, "id": "unit-26__lesson-24__b28", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "نشاط دعوي وبحثي", "page": 358, "id": "unit-26__lesson-24__b29", "role": "activity"}, {"type": "paragraph", "md": "نرجع إلى الكتب الآتية للتوسع في أحكام المرأة المسلمة: «إليكِ أنتِ» للدكتورة ليلى حمدان، « سيماء المرأة في الإسلام» لفريد الأنصاري، « المفصل في أحكام المرأة والبيت المسلم في الشريعة الإسلامية» لشيخنا د. عبد الكريم زيدان، «أسئلة الأسرة المسلمة» للشيخ محمد العثيمين، «صور من حياة الصحابيات» لعبد الرحمن الباشا، « شخصية المرأة المسلمة كما يصوغها الإسلام في الكتاب والسنة» للدكتور محمد الهاشمي", "page": 358, "id": "unit-26__lesson-24__b30", "inline": [{"t": "text", "s": "نرجع إلى الكتب الآتية للتوسع في أحكام المرأة المسلمة: "}, {"t": "quote", "s": "إليكِ أنتِ"}, {"t": "text", "s": " للدكتورة ليلى حمدان، "}, {"t": "quote", "s": "سيماء المرأة في الإسلام"}, {"t": "text", "s": " لفريد الأنصاري، "}, {"t": "quote", "s": "المفصل في أحكام المرأة والبيت المسلم في الشريعة الإسلامية"}, {"t": "text", "s": " لشيخنا د. عبد الكريم زيدان، "}, {"t": "quote", "s": "أسئلة الأسرة المسلمة"}, {"t": "text", "s": " للشيخ محمد العثيمين، "}, {"t": "quote", "s": "صور من حياة الصحابيات"}, {"t": "text", "s": " لعبد الرحمن الباشا، "}, {"t": "quote", "s": "شخصية المرأة المسلمة كما يصوغها الإسلام في الكتاب والسنة"}, {"t": "text", "s": " للدكتور محمد الهاشمي"}], "item_role": "activity_step"}, {"type": "paragraph", "md": "المجلس (10)، الفقهالمجلس (10)، الفقهالمجلس (10)، الفقهالمجلس (10)، الفقه", "page": 360, "id": "unit-26__lesson-24__b31", "inline": [{"t": "emphasis", "s": "المجلس (10)، الفقهالمجلس (10)، الفقه", "role": "emphasis"}, {"t": "emphasis", "s": "المجلس (10)، الفقهالمجلس (10)، الفقه", "role": "emphasis"}], "item_role": "activity_step"}, {"type": "image", "src": "assets/image64.jpeg", "caption": "نموذج تحضير الدرس", "page": 360, "id": "unit-26__lesson-24__b32"}, {"type": "paragraph", "md": "نموذج لتحضير الدس", "page": 360, "id": "unit-26__lesson-24__b33", "item_role": "activity_step"}, {"type": "paragraph", "md": "الثانيةالثانيةالثانيةالثانيةحصة واحدةحصة واحدةحصة واحدةحصة واحدةالتيممالتيممالتيممالتيمم27 / 9 / 144627 / 9 / 144627 / 9 / 144627 / 9 / 1446الاثنين الاثنين الاثنين الاثنين الثالثة \"عثمان بن عفان\"الثالثة \"عثمان بن عفان\"الثالثة \"عثمان بن عفان\"الثالثة \"عثمان بن عفان\"", "page": 360, "id": "unit-26__lesson-24__b34", "inline": [{"t": "emphasis", "s": "الثانيةالثانية", "role": "emphasis"}, {"t": "emphasis", "s": "الثانيةالثانية", "role": "emphasis"}, {"t": "emphasis", "s": "حصة واحدةحصة واحدة", "role": "emphasis"}, {"t": "emphasis", "s": "حصة واحدةحصة واحدة", "role": "emphasis"}, {"t": "emphasis", "s": "التيممالتيمم", "role": "emphasis"}, {"t": "emphasis", "s": "التيممالتيمم", "role": "emphasis"}, {"t": "text", "s": "27 / 9 / 144627 / 9 / 144627 / 9 / 144627 / 9 / 1446"}, {"t": "emphasis", "s": "الاثنين الاثنين", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "الاثنين الاثنين", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "الثالثة \"عثمان بن عفان\"الثالثة \"عثم